_MATERIAL_INDEX_CACHE: Dict[str, Dict[str, object]] = {}
_MATERIAL_INDEX_CACHE_ORDER: List[str] = []
_MATERIAL_INDEX_CACHE_LOCK = threading.RLock()
_MATERIAL_PARSE_STATE_LOCK = threading.RLock()
_MATERIAL_PARSE_WORKER_LOCK = threading.RLock()
_MATERIAL_PARSE_STOP_EVENT = threading.Event()
_MATERIAL_PARSE_WORKER: Optional[threading.Thread] = None
_MATERIAL_PARSE_WORKERS: List[threading.Thread] = []
_MATERIAL_PARSE_PENDING_REBUILDS: Dict[str, float] = {}
_MATERIAL_PARSE_PENDING_REBUILDS_LOCK = threading.RLock()


class _MaterialParseWorkerHealthProbe:
    def is_alive(self) -> bool:
        with _MATERIAL_PARSE_WORKER_LOCK:
            workers = _refresh_material_parse_workers_locked()
            return any(worker.is_alive() for worker in workers)


_MATERIAL_PARSE_WORKER_HEALTH_PROBE = _MaterialParseWorkerHealthProbe()


def _refresh_material_parse_workers_locked() -> List[threading.Thread]:
    global _MATERIAL_PARSE_WORKER
    workers = [worker for worker in _MATERIAL_PARSE_WORKERS if worker and worker.is_alive()]
    if _MATERIAL_PARSE_WORKER and _MATERIAL_PARSE_WORKER.is_alive():
        if all(worker is not _MATERIAL_PARSE_WORKER for worker in workers):
            workers.insert(0, _MATERIAL_PARSE_WORKER)
    _MATERIAL_PARSE_WORKERS[:] = workers
    _MATERIAL_PARSE_WORKER = workers[0] if workers else None
    return list(workers)


def _schedule_project_material_rebuild(project_id: str) -> None:
    project_key = str(project_id or "").strip()
    if not project_key:
        return
    due_at = time.monotonic() + DEFAULT_MATERIAL_PARSE_REBUILD_DEBOUNCE_SECONDS
    with _MATERIAL_PARSE_PENDING_REBUILDS_LOCK:
        _MATERIAL_PARSE_PENDING_REBUILDS[project_key] = due_at


def _claim_due_project_material_rebuilds(*, limit: int = 1) -> List[str]:
    now = time.monotonic()
    with _MATERIAL_PARSE_PENDING_REBUILDS_LOCK:
        due_project_ids = [
            project_id
            for project_id, due_at in _MATERIAL_PARSE_PENDING_REBUILDS.items()
            if due_at <= now
        ]
        due_project_ids.sort()
        claimed = due_project_ids[: max(1, int(limit))]
        for project_id in claimed:
            _MATERIAL_PARSE_PENDING_REBUILDS.pop(project_id, None)
    return claimed


def _drain_due_project_material_rebuilds(*, limit: int = 1) -> int:
    rebuilt = 0
    for project_id in _claim_due_project_material_rebuilds(limit=limit):
        try:
            _rebuild_project_anchors_and_requirements(project_id)
        except Exception:
            logger.exception("material parse deferred rebuild failed for project %s", project_id)
        else:
            rebuilt += 1
    return rebuilt


def _material_row_cache_token(row: Dict[str, object]) -> Dict[str, object]:
    path_text = str(row.get("path") or "").strip()
    stat_size = -1
    stat_mtime_ns = -1
    if path_text:
        p = Path(path_text)
        if p.exists():
            try:
                st = p.stat()
                stat_size = int(st.st_size)
                stat_mtime_ns = int(getattr(st, "st_mtime_ns", int(st.st_mtime * 1_000_000_000)))
            except Exception:
                stat_size = -1
                stat_mtime_ns = -1
    return {
        "id": str(row.get("id") or ""),
        "material_type": _normalize_material_type(
            row.get("material_type"), filename=row.get("filename")
        ),
        "filename": str(row.get("filename") or ""),
        "path": path_text,
        "created_at": str(row.get("created_at") or ""),
        "updated_at": str(row.get("updated_at") or ""),
        "size": stat_size,
        "mtime_ns": stat_mtime_ns,
    }


def _compute_material_index_signature(project_id: str, rows: List[Dict[str, object]]) -> str:
    payload = {
        "project_id": project_id,
        "rows": [_material_row_cache_token(row) for row in rows],
    }
    digest = hashlib.sha1(json.dumps(payload, ensure_ascii=False, sort_keys=True).encode("utf-8"))
    return digest.hexdigest()


def _touch_material_index_cache(project_id: str) -> None:
    if project_id in _MATERIAL_INDEX_CACHE_ORDER:
        _MATERIAL_INDEX_CACHE_ORDER.remove(project_id)
    _MATERIAL_INDEX_CACHE_ORDER.append(project_id)
    while len(_MATERIAL_INDEX_CACHE_ORDER) > int(DEFAULT_MATERIAL_INDEX_CACHE_SIZE):
        stale = _MATERIAL_INDEX_CACHE_ORDER.pop(0)
        _MATERIAL_INDEX_CACHE.pop(stale, None)


def _invalidate_material_index_cache(project_id: Optional[str] = None) -> None:
    with _MATERIAL_INDEX_CACHE_LOCK:
        if project_id is None:
            _MATERIAL_INDEX_CACHE.clear()
            _MATERIAL_INDEX_CACHE_ORDER.clear()
            return
        _MATERIAL_INDEX_CACHE.pop(project_id, None)
        if project_id in _MATERIAL_INDEX_CACHE_ORDER:
            _MATERIAL_INDEX_CACHE_ORDER.remove(project_id)


def _default_material_parse_state(material_type: str, *, path: str = "") -> Dict[str, object]:
    has_path = bool(str(path or "").strip())
    return {
        "parse_status": "queued" if has_path else "failed",
        "parse_backend": "queued" if has_path else "none",
        "parse_confidence": 0.0,
        "parse_error_class": None if has_path else "missing_path",
        "parse_error_message": None if has_path else "missing_path",
        "parse_started_at": None,
        "parse_finished_at": None,
        "parse_version": DEFAULT_MATERIAL_PARSE_VERSION,
        "structured_summary": None,
        "job_id": None,
        "parsed_text": "",
        "parsed_chars": 0,
        "parsed_chunks": [],
        "numeric_terms_norm": [],
        "lexical_terms": [],
        "updated_at": _now_iso(),
    }


def _normalize_material_row_for_parse(row: Dict[str, object]) -> tuple[Dict[str, object], bool]:
    normalized = dict(row)
    changed = False
    filename = str(normalized.get("filename") or "")
    material_type = _normalize_material_type(normalized.get("material_type"), filename=filename)
    if str(normalized.get("material_type") or "") != material_type:
        normalized["material_type"] = material_type
        changed = True
    defaults = _default_material_parse_state(material_type, path=str(normalized.get("path") or ""))
    for key, value in defaults.items():
        if key not in normalized:
            normalized[key] = value
            changed = True
    if str(normalized.get("parse_status") or "") == "processing":
        normalized["parse_status"] = "queued"
        normalized["parse_backend"] = "queued"
        normalized["parse_error_class"] = "worker_recovered"
        normalized["parse_error_message"] = "worker_recovered"
        normalized["parse_started_at"] = None
        normalized["updated_at"] = _now_iso()
        changed = True
    return normalized, changed


def _normalize_material_parse_job(job: Dict[str, object]) -> tuple[Dict[str, object], bool]:
    normalized = dict(job)
    changed = False
    now = _now_iso()
    defaults: Dict[str, object] = {
        "status": "queued",
        "attempt": 0,
        "parse_backend": None,
        "next_retry_at": None,
        "created_at": now,
        "updated_at": now,
        "started_at": None,
        "finished_at": None,
        "error_class": None,
        "error_message": None,
        "parse_confidence": 0.0,
    }
    for key, value in defaults.items():
        if key not in normalized:
            normalized[key] = value
            changed = True
    return normalized, changed


def _material_parse_job_sort_key(job: Dict[str, object]) -> tuple[str, str, str]:
    return (
        str(job.get("updated_at") or job.get("created_at") or ""),
        str(job.get("created_at") or ""),
        str(job.get("id") or ""),
    )


def _find_latest_material_parse_job(
    jobs: List[Dict[str, object]], material_id: str
) -> tuple[Optional[int], Optional[Dict[str, object]]]:
    latest_idx: Optional[int] = None
    latest_job: Optional[Dict[str, object]] = None
    for idx, job in enumerate(jobs):
        if str(job.get("material_id") or "") != material_id:
            continue
        if latest_job is None or _material_parse_job_sort_key(job) > _material_parse_job_sort_key(
            latest_job
        ):
            latest_idx = idx
            latest_job = job
    return latest_idx, latest_job


def _mark_material_parse_job_queued(
    job: Dict[str, object],
    *,
    reason: Optional[str] = None,
    reset_attempt: bool = False,
) -> bool:
    changed = False
    desired_updates: Dict[str, object] = {
        "status": "queued",
        "parse_backend": None,
        "next_retry_at": None,
        "started_at": None,
        "finished_at": None,
        "parse_confidence": 0.0,
        "error_class": reason,
        "error_message": reason,
    }
    if reset_attempt:
        desired_updates["attempt"] = 0
    for key, value in desired_updates.items():
        if job.get(key) != value:
            job[key] = value
            changed = True
    if changed:
        job["updated_at"] = _now_iso()
    return changed


def _mark_material_parse_job_terminal(
    job: Dict[str, object],
    material_row: Dict[str, object],
) -> bool:
    material_status = str(material_row.get("parse_status") or "").strip().lower()
    if material_status not in {"parsed", "failed"}:
        return False
    changed = False
    finished_at = str(
        material_row.get("parse_finished_at") or material_row.get("updated_at") or _now_iso()
    )
    confidence = float(
        _to_float_or_none(material_row.get("parse_confidence"))
        or _to_float_or_none(job.get("parse_confidence"))
        or 0.0
    )
    desired_updates: Dict[str, object] = {
        "status": material_status,
        "parse_backend": material_row.get("parse_backend") or job.get("parse_backend"),
        "next_retry_at": None,
        "finished_at": finished_at,
        "parse_confidence": confidence,
        "error_class": material_row.get("parse_error_class")
        if material_status == "failed"
        else None,
        "error_message": (
            material_row.get("parse_error_message") if material_status == "failed" else None
        ),
    }
    for key, value in desired_updates.items():
        if job.get(key) != value:
            job[key] = value
            changed = True
    if changed:
        job["updated_at"] = str(material_row.get("updated_at") or _now_iso())
    return changed


def _compact_material_parse_jobs(
    jobs: List[Dict[str, object]],
) -> tuple[List[Dict[str, object]], int]:
    grouped: Dict[str, List[int]] = {}
    for idx, job in enumerate(jobs):
        material_id = str(job.get("material_id") or "").strip()
        status = str(job.get("status") or "queued")
        if material_id and status in {"queued", "processing"}:
            grouped.setdefault(material_id, []).append(idx)
    keep_indices = set(range(len(jobs)))
    removed_count = 0
    for indices in grouped.values():
        if len(indices) <= 1:
            continue
        keep_idx = max(
            indices,
            key=lambda idx: (
                str(jobs[idx].get("status") or "") == "processing",
                _material_parse_job_sort_key(jobs[idx]),
            ),
        )
        for idx in indices:
            if idx == keep_idx:
                continue
            keep_indices.discard(idx)
            removed_count += 1
    compacted = [job for idx, job in enumerate(jobs) if idx in keep_indices]
    return compacted, removed_count


def _ensure_material_parse_job(
    jobs: List[Dict[str, object]],
    material_row: Dict[str, object],
    *,
    force_requeue: bool = False,
) -> tuple[List[Dict[str, object]], Optional[str], bool]:
    material_id = str(material_row.get("id") or "").strip()
    if not material_id:
        return jobs, None, False
    _, latest_job = _find_latest_material_parse_job(jobs, material_id)
    if latest_job and not force_requeue:
        status = str(latest_job.get("status") or "")
        if status in {"queued", "processing", "parsed"}:
            return jobs, str(latest_job.get("id") or ""), False

    job_id = str(uuid4())
    now = _now_iso()
    job = {
        "id": job_id,
        "material_id": material_id,
        "project_id": str(material_row.get("project_id") or ""),
        "material_type": _normalize_material_type(
            material_row.get("material_type"), filename=material_row.get("filename")
        ),
        "filename": str(material_row.get("filename") or ""),
        "status": "queued",
        "attempt": 0,
        "parse_backend": None,
        "next_retry_at": None,
        "created_at": now,
        "updated_at": now,
        "started_at": None,
        "finished_at": None,
        "error_class": None,
        "error_message": None,
        "parse_confidence": 0.0,
    }
    jobs.append(job)
    return jobs, job_id, True


def _requeue_material_parse_job(
    jobs: List[Dict[str, object]],
    material_row: Dict[str, object],
) -> tuple[List[Dict[str, object]], Optional[str], bool, bool]:
    material_id = str(material_row.get("id") or "").strip()
    if not material_id:
        return jobs, None, False, False
    latest_idx, latest_job = _find_latest_material_parse_job(jobs, material_id)
    if latest_job is None:
        jobs, job_id, created = _ensure_material_parse_job(jobs, material_row, force_requeue=True)
        return jobs, job_id, created, created
    status = str(latest_job.get("status") or "")
    if status in {"queued", "processing", "failed"}:
        changed = _mark_material_parse_job_queued(
            latest_job,
            reason="worker_recovered" if status == "processing" else None,
            reset_attempt=status == "failed",
        )
        if latest_idx is not None:
            jobs[latest_idx] = latest_job
        return jobs, str(latest_job.get("id") or ""), False, changed
    jobs, job_id, created = _ensure_material_parse_job(jobs, material_row, force_requeue=True)
    return jobs, job_id, created, created


def _bootstrap_material_parse_state() -> Dict[str, int]:
    materials = load_materials()
    raw_jobs = load_material_parse_jobs()
    materials_changed = False
    jobs_changed = False
    queued_count = 0
    normalized_jobs: List[Dict[str, object]] = []
    for job in raw_jobs:
        normalized_job, job_changed = _normalize_material_parse_job(job)
        normalized_jobs.append(normalized_job)
        jobs_changed = jobs_changed or job_changed
    jobs, deduplicated_jobs = _compact_material_parse_jobs(normalized_jobs)
    jobs_changed = jobs_changed or deduplicated_jobs > 0
    recovered_jobs = 0
    terminal_synced_jobs = 0
    for idx, row in enumerate(materials):
        normalized, row_changed = _normalize_material_row_for_parse(row)
        job_id = str(normalized.get("job_id") or "")
        created = False
        material_id = str(normalized.get("id") or "").strip()
        material_status = str(normalized.get("parse_status") or "").strip().lower()
        latest_idx, latest_job = _find_latest_material_parse_job(jobs, material_id)
        latest_status = str((latest_job or {}).get("status") or "")
        if (
            latest_job
            and latest_status in {"queued", "processing"}
            and material_status
            in {
                "parsed",
                "failed",
            }
        ):
            if _mark_material_parse_job_terminal(latest_job, normalized):
                if latest_idx is not None:
                    jobs[latest_idx] = latest_job
                jobs_changed = True
                terminal_synced_jobs += 1
                job_id = str(latest_job.get("id") or "")
        elif material_status != "parsed":
            if latest_job and latest_status == "processing":
                if _mark_material_parse_job_queued(latest_job, reason="worker_recovered"):
                    if latest_idx is not None:
                        jobs[latest_idx] = latest_job
                    jobs_changed = True
                    recovered_jobs += 1
                job_id = str(latest_job.get("id") or "")
            elif latest_job:
                job_id = str(latest_job.get("id") or "")
            else:
                jobs, job_id, created = _ensure_material_parse_job(
                    jobs,
                    normalized,
                    force_requeue=False,
                )
            if created:
                normalized["job_id"] = job_id
                normalized["parse_status"] = "queued"
                normalized["parse_backend"] = "queued"
                normalized["updated_at"] = _now_iso()
                jobs_changed = True
                queued_count += 1
                row_changed = True
            elif job_id and str(normalized.get("job_id") or "") != job_id:
                normalized["job_id"] = job_id
                row_changed = True
        if row_changed:
            materials[idx] = normalized
            materials_changed = True
    if materials_changed:
        save_materials(materials)
    if jobs_changed:
        save_material_parse_jobs(jobs)
    return {
        "materials_changed": int(materials_changed),
        "jobs_changed": int(jobs_changed),
        "queued_count": int(queued_count),
        "deduplicated_jobs": int(deduplicated_jobs),
        "recovered_jobs": int(recovered_jobs),
        "terminal_synced_jobs": int(terminal_synced_jobs),
    }


def _build_material_parse_jobs_summary(
    project_id: Optional[str] = None,
) -> tuple[List[Dict[str, object]], Dict[str, object]]:
    jobs = load_material_parse_jobs()
    filtered: List[Dict[str, object]] = []
    status_counts: Dict[str, int] = {}
    backlog = 0
    failure_count = 0
    gpt_jobs = 0
    gpt_failed_jobs = 0
    latest_finished_at = ""
    latest_finished_filename = ""
    for job in jobs:
        normalized, _ = _normalize_material_parse_job(job)
        if project_id and str(normalized.get("project_id") or "") != str(project_id):
            continue
        filtered.append(normalized)
        status = str(normalized.get("status") or "queued")
        status_counts[status] = status_counts.get(status, 0) + 1
        if status in {"queued", "processing"}:
            backlog += 1
        if status == "failed":
            failure_count += 1
        if str(normalized.get("parse_backend") or "").startswith("gpt"):
            gpt_jobs += 1
            if status == "failed":
                gpt_failed_jobs += 1
        finished_at = str(normalized.get("finished_at") or "").strip()
        if finished_at and finished_at > latest_finished_at:
            latest_finished_at = finished_at
            latest_finished_filename = str(normalized.get("filename") or "").strip()
    total_jobs = len(filtered)
    return filtered, {
        "total_jobs": total_jobs,
        "status_counts": status_counts,
        "backlog": backlog,
        "failed_jobs": failure_count,
        "gpt_jobs": gpt_jobs,
        "gpt_failed_jobs": gpt_failed_jobs,
        "gpt_ratio": round(float(gpt_jobs) / float(total_jobs), 4) if total_jobs > 0 else 0.0,
        "latest_finished_at": latest_finished_at or None,
        "latest_finished_filename": latest_finished_filename or None,
    }


def _material_parse_status_label(
    parse_status: Optional[str],
    *,
    parse_backend: Optional[str] = None,
    parse_error_message: Optional[str] = None,
) -> str:
    status = str(parse_status or "").strip().lower()
    backend = str(parse_backend or "").strip()
    if status == "parsed":
        if backend.startswith("gpt"):
            return "已解析（GPT-5.4）"
        if backend:
            return f"已解析（{backend}）"
        return "已解析"
    if status == "processing":
        return "解析中"
    if status == "failed":
        detail = str(parse_error_message or "").strip()
        return f"解析失败：{detail[:36]}" if detail else "解析失败"
    if status == "queued":
        return "排队中"
    return "待解析"


def _material_parse_worker_alive_count() -> int:
    with _MATERIAL_PARSE_WORKER_LOCK:
        return len(_refresh_material_parse_workers_locked())


def _material_supports_gpt_deep_parse(material_type: object) -> bool:
    normalized = _normalize_material_type(material_type)
    return bool(get_openai_api_key()) and normalized in {"tender_qa", "drawing", "site_photo"}


def _material_parse_route_label(
    material_row: Dict[str, object],
    *,
    effective_status: Optional[str] = None,
    active_job: Optional[Dict[str, object]] = None,
) -> str:
    material_type = _normalize_material_type(
        material_row.get("material_type"), filename=material_row.get("filename")
    )
    status = str(effective_status or material_row.get("parse_status") or "").strip().lower()
    backend = str(
        material_row.get("parse_backend") or (active_job or {}).get("parse_backend") or ""
    ).strip()
    summary = (
        material_row.get("structured_summary")
        if isinstance(material_row.get("structured_summary"), dict)
        else {}
    )
    if status in {"queued", "processing"} and _material_supports_gpt_deep_parse(material_type):
        return "本地预解析，必要时 GPT 深解析"
    if str(summary.get("gpt_skip_reason") or "").strip() == "local_summary_strong":
        return "本地快解析"
    if backend == "hybrid":
        return "本地预解析 + GPT 深解析"
    if backend.startswith("gpt"):
        return "GPT 深解析"
    if backend == "local":
        return "本地解析"
    if _material_supports_gpt_deep_parse(material_type):
        return "本地预解析，必要时 GPT 深解析"
    return "本地解析"


def _build_material_parse_runtime_details(
    material_row: Dict[str, object],
    *,
    active_job: Optional[Dict[str, object]] = None,
    queue_position: Optional[int] = None,
) -> Dict[str, object]:
    row = dict(material_row)
    row_status = str(row.get("parse_status") or "queued").strip().lower()
    job_status = str((active_job or {}).get("status") or "").strip().lower()
    effective_status = job_status if job_status in {"queued", "processing"} else row_status
    parse_route_label = _material_parse_route_label(
        row,
        effective_status=effective_status,
        active_job=active_job,
    )
    error_text = str(row.get("parse_error_message") or row.get("parse_error_class") or "").strip()
    note = ""
    if effective_status == "queued":
        if queue_position == 1:
            stage_label = "排队中（即将开始）"
        elif isinstance(queue_position, int) and queue_position > 1:
            stage_label = f"排队中（第 {queue_position} 位）"
        else:
            stage_label = "排队中"
        note = (
            "先做本地结构化预解析，只有本地结果不足时才会进入 GPT 深解析。"
            if parse_route_label.startswith("本地预解析")
            else "等待本地解析 worker 处理。"
        )
    elif effective_status == "processing":
        if parse_route_label.startswith("本地预解析"):
            stage_label = "解析中（本地预解析/深解析决策）"
            note = "当前先做本地结构化预解析；若本地结果不足，再进入 GPT 深解析。"
        else:
            stage_label = f"解析中（{parse_route_label}）"
            note = "当前正在执行本地解析。"
    elif effective_status == "parsed":
        stage_label = _material_parse_status_label(
            effective_status,
            parse_backend=row.get("parse_backend"),
            parse_error_message=row.get("parse_error_message"),
        )
        if parse_route_label == "本地快解析":
            note = "本地结构化结果已足够强，已跳过 GPT 深解析。"
        elif parse_route_label == "本地预解析 + GPT 深解析":
            note = "已完成本地预解析与 GPT 深解析。"
        elif parse_route_label == "本地解析":
            note = "已完成本地解析。"
    elif effective_status == "failed":
        stage_label = _material_parse_status_label(
            effective_status,
            parse_backend=row.get("parse_backend"),
            parse_error_message=row.get("parse_error_message"),
        )
        note = (
            "本次解析失败，可点击重新解析；系统会继续优先保留本地解析结果。"
            if error_text
            else "可点击重新解析。"
        )
    else:
        stage_label = _material_parse_status_label(
            effective_status,
            parse_backend=row.get("parse_backend"),
            parse_error_message=row.get("parse_error_message"),
        )
    return {
        "parse_effective_status": effective_status,
        "parse_stage_label": stage_label,
        "parse_route_label": parse_route_label,
        "parse_note": note,
        "queue_position": int(queue_position)
        if isinstance(queue_position, int) and queue_position > 0
        else None,
    }


def _build_project_material_index(project_id: str) -> Dict[str, object]:
    rows = [m for m in load_materials() if str(m.get("project_id")) == str(project_id)]
    rows.sort(key=lambda x: str(x.get("created_at") or ""), reverse=True)
    signature = _compute_material_index_signature(project_id, rows)
    with _MATERIAL_INDEX_CACHE_LOCK:
        cached = _MATERIAL_INDEX_CACHE.get(project_id)
        if cached and str(cached.get("signature") or "") == signature:
            _touch_material_index_cache(project_id)
            return cached

    counts_by_type: Dict[str, int] = {}
    parsed_ok_by_type: Dict[str, int] = {}
    parsed_fail_by_type: Dict[str, int] = {}
    parse_status_by_type: Dict[str, Dict[str, int]] = {}
    chars_by_type: Dict[str, int] = {}
    chunks_by_type: Dict[str, int] = {}
    numeric_terms_by_type: Dict[str, int] = {}
    lexical_terms_by_type: Dict[str, int] = {}
    parsed_fail_details: List[Dict[str, str]] = []
    parsed_ok_files = 0
    parsed_failed_files = 0
    total_parsed_chunks = 0
    total_numeric_terms = 0
    total_lexical_terms = 0
    files: List[Dict[str, object]] = []
    available_types: List[str] = []
    available_filenames: List[str] = []

    for raw_row in rows:
        legacy_sync_parse = (
            "parse_status" not in raw_row and not str(raw_row.get("job_id") or "").strip()
        )
        row, _ = _normalize_material_row_for_parse(raw_row)
        filename = str(row.get("filename") or "").strip()
        mat_type = _normalize_material_type(row.get("material_type"), filename=filename)
        if mat_type and mat_type not in available_types:
            available_types.append(mat_type)
        if filename and filename not in available_filenames:
            available_filenames.append(filename)
        counts_by_type[mat_type] = counts_by_type.get(mat_type, 0) + 1
        parse_status = str(row.get("parse_status") or "queued")
        parse_status_by_type.setdefault(mat_type, {})
        parse_status_by_type[mat_type][parse_status] = (
            parse_status_by_type[mat_type].get(parse_status, 0) + 1
        )

        entry: Dict[str, object] = {
            "id": str(row.get("id") or ""),
            "project_id": project_id,
            "material_type": mat_type,
            "filename": filename,
            "path": str(row.get("path") or "").strip(),
            "created_at": str(row.get("created_at") or ""),
            "updated_at": str(row.get("updated_at") or ""),
            "row": dict(row),
            "parsed_ok": False,
            "chars": 0,
            "chunks": [],
            "numeric_terms_norm": [],
            "lexical_terms": [],
            "text": "",
            "parse_error": "",
            "parse_status": parse_status,
            "parse_backend": str(row.get("parse_backend") or ""),
            "parse_confidence": float(_to_float_or_none(row.get("parse_confidence")) or 0.0),
            "job_id": str(row.get("job_id") or ""),
        }

        path = str(row.get("path") or "").strip()
        if not path:
            parsed_failed_files += 1
            parsed_fail_by_type[mat_type] = parsed_fail_by_type.get(mat_type, 0) + 1
            entry["parse_error"] = "missing_path"
            parsed_fail_details.append(
                {"filename": filename, "material_type": mat_type, "reason": "missing_path"}
            )
            files.append(entry)
            continue

        p = Path(path)
        if not p.exists():
            parsed_failed_files += 1
            parsed_fail_by_type[mat_type] = parsed_fail_by_type.get(mat_type, 0) + 1
            entry["parse_error"] = "path_not_exists"
            parsed_fail_details.append(
                {"filename": filename, "material_type": mat_type, "reason": "path_not_exists"}
            )
            files.append(entry)
            continue

        if parse_status == "parsed":
            text_value = str(row.get("parsed_text") or row.get("text") or "")
            chars = int(_to_float_or_none(row.get("parsed_chars")) or len(text_value.strip()))
            chunks = (
                row.get("parsed_chunks")
                if isinstance(row.get("parsed_chunks"), list)
                else row.get("chunks")
            )
            chunks = (
                chunks
                if isinstance(chunks, list)
                else _split_material_text_chunks(text_value, max_chars=900)
            )
            numeric_terms_norm = (
                row.get("numeric_terms_norm")
                if isinstance(row.get("numeric_terms_norm"), list)
                else []
            )
            if not numeric_terms_norm and text_value:
                numeric_terms_norm = sorted(
                    {
                        token
                        for token in (
                            _normalize_numeric_token(item)
                            for item in _extract_numeric_terms(text_value, max_terms=260)
                        )
                        if token
                    }
                )
            lexical_terms = (
                row.get("lexical_terms") if isinstance(row.get("lexical_terms"), list) else []
            )
            if not lexical_terms and text_value:
                lexical_terms = _extract_terms(text_value, max_terms=220)
            structured_summary = (
                row.get("structured_summary")
                if isinstance(row.get("structured_summary"), dict)
                else {}
            )
            entry.update(
                {
                    "parsed_ok": True,
                    "text": text_value,
                    "chars": chars,
                    "chunks": chunks,
                    "numeric_terms_norm": numeric_terms_norm,
                    "lexical_terms": lexical_terms,
                    "structured_summary": structured_summary,
                }
            )
            if isinstance(row.get("tender_qa_structured_summary"), dict):
                entry["tender_qa_structured_summary"] = row.get("tender_qa_structured_summary")
            if isinstance(row.get("boq_structured_summary"), dict):
                entry["boq_structured_summary"] = row.get("boq_structured_summary")
            if isinstance(row.get("drawing_structured_summary"), dict):
                entry["drawing_structured_summary"] = row.get("drawing_structured_summary")
            if isinstance(row.get("site_photo_structured_summary"), dict):
                entry["site_photo_structured_summary"] = row.get("site_photo_structured_summary")
            parsed_ok_files += 1
            parsed_ok_by_type[mat_type] = parsed_ok_by_type.get(mat_type, 0) + 1
            chars_by_type[mat_type] = chars_by_type.get(mat_type, 0) + chars
            chunks_by_type[mat_type] = chunks_by_type.get(mat_type, 0) + len(chunks)
            numeric_terms_by_type[mat_type] = numeric_terms_by_type.get(mat_type, 0) + len(
                numeric_terms_norm
            )
            lexical_terms_by_type[mat_type] = lexical_terms_by_type.get(mat_type, 0) + len(
                lexical_terms
            )
            total_parsed_chunks += len(chunks)
            total_numeric_terms += len(numeric_terms_norm)
            total_lexical_terms += len(lexical_terms)
        elif legacy_sync_parse:
            try:
                content = read_bytes(p)
                text = _read_uploaded_file_content(content, p.name)
                text_value = str(text or "")
                chars = len(text_value.strip())
                chunks = _split_material_text_chunks(text_value, max_chars=900)
                numeric_terms_norm = sorted(
                    {
                        token
                        for token in (
                            _normalize_numeric_token(item)
                            for item in _extract_numeric_terms(text_value, max_terms=260)
                        )
                        if token
                    }
                )
                lexical_terms = _extract_terms(text_value, max_terms=220)
                entry.update(
                    {
                        "parsed_ok": True,
                        "parse_status": "parsed",
                        "parse_backend": "legacy_sync",
                        "text": text_value,
                        "chars": chars,
                        "chunks": chunks,
                        "numeric_terms_norm": numeric_terms_norm,
                        "lexical_terms": lexical_terms,
                    }
                )
                if mat_type == "tender_qa":
                    summary = _build_tender_qa_structured_summary(
                        content, p.name, parsed_text=text_value
                    )
                    entry["tender_qa_structured_summary"] = summary
                    entry["structured_summary"] = summary
                elif mat_type == "boq":
                    summary = _build_boq_structured_summary(content, p.name, parsed_text=text_value)
                    entry["boq_structured_summary"] = summary
                    entry["structured_summary"] = summary
                elif mat_type == "drawing":
                    summary = _build_drawing_structured_summary(
                        content, p.name, parsed_text=text_value
                    )
                    entry["drawing_structured_summary"] = summary
                    entry["structured_summary"] = summary
                elif mat_type == "site_photo":
                    summary = _build_site_photo_structured_summary(
                        content, p.name, parsed_text=text_value
                    )
                    entry["site_photo_structured_summary"] = summary
                    entry["structured_summary"] = summary
                parsed_ok_files += 1
                parsed_ok_by_type[mat_type] = parsed_ok_by_type.get(mat_type, 0) + 1
                chars_by_type[mat_type] = chars_by_type.get(mat_type, 0) + chars
                chunks_by_type[mat_type] = chunks_by_type.get(mat_type, 0) + len(chunks)
                numeric_terms_by_type[mat_type] = numeric_terms_by_type.get(mat_type, 0) + len(
                    numeric_terms_norm
                )
                lexical_terms_by_type[mat_type] = lexical_terms_by_type.get(mat_type, 0) + len(
                    lexical_terms
                )
                total_parsed_chunks += len(chunks)
                total_numeric_terms += len(numeric_terms_norm)
                total_lexical_terms += len(lexical_terms)
            except Exception as exc:
                parsed_failed_files += 1
                parsed_fail_by_type[mat_type] = parsed_fail_by_type.get(mat_type, 0) + 1
                reason = f"{type(exc).__name__}: {exc}"
                entry["parse_error"] = reason
                parsed_fail_details.append(
                    {"filename": filename, "material_type": mat_type, "reason": reason}
                )
        else:
            parsed_failed_files += 1 if parse_status == "failed" else 0
            if parse_status == "failed":
                parsed_fail_by_type[mat_type] = parsed_fail_by_type.get(mat_type, 0) + 1
            reason = str(
                row.get("parse_error_message") or row.get("parse_error_class") or parse_status
            )
            entry["parse_error"] = reason
            parsed_fail_details.append(
                {
                    "filename": filename,
                    "material_type": mat_type,
                    "reason": reason,
                }
            )
        files.append(entry)

    total_files = len(rows)
    total_chars = int(sum(chars_by_type.values()))
    fail_ratio = (float(parsed_failed_files) / float(total_files)) if total_files > 0 else 0.0
    quality_snapshot = {
        "project_id": project_id,
        "total_files": total_files,
        "counts_by_type": counts_by_type,
        "parse_status_by_type": parse_status_by_type,
        "parsed_ok_files": parsed_ok_files,
        "parsed_failed_files": parsed_failed_files,
        "queued_files": sum(
            int(statuses.get("queued", 0)) for statuses in parse_status_by_type.values()
        ),
        "processing_files": sum(
            int(statuses.get("processing", 0)) for statuses in parse_status_by_type.values()
        ),
        "parsed_ok_by_type": parsed_ok_by_type,
        "parsed_fail_by_type": parsed_fail_by_type,
        "chars_by_type": chars_by_type,
        "chunks_by_type": chunks_by_type,
        "numeric_terms_by_type": numeric_terms_by_type,
        "lexical_terms_by_type": lexical_terms_by_type,
        "total_parsed_chars": total_chars,
        "total_parsed_chunks": int(total_parsed_chunks),
        "total_numeric_terms": int(total_numeric_terms),
        "total_lexical_terms": int(total_lexical_terms),
        "parse_fail_ratio": round(fail_ratio, 4),
        "parsed_fail_details": parsed_fail_details[:20],
        "available_types": available_types,
        "available_filenames": available_filenames[:120],
    }
    index: Dict[str, object] = {
        "project_id": project_id,
        "signature": signature,
        "rows": [dict(r) for r in rows],
        "files": files,
        "available_types": available_types,
        "available_filenames": available_filenames,
        "quality_snapshot": quality_snapshot,
        "built_at": _now_iso(),
    }
    with _MATERIAL_INDEX_CACHE_LOCK:
        _MATERIAL_INDEX_CACHE[project_id] = index
        _touch_material_index_cache(project_id)
    return index


def _merge_unique_text_values(*groups: object, limit: int = 24) -> List[str]:
    merged: List[str] = []
    for group in groups:
        merged.extend(_to_text_items(group, max_items=limit * 2))
    return _limit_unique_texts(merged, limit=limit)


def _merge_numeric_values(*groups: object, limit: int = 18) -> List[str]:
    merged: List[str] = []
    for group in groups:
        merged.extend(_to_text_items(group, max_items=limit * 2))
    return _limit_unique_numeric_tokens(merged, limit=limit)


def _render_pdf_page_pngs_for_gpt(
    content: bytes,
    *,
    max_pages: int = 8,
) -> List[Dict[str, object]]:
    if pymupdf is None:
        return []
    pages: List[Dict[str, object]] = []
    doc = pymupdf.open(stream=content, filetype="pdf")
    try:
        for idx, page in enumerate(doc, start=1):
            if len(pages) >= max_pages:
                break
            page_text = _normalize_ocr_text_block(page.get_text() or "")
            should_pick = idx <= 4 or len(page_text.strip()) < 200
            if not should_pick and any(
                token in page_text.lower()
                for token in ("评分", "评审", "得分", "加分", "扣分", "目录", "答疑", "补遗")
            ):
                should_pick = True
            if not should_pick:
                continue
            try:
                pix = page.get_pixmap(matrix=pymupdf.Matrix(1.8, 1.8), alpha=False)
                pages.append(
                    {
                        "page_no": idx,
                        "text": page_text[:4000],
                        "image_bytes": pix.tobytes("png"),
                        "image_mime": "image/png",
                    }
                )
            except Exception:
                continue
    finally:
        doc.close()
    return pages


def _build_gpt_pdf_page_prompt(
    filename: str,
    page_no: int,
    page_text: str,
) -> str:
    excerpt = str(page_text or "")[:3200]
    return (
        "你是施工招标资料结构化解析器。请基于当前 PDF 页面，输出 JSON，禁止解释性文本。"
        "字段必须包含：page_type, section_title, section_level, section_path, scoring_terms, mandatory_clauses, "
        "numeric_constraints, table_rows, focused_dimensions, parse_confidence。"
        "page_type 仅可取 cover/toc/chapter/scoring_rules/table/attachment/drawing_like/narrative。"
        "section_path、scoring_terms、mandatory_clauses、numeric_constraints、focused_dimensions、table_rows 必须为数组。"
        "focused_dimensions 使用两位维度编号。"
        f"\n文件名：{filename}\n页码：{page_no}\n本地预读文本：\n{excerpt}"
    )


