def _call_gpt_material_parser(
    prompt: str,
    *,
    image_bytes: Optional[bytes] = None,
    image_mime: str = "image/png",
) -> tuple[bool, Dict[str, object], str]:
    if not get_openai_api_key():
        return False, {}, "missing_openai_credentials"
    ok, payload, err = call_openai_multimodal_json(
        prompt,
        image_bytes=image_bytes,
        image_mime=image_mime,
        model=get_openai_model(),
        max_tokens=2200,
        timeout=120,
        temperature=0.1,
    )
    if not ok or not isinstance(payload, dict):
        return False, {}, err or "gpt_parse_failed"
    return True, payload, ""


def _normalize_gpt_pdf_page_payload(
    payload: Dict[str, object],
    *,
    page_no: int,
) -> Dict[str, object]:
    normalized: Dict[str, object] = dict(payload or {})
    page_type = str(normalized.get("page_type") or "").strip().lower()
    if page_type not in {
        "cover",
        "toc",
        "chapter",
        "scoring_rules",
        "table",
        "attachment",
        "drawing_like",
        "narrative",
    }:
        page_type = "narrative"
    normalized["page_type"] = page_type
    normalized["page_no"] = int(page_no)
    normalized["section_title"] = str(normalized.get("section_title") or "").strip()[:80]
    try:
        section_level = int(float(normalized.get("section_level") or 0))
    except (TypeError, ValueError):
        section_level = 0
    normalized["section_level"] = max(0, min(6, section_level))
    normalized["section_path"] = _merge_unique_text_values(normalized.get("section_path"), limit=6)
    normalized["scoring_terms"] = _filter_structured_signal_terms(
        _to_text_items(normalized.get("scoring_terms"), max_items=12),
        limit=10,
        material_type="tender_qa",
    )
    normalized["mandatory_clauses"] = _merge_unique_text_values(
        normalized.get("mandatory_clauses"),
        limit=8,
    )
    normalized["numeric_constraints"] = _merge_numeric_values(
        normalized.get("numeric_constraints"),
        limit=10,
    )
    normalized["focused_dimensions"] = _limit_unique_texts(
        [
            str(item or "").zfill(2)
            for item in _to_text_items(normalized.get("focused_dimensions"), max_items=8)
            if str(item or "").strip().zfill(2) in DIMENSION_IDS
        ],
        limit=8,
    )
    table_rows: List[Dict[str, object]] = []
    raw_rows = normalized.get("table_rows")
    if isinstance(raw_rows, list):
        for item in raw_rows[:12]:
            if isinstance(item, dict):
                row_obj = {
                    "label": str(item.get("label") or item.get("name") or "").strip()[:80],
                    "value": str(item.get("value") or item.get("content") or "").strip()[:120],
                    "numbers": _merge_numeric_values(item.get("numbers"), limit=6),
                }
                if row_obj["label"] or row_obj["value"] or row_obj["numbers"]:
                    table_rows.append(row_obj)
            else:
                text_value = str(item or "").strip()
                if text_value:
                    table_rows.append(
                        {
                            "label": text_value[:80],
                            "value": text_value[:120],
                            "numbers": _merge_numeric_values(text_value, limit=6),
                        }
                    )
    normalized["table_rows"] = table_rows
    normalized["parse_confidence"] = round(
        _clip_score01(normalized.get("parse_confidence") or 0.0),
        4,
    )
    return normalized


def _aggregate_tender_page_structures(
    page_structures: List[Dict[str, object]],
) -> Dict[str, object]:
    if not page_structures:
        return {}
    page_type_counter: Counter[str] = Counter()
    outline_rows: List[Dict[str, object]] = []
    scoring_rule_pages: List[int] = []
    table_constraint_rows: List[Dict[str, object]] = []
    section_title_paths: List[str] = []
    table_numeric_constraints: List[str] = []
    for page in page_structures:
        if not isinstance(page, dict):
            continue
        page_type = str(page.get("page_type") or "narrative").strip() or "narrative"
        page_no = int(_to_float_or_none(page.get("page_no")) or 0)
        page_type_counter[page_type] += 1
        section_title = str(page.get("section_title") or "").strip()
        section_level = int(_to_float_or_none(page.get("section_level")) or 0)
        section_path = _merge_unique_text_values(page.get("section_path"), limit=6)
        if section_path:
            section_title_paths.extend(section_path)
        elif section_title:
            section_title_paths.append(section_title)
        if section_title or section_path:
            outline_rows.append(
                {
                    "page_no": page_no,
                    "page_type": page_type,
                    "section_title": section_title,
                    "section_level": section_level,
                    "section_path": section_path,
                    "parse_confidence": round(
                        float(_to_float_or_none(page.get("parse_confidence")) or 0.0),
                        4,
                    ),
                }
            )
        if (
            page_type in {"scoring_rules", "table"}
            or page.get("scoring_terms")
            or page.get("mandatory_clauses")
        ):
            if page_no > 0 and page_no not in scoring_rule_pages:
                scoring_rule_pages.append(page_no)
        for row in page.get("table_rows") or []:
            if not isinstance(row, dict):
                continue
            row_obj = {
                "page_no": page_no,
                "label": str(row.get("label") or "").strip()[:80],
                "value": str(row.get("value") or "").strip()[:120],
                "numbers": _merge_numeric_values(row.get("numbers"), limit=6),
            }
            if row_obj["label"] or row_obj["value"] or row_obj["numbers"]:
                table_constraint_rows.append(row_obj)
                table_numeric_constraints.extend(
                    _extract_numeric_terms(
                        "\n".join(
                            [
                                str(row_obj.get("label") or ""),
                                str(row_obj.get("value") or ""),
                                " ".join(str(x) for x in (row_obj.get("numbers") or [])),
                            ]
                        ),
                        max_terms=8,
                    )
                )
        table_numeric_constraints.extend(
            _merge_numeric_values(page.get("numeric_constraints"), limit=8)
        )
    page_type_summary = [
        {"page_type": page_type, "count": int(count)}
        for page_type, count in sorted(
            page_type_counter.items(), key=lambda item: (-item[1], item[0])
        )
    ]
    outline_rows.sort(
        key=lambda item: (
            int(_to_float_or_none(item.get("page_no")) or 0),
            int(_to_float_or_none(item.get("section_level")) or 0),
            str(item.get("section_title") or ""),
        )
    )
    return {
        "page_type_summary": page_type_summary,
        "document_outline": outline_rows[:24],
        "section_title_paths": _limit_unique_texts(section_title_paths, limit=16),
        "scoring_rule_pages": sorted(scoring_rule_pages)[:12],
        "table_constraint_rows": table_constraint_rows[:16],
        "table_numeric_constraints": _limit_unique_numeric_tokens(
            table_numeric_constraints, limit=14
        ),
    }


def _extract_dwg_binary_marker_terms(
    content: bytes,
    *,
    limit: int = 18,
) -> List[str]:
    if not content:
        return []
    patterns = [
        rb"[A-Za-z][A-Za-z0-9_./:-]{2,40}",
        rb"\d+(?:\.\d+)?",
    ]
    raw_tokens: List[str] = []
    for pattern in patterns:
        for match in re.findall(pattern, content):
            try:
                token = (
                    match.decode("utf-8", errors="ignore")
                    if isinstance(match, (bytes, bytearray))
                    else str(match)
                )
            except Exception:
                token = str(match)
            token = str(token or "").strip().strip("\x00")
            if token:
                raw_tokens.append(token)
    return _filter_structured_signal_terms(raw_tokens, limit=limit, material_type="drawing")


def _render_text_preview_png(lines: List[str]) -> Optional[bytes]:
    if Image is None or ImageDraw is None:
        return None
    safe_lines = [str(line or "").strip() for line in lines if str(line or "").strip()][:10]
    if not safe_lines:
        return None
    width = 1280
    height = 80 + len(safe_lines) * 56
    img = Image.new("RGB", (width, min(height, 1400)), color=(248, 250, 252))
    draw = ImageDraw.Draw(img)
    y = 24
    for idx, line in enumerate(safe_lines):
        prefix = f"{idx + 1}. "
        draw.text((28, y), prefix + line[:96], fill=(15, 23, 42))
        y += 50
        if y >= img.height - 40:
            break
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return buf.getvalue()


def _build_site_photo_evidence_summary(
    photo_summaries: List[Dict[str, object]],
) -> Dict[str, object]:
    if not photo_summaries:
        return {}
    signature_counter: Counter[str] = Counter()
    unique_evidence: List[Dict[str, object]] = []
    scene_counter: Counter[str] = Counter()
    risk_counter: Counter[str] = Counter()
    findings_counter: Counter[str] = Counter()
    object_counter: Counter[str] = Counter()
    numeric_markers: List[str] = []
    confidence_values: List[float] = []
    for summary in photo_summaries:
        if not isinstance(summary, dict):
            continue
        scene_type = str(summary.get("scene_type") or "").strip() or "unknown"
        risk_level = str(summary.get("risk_level") or "").strip() or "unknown"
        findings = _merge_unique_text_values(
            summary.get("safety_findings"),
            summary.get("civilization_findings"),
            summary.get("quality_findings"),
            summary.get("progress_findings"),
            limit=8,
        )
        visible_objects = _merge_unique_text_values(summary.get("visible_objects"), limit=8)
        signature_parts = (
            [scene_type, risk_level] + sorted(findings[:3]) + sorted(visible_objects[:3])
        )
        signature = "|".join(part.lower() for part in signature_parts if part)
        if not signature:
            signature = f"unknown|{len(unique_evidence)}"
        signature_counter[signature] += 1
        confidence = float(
            _clip_score01(
                summary.get("evidence_confidence")
                or summary.get("structured_quality_score")
                or summary.get("ocr_quality_score")
                or 0.0
            )
        )
        confidence_values.append(confidence)
        scene_counter[scene_type] += 1
        risk_counter[risk_level] += 1
        findings_counter.update(findings)
        object_counter.update(visible_objects)
        numeric_markers.extend(
            _merge_numeric_values(
                summary.get("numeric_markers"), summary.get("top_numeric_terms"), limit=8
            )
        )
        if signature_counter[signature] == 1:
            unique_evidence.append(
                {
                    "scene_type": scene_type,
                    "risk_level": risk_level,
                    "findings": findings[:6],
                    "visible_objects": visible_objects[:6],
                    "numeric_markers": _merge_numeric_values(
                        summary.get("numeric_markers"),
                        summary.get("top_numeric_terms"),
                        limit=6,
                    ),
                    "confidence": round(confidence, 4),
                }
            )
    duplicate_items = sum(max(0, count - 1) for count in signature_counter.values())
    return {
        "photo_count": len(photo_summaries),
        "unique_evidence_count": len(unique_evidence),
        "duplicate_evidence_count": duplicate_items,
        "dedup_ratio": round(
            float(duplicate_items) / float(max(1, len(photo_summaries))),
            4,
        ),
        "scene_type_summary": [
            {"scene_type": key, "count": int(value)} for key, value in scene_counter.most_common(6)
        ],
        "risk_level_summary": [
            {"risk_level": key, "count": int(value)} for key, value in risk_counter.most_common(4)
        ],
        "top_findings": [key for key, _ in findings_counter.most_common(10)],
        "top_visible_objects": [key for key, _ in object_counter.most_common(10)],
        "numeric_markers": _limit_unique_numeric_tokens(numeric_markers, limit=10),
        "avg_evidence_confidence": round(
            sum(confidence_values) / float(max(1, len(confidence_values))),
            4,
        ),
        "max_evidence_confidence": round(max(confidence_values) if confidence_values else 0.0, 4),
        "unique_evidence_preview": unique_evidence[:8],
    }


def _augment_tender_summary_with_gpt(
    content: bytes,
    filename: str,
    parsed_text: str,
    local_summary: Dict[str, object],
) -> tuple[Dict[str, object], str, float, str]:
    gpt_backend = "local"
    gpt_error = ""
    parse_confidence = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    merged = dict(local_summary)
    if _should_fastpath_tender_local_summary(local_summary, parsed_text=parsed_text):
        merged["gpt_skip_reason"] = "local_summary_strong"
        return merged, gpt_backend, round(parse_confidence, 4), gpt_error
    page_structures: List[Dict[str, object]] = []
    pages = (
        _render_pdf_page_pngs_for_gpt(content, max_pages=8)
        if filename.lower().endswith(".pdf")
        else []
    )
    if pages:
        for page in pages:
            ok, payload, err = _call_gpt_material_parser(
                _build_gpt_pdf_page_prompt(
                    filename, int(page.get("page_no") or 0), str(page.get("text") or "")
                ),
                image_bytes=page.get("image_bytes")
                if isinstance(page.get("image_bytes"), (bytes, bytearray))
                else None,
                image_mime=str(page.get("image_mime") or "image/png"),
            )
            if ok:
                page_structures.append(
                    _normalize_gpt_pdf_page_payload(
                        payload,
                        page_no=int(page.get("page_no") or 0),
                    )
                )
            elif err and not gpt_error:
                gpt_error = err
        if page_structures:
            gpt_backend = "hybrid"
            merged["page_structures"] = page_structures[:12]
            page_aggregate = _aggregate_tender_page_structures(page_structures)
            merged["page_type_summary"] = list(page_aggregate.get("page_type_summary") or [])
            merged["document_outline"] = list(page_aggregate.get("document_outline") or [])
            merged["section_title_paths"] = list(page_aggregate.get("section_title_paths") or [])
            merged["scoring_rule_pages"] = list(page_aggregate.get("scoring_rule_pages") or [])
            merged["table_constraint_rows"] = list(
                page_aggregate.get("table_constraint_rows") or []
            )
            merged["table_numeric_constraints"] = list(
                page_aggregate.get("table_numeric_constraints") or []
            )
            merged["section_titles"] = _merge_unique_text_values(
                merged.get("section_titles"),
                [p.get("section_title") for p in page_structures],
                [p.get("section_path") for p in page_structures],
                page_aggregate.get("section_title_paths"),
                limit=14,
            )
            merged["scoring_point_terms"] = _merge_unique_text_values(
                merged.get("scoring_point_terms"),
                *[p.get("scoring_terms") for p in page_structures],
                [row.get("label") for row in (page_aggregate.get("table_constraint_rows") or [])],
                limit=16,
            )
            merged["mandatory_clause_terms"] = _merge_unique_text_values(
                merged.get("mandatory_clause_terms"),
                *[p.get("mandatory_clauses") for p in page_structures],
                limit=12,
            )
            merged["top_numeric_terms"] = _merge_numeric_values(
                merged.get("top_numeric_terms"),
                *[p.get("numeric_constraints") for p in page_structures],
                page_aggregate.get("table_numeric_constraints"),
                limit=14,
            )
            merged["focused_dimensions"] = _merge_unique_text_values(
                merged.get("focused_dimensions"),
                *[p.get("focused_dimensions") for p in page_structures],
                limit=10,
            )
            merged["structured_terms"] = _merge_unique_text_values(
                merged.get("structured_terms"),
                merged.get("section_titles"),
                merged.get("section_title_paths"),
                merged.get("scoring_point_terms"),
                merged.get("mandatory_clause_terms"),
                limit=28,
            )
            gpt_conf = sum(
                float(_to_float_or_none(p.get("parse_confidence")) or 0.0) for p in page_structures
            ) / max(1, len(page_structures))
            parse_confidence = round(max(parse_confidence, _clip_score01(gpt_conf)), 4)
            merged["structured_quality_score"] = round(
                max(
                    float(_to_float_or_none(merged.get("structured_quality_score")) or 0.0),
                    0.45 + 0.35 * parse_confidence,
                ),
                4,
            )
            return merged, gpt_backend, parse_confidence, gpt_error

    ok, payload, err = _call_gpt_material_parser(_build_gpt_tender_prompt(filename, parsed_text))
    if ok:
        gpt_backend = "hybrid"
        merged["section_titles"] = _merge_unique_text_values(
            merged.get("section_titles"),
            payload.get("section_titles"),
            limit=14,
        )
        merged["scoring_point_terms"] = _merge_unique_text_values(
            merged.get("scoring_point_terms"),
            payload.get("scoring_point_terms"),
            limit=16,
        )
        merged["mandatory_clause_terms"] = _merge_unique_text_values(
            merged.get("mandatory_clause_terms"),
            payload.get("mandatory_clause_terms"),
            limit=12,
        )
        merged["top_numeric_terms"] = _merge_numeric_values(
            merged.get("top_numeric_terms"),
            payload.get("numeric_constraints"),
            limit=14,
        )
        merged["focused_dimensions"] = _merge_unique_text_values(
            merged.get("focused_dimensions"),
            payload.get("focused_dimensions"),
            limit=10,
        )
        merged["structured_terms"] = _merge_unique_text_values(
            merged.get("structured_terms"),
            merged.get("section_titles"),
            merged.get("scoring_point_terms"),
            merged.get("mandatory_clause_terms"),
            limit=28,
        )
        parse_confidence = round(
            max(parse_confidence, float(_to_float_or_none(payload.get("parse_confidence")) or 0.0)),
            4,
        )
        merged["structured_quality_score"] = round(
            max(
                float(_to_float_or_none(merged.get("structured_quality_score")) or 0.0),
                0.42 + 0.32 * parse_confidence,
            ),
            4,
        )
    else:
        gpt_error = err
    return merged, gpt_backend, parse_confidence, gpt_error


def _augment_drawing_summary_with_gpt(
    content: bytes,
    filename: str,
    parsed_text: str,
    local_summary: Dict[str, object],
) -> tuple[Dict[str, object], str, float, str]:
    merged = dict(local_summary)
    parse_confidence = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    if _should_fastpath_drawing_local_summary(local_summary, parsed_text=parsed_text):
        merged["gpt_skip_reason"] = "local_summary_strong"
        return merged, "local", round(parse_confidence, 4), ""
    image_bytes: Optional[bytes] = None
    image_mime = "image/png"
    ext = Path(filename).suffix.lower()
    if ext == ".pdf":
        previews = _render_pdf_page_pngs_for_gpt(content, max_pages=1)
        if previews:
            image_bytes = (
                previews[0].get("image_bytes")
                if isinstance(previews[0].get("image_bytes"), (bytes, bytearray))
                else None
            )
    elif ext in {".png", ".jpg", ".jpeg", ".webp", ".bmp", ".tif", ".tiff"}:
        image_bytes = content
        image_mime = f"image/{'jpeg' if ext in {'.jpg', '.jpeg'} else ext.lstrip('.')}"
    elif ext == ".dwg":
        dwg_binary_markers = _extract_dwg_binary_marker_terms(content, limit=18)
        if dwg_binary_markers:
            merged["dwg_binary_markers"] = dwg_binary_markers[:12]
            merged["binary_marker_terms"] = _merge_unique_text_values(
                merged.get("binary_marker_terms"),
                dwg_binary_markers,
                limit=14,
            )
            if image_bytes is None:
                image_bytes = _render_text_preview_png(
                    ["DWG Binary Marker Preview"] + dwg_binary_markers[:8]
                )
                if image_bytes:
                    image_mime = "image/png"
    ok, payload, err = _call_gpt_material_parser(
        _build_gpt_drawing_prompt(
            filename,
            parsed_text
            + (
                "\nDWG二进制标识提取："
                + "、".join(str(x) for x in (merged.get("dwg_binary_markers") or [])[:12])
                if ext == ".dwg"
                else ""
            ),
        ),
        image_bytes=image_bytes,
        image_mime=image_mime,
    )
    if not ok:
        return merged, "local", parse_confidence, err
    merged["discipline"] = str(payload.get("discipline") or merged.get("discipline") or "")
    merged["sheet_type"] = str(payload.get("sheet_type") or merged.get("sheet_type") or "")
    for field in (
        "layout_tags",
        "space_tags",
        "component_tags",
        "dimension_markers",
        "risk_tags",
        "constraint_terms",
        "numeric_constraints",
        "focused_dimensions",
    ):
        merged[field] = _merge_unique_text_values(merged.get(field), payload.get(field), limit=18)
    merged["structured_terms"] = _merge_unique_text_values(
        merged.get("structured_terms"),
        payload.get("layout_tags"),
        payload.get("space_tags"),
        payload.get("component_tags"),
        payload.get("constraint_terms"),
        limit=28,
    )
    merged["top_numeric_terms"] = _merge_numeric_values(
        merged.get("top_numeric_terms"),
        payload.get("dimension_markers"),
        payload.get("numeric_constraints"),
        limit=16,
    )
    parse_confidence = round(
        max(parse_confidence, float(_to_float_or_none(payload.get("parse_confidence")) or 0.0)),
        4,
    )
    merged["structured_quality_score"] = round(
        max(
            float(_to_float_or_none(merged.get("structured_quality_score")) or 0.0),
            0.44 + 0.34 * parse_confidence,
        ),
        4,
    )
    return merged, "hybrid", parse_confidence, ""


def _should_fastpath_tender_local_summary(
    local_summary: Dict[str, object],
    *,
    parsed_text: str,
) -> bool:
    quality = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    section_titles = _to_text_items(local_summary.get("section_titles"), max_items=18)
    scoring_terms = _to_text_items(local_summary.get("scoring_point_terms"), max_items=18)
    mandatory_terms = _to_text_items(local_summary.get("mandatory_clause_terms"), max_items=18)
    numeric_terms = _merge_numeric_values(local_summary.get("top_numeric_terms"), limit=18)
    parsed_chars = len(str(parsed_text or "").strip())
    return bool(
        quality >= DEFAULT_TENDER_GPT_FASTPATH_MIN_QUALITY
        and parsed_chars >= 2400
        and len(section_titles) >= 4
        and (len(scoring_terms) + len(mandatory_terms) >= 4 or len(numeric_terms) >= 5)
    )


def _should_fastpath_drawing_local_summary(
    local_summary: Dict[str, object],
    *,
    parsed_text: str,
) -> bool:
    quality = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    structured_terms = _to_text_items(local_summary.get("structured_terms"), max_items=24)
    discipline_keywords = _to_text_items(local_summary.get("discipline_keywords"), max_items=12)
    sheet_type_tags = _to_text_items(local_summary.get("sheet_type_tags"), max_items=12)
    risk_keywords = _to_text_items(local_summary.get("risk_keywords"), max_items=12)
    top_numeric_terms = _merge_numeric_values(local_summary.get("top_numeric_terms"), limit=18)
    binary_marker_terms = _to_text_items(local_summary.get("binary_marker_terms"), max_items=18)
    detected_format = str(local_summary.get("detected_format") or "").strip().lower()
    parsed_chars = len(str(parsed_text or "").strip())
    return bool(
        quality >= DEFAULT_DRAWING_GPT_FASTPATH_MIN_QUALITY
        and len(structured_terms) >= 8
        and (
            len(discipline_keywords) + len(sheet_type_tags) + len(risk_keywords) >= 4
            or len(top_numeric_terms) >= 6
            or len(binary_marker_terms) >= 6
        )
        and (parsed_chars >= 900 or detected_format in {"dwg", "dxf"})
    )


def _augment_site_photo_summary_with_gpt(
    content: bytes,
    filename: str,
    parsed_text: str,
    local_summary: Dict[str, object],
) -> tuple[Dict[str, object], str, float, str]:
    merged = dict(local_summary)
    parse_confidence = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    if _should_fastpath_site_photo_local_summary(local_summary, parsed_text=parsed_text):
        merged["gpt_skip_reason"] = "local_summary_strong"
        merged["evidence_confidence"] = round(
            max(
                parse_confidence,
                float(_clip_score01(local_summary.get("ocr_quality_score") or 0.0)),
            ),
            4,
        )
        return merged, "local", round(parse_confidence, 4), ""
    ext = Path(filename).suffix.lower()
    image_mime = f"image/{'jpeg' if ext in {'.jpg', '.jpeg'} else ext.lstrip('.')}"
    ok, payload, err = _call_gpt_material_parser(
        _build_gpt_site_photo_prompt(filename, parsed_text),
        image_bytes=content,
        image_mime=image_mime,
    )
    if not ok:
        return merged, "local", parse_confidence, err
    for field in (
        "safety_findings",
        "civilization_findings",
        "quality_findings",
        "progress_findings",
        "visible_objects",
        "visible_text",
        "numeric_markers",
    ):
        merged[field] = _merge_unique_text_values(merged.get(field), payload.get(field), limit=16)
    merged["scene_type"] = str(payload.get("scene_type") or merged.get("scene_type") or "")
    merged["risk_level"] = str(payload.get("risk_level") or merged.get("risk_level") or "")
    merged["structured_terms"] = _merge_unique_text_values(
        merged.get("structured_terms"),
        payload.get("safety_findings"),
        payload.get("civilization_findings"),
        payload.get("quality_findings"),
        payload.get("progress_findings"),
        payload.get("visible_objects"),
        limit=30,
    )
    merged["top_numeric_terms"] = _merge_numeric_values(
        merged.get("top_numeric_terms"),
        payload.get("numeric_markers"),
        limit=12,
    )
    parse_confidence = round(
        max(
            parse_confidence,
            float(_to_float_or_none(payload.get("evidence_confidence")) or 0.0),
        ),
        4,
    )
    merged["evidence_confidence"] = parse_confidence
    merged["visual_capability"] = "gpt_vision_hybrid"
    merged["evidence_signature"] = "|".join(
        item.lower()
        for item in (
            [merged.get("scene_type"), merged.get("risk_level")]
            + _to_text_items(merged.get("visible_objects"), max_items=3)
            + _to_text_items(merged.get("safety_findings"), max_items=2)
            + _to_text_items(merged.get("quality_findings"), max_items=2)
        )
        if str(item or "").strip()
    )[:160]
    merged["structured_quality_score"] = round(
        max(
            float(_to_float_or_none(merged.get("structured_quality_score")) or 0.0),
            0.46 + 0.30 * parse_confidence,
        ),
        4,
    )
    return merged, "hybrid", parse_confidence, ""


def _should_fastpath_site_photo_local_summary(
    local_summary: Dict[str, object],
    *,
    parsed_text: str,
) -> bool:
    quality = float(_clip_score01(local_summary.get("structured_quality_score") or 0.0))
    ocr_quality = float(_clip_score01(local_summary.get("ocr_quality_score") or 0.0))
    structured_terms = _to_text_items(local_summary.get("structured_terms"), max_items=24)
    scene_tags = (
        _to_text_items(local_summary.get("safety_scene_tags"), max_items=10)
        + _to_text_items(local_summary.get("civilization_scene_tags"), max_items=10)
        + _to_text_items(local_summary.get("quality_scene_tags"), max_items=10)
        + _to_text_items(local_summary.get("progress_scene_tags"), max_items=10)
    )
    top_numeric_terms = _merge_numeric_values(local_summary.get("top_numeric_terms"), limit=16)
    visual_capability = str(local_summary.get("visual_capability") or "").strip().lower()
    parsed_chars = len(str(parsed_text or "").strip())
    return bool(
        quality >= DEFAULT_SITE_PHOTO_GPT_FASTPATH_MIN_QUALITY
        and visual_capability in {"ocr_text", "ocr_multistage"}
        and ocr_quality >= 0.4
        and parsed_chars >= 160
        and (len(scene_tags) >= 4 or len(structured_terms) >= 8 or len(top_numeric_terms) >= 5)
    )


def _parse_material_record_payload(row: Dict[str, object]) -> Dict[str, object]:
    path = Path(str(row.get("path") or "").strip())
    if not path.exists():
        raise FileNotFoundError("path_not_exists")
    content = read_bytes(path)
    filename = path.name
    material_type = _normalize_material_type(row.get("material_type"), filename=filename)
    parsed_text = _read_uploaded_file_content(content, filename)
    text_value = str(parsed_text or "")
    chunks = _split_material_text_chunks(text_value, max_chars=900)
    numeric_terms_norm = sorted(
        {
            token
            for token in (
                _normalize_numeric_token(item)
                for item in _extract_numeric_terms(text_value, max_terms=260)
            )
            if token
        }
    )
    lexical_terms = _extract_terms(text_value, max_terms=220)
    backend = "local"
    parse_confidence = 0.0
    parse_error_class = None
    parse_error_message = None
    structured_summary: Dict[str, object] = {}
    type_specific: Dict[str, object] = {}
    if material_type == "tender_qa":
        local_summary = _build_tender_qa_structured_summary(
            content, filename, parsed_text=text_value
        )
        structured_summary, backend, parse_confidence, gpt_error = _augment_tender_summary_with_gpt(
            content,
            filename,
            text_value,
            local_summary,
        )
        type_specific["tender_qa_structured_summary"] = structured_summary
        if gpt_error and backend == "local":
            parse_error_class = "gpt_parse_failed"
            parse_error_message = gpt_error
    elif material_type == "boq":
        structured_summary = _build_boq_structured_summary(
            content, filename, parsed_text=text_value
        )
        parse_confidence = float(
            _clip_score01(structured_summary.get("structured_quality_score") or 0.0)
        )
        type_specific["boq_structured_summary"] = structured_summary
    elif material_type == "drawing":
        local_summary = _build_drawing_structured_summary(content, filename, parsed_text=text_value)
        (
            structured_summary,
            backend,
            parse_confidence,
            gpt_error,
        ) = _augment_drawing_summary_with_gpt(
            content,
            filename,
            text_value,
            local_summary,
        )
        type_specific["drawing_structured_summary"] = structured_summary
        if gpt_error and backend == "local":
            parse_error_class = "gpt_parse_failed"
            parse_error_message = gpt_error
    elif material_type == "site_photo":
        local_summary = _build_site_photo_structured_summary(
            content, filename, parsed_text=text_value
        )
        (
            structured_summary,
            backend,
            parse_confidence,
            gpt_error,
        ) = _augment_site_photo_summary_with_gpt(
            content,
            filename,
            text_value,
            local_summary,
        )
        type_specific["site_photo_structured_summary"] = structured_summary
        if gpt_error and backend == "local":
            parse_error_class = "gpt_parse_failed"
            parse_error_message = gpt_error
    else:
        structured_summary = {
            "filename": filename,
            "structured_terms": lexical_terms[:24],
            "top_numeric_terms": numeric_terms_norm[:16],
            "focused_dimensions": [],
            "structured_quality_score": min(1.0, len(lexical_terms) / 50.0),
        }
        parse_confidence = float(
            _clip_score01(structured_summary.get("structured_quality_score") or 0.0)
        )
    return {
        "parse_status": "parsed",
        "parse_backend": backend,
        "parse_confidence": round(parse_confidence, 4),
        "parse_error_class": parse_error_class,
        "parse_error_message": parse_error_message,
        "parse_finished_at": _now_iso(),
        "parse_version": DEFAULT_MATERIAL_PARSE_VERSION,
        "structured_summary": structured_summary,
        "parsed_text": text_value,
        "parsed_chars": len(text_value.strip()),
        "parsed_chunks": chunks,
        "numeric_terms_norm": numeric_terms_norm,
        "lexical_terms": lexical_terms,
        **type_specific,
    }


def _claim_next_material_parse_job() -> Optional[Dict[str, object]]:
    with _MATERIAL_PARSE_STATE_LOCK:
        jobs = load_material_parse_jobs()
        materials = load_materials()
        now = datetime.now(timezone.utc)
        material_by_id = {str(row.get("id") or ""): dict(row) for row in materials}
        jobs_changed = False
        materials_changed = False
        claimed: Optional[Dict[str, object]] = None
        for idx, job in enumerate(jobs):
            job, normalized = _normalize_material_parse_job(job)
            jobs[idx] = job
            jobs_changed = jobs_changed or normalized
            status = str(job.get("status") or "queued")
            due_at = _parse_iso_datetime_utc(job.get("next_retry_at"))
            if status == "processing":
                continue
            if status == "failed":
                if (
                    int(_to_float_or_none(job.get("attempt")) or 0)
                    >= DEFAULT_MATERIAL_PARSE_MAX_ATTEMPTS
                ):
                    continue
                if due_at and due_at > now:
                    continue
            if status not in {"queued", "failed"}:
                continue
            material_id = str(job.get("material_id") or "")
            material = material_by_id.get(material_id)
            if not material:
                continue
            started_at = _now_iso()
            job["status"] = "processing"
            job["started_at"] = started_at
            job["updated_at"] = started_at
            jobs[idx] = job
            material, _ = _normalize_material_row_for_parse(material)
            material["parse_status"] = "processing"
            material["parse_backend"] = "gpt-5.4" if get_openai_api_key() else "local"
            material["parse_started_at"] = started_at
            material["parse_error_class"] = None
            material["parse_error_message"] = None
            material["updated_at"] = started_at
            for m_idx, raw_row in enumerate(materials):
                if str(raw_row.get("id") or "") == material_id:
                    materials[m_idx] = material
                    materials_changed = True
                    break
            claimed = dict(job)
            break
        if jobs_changed or claimed is not None:
            save_material_parse_jobs(jobs)
        if materials_changed:
            save_materials(materials)
            _invalidate_material_index_cache(claimed.get("project_id") if claimed else None)
        return claimed


def _complete_material_parse_job(
    job_id: str, updates: Dict[str, object], *, failed: bool = False
) -> None:
    with _MATERIAL_PARSE_STATE_LOCK:
        jobs = load_material_parse_jobs()
        materials = load_materials()
        target_job: Optional[Dict[str, object]] = None
        target_material_id = ""
        for idx, job in enumerate(jobs):
            if str(job.get("id") or "") != job_id:
                continue
            target_job = dict(job)
            target_material_id = str(job.get("material_id") or "")
            target_job.update(
                {
                    "status": "failed" if failed else "parsed",
                    "updated_at": _now_iso(),
                    "finished_at": _now_iso(),
                    "attempt": int(_to_float_or_none(job.get("attempt")) or 0) + 1,
                    "parse_backend": updates.get("parse_backend") or job.get("parse_backend"),
                    "parse_confidence": float(
                        _to_float_or_none(
                            updates.get("parse_confidence") or job.get("parse_confidence")
                        )
                        or 0.0
                    ),
                    "error_class": updates.get("parse_error_class"),
                    "error_message": updates.get("parse_error_message"),
                }
            )
            if failed and target_job["attempt"] < DEFAULT_MATERIAL_PARSE_MAX_ATTEMPTS:
                retry_at = datetime.now(timezone.utc).timestamp() + min(
                    60.0, 8.0 * target_job["attempt"]
                )
                target_job["next_retry_at"] = datetime.fromtimestamp(
                    retry_at, tz=timezone.utc
                ).isoformat()
            else:
                target_job["next_retry_at"] = None
            jobs[idx] = target_job
            break
        for idx, row in enumerate(materials):
            if str(row.get("id") or "") != target_material_id:
                continue
            normalized, _ = _normalize_material_row_for_parse(row)
            normalized.update(updates)
            normalized["parse_status"] = "failed" if failed else "parsed"
            normalized["updated_at"] = _now_iso()
            materials[idx] = normalized
            _invalidate_material_index_cache(str(normalized.get("project_id") or ""))
            break
        save_material_parse_jobs(jobs)
        save_materials(materials)
    project_id = str(updates.get("project_id") or "")
    if project_id and not failed:
        _schedule_project_material_rebuild(project_id)


def _process_material_parse_job(job: Dict[str, object]) -> None:
    material_id = str(job.get("material_id") or "")
    materials = load_materials()
    row = next((dict(item) for item in materials if str(item.get("id") or "") == material_id), None)
    if not row:
        _complete_material_parse_job(
            str(job.get("id") or ""),
            {
                "parse_error_class": "material_not_found",
                "parse_error_message": "material_not_found",
            },
            failed=True,
        )
        return
    try:
        payload = _parse_material_record_payload(row)
        payload["project_id"] = str(row.get("project_id") or "")
        _complete_material_parse_job(str(job.get("id") or ""), payload, failed=False)
    except Exception as exc:
        _complete_material_parse_job(
            str(job.get("id") or ""),
            {
                "project_id": str(row.get("project_id") or ""),
                "parse_backend": "local",
                "parse_confidence": 0.0,
                "parse_error_class": type(exc).__name__,
                "parse_error_message": str(exc),
                "parse_finished_at": _now_iso(),
                "parse_version": DEFAULT_MATERIAL_PARSE_VERSION,
            },
            failed=True,
        )


def _material_parse_worker_loop() -> None:
    while not _MATERIAL_PARSE_STOP_EVENT.is_set():
        job = _claim_next_material_parse_job()
        if not job:
            if _drain_due_project_material_rebuilds(limit=1) > 0:
                continue
            _MATERIAL_PARSE_STOP_EVENT.wait(DEFAULT_MATERIAL_PARSE_JOB_POLL_SECONDS)
            continue
        _process_material_parse_job(job)
        _drain_due_project_material_rebuilds(limit=1)


def _start_material_parse_worker() -> None:
    global _MATERIAL_PARSE_WORKER
    with _MATERIAL_PARSE_WORKER_LOCK:
        active_workers = _refresh_material_parse_workers_locked()
        if active_workers:
            return
        _MATERIAL_PARSE_STOP_EVENT.clear()
        _bootstrap_material_parse_state()
        for index in range(DEFAULT_MATERIAL_PARSE_WORKER_COUNT):
            worker = threading.Thread(
                target=_material_parse_worker_loop,
                name=f"material-parse-worker-{index + 1}",
                daemon=True,
            )
            worker.start()
            active_workers.append(worker)
        _MATERIAL_PARSE_WORKERS[:] = active_workers
        _MATERIAL_PARSE_WORKER = active_workers[0] if active_workers else None


def _stop_material_parse_worker() -> None:
    global _MATERIAL_PARSE_WORKER
    _MATERIAL_PARSE_STOP_EVENT.set()
    with _MATERIAL_PARSE_WORKER_LOCK:
        workers = _refresh_material_parse_workers_locked()
    if not workers:
        _MATERIAL_PARSE_WORKER = None
        return
    alive_after_join: List[threading.Thread] = []
    for worker in workers:
        if worker.is_alive():
            worker.join(timeout=2.0)
        if worker.is_alive():
            alive_after_join.append(worker)
    if alive_after_join:
        with _MATERIAL_PARSE_WORKER_LOCK:
            _MATERIAL_PARSE_WORKERS[:] = alive_after_join
            _MATERIAL_PARSE_WORKER = alive_after_join[0]
        logger.warning(
            "material parse worker did not stop within timeout; keeping reference to avoid duplicate workers"
        )
        return
    with _MATERIAL_PARSE_WORKER_LOCK:
        _MATERIAL_PARSE_WORKERS.clear()
        _MATERIAL_PARSE_WORKER = None


def _now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _default_weights_raw() -> Dict[str, int]:
    return {dim_id: 5 for dim_id in DIMENSION_IDS}


def _normalize_weights(weights_raw: Dict[str, int]) -> Dict[str, float]:
    multipliers = {
        dim_id: 0.5 + (int(weights_raw.get(dim_id, 5)) / 10.0) for dim_id in DIMENSION_IDS
    }
    total = sum(multipliers.values()) or 1.0
    return {dim_id: multipliers[dim_id] / total for dim_id in DIMENSION_IDS}


def _weights_raw_from_norm(weights_norm: Dict[str, float]) -> Dict[str, int]:
    """
    将归一化权重反推为 0..10 的关注度整数（用于专家配置落库与前端滑杆展示）。
    """
    total_dims = max(1, len(DIMENSION_IDS))
    out: Dict[str, int] = {}
    for dim_id in DIMENSION_IDS:
        w = max(0.0, float(weights_norm.get(dim_id, 1.0 / total_dims)))
        multiplier = w * total_dims
        raw = int(round((multiplier - 0.5) * 10.0))
        out[dim_id] = max(0, min(10, raw))
    return out


def _coerce_weights_raw(weights_raw: Dict[str, int]) -> Dict[str, int]:
    merged = dict(_default_weights_raw())
    for dim_id in DIMENSION_IDS:
        raw_value = weights_raw.get(dim_id, merged[dim_id])
        try:
            value = int(raw_value)
        except Exception:
            raise HTTPException(status_code=422, detail=f"维度 {dim_id} 的关注度必须是整数(0..10)")
        if value < 0 or value > 10:
            raise HTTPException(status_code=422, detail=f"维度 {dim_id} 的关注度超出范围(0..10)")
        merged[dim_id] = value
    return merged


def _new_expert_profile(name: str, weights_raw: Dict[str, int]) -> Dict[str, object]:
    now = _now_iso()
    normalized = _normalize_weights(weights_raw)
    return {
        "id": str(uuid4()),
        "name": name,
        "weights_raw": weights_raw,
        "weights_norm": normalized,
        "norm_rule_version": DEFAULT_NORM_RULE_VERSION,
        "created_at": now,
        "updated_at": now,
    }


def _ensure_project_v2_fields(
    project: Dict[str, object], *, include_engine_defaults: bool = True
) -> bool:
    changed = False
    if not str(project.get("name") or "").strip():
        project_id = str(project.get("id") or "").strip()
        project["name"] = f"恢复项目_{project_id[:8]}" if project_id else "恢复项目"
        changed = True
    if not project.get("created_at"):
        project["created_at"] = _now_iso()
        changed = True
    if not project.get("region"):
        project["region"] = DEFAULT_REGION
        changed = True
    if not project.get("qingtian_model_version"):
        project["qingtian_model_version"] = DEFAULT_QINGTIAN_MODEL_VERSION
        changed = True
    if include_engine_defaults and not project.get("scoring_engine_version_locked"):
        project["scoring_engine_version_locked"] = DEFAULT_SCORING_ENGINE_LOCKED
        changed = True
    # 校准器锁定版本默认留空，避免误套历史/跨项目模型。
    if include_engine_defaults and "calibrator_version_locked" not in project:
        project["calibrator_version_locked"] = DEFAULT_CALIBRATOR_LOCKED
        changed = True
    if not project.get("status"):
        project["status"] = "scoring_preparation"
        changed = True
    if not project.get("updated_at"):
        project["updated_at"] = project.get("created_at") or _now_iso()
        changed = True
    meta = project.get("meta")
    if not isinstance(meta, dict):
        project["meta"] = {}
        meta = project["meta"]
        changed = True
    strict_mode = bool(meta.get("strict_material_mode", True))

    def _set_min_rate(key: str, value: float) -> None:
        nonlocal changed
        current = _to_float_or_none(meta.get(key))
        if current is None or float(current) < float(value):
            meta[key] = float(value)
            changed = True

    def _set_min_int(key: str, value: int) -> None:
        nonlocal changed
        current = _to_float_or_none(meta.get(key))
        if current is None or int(round(float(current))) < int(value):
            meta[key] = int(value)
            changed = True

    if "score_scale_max" not in meta:
        meta["score_scale_max"] = DEFAULT_SCORE_SCALE_MAX
        changed = True
    if "enforce_gb_redline" not in meta:
        meta["enforce_gb_redline"] = bool(DEFAULT_ENFORCE_GB_REDLINE)
        changed = True
    if "enforce_material_gate" not in meta:
        meta["enforce_material_gate"] = DEFAULT_ENFORCE_MATERIAL_GATE
        changed = True
    required_material_types = meta.get("required_material_types")
    if not isinstance(required_material_types, list):
        meta["required_material_types"] = list(DEFAULT_REQUIRED_MATERIAL_TYPES)
        changed = True
    else:
        normalized_required: List[str] = []
        for item in required_material_types:
            key = _normalize_material_type(item)
            if key and key not in normalized_required:
                normalized_required.append(key)
        for required_key in DEFAULT_REQUIRED_MATERIAL_TYPES:
            if required_key not in normalized_required:
                normalized_required.append(required_key)
                changed = True
        if normalized_required != required_material_types:
            meta["required_material_types"] = normalized_required
            changed = True
    if "min_parsed_chars_by_type" not in meta:
        meta["min_parsed_chars_by_type"] = dict(DEFAULT_MIN_PARSED_CHARS_BY_TYPE)
        changed = True
    if "enforce_material_depth_gate" not in meta:
        meta["enforce_material_depth_gate"] = bool(DEFAULT_ENFORCE_MATERIAL_DEPTH_GATE)
        changed = True
    elif strict_mode and not bool(meta.get("enforce_material_depth_gate")):
        meta["enforce_material_depth_gate"] = True
        changed = True
    if "min_parsed_chunks_by_type" not in meta:
        meta["min_parsed_chunks_by_type"] = dict(DEFAULT_MIN_PARSED_CHUNKS_BY_TYPE)
        changed = True
    if "min_numeric_terms_by_type" not in meta:
        meta["min_numeric_terms_by_type"] = dict(DEFAULT_MIN_NUMERIC_TERMS_BY_TYPE)
        changed = True
    if "min_total_parsed_chunks" not in meta:
        meta["min_total_parsed_chunks"] = int(DEFAULT_MIN_TOTAL_PARSED_CHUNKS)
        changed = True
    if "min_total_parsed_chars" not in meta:
        meta["min_total_parsed_chars"] = int(DEFAULT_MIN_TOTAL_PARSED_CHARS)
        changed = True
    if "max_material_parse_fail_ratio" not in meta:
        meta["max_material_parse_fail_ratio"] = float(DEFAULT_MAX_MATERIAL_PARSE_FAIL_RATIO)
        changed = True
    if "block_on_any_material_parse_failure" not in meta:
        meta["block_on_any_material_parse_failure"] = bool(
            DEFAULT_BLOCK_ON_ANY_MATERIAL_PARSE_FAILURE
        )
        changed = True
    if "enforce_material_utilization_gate" not in meta:
        meta["enforce_material_utilization_gate"] = bool(DEFAULT_ENFORCE_MATERIAL_UTILIZATION_GATE)
        changed = True
    if "material_utilization_gate_mode" not in meta:
        meta["material_utilization_gate_mode"] = DEFAULT_MATERIAL_UTILIZATION_GATE_MODE
        changed = True
    if "min_material_retrieval_hit_rate" not in meta:
        meta["min_material_retrieval_hit_rate"] = float(DEFAULT_MIN_MATERIAL_RETRIEVAL_HIT_RATE)
        changed = True
    if "min_material_consistency_hit_rate" not in meta:
        meta["min_material_consistency_hit_rate"] = float(DEFAULT_MIN_MATERIAL_CONSISTENCY_HIT_RATE)
        changed = True
    if "min_material_retrieval_total" not in meta:
        meta["min_material_retrieval_total"] = int(DEFAULT_MIN_MATERIAL_RETRIEVAL_TOTAL)
        changed = True
    if "max_uncovered_required_types" not in meta:
        meta["max_uncovered_required_types"] = int(DEFAULT_MAX_UNCOVERED_REQUIRED_TYPES)
        changed = True
    if "min_required_type_presence_rate" not in meta:
        meta["min_required_type_presence_rate"] = float(DEFAULT_MIN_REQUIRED_TYPE_PRESENCE_RATE)
        changed = True
    if "min_required_type_coverage_rate" not in meta:
        meta["min_required_type_coverage_rate"] = float(DEFAULT_MIN_REQUIRED_TYPE_COVERAGE_RATE)
        changed = True
    if "material_retrieval_top_k" not in meta:
        meta["material_retrieval_top_k"] = int(DEFAULT_MATERIAL_RETRIEVAL_TOP_K)
        changed = True
    if "material_retrieval_per_type_quota" not in meta:
        meta["material_retrieval_per_type_quota"] = int(DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA)
        changed = True
    if "material_retrieval_per_file_quota" not in meta:
        meta["material_retrieval_per_file_quota"] = int(DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA)
        changed = True
    if "min_material_retrieval_file_coverage_rate" not in meta:
        meta["min_material_retrieval_file_coverage_rate"] = float(
            DEFAULT_MIN_MATERIAL_RETRIEVAL_FILE_COVERAGE_RATE
        )
        changed = True
    if "enforce_uploaded_type_coverage" not in meta:
        meta["enforce_uploaded_type_coverage"] = bool(DEFAULT_ENFORCE_UPLOADED_TYPE_COVERAGE)
        changed = True
    if "min_uploaded_type_coverage_rate" not in meta:
        meta["min_uploaded_type_coverage_rate"] = float(DEFAULT_MIN_UPLOADED_TYPE_COVERAGE_RATE)
        changed = True
    if "evolution_weight_min_samples" not in meta:
        meta["evolution_weight_min_samples"] = DEFAULT_PROJECT_LEARNING_MIN_SAMPLES
        changed = True
    if "evolution_weight_max_age_days" not in meta:
        meta["evolution_weight_max_age_days"] = DEFAULT_CALIBRATION_FRESHNESS_DAYS
        changed = True
    if strict_mode:
        _set_min_int("min_material_retrieval_total", DEFAULT_MIN_MATERIAL_RETRIEVAL_TOTAL)
        _set_min_rate(
            "min_material_retrieval_file_coverage_rate",
            DEFAULT_MIN_MATERIAL_RETRIEVAL_FILE_COVERAGE_RATE,
        )
        _set_min_rate("min_required_type_coverage_rate", DEFAULT_MIN_REQUIRED_TYPE_COVERAGE_RATE)
    return changed


def _normalize_project_name_key(name: object) -> str:
    raw = unicodedata.normalize("NFKC", str(name or "")).replace("\u3000", " ")
    return re.sub(r"\s+", " ", raw).strip()


def _find_project_by_name(
    projects: List[Dict[str, object]], name: object
) -> Optional[Dict[str, object]]:
    target = _normalize_project_name_key(name)
    if not target:
        return None
    for project in projects:
        if _normalize_project_name_key(project.get("name")) == target:
            return project
    return None


def _build_project_record(name: str, meta: Optional[Dict[str, Any]] = None) -> Dict[str, object]:
    record = {
        "id": str(uuid4()),
        "name": name,
        "meta": meta or {},
        "region": DEFAULT_REGION,
        "expert_profile_id": None,
        "qingtian_model_version": DEFAULT_QINGTIAN_MODEL_VERSION,
        "scoring_engine_version_locked": DEFAULT_SCORING_ENGINE_LOCKED,
        "calibrator_version_locked": DEFAULT_CALIBRATOR_LOCKED,
        "status": "scoring_preparation",
        "created_at": _now_iso(),
        "updated_at": _now_iso(),
    }
    _ensure_project_v2_fields(record)
    return record


def _rename_project_record(
    projects: List[Dict[str, object]],
    project_id: str,
    *,
    new_name: object,
) -> Dict[str, object]:
    project = _find_project(project_id, projects)
    clean_name = _normalize_project_name_key(new_name)
    if not clean_name:
        raise HTTPException(status_code=422, detail="项目名称不能为空")
    existing = _find_project_by_name(projects, clean_name)
    if existing is not None and str(existing.get("id") or "") != str(project.get("id") or ""):
        raise HTTPException(status_code=422, detail="项目名称已存在，请更换名称")
    if str(project.get("name") or "") != clean_name:
        project["name"] = clean_name
        project["updated_at"] = _now_iso()
    _ensure_project_v2_fields(project)
    return project


def _resolve_project_learning_min_samples(project: Optional[Dict[str, object]]) -> int:
    meta = project.get("meta") if isinstance(project, dict) else None
    if not isinstance(meta, dict):
        return DEFAULT_PROJECT_LEARNING_MIN_SAMPLES
    explicit = _to_float_or_none(meta.get("learning_min_samples"))
    if explicit is not None:
        return max(1, int(explicit))
    raw = _to_float_or_none(meta.get("evolution_weight_min_samples"))
    if raw is None:
        return DEFAULT_PROJECT_LEARNING_MIN_SAMPLES
    normalized = max(1, int(raw))
    if bool(meta.get("evolution_weight_min_samples_explicit")):
        return normalized
    if normalized == LEGACY_PROJECT_LEARNING_MIN_SAMPLES:
        return DEFAULT_PROJECT_LEARNING_MIN_SAMPLES
    return normalized


_PROJECT_NAME_FIELD_PATTERNS = [
    re.compile(
        r"(?:招标项目名称|项目名称|工程名称|标段名称|项目名|工程名|标段名)\s*[:：]\s*([^\n\r]{2,120})"
    ),
    re.compile(r"(?:项目概况|工程概况)\s*[:：]\s*([^\n\r]{6,120}(?:工程|项目|标段)[^\n\r]{0,80})"),
]
_PROJECT_NAME_TITLE_SUFFIX_RE = re.compile(
    r"(?:招标文件(?:正文)?|施工招标(?:文件)?|公开招标(?:文件)?|招标公告|答疑澄清|答疑|澄清|补遗)$"
)
_PROJECT_NAME_FIELD_LINE_RE = re.compile(
    r"^(?:\d+(?:\.\d+)*)?\s*"
    r"(?:招标项目名称|项目名称|工程名称|标段名称|项目名|工程名|标段名)\s*[:：]\s*(.*)$"
)
_PROJECT_NAME_FILENAME_SUFFIX_RE = re.compile(
    r"(?:招标文件(?:正文|及答疑)?|招标答疑|答疑澄清|答疑|澄清|补遗|招标公告|公开招标|施工招标|文件)$"
)
_PROJECT_NAME_COPY_SUFFIX_RE = re.compile(r"(?:[\s_-]*[（(]\d+[)）]|[\s_-]+\d+)$")
_PROJECT_NAME_VERSION_SUFFIX_RE = re.compile(
    r"(?:[\s_-]*(?:副本|终稿|最终版|最新版|定稿|扫描件|电子版|打印版|修订版|完整版|文本版|正式版|封面))+$"
)
_GENERIC_PROJECT_NAME_KEYWORDS = (
    "招标示范文本",
    "示范文本",
    "标准文本",
    "标准文件",
    "范本",
    "模板",
    "房屋建筑和市政基础设施工程总承包",
    "房屋建筑和市政基础设施工程施工",
    "招标文件示范文本",
)
_GENERIC_PROJECT_NAME_EXACT = {
    "招标文件",
    "招标文件正文",
    "施工招标文件",
    "公开招标文件",
    "房建市政工程总承包招标示范文本",
    "房建市政工程总承包招标示范文本〈2023年版〉",
    "房建市政工程总承包招标示范文本（2023年版）",
    "合肥市房屋建筑和市政基础设施工程总承包",
    "合肥市房屋建筑和市政基础设施工程施工",
}


def _strip_inferred_project_name_noise(name: object) -> str:
    text = _normalize_project_name_key(name)
    previous = ""
    while text and text != previous:
        previous = text
        text = _PROJECT_NAME_COPY_SUFFIX_RE.sub("", text).strip()
        text = _PROJECT_NAME_VERSION_SUFFIX_RE.sub("", text).strip()
        text = _PROJECT_NAME_TITLE_SUFFIX_RE.sub("", text).strip(
            "：:;；,，。.()（）[]【】<>《》〈〉"
        )
        text = _PROJECT_NAME_FILENAME_SUFFIX_RE.sub("", text).strip(
            "：:;；,，。.()（）[]【】<>《》〈〉"
        )
    return text


def _looks_like_generic_project_name_candidate(name: object) -> bool:
    normalized = _normalize_project_name_key(name)
    if not normalized:
        return False
    if normalized in _GENERIC_PROJECT_NAME_EXACT:
        return True
    return any(keyword in normalized for keyword in _GENERIC_PROJECT_NAME_KEYWORDS)


def _clean_project_name_candidate(name: object) -> str:
    text = _normalize_project_name_key(name).strip("：:;；,，。.()（）[]【】<>《》〈〉")
    text = re.sub(
        r"[，。；;]\s*(?:招标编号|项目编号|建设地点|建设单位|招标人|招标范围|工期|质量标准).*$",
        "",
        text,
    )
    text = re.sub(r"\s*([()（）\-、])\s*", r"\1", text)
    text = re.sub(
        r"(?<=[\u4e00-\u9fffA-Za-z0-9])\s+(?=[\u4e00-\u9fffA-Za-z0-9])",
        "",
        text,
    )
    return text[:120].rstrip()


def _is_valid_project_name_candidate(name: str, *, require_project_token: bool = True) -> bool:
    text = _clean_project_name_candidate(name)
    if len(text) < 4:
        return False
    if not any("\u4e00" <= ch <= "\u9fff" or ch.isalnum() for ch in text):
        return False
    if _looks_like_generic_project_name_candidate(text):
        return False
    if text in {"项目名称", "工程名称", "标段名称", "项目概况", "工程概况", "本项目", "本工程"}:
        return False
    if text.endswith(("项目名称", "工程名称", "标段名称")):
        return False
    if not require_project_token:
        return True
    return any(token in text for token in ("工程", "项目", "标段"))


def _candidate_project_name_from_filename(filename: str) -> str:
    stem = Path(_normalize_uploaded_filename(filename)).stem
    candidate = re.sub(r"[_\-]+", " ", stem)
    candidate = _strip_inferred_project_name_noise(candidate)
    return _clean_project_name_candidate(candidate)


def _infer_project_name_from_filename(filename: str) -> str:
    candidate = _candidate_project_name_from_filename(filename)
    if _is_valid_project_name_candidate(candidate):
        return candidate
    return ""


def _collect_multiline_project_name_field(
    lines: Sequence[str], start_index: int, initial: str
) -> str:
    parts: List[str] = []

    def _append_part(value: str) -> None:
        normalized = unicodedata.normalize("NFKC", str(value or "")).replace("\u3000", " ")
        cleaned = normalized.strip().strip("：:;；,，。")
        if cleaned:
            parts.append(cleaned)

    _append_part(initial)
    for raw_line in lines[start_index + 1 : start_index + 4]:
        normalized = (
            unicodedata.normalize("NFKC", str(raw_line or "")).replace("\u3000", " ").strip()
        )
        if not normalized:
            continue
        if re.match(r"^\d+(?:\.\d+)+\s*", normalized):
            break
        if _PROJECT_NAME_FIELD_LINE_RE.match(normalized):
            break
        if any(
            marker in normalized
            for marker in (
                "项目审批",
                "核准",
                "备案机关",
                "批文名称",
                "项目编号",
                "招标项目编号",
                "标段编号",
                "招标人",
                "项目业主",
                "资金来源",
                "资金落实情况",
                "建设地点",
                "建设规模",
                "招标范围",
            )
        ):
            break
        _append_part(normalized)
        merged = "".join(parts)
        if any(token in merged for token in ("工程", "项目", "标段")) and merged.endswith(
            ("工程", "项目", "标段")
        ):
            break
    return "".join(parts)


def _infer_project_name_from_title_lines(text: str) -> str:
    title_hints = ("招标文件", "招标", "施工总承包", "总承包", "EPC", "改造", "装修", "工程")
    ignored_prefixes = ("第", "目录", "说明", "附件", "投标", "投标人", "资格", "评标", "招标编号")
    non_empty_lines = [
        unicodedata.normalize("NFKC", str(raw or "")).replace("\u3000", " ").strip()
        for raw in str(text or "").splitlines()
    ]
    for raw_line in non_empty_lines[:80]:
        if not raw_line or len(raw_line) < 6 or len(raw_line) > 80:
            continue
        if raw_line.startswith(ignored_prefixes):
            continue
        if not any(marker in raw_line for marker in ("工程", "项目", "标段")):
            continue
        if not any(hint in raw_line for hint in title_hints):
            continue
        candidate = _strip_inferred_project_name_noise(raw_line)
        candidate = _clean_project_name_candidate(candidate)
        if _is_valid_project_name_candidate(candidate):
            return candidate
    return ""


def _infer_project_name_from_tender_text(text: str, filename: str) -> str:
    normalized_text = unicodedata.normalize("NFKC", str(text or "")).replace("\u3000", " ")
    scan_text = normalized_text[:40000]
    generic_candidate_seen = False
    scan_lines = [line.strip() for line in scan_text.splitlines()]
    for line_index, raw_line in enumerate(scan_lines[:500]):
        match = _PROJECT_NAME_FIELD_LINE_RE.match(raw_line)
        if not match:
            continue
        candidate = _collect_multiline_project_name_field(scan_lines, line_index, match.group(1))
        candidate = _strip_inferred_project_name_noise(candidate)
        candidate = _clean_project_name_candidate(candidate)
        if _looks_like_generic_project_name_candidate(candidate):
            generic_candidate_seen = True
            continue
        if _is_valid_project_name_candidate(candidate, require_project_token=False):
            return candidate
    for pattern in _PROJECT_NAME_FIELD_PATTERNS:
        for match in pattern.finditer(scan_text):
            candidate = _strip_inferred_project_name_noise(match.group(1))
            candidate = _clean_project_name_candidate(candidate)
            if _looks_like_generic_project_name_candidate(candidate):
                generic_candidate_seen = True
                continue
            if _is_valid_project_name_candidate(candidate, require_project_token=False):
                return candidate
    for raw_line in scan_lines[:500]:
        if not any(marker in raw_line for marker in ("项目名称", "工程名称", "标段名称")):
            continue
        candidate = _strip_inferred_project_name_noise(
            raw_line.split("：", 1)[-1].split(":", 1)[-1]
        )
        candidate = _clean_project_name_candidate(candidate)
        if _looks_like_generic_project_name_candidate(candidate):
            generic_candidate_seen = True
            continue
        if _is_valid_project_name_candidate(candidate, require_project_token=False):
            return candidate
    title_line_candidate = _infer_project_name_from_title_lines(scan_text)
    if title_line_candidate:
        return title_line_candidate
    fallback_candidate = _candidate_project_name_from_filename(filename)
    if _looks_like_generic_project_name_candidate(fallback_candidate):
        generic_candidate_seen = True
    fallback = _infer_project_name_from_filename(filename)
    if fallback:
        return fallback
    if generic_candidate_seen:
        raise HTTPException(
            status_code=422,
            detail=(
                "当前文件更像招标示范文本/模板，未识别到真实项目名称。"
                "请先在上方填写项目名称，再点“自动创建”，或改用“创建”先建项目。"
            ),
        )
    raise HTTPException(
        status_code=422,
        detail=(
            "无法从招标文件中识别项目名称。请上传包含“项目名称/工程名称/标段名称”的招标文件，"
            "或改用手动输入项目名称创建。"
        ),
    )


def _resolve_tender_project_name(
    preview_text: str,
    filename: str,
    *,
    project_name_override: object = "",
) -> str:
    manual_name = _clean_project_name_candidate(project_name_override)
    if manual_name:
        if not _is_valid_project_name_candidate(manual_name, require_project_token=False):
            raise HTTPException(
                status_code=422,
                detail="手动填写的项目名称不完整，请补充到“XX项目/XX工程/XX标段”级别后重试。",
            )
        return manual_name
    return _infer_project_name_from_tender_text(preview_text, filename)


def _read_tender_upload_and_infer_project_name(
    file: UploadFile,
    *,
    project_name_override: object = "",
) -> tuple[str, bytes, str]:
    raw_filename = file.filename or ""
    normalized_filename = _normalize_uploaded_filename(raw_filename)
    if not normalized_filename:
        raise HTTPException(status_code=422, detail="招标文件名为空，请重试或重命名后上传。")
    if not _is_allowed_material_upload(normalized_filename, file.content_type or "", "tender_qa"):
        raise HTTPException(
            status_code=422,
            detail="招标文件和答疑支持：" + _material_type_ext_hint("tender_qa"),
        )
    content = file.file.read()
    if not content:
        raise HTTPException(status_code=422, detail="招标文件为空，请重新选择文件。")
    try:
        preview_text = _read_uploaded_file_preview_for_project_name(content, normalized_filename)
    except ValueError as exc:
        raise HTTPException(status_code=422, detail=str(exc)) from exc
    inferred_name = _resolve_tender_project_name(
        preview_text,
        normalized_filename,
        project_name_override=project_name_override,
    )
    return normalized_filename, content, inferred_name


def _mark_project_expert_profile_read_only(
    project: Dict[str, object],
    *,
    source: str,
    locked_at: Optional[str] = None,
) -> bool:
    meta = project.get("meta")
    if not isinstance(meta, dict):
        meta = {}
        project["meta"] = meta
    changed = False
    if not bool(meta.get("expert_profile_read_only")):
        meta["expert_profile_read_only"] = True
        changed = True
    if not str(meta.get("expert_profile_locked_at") or "").strip():
        meta["expert_profile_locked_at"] = locked_at or _now_iso()
        changed = True
    if not str(meta.get("expert_profile_lock_source") or "").strip():
        meta["expert_profile_lock_source"] = str(source).strip()
        changed = True
    return changed


def _assert_project_profile_operation_unlocked(
    project: Dict[str, object], force_unlock: bool
) -> None:
    status = str(project.get("status") or "").strip()
    if status in PROFILE_LOCKED_STATUSES and not force_unlock:
        raise HTTPException(
            status_code=409,
            detail="项目已进入青天评标阶段，默认锁定专家配置与重算。请确认后使用 force_unlock=true 重试。",
        )


def _ensure_project_expert_profile(
    project: Dict[str, object],
    all_profiles: List[Dict[str, object]],
) -> tuple[Dict[str, object], bool]:
    profile_id = str(project.get("expert_profile_id") or "")
    if profile_id:
        for profile in all_profiles:
            if profile.get("id") == profile_id:
                return profile, False

    profile_name = f"{project.get('name', '项目')} 默认配置"
    created = _new_expert_profile(profile_name, _default_weights_raw())
    all_profiles.append(created)
    project["expert_profile_id"] = created["id"]
    _mark_project_expert_profile_read_only(project, source="auto_default")
    project["updated_at"] = _now_iso()
    return created, True


def _resolve_versioned_json_artifact_path(artifact: str) -> Path:
    key = str(artifact or "").strip()
    path = VERSIONED_JSON_ARTIFACTS.get(key)
    if path is None:
        raise HTTPException(status_code=404, detail="历史版本配置不存在")
    return path


def _recover_missing_project_from_artifacts(
    project_id: str, projects: List[Dict[str, object]]
) -> Optional[Dict[str, object]]:
    pid = str(project_id or "").strip()
    if not pid:
        return None
    for p in projects:
        if str(p.get("id") or "") == pid:
            return p

    submissions = [s for s in load_submissions() if str(s.get("project_id") or "") == pid]
    materials = [m for m in load_materials() if str(m.get("project_id") or "") == pid]
    ground_truth = [g for g in load_ground_truth() if str(g.get("project_id") or "") == pid]
    evo_reports = load_evolution_reports()
    has_evolution = pid in evo_reports

    if not submissions and not materials and not ground_truth and not has_evolution:
        return None

    name_seed = ""
    for row in materials + submissions:
        filename = str(row.get("filename") or "").strip()
        if filename:
            name_seed = filename
            break
    if name_seed:
        stem = name_seed.rsplit(".", 1)[0].strip()
        recovered_name = (stem or name_seed) + "（恢复）"
    else:
        recovered_name = f"恢复项目_{pid[:8]}"

    time_points: List[str] = []
    for row in submissions:
        created_at = str(row.get("created_at") or "").strip()
        updated_at = str(row.get("updated_at") or "").strip()
        if created_at:
            time_points.append(created_at)
        if updated_at:
            time_points.append(updated_at)
    for row in materials + ground_truth:
        created_at = str(row.get("created_at") or "").strip()
        if created_at:
            time_points.append(created_at)
    evo_updated_at = str((evo_reports.get(pid) or {}).get("updated_at") or "").strip()
    if evo_updated_at:
        time_points.append(evo_updated_at)
    created_at = min(time_points) if time_points else _now_iso()
    updated_at = max(time_points) if time_points else _now_iso()

    score_scale_max = DEFAULT_SCORE_SCALE_MAX
    for s in submissions:
        report = s.get("report")
        if not isinstance(report, dict):
            continue
        meta = report.get("meta")
        if not isinstance(meta, dict):
            continue
        raw = meta.get("score_scale_max")
        if str(raw) == "5":
            score_scale_max = 5
            break
        if str(raw) == "100":
            score_scale_max = 100

    recovered = {
        "id": pid,
        "name": recovered_name,
        "meta": {"score_scale_max": score_scale_max},
        "region": DEFAULT_REGION,
        "expert_profile_id": None,
        "qingtian_model_version": DEFAULT_QINGTIAN_MODEL_VERSION,
        "scoring_engine_version_locked": DEFAULT_SCORING_ENGINE_LOCKED,
        "calibrator_version_locked": DEFAULT_CALIBRATOR_LOCKED,
        "status": "scoring_preparation",
        "created_at": created_at,
        "updated_at": updated_at,
    }
    _ensure_project_v2_fields(recovered)
    projects.append(recovered)
    save_projects(projects)
    return recovered


def _recover_latest_orphan_project(
    projects: List[Dict[str, object]],
) -> Optional[Dict[str, object]]:
    existing_ids = {str(p.get("id") or "") for p in projects}
    latest_pid = ""
    latest_at = ""

    for row in load_submissions():
        pid = str(row.get("project_id") or "").strip()
        if not pid or pid in existing_ids:
            continue
        ts = str(row.get("updated_at") or row.get("created_at") or "").strip()
        if ts and ts > latest_at:
            latest_at = ts
            latest_pid = pid
    for row in load_materials():
        pid = str(row.get("project_id") or "").strip()
        if not pid or pid in existing_ids:
            continue
        ts = str(row.get("created_at") or "").strip()
        if ts and ts > latest_at:
            latest_at = ts
            latest_pid = pid
    if not latest_pid:
        return None
    return _recover_missing_project_from_artifacts(latest_pid, projects)


def _find_project(project_id: str, projects: List[Dict[str, object]]) -> Dict[str, object]:
    for p in projects:
        if p.get("id") == project_id:
            return p
    if not os.environ.get("PYTEST_CURRENT_TEST"):
        recovered = _recover_missing_project_from_artifacts(project_id, projects)
        if recovered is not None:
            return recovered
    raise HTTPException(status_code=404, detail="项目不存在")


def _find_submission(submission_id: str, submissions: List[Dict[str, object]]) -> Dict[str, object]:
    for s in submissions:
        if str(s.get("id")) == submission_id:
            return s
    raise HTTPException(status_code=404, detail="施组提交记录不存在")


def _latest_project_submission(
    project_id: str,
    submissions: List[Dict[str, object]],
    *,
    prefer_scored: bool = True,
) -> Optional[Dict[str, object]]:
    rows = [s for s in submissions if str(s.get("project_id") or "") == project_id]
    if not rows:
        return None
    rows = sorted(rows, key=lambda x: str(x.get("created_at") or ""), reverse=True)
    if prefer_scored:
        for row in rows:
            if _submission_is_scored(row):
                return row
    return rows[0]


def _weights_norm_to_dimension_multipliers(weights_norm: Dict[str, float]) -> Dict[str, float]:
    baseline = 1.0 / len(DIMENSION_IDS)
    if baseline <= 0:
        return {}
    return {
        dim_id: float(weights_norm.get(dim_id, baseline)) / baseline for dim_id in DIMENSION_IDS
    }


def _evaluate_evolution_weight_status(
    project_id: str,
    *,
    project: Optional[Dict[str, object]] = None,
    evo: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    current_project = project
    if not isinstance(current_project, dict):
        current_project = _find_project(project_id, load_projects())
    _ensure_project_v2_fields(current_project, include_engine_defaults=False)

    current_evo = evo if isinstance(evo, dict) else (load_evolution_reports().get(project_id) or {})
    scoring_evolution = (
        current_evo.get("scoring_evolution")
        if isinstance(current_evo.get("scoring_evolution"), dict)
        else {}
    )
    dimension_multipliers = (
        scoring_evolution.get("dimension_multipliers")
        if isinstance(scoring_evolution.get("dimension_multipliers"), dict)
        else {}
    )
    stored = bool(dimension_multipliers)
    meta = current_project.get("meta") if isinstance(current_project.get("meta"), dict) else {}
    min_samples = _resolve_project_learning_min_samples(current_project)
    max_age_days = max(
        1.0,
        float(
            _to_float_or_none(meta.get("evolution_weight_max_age_days"))
            or DEFAULT_CALIBRATION_FRESHNESS_DAYS
        ),
    )
    sample_count = int(_to_float_or_none(current_evo.get("sample_count")) or 0)
    updated_at_dt = _parse_iso_datetime(
        current_evo.get("updated_at") or current_evo.get("created_at")
    )
    age_days = None
    if updated_at_dt is not None:
        age_days = max(
            0.0,
            (datetime.now(timezone.utc) - updated_at_dt.astimezone(timezone.utc)).total_seconds()
            / 86400.0,
        )
    thin = stored and sample_count < min_samples
    stale = stored and age_days is not None and float(age_days) > float(max_age_days)
    missing_timestamp = stored and age_days is None
    usable = stored and not thin and not stale and not missing_timestamp
    inactive_reason = None
    if stored and not usable:
        if thin:
            inactive_reason = "sample_count_below_min"
        elif stale:
            inactive_reason = "stale"
        elif missing_timestamp:
            inactive_reason = "missing_timestamp"
        else:
            inactive_reason = "inactive"
    return {
        "stored": stored,
        "usable": usable,
        "inactive_reason": inactive_reason,
        "sample_count": sample_count,
        "min_samples": min_samples,
        "age_days": age_days,
        "max_age_days": max_age_days,
        "dimension_multipliers": dimension_multipliers,
    }


def _resolve_project_scoring_context(
    project_id: str,
) -> tuple[Dict[str, float], Optional[Dict[str, object]], Dict[str, object]]:
    projects = load_projects()
    project = _find_project(project_id, projects)
    _ensure_project_v2_fields(project, include_engine_defaults=False)

    profiles = load_expert_profiles()
    profile = None
    if project.get("expert_profile_id"):
        for item in profiles:
            if item.get("id") == project.get("expert_profile_id"):
                profile = item
                break

    # 进化权重优先，但必须满足最小样本量与时效性，避免概念漂移导致误导评分。
    evo_status = _evaluate_evolution_weight_status(project_id, project=project)
    if bool(evo_status.get("usable")):
        return dict(evo_status.get("dimension_multipliers") or {}), None, project
    if bool(evo_status.get("stored")):
        age_days = _to_float_or_none(evo_status.get("age_days"))
        logger.info(
            "skip stale_or_thin_evolution_weights project_id=%s sample_count=%s min_samples=%s age_days=%s max_age_days=%s",
            project_id,
            int(_to_float_or_none(evo_status.get("sample_count")) or 0),
            int(_to_float_or_none(evo_status.get("min_samples")) or 0),
            round(float(age_days), 2) if age_days is not None else None,
            float(_to_float_or_none(evo_status.get("max_age_days")) or 0.0),
        )

    if profile and isinstance(profile.get("weights_norm"), dict):
        multipliers = _weights_norm_to_dimension_multipliers(profile.get("weights_norm", {}))
        return multipliers, profile, project

    for p in load_learning_profiles():
        if p.get("project_id") == project_id:
            return dict(p.get("dimension_multipliers") or {}), None, project
    return {}, None, project


def _parse_iso_datetime(value: object) -> Optional[datetime]:
    text = str(value or "").strip()
    if not text:
        return None
    if text.endswith("Z"):
        text = text[:-1] + "+00:00"
    try:
        return datetime.fromisoformat(text)
    except Exception:
        return None


PROJECT_PICKER_HIDDEN_PREFIXES = (
    "ops_",
    "ops招标项目_",
    "ops上传项目_",
    "ops_smoke_",
    "e2e_",
)


def _project_is_hidden_from_picker(project: Dict[str, object]) -> bool:
    name = str(project.get("name") or project.get("id") or "").strip().lower()
    return any(name.startswith(prefix) for prefix in PROJECT_PICKER_HIDDEN_PREFIXES)


def _project_picker_month_key(project: Dict[str, object]) -> str:
    dt = _parse_iso_datetime(project.get("created_at") or project.get("updated_at"))
    if dt is None:
        return ""
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    local_dt = dt.astimezone()
    return f"{local_dt.year:04d}-{local_dt.month:02d}"


def _project_picker_month_label(month_key: str) -> str:
    if not re.fullmatch(r"\d{4}-\d{2}", str(month_key or "").strip()):
        return "全部月份"
    year, month = str(month_key).split("-", 1)
    return f"{year}年{month}月"


def _project_picker_month_choices(projects: List[Dict[str, object]]) -> List[str]:
    months = {
        _project_picker_month_key(project)
        for project in projects
        if not _project_is_hidden_from_picker(project)
    }
    return sorted((month for month in months if month), reverse=True)


def _default_project_picker_month_key(projects: List[Dict[str, object]]) -> str:
    current_month = datetime.now().astimezone().strftime("%Y-%m")
    choices = _project_picker_month_choices(projects)
    if current_month in choices:
        return current_month
    if choices:
        return choices[0]
    return "all"


def _filter_projects_for_picker(
    projects: List[Dict[str, object]],
    *,
    month_key: str,
) -> List[Dict[str, object]]:
    normalized_month = str(month_key or "").strip()
    rows: List[Dict[str, object]] = []
    for project in projects:
        if _project_is_hidden_from_picker(project):
            continue
        if normalized_month and normalized_month != "all":
            if _project_picker_month_key(project) != normalized_month:
                continue
        rows.append(project)
    return rows


def _latest_record_time(
    rows: List[Dict[str, object]], field: str = "created_at"
) -> Optional[datetime]:
    latest: Optional[datetime] = None
    for row in rows:
        if not isinstance(row, dict):
            continue
        dt = _parse_iso_datetime(row.get(field))
        if dt is None:
            continue
        if latest is None or dt > latest:
            latest = dt
    return latest


def _load_project_context_text(project_id: str) -> str:
    ctx = load_project_context().get(project_id) or {}
    return str(ctx.get("text") or "").strip()


def _build_constraints_source_text(project_id: str) -> str:
    materials_text = _merge_materials_text(project_id).strip()
    context_text = _load_project_context_text(project_id)
    if not context_text:
        return materials_text
    marker = "--- 项目上下文（投喂包/自定义指令） ---"
    if materials_text:
        return f"{materials_text}\n\n{marker}\n{context_text}".strip()
    return f"{marker}\n{context_text}".strip()


def _constraints_need_rebuild(
    project_id: str,
    anchors: List[Dict[str, object]],
    requirements: List[Dict[str, object]],
) -> bool:
    source_rows = [m for m in load_materials() if str(m.get("project_id")) == project_id]
    source_latest = _latest_record_time(source_rows, field="created_at")
    ctx_data = load_project_context().get(project_id) or {}
    ctx_updated = _parse_iso_datetime(ctx_data.get("updated_at"))
    if ctx_updated is not None and (source_latest is None or ctx_updated > source_latest):
        source_latest = ctx_updated
    if source_latest is None:
        return not anchors or not requirements
    constraints_latest = _latest_record_time(anchors, field="created_at")
    req_latest = _latest_record_time(requirements, field="created_at")
    if req_latest is not None and (constraints_latest is None or req_latest > constraints_latest):
        constraints_latest = req_latest
    if constraints_latest is None:
        return True
    return source_latest > constraints_latest


def _to_text_items(raw: object, *, max_items: int = 24) -> List[str]:
    items: List[str] = []
    if isinstance(raw, list):
        for v in raw:
            s = str(v or "").strip()
            if not s:
                continue
            items.append(s)
    elif isinstance(raw, str):
        for line in raw.replace("；", "\n").replace(";", "\n").splitlines():
            s = line.strip()
            if s:
                items.append(s)
    dedup: List[str] = []
    seen: set[str] = set()
    for item in items:
        key = item.lower()
        if key in seen:
            continue
        seen.add(key)
        dedup.append(item)
        if len(dedup) >= max(1, int(max_items)):
            break
    return dedup


def _resolve_material_retrieval_config(project: Dict[str, object]) -> Dict[str, int]:
    meta = project.get("meta") if isinstance(project.get("meta"), dict) else {}

    def _resolve_int(raw: object, default: int, *, lower: int, upper: int) -> int:
        numeric = _to_float_or_none(raw)
        if numeric is None:
            numeric = float(default)
        return max(lower, min(upper, int(round(float(numeric)))))

    top_k = _resolve_int(
        meta.get("material_retrieval_top_k"),
        DEFAULT_MATERIAL_RETRIEVAL_TOP_K,
        lower=6,
        upper=48,
    )
    per_type_quota = _resolve_int(
        meta.get("material_retrieval_per_type_quota"),
        DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA,
        lower=1,
        upper=6,
    )
    per_file_quota = _resolve_int(
        meta.get("material_retrieval_per_file_quota"),
        DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA,
        lower=1,
        upper=8,
    )
    return {
        "top_k": top_k,
        "per_type_quota": per_type_quota,
        "per_file_quota": per_file_quota,
    }


def _compute_dynamic_retrieval_budget(
    project_id: str,
    base_cfg: Dict[str, int],
    material_rows: List[Dict[str, object]],
    *,
    available_material_types: Optional[List[str]] = None,
) -> Dict[str, object]:
    """
    按资料体量动态放大检索预算，确保资料越多时检索“读得更深”。
    - top_k：随文件数、文件总大小、资料类型数增长（封顶48）。
    - per_type_quota：当类型丰富时，至少保证每类2条证据。
    - per_file_quota：当文件较多时，允许单文件更深采样，降低偶然漏命中。
    """
    base_top_k = max(6, min(48, int(base_cfg.get("top_k") or DEFAULT_MATERIAL_RETRIEVAL_TOP_K)))
    base_per_type = max(
        1,
        min(
            6,
            int(
                base_cfg.get(
                    "per_type_quota",
                    DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA,
                )
                or DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA
            ),
        ),
    )
    base_per_file = max(
        1,
        min(
            8,
            int(
                base_cfg.get(
                    "per_file_quota",
                    DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA,
                )
                or DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA
            ),
        ),
    )

    types: List[str] = []
    if isinstance(available_material_types, list):
        for item in available_material_types:
            key = _normalize_material_type(item)
            if key and key not in types:
                types.append(key)
    if not types:
        for row in material_rows:
            key = _normalize_material_type(row.get("material_type"), filename=row.get("filename"))
            if key and key not in types:
                types.append(key)

    file_count = 0
    total_size_bytes = 0
    for row in material_rows:
        if str(row.get("project_id") or "") != str(project_id):
            continue
        file_count += 1
        path = str(row.get("path") or "").strip()
        if not path:
            continue
        try:
            total_size_bytes += max(0, int(Path(path).stat().st_size))
        except Exception:
            continue
    total_size_mb = round(float(total_size_bytes) / (1024.0 * 1024.0), 3)

    type_count = len(types)
    # 类型覆盖底线：至少满足 “每类配额” 的总量。
    type_floor = max(6, int(type_count) * int(base_per_type))
    # 体量增强项：文件数和总体积越大，越需要更深检索。
    file_boost = max(0, min(12, file_count - 3))
    size_boost = max(0, min(12, int(total_size_mb // 20)))
    diversity_boost = 2 if type_count >= 4 else (1 if type_count >= 3 else 0)
    volume_boost = file_boost + size_boost + diversity_boost
    top_k = max(base_top_k, type_floor, type_floor + min(12, volume_boost))
    top_k = max(6, min(48, int(top_k)))

    per_type_quota = base_per_type
    if type_count >= 4:
        per_type_quota = max(per_type_quota, 2)
    per_type_quota = max(1, min(6, int(per_type_quota)))

    per_file_quota = base_per_file
    if file_count >= 12:
        per_file_quota = max(per_file_quota, 4)
    elif file_count >= 6:
        per_file_quota = max(per_file_quota, 3)
    per_file_quota = max(1, min(8, int(per_file_quota)))

    reasons: List[str] = []
    if top_k > base_top_k:
        reasons.append(f"top_k:{base_top_k}->{top_k}")
    if per_type_quota > base_per_type:
        reasons.append(f"per_type_quota:{base_per_type}->{per_type_quota}")
    if per_file_quota > base_per_file:
        reasons.append(f"per_file_quota:{base_per_file}->{per_file_quota}")
    if not reasons:
        reasons.append("base_budget_kept")

    return {
        "top_k": top_k,
        "per_type_quota": per_type_quota,
        "per_file_quota": per_file_quota,
        "base_top_k": base_top_k,
        "base_per_type_quota": base_per_type,
        "base_per_file_quota": base_per_file,
        "material_file_count": file_count,
        "material_type_count": type_count,
        "material_total_size_mb": total_size_mb,
        "budget_reasons": reasons,
    }


def _build_material_query_features(
    *,
    project_id: str,
    submission_text: str,
    required_sections: List[str],
    required_charts: List[str],
    mandatory_elements: List[str],
    custom_text_items: List[str],
    context_text: str,
    material_knowledge_profile: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    def _append_unique(items: List[str], target: List[str], *, limit: int) -> None:
        seen = {str(x).strip().lower() for x in target if str(x).strip()}
        for item in items:
            text_value = str(item or "").strip()
            if not text_value:
                continue
            key = text_value.lower()
            if key in seen:
                continue
            target.append(text_value)
            seen.add(key)
            if len(target) >= limit:
                return

    def _filter_profile_terms(
        raw_terms: object,
        *,
        limit: int = 8,
        material_type: str = "",
    ) -> List[str]:
        candidates = raw_terms if isinstance(raw_terms, list) else []
        cleaned = _filter_structured_signal_terms(
            [str(item or "").strip().lower() for item in candidates],
            limit=limit,
            material_type=material_type,
        )
        return [str(item or "").strip().lower() for item in cleaned if str(item or "").strip()]

    seed_lines: List[str] = []
    seed_lines.extend(required_sections)
    seed_lines.extend(required_charts)
    seed_lines.extend(mandatory_elements)
    seed_lines.extend(custom_text_items)
    if context_text:
        seed_lines.append(context_text[:4000])

    project_anchors = [a for a in load_project_anchors() if str(a.get("project_id")) == project_id]
    for anchor in project_anchors[:80]:
        key = str(anchor.get("anchor_key") or "").strip()
        if key:
            seed_lines.append(key)
        value = anchor.get("anchor_value")
        if isinstance(value, list):
            seed_lines.extend(str(v) for v in value[:6] if str(v).strip())
        elif isinstance(value, str) and value.strip():
            seed_lines.append(value.strip())
        value_num = anchor.get("value_num")
        if value_num is not None:
            seed_lines.append(str(value_num))

    project_requirements = [
        r for r in load_project_requirements() if str(r.get("project_id")) == project_id
    ]
    for req in project_requirements[:120]:
        label = str(req.get("req_label") or "").strip()
        if label:
            seed_lines.append(label)
        patterns = req.get("patterns") if isinstance(req.get("patterns"), dict) else {}
        for key in ("keywords", "hints", "must_hit_terms"):
            values = patterns.get(key)
            if isinstance(values, list):
                seed_lines.extend(str(v) for v in values[:8] if str(v).strip())
            elif isinstance(values, str) and values.strip():
                seed_lines.append(values.strip())

    seed_text = "\n".join(seed_lines)
    text_terms = _extract_terms(seed_text, max_terms=100)
    numeric_terms = _extract_numeric_terms(seed_text, max_terms=40)

    material_profile_query_terms: List[str] = []
    material_profile_query_numeric_terms: List[str] = []
    material_profile_focus_dimensions: List[str] = []
    by_type_rows = (
        material_knowledge_profile.get("by_type")
        if isinstance(material_knowledge_profile, dict)
        and isinstance(material_knowledge_profile.get("by_type"), list)
        else []
    )
    by_dimension_rows = (
        material_knowledge_profile.get("by_dimension")
        if isinstance(material_knowledge_profile, dict)
        and isinstance(material_knowledge_profile.get("by_dimension"), list)
        else []
    )
    by_type_map = {
        _normalize_material_type(row.get("material_type")): row
        for row in by_type_rows
        if isinstance(row, dict)
    }
    ordered_dimensions = sorted(
        [row for row in by_dimension_rows if isinstance(row, dict)],
        key=lambda x: (
            -float(_to_float_or_none(x.get("coverage_score")) or 0.0),
            -int(_to_float_or_none(x.get("source_file_count")) or 0),
            str(x.get("dimension_id") or ""),
        ),
    )
    for dim_row in ordered_dimensions[:8]:
        coverage_score = float(_to_float_or_none(dim_row.get("coverage_score")) or 0.0)
        source_file_count = int(_to_float_or_none(dim_row.get("source_file_count")) or 0)
        if coverage_score < 0.22 or source_file_count <= 0:
            continue
        dim_id = str(dim_row.get("dimension_id") or "").strip()
        if not dim_id:
            continue
        material_profile_focus_dimensions.append(dim_id)
        _append_unique(
            [str(x) for x in (DIMENSION_RAG_KEYWORDS.get(dim_id) or [])[:4]],
            material_profile_query_terms,
            limit=36,
        )
        for mat_type in dim_row.get("source_types") or []:
            normalized_type = _normalize_material_type(mat_type)
            row = by_type_map.get(normalized_type)
            if not isinstance(row, dict):
                continue
            row_quality = float(_clip_score01(row.get("structured_quality_score")) or 0.0)
            top_terms_limit = 5 if row_quality >= 0.45 else 3
            structured_terms_limit = 5 if row_quality >= 0.45 else 3
            section_terms_limit = 4 if row_quality >= 0.5 else 2
            scoring_terms_limit = 4 if row_quality >= 0.5 else 2
            mandatory_terms_limit = 3 if row_quality >= 0.4 else 1
            outline_terms_limit = 4 if row_quality >= 0.5 else 2
            table_terms_limit = 4 if row_quality >= 0.5 else 2
            _append_unique(
                _filter_profile_terms(
                    row.get("top_terms"),
                    limit=top_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                [
                    token
                    for token in (
                        _normalize_numeric_token(item)
                        for item in (row.get("top_numeric_terms") or [])[:4]
                    )
                    if token
                ],
                material_profile_query_numeric_terms,
                limit=24 if row_quality >= 0.45 else 18,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("structured_terms_preview"),
                    limit=structured_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("section_titles_preview"),
                    limit=section_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("outline_terms_preview"),
                    limit=outline_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("table_constraint_terms_preview"),
                    limit=table_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("scoring_point_terms_preview"),
                    limit=scoring_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            _append_unique(
                _filter_profile_terms(
                    row.get("mandatory_clause_terms_preview"),
                    limit=mandatory_terms_limit,
                    material_type=normalized_type,
                ),
                material_profile_query_terms,
                limit=36,
            )
            if dim_id in [str(x or "").zfill(2) for x in (row.get("focused_dimensions") or [])]:
                _append_unique(
                    [str(x) for x in (DIMENSION_RAG_KEYWORDS.get(dim_id) or [])[:2]],
                    material_profile_query_terms,
                    limit=36,
                )
        if (
            len(material_profile_query_terms) >= 36
            and len(material_profile_query_numeric_terms) >= 18
        ):
            break

    _append_unique(material_profile_query_terms, text_terms, limit=100)
    _append_unique(material_profile_query_numeric_terms, numeric_terms, limit=60)
    submission_numeric_terms = _extract_numeric_terms(submission_text, max_terms=24)
    for token in submission_numeric_terms:
        if token not in numeric_terms:
            numeric_terms.append(token)

    return {
        "query_terms": text_terms,
        "query_numeric_terms": numeric_terms[:60],
        "seed_lines_count": len(seed_lines),
        "project_anchor_count": len(project_anchors),
        "project_requirement_count": len(project_requirements),
        "material_profile_query_terms_count": len(material_profile_query_terms),
        "material_profile_query_numeric_terms_count": len(material_profile_query_numeric_terms),
        "material_profile_structured_terms_count": len(
            _limit_unique_texts(material_profile_query_terms, limit=36)
        ),
        "material_profile_focus_dimensions": material_profile_focus_dimensions[:8],
        "material_profile_query_terms_preview": material_profile_query_terms[:16],
        "material_profile_query_numeric_terms_preview": material_profile_query_numeric_terms[:12],
    }


def _build_material_dimension_requirements(
    project_id: str,
    material_knowledge_profile: Optional[Dict[str, object]],
    *,
    available_material_types: Optional[List[str]] = None,
) -> List[Dict[str, object]]:
    if not isinstance(material_knowledge_profile, dict):
        return []

    by_type_rows = (
        material_knowledge_profile.get("by_type")
        if isinstance(material_knowledge_profile.get("by_type"), list)
        else []
    )
    by_dimension_rows = (
        material_knowledge_profile.get("by_dimension")
        if isinstance(material_knowledge_profile.get("by_dimension"), list)
        else []
    )
    if not by_type_rows or not by_dimension_rows:
        return []

    def _collect_terms(raw_terms: object, *, limit: int = 8, material_type: str = "") -> List[str]:
        candidates = raw_terms if isinstance(raw_terms, list) else []
        cleaned = _filter_structured_signal_terms(
            [str(item or "").strip().lower() for item in candidates],
            limit=limit,
            material_type=material_type,
        )
        return [str(item or "").strip().lower() for item in cleaned if str(item or "").strip()]

    allowed_types = {
        _normalize_material_type(item)
        for item in (available_material_types or [])
        if str(item or "").strip()
    }
    by_type_map = {
        _normalize_material_type(row.get("material_type")): row
        for row in by_type_rows
        if isinstance(row, dict)
    }
    ordered_dimensions = sorted(
        [row for row in by_dimension_rows if isinstance(row, dict)],
        key=lambda x: (
            -float(_to_float_or_none(x.get("coverage_score")) or 0.0),
            -int(_to_float_or_none(x.get("source_file_count")) or 0),
            str(x.get("dimension_id") or ""),
        ),
    )
    reqs: List[Dict[str, object]] = []
    now = _now_iso()
    req_index = 0
    for dim_row in ordered_dimensions:
        coverage_score = float(_to_float_or_none(dim_row.get("coverage_score")) or 0.0)
        source_file_count = int(_to_float_or_none(dim_row.get("source_file_count")) or 0)
        if coverage_score < 0.28 or source_file_count <= 0:
            continue
        dim_id = str(dim_row.get("dimension_id") or "").strip()
        if not dim_id:
            continue
        source_types = [
            _normalize_material_type(item)
            for item in (dim_row.get("source_types") or [])
            if str(item or "").strip()
        ]
        if allowed_types:
            source_types = [item for item in source_types if item in allowed_types]
        if not source_types:
            continue

        hints: List[str] = []
        for token in DIMENSION_RAG_KEYWORDS.get(dim_id, [])[:4]:
            text_value = str(token or "").strip().lower()
            if text_value and text_value not in hints:
                hints.append(text_value)
        numeric_terms: List[str] = []
        structured_terms: List[str] = []
        section_titles: List[str] = []
        outline_terms: List[str] = []
        table_constraint_terms: List[str] = []
        scoring_point_terms: List[str] = []
        mandatory_clause_terms: List[str] = []
        numeric_category_summary: List[str] = []
        focused_dimensions: List[str] = []
        structured_alignment_hits = 0
        strongest_structured_quality = 0.0
        strong_quality_sources = 0
        for mat_type in source_types[:3]:
            row = by_type_map.get(mat_type)
            if not isinstance(row, dict):
                continue
            row_structured_quality = float(
                _clip_score01(row.get("structured_quality_score")) or 0.0
            )
            strongest_structured_quality = max(strongest_structured_quality, row_structured_quality)
            if row_structured_quality >= 0.45:
                strong_quality_sources += 1
            for term in _collect_terms(row.get("top_terms"), limit=5, material_type=mat_type):
                if term not in hints:
                    hints.append(term)
                if len(hints) >= 8:
                    break
            for raw_num in (row.get("top_numeric_terms") or [])[:4]:
                token = _normalize_numeric_token(raw_num)
                if token and token not in numeric_terms:
                    numeric_terms.append(token)
                if len(numeric_terms) >= 4:
                    break
            for term in _collect_terms(
                row.get("structured_terms_preview"),
                limit=4,
                material_type=mat_type,
            ):
                if term not in structured_terms:
                    structured_terms.append(term)
            for term in _collect_terms(
                row.get("section_titles_preview"),
                limit=3,
                material_type=mat_type,
            ):
                if term not in section_titles:
                    section_titles.append(term)
            for term in _collect_terms(
                row.get("outline_terms_preview"),
                limit=4,
                material_type=mat_type,
            ):
                if term not in outline_terms:
                    outline_terms.append(term)
            for term in _collect_terms(
                row.get("table_constraint_terms_preview"),
                limit=4,
                material_type=mat_type,
            ):
                if term not in table_constraint_terms:
                    table_constraint_terms.append(term)
            for term in _collect_terms(
                row.get("scoring_point_terms_preview"),
                limit=3,
                material_type=mat_type,
            ):
                if term not in scoring_point_terms:
                    scoring_point_terms.append(term)
            for term in _collect_terms(
                row.get("mandatory_clause_terms_preview"),
                limit=2,
                material_type=mat_type,
            ):
                if term not in mandatory_clause_terms:
                    mandatory_clause_terms.append(term)
            for item in _to_text_items(row.get("numeric_category_summary"), max_items=2):
                if item not in numeric_category_summary:
                    numeric_category_summary.append(item)
            row_focused_dimensions = [
                str(item or "").zfill(2)
                for item in (row.get("focused_dimensions") or [])
                if str(item or "").strip()
            ]
            for focused_dim in row_focused_dimensions:
                if focused_dim not in focused_dimensions:
                    focused_dimensions.append(focused_dim)
            if dim_id in row_focused_dimensions:
                structured_alignment_hits += 1
        merged_hints = _to_text_items(
            hints
            + outline_terms
            + table_constraint_terms
            + section_titles
            + scoring_point_terms
            + mandatory_clause_terms
            + structured_terms
            + numeric_terms,
            max_items=14,
        )
        if len(merged_hints) < 3:
            continue

        minimum_hint_hits = (
            2
            if (coverage_score >= 0.52 or len(source_types) >= 2 or structured_alignment_hits > 0)
            else 1
        )
        if mandatory_clause_terms:
            minimum_hint_hits = max(minimum_hint_hits, 3)
        if coverage_score >= 0.72 and (structured_terms or numeric_terms):
            minimum_hint_hits = max(minimum_hint_hits, 3)
        if strongest_structured_quality >= 0.6:
            minimum_hint_hits = max(minimum_hint_hits, 3)
        if (outline_terms or table_constraint_terms) and strongest_structured_quality >= 0.45:
            minimum_hint_hits = max(minimum_hint_hits, 3)
        weight = round(
            min(
                1.2,
                0.58
                + coverage_score * 0.3
                + min(0.08, len(source_types) * 0.03)
                + min(0.12, structured_alignment_hits * 0.06)
                + min(0.12, strongest_structured_quality * 0.16)
                + min(0.08, strong_quality_sources * 0.03)
                + min(0.08, len(outline_terms) * 0.02)
                + min(0.08, len(table_constraint_terms) * 0.02)
                + min(0.08, len(section_titles) * 0.02)
                + min(0.08, len(scoring_point_terms) * 0.025)
                + min(0.1, len(mandatory_clause_terms) * 0.04)
                + (0.04 if numeric_terms else 0.0),
            ),
            2,
        )
        req_index += 1
        reqs.append(
            {
                "id": f"runtime-material-dim-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": (
                    f"资料维度约束：{str(dim_row.get('dimension_name') or dim_id)}"
                    "需体现项目资料关键锚点"
                ),
                "req_type": "semantic",
                "patterns": {
                    "hints": merged_hints,
                    "minimum_hint_hits": minimum_hint_hits,
                    "structured_terms": structured_terms[:6],
                    "section_titles": section_titles[:4],
                    "outline_terms": outline_terms[:4],
                    "table_constraint_terms": table_constraint_terms[:4],
                    "scoring_point_terms": scoring_point_terms[:4],
                    "mandatory_clause_terms": mandatory_clause_terms[:3],
                    "source_types": source_types,
                    "source_mode": "material_knowledge_profile",
                    "source_coverage_score": round(coverage_score, 4),
                    "source_file_count": source_file_count,
                    "focused_dimensions": focused_dimensions[:6],
                    "numeric_category_summary": numeric_category_summary[:4],
                    "structured_alignment_hits": structured_alignment_hits,
                    "strongest_structured_quality": round(strongest_structured_quality, 4),
                    "strong_quality_sources": strong_quality_sources,
                    "top_numeric_terms": numeric_terms[:4],
                },
                "mandatory": False,
                "weight": weight,
                "source_anchor_id": None,
                "source_pack_id": "runtime_material_dimension",
                "source_pack_version": "v2-material-dimension-4",
                "priority": 89.0,
                "override_key": f"runtime::material_dimension::{dim_id}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _logic_skeleton_to_runtime_hints(raw_lines: object, *, limit: int = 8) -> List[str]:
    fragments: List[str] = []
    for line in raw_lines if isinstance(raw_lines, list) else []:
        text_value = str(line or "").strip()
        if not text_value:
            continue
        normalized = re.sub(r"\[[^\]]+\]", " ", text_value)
        parts = [part.strip() for part in re.split(r"\+|；|;|｜|\|", normalized) if part.strip()]
        fragments.extend(parts if parts else [normalized])
    hints = _filter_structured_signal_terms(fragments, limit=limit)
    if len(hints) >= max(1, int(limit)):
        return hints[: max(1, int(limit))]
    lexical = _filter_structured_signal_terms(
        _extract_terms("\n".join(str(x) for x in fragments), max_terms=limit * 2),
        limit=limit,
    )
    merged = _filter_structured_signal_terms(hints + lexical, limit=limit)
    return merged[: max(1, int(limit))]


def _build_runtime_feature_requirements(
    project_id: str,
    *,
    material_knowledge_profile: Optional[Dict[str, object]],
    weights_norm: Optional[Dict[str, float]] = None,
) -> List[Dict[str, object]]:
    by_dimension_rows = (
        material_knowledge_profile.get("by_dimension")
        if isinstance(material_knowledge_profile, dict)
        and isinstance(material_knowledge_profile.get("by_dimension"), list)
        else []
    )
    weight_map = (
        {dim_id: float(weights_norm.get(dim_id, 0.0)) for dim_id in DIMENSION_IDS}
        if isinstance(weights_norm, dict)
        else {}
    )
    baseline_weight = (1.0 / len(DIMENSION_IDS)) if DIMENSION_IDS else 0.0

    focus_dims: List[str] = []
    weighted_dims = sorted(
        DIMENSION_IDS,
        key=lambda dim_id: (-float(weight_map.get(dim_id, 0.0)), dim_id),
    )
    for dim_id in weighted_dims[:6]:
        if float(weight_map.get(dim_id, 0.0)) > baseline_weight * 1.02 or len(focus_dims) < 3:
            focus_dims.append(dim_id)

    material_dims = sorted(
        [row for row in by_dimension_rows if isinstance(row, dict)],
        key=lambda row: (
            -float(_to_float_or_none(row.get("coverage_score")) or 0.0),
            str(row.get("dimension_id") or ""),
        ),
    )
    for row in material_dims[:8]:
        dim_id = str(row.get("dimension_id") or "").strip()
        if not dim_id or dim_id in focus_dims:
            continue
        if float(_to_float_or_none(row.get("coverage_score")) or 0.0) < 0.28:
            continue
        focus_dims.append(dim_id)

    now = _now_iso()
    reqs: List[Dict[str, object]] = []
    req_index = 0
    for dim_id in focus_dims[:8]:
        features = select_top_logic_skeletons(dimension_ids=[dim_id], top_k=2)
        if not features:
            continue
        hints: List[str] = []
        feature_ids: List[str] = []
        confidences: List[float] = []
        usage_counts: List[int] = []
        for feature in features:
            confidence = float(_to_float_or_none(getattr(feature, "confidence_score", None)) or 0.0)
            if confidence < 0.45:
                continue
            feature_hints = _logic_skeleton_to_runtime_hints(
                getattr(feature, "logic_skeleton", []) or [],
                limit=6,
            )
            if not feature_hints:
                continue
            for hint in feature_hints:
                if hint not in hints:
                    hints.append(hint)
            feature_id = str(getattr(feature, "feature_id", "") or "").strip()
            if feature_id:
                feature_ids.append(feature_id)
            confidences.append(confidence)
            usage_counts.append(int(_to_float_or_none(getattr(feature, "usage_count", 0)) or 0))
        if len(hints) < 2 or not confidences:
            continue
        avg_confidence = sum(confidences) / len(confidences)
        req_index += 1
        reqs.append(
            {
                "id": f"runtime-feature-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": (
                    f"学习骨架约束：{str((DIMENSIONS.get(dim_id) or {}).get('name') or dim_id)}"
                    "需体现高置信逻辑骨架"
                ),
                "req_type": "semantic",
                "patterns": {
                    "hints": _to_text_items(hints, max_items=10),
                    "minimum_hint_hits": 2 if avg_confidence >= 0.7 and len(hints) >= 4 else 1,
                    "source_mode": "feature_confidence_loop",
                    "feature_ids": feature_ids[:4],
                    "feature_confidence_scores": [round(val, 4) for val in confidences[:4]],
                    "feature_usage_counts": usage_counts[:4],
                    "focus_dimension": dim_id,
                },
                "mandatory": False,
                "weight": round(min(1.25, 0.78 + avg_confidence * 0.4), 2),
                "source_anchor_id": None,
                "source_pack_id": "runtime_feature_confidence",
                "source_pack_version": "v1",
                "priority": 88.0,
                "override_key": f"runtime::feature_confidence::{dim_id}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_material_constraint_pack(
    *,
    project_id: str,
    project: Dict[str, object],
    submission_text: str,
    material_index: Dict[str, object],
    material_knowledge_profile: Dict[str, object],
    weights_norm: Optional[Dict[str, float]],
    query_features: Dict[str, object],
    retrieval_cfg: Dict[str, object],
) -> Dict[str, object]:
    material_rows = list(material_index.get("rows") or [])
    available_material_types = [
        str(x) for x in (material_index.get("available_types") or []) if str(x).strip()
    ]
    available_material_filenames = [
        str(x) for x in (material_index.get("available_filenames") or []) if str(x).strip()
    ]
    retrieval_budget = _compute_dynamic_retrieval_budget(
        project_id,
        retrieval_cfg,
        material_rows,
        available_material_types=available_material_types,
    )
    retrieval_top_k = int(
        retrieval_budget.get("top_k")
        or retrieval_cfg.get("top_k")
        or DEFAULT_MATERIAL_RETRIEVAL_TOP_K
    )
    retrieval_per_type_quota = int(
        retrieval_budget.get("per_type_quota")
        or retrieval_cfg.get("per_type_quota")
        or DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA
    )
    retrieval_per_file_quota = int(
        retrieval_budget.get("per_file_quota")
        or retrieval_cfg.get("per_file_quota")
        or DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA
    )
    retrieval_chunks = _select_material_retrieval_chunks(
        project_id,
        submission_text,
        top_k=retrieval_top_k,
        per_type_quota=retrieval_per_type_quota,
        per_file_quota=retrieval_per_file_quota,
        query_terms_extra=query_features.get("query_terms"),
        query_numeric_terms=query_features.get("query_numeric_terms"),
        material_index=material_index,
    )
    retrieval_selected_filenames: List[str] = []
    for chunk in retrieval_chunks:
        filename_text = str(chunk.get("filename") or "").strip()
        if filename_text and filename_text not in retrieval_selected_filenames:
            retrieval_selected_filenames.append(filename_text)
    retrieval_types = sorted(
        {
            str(c.get("material_type") or "")
            for c in retrieval_chunks
            if str(c.get("material_type") or "").strip()
        }
    )
    retrieval_selected_via_counts: Dict[str, int] = {}
    for chunk in retrieval_chunks:
        selected_via = str(chunk.get("selected_via") or "").strip() or "unknown"
        retrieval_selected_via_counts[selected_via] = (
            int(retrieval_selected_via_counts.get(selected_via, 0)) + 1
        )
    retrieval_requirements = _build_material_retrieval_requirements(project_id, retrieval_chunks)
    consistency_requirements = _build_material_consistency_requirements(
        project_id,
        retrieval_chunks,
        available_material_types=available_material_types,
    )
    material_dimension_requirements = _build_material_dimension_requirements(
        project_id,
        material_knowledge_profile,
        available_material_types=available_material_types,
    )
    material_consensus_requirements = _build_material_consensus_requirements(
        project_id,
        material_knowledge_profile,
        available_material_types=available_material_types,
    )
    site_photo_visual_requirements = _build_site_photo_visual_requirements(
        project_id,
        material_knowledge_profile,
    )
    feedback_requirements = _build_runtime_feedback_requirements(
        project_id,
        material_knowledge_profile=material_knowledge_profile,
    )
    feature_requirements = _build_runtime_feature_requirements(
        project_id,
        material_knowledge_profile=material_knowledge_profile,
        weights_norm=weights_norm,
    )
    all_requirements: List[Dict[str, object]] = []
    all_requirements.extend(retrieval_requirements)
    all_requirements.extend(consistency_requirements)
    all_requirements.extend(material_dimension_requirements)
    all_requirements.extend(material_consensus_requirements)
    all_requirements.extend(site_photo_visual_requirements)
    all_requirements.extend(feedback_requirements)
    all_requirements.extend(feature_requirements)
    return {
        "requirements": all_requirements,
        "retrieval_chunks": retrieval_chunks,
        "retrieval_requirements": retrieval_requirements,
        "consistency_requirements": consistency_requirements,
        "material_dimension_requirements": material_dimension_requirements,
        "material_consensus_requirements": material_consensus_requirements,
        "site_photo_visual_requirements": site_photo_visual_requirements,
        "feedback_requirements": feedback_requirements,
        "feature_requirements": feature_requirements,
        "available_material_types": available_material_types,
        "available_material_filenames": available_material_filenames,
        "retrieval_budget": retrieval_budget,
        "retrieval_top_k": retrieval_top_k,
        "retrieval_per_type_quota": retrieval_per_type_quota,
        "retrieval_per_file_quota": retrieval_per_file_quota,
        "retrieval_selected_filenames": retrieval_selected_filenames,
        "retrieval_selected_via_counts": retrieval_selected_via_counts,
        "retrieval_types": retrieval_types,
    }


def _build_feature_confidence_summary(
    project_id: str,
    *,
    material_knowledge_profile: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    features = load_feature_kb()
    if not features:
        return {
            "project_id": project_id,
            "active_count": 0,
            "retired_count": 0,
            "high_confidence_count": 0,
            "focus_dimensions": [],
            "top_dimensions": [],
        }

    by_dimension_rows = (
        material_knowledge_profile.get("by_dimension")
        if isinstance(material_knowledge_profile, dict)
        and isinstance(material_knowledge_profile.get("by_dimension"), list)
        else []
    )
    focus_dimensions: List[str] = []
    ordered_rows = sorted(
        [row for row in by_dimension_rows if isinstance(row, dict)],
        key=lambda row: (
            -float(_to_float_or_none(row.get("coverage_score")) or 0.0),
            str(row.get("dimension_id") or ""),
        ),
    )
    for row in ordered_rows[:6]:
        dim_id = str(row.get("dimension_id") or "").strip()
        if dim_id:
            focus_dimensions.append(dim_id)

    active_features = [feature for feature in features if bool(getattr(feature, "active", False))]
    high_confidence_features = [
        feature
        for feature in active_features
        if float(_to_float_or_none(getattr(feature, "confidence_score", None)) or 0.0) >= 0.7
    ]
    dim_stats: Dict[str, Dict[str, float]] = {}
    for feature in active_features:
        dim_id = str(getattr(feature, "dimension_id", "") or "").strip()
        if not dim_id:
            continue
        row = dim_stats.setdefault(
            dim_id,
            {
                "count": 0.0,
                "high_confidence_count": 0.0,
                "confidence_sum": 0.0,
                "usage_sum": 0.0,
            },
        )
        confidence = float(_to_float_or_none(getattr(feature, "confidence_score", None)) or 0.0)
        usage_count = float(_to_float_or_none(getattr(feature, "usage_count", 0)) or 0.0)
        row["count"] += 1.0
        row["confidence_sum"] += confidence
        row["usage_sum"] += usage_count
        if confidence >= 0.7:
            row["high_confidence_count"] += 1.0

    top_dimensions = sorted(
        [
            {
                "dimension_id": dim_id,
                "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
                "active_feature_count": int(stats.get("count", 0.0)),
                "high_confidence_count": int(stats.get("high_confidence_count", 0.0)),
                "avg_confidence": round(
                    float(stats.get("confidence_sum", 0.0))
                    / max(1.0, float(stats.get("count", 0.0))),
                    4,
                ),
                "avg_usage_count": round(
                    float(stats.get("usage_sum", 0.0)) / max(1.0, float(stats.get("count", 0.0))),
                    2,
                ),
                "is_project_focus": dim_id in focus_dimensions,
            }
            for dim_id, stats in dim_stats.items()
        ],
        key=lambda row: (
            not bool(row.get("is_project_focus")),
            -float(_to_float_or_none(row.get("avg_confidence")) or 0.0),
            -int(_to_float_or_none(row.get("high_confidence_count")) or 0),
            str(row.get("dimension_id") or ""),
        ),
    )

    return {
        "project_id": project_id,
        "active_count": len(active_features),
        "retired_count": len(
            [feature for feature in features if not bool(getattr(feature, "active", False))]
        ),
        "high_confidence_count": len(high_confidence_features),
        "focus_dimensions": focus_dimensions[:6],
        "top_dimensions": top_dimensions[:8],
    }


def _build_runtime_feedback_requirements(
    project_id: str,
    *,
    material_knowledge_profile: Optional[Dict[str, object]] = None,
) -> List[Dict[str, object]]:
    evo = load_evolution_reports().get(project_id) or {}
    scoring_evolution = (
        evo.get("scoring_evolution") if isinstance(evo.get("scoring_evolution"), dict) else {}
    )
    multipliers = (
        scoring_evolution.get("dimension_multipliers")
        if isinstance(scoring_evolution.get("dimension_multipliers"), dict)
        else {}
    )
    rationales = (
        scoring_evolution.get("rationale")
        if isinstance(scoring_evolution.get("rationale"), dict)
        else {}
    )
    sample_count = int(_to_float_or_none(evo.get("sample_count")) or 0)
    recent_feedback_boosts = _build_recent_feedback_dimension_boosts(project_id)
    if (not multipliers or sample_count <= 0) and not recent_feedback_boosts:
        return []

    by_dimension_rows = (
        material_knowledge_profile.get("by_dimension")
        if isinstance(material_knowledge_profile, dict)
        and isinstance(material_knowledge_profile.get("by_dimension"), list)
        else []
    )
    by_dimension_map = {
        str(row.get("dimension_id") or "").strip(): row
        for row in by_dimension_rows
        if isinstance(row, dict) and str(row.get("dimension_id") or "").strip()
    }
    dimension_candidates: List[tuple[str, float]] = []
    seen_dims: set[str] = set()
    for dim_id, multiplier in multipliers.items():
        normalized_dim = str(dim_id).zfill(2)
        if normalized_dim not in DIMENSION_IDS or normalized_dim in seen_dims:
            continue
        seen_dims.add(normalized_dim)
        dimension_candidates.append((normalized_dim, float(_to_float_or_none(multiplier) or 1.0)))
    for dim_id, boost in recent_feedback_boosts.items():
        if dim_id in seen_dims or dim_id not in DIMENSION_IDS:
            continue
        avg_strength = float(_to_float_or_none(boost.get("avg_strength")) or 0.0)
        positive_count = int(_to_float_or_none(boost.get("positive_count")) or 0)
        if avg_strength <= 0.08 and positive_count <= 0:
            continue
        seen_dims.add(dim_id)
        dimension_candidates.append(
            (dim_id, 1.0 + min(0.18, max(0.0, avg_strength) * 0.18 + positive_count * 0.02))
        )

    ranked_dims = sorted(
        dimension_candidates,
        key=lambda item: (
            -(
                item[1]
                + max(
                    0.0,
                    float(
                        _to_float_or_none(
                            (recent_feedback_boosts.get(item[0]) or {}).get("avg_strength")
                        )
                        or 0.0
                    ),
                )
                * 0.15
            ),
            item[0],
        ),
    )
    reqs: List[Dict[str, object]] = []
    now = _now_iso()
    req_index = 0
    for dim_id, multiplier in ranked_dims[:8]:
        feedback_boost = recent_feedback_boosts.get(dim_id) or {}
        avg_strength = float(_to_float_or_none(feedback_boost.get("avg_strength")) or 0.0)
        avg_delta_100 = float(_to_float_or_none(feedback_boost.get("avg_delta_100")) or 0.0)
        feedback_positive_count = int(_to_float_or_none(feedback_boost.get("positive_count")) or 0)
        feedback_negative_count = int(_to_float_or_none(feedback_boost.get("negative_count")) or 0)
        feedback_sample_count = int(_to_float_or_none(feedback_boost.get("sample_count")) or 0)
        effective_multiplier = float(multiplier) + max(0.0, avg_strength) * 0.16
        if effective_multiplier <= 1.03 and avg_strength <= 0.08:
            continue
        material_dim_row = by_dimension_map.get(dim_id) or {}
        coverage_score = float(_to_float_or_none(material_dim_row.get("coverage_score")) or 0.0)
        rationale_text = str(rationales.get(dim_id) or "").strip()
        rationale_hints = _filter_structured_signal_terms(
            _extract_terms(rationale_text, max_terms=8),
            limit=6,
        )
        material_hints = [
            str(x)
            for x in (material_dim_row.get("suggested_keywords") or [])[:4]
            if str(x or "").strip()
        ]
        feedback_hints = [
            str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
            "真实评分反馈",
            f"近期样本{feedback_sample_count}条" if feedback_sample_count > 0 else "",
            f"平均分差{round(avg_delta_100, 2)}" if abs(avg_delta_100) >= 0.5 else "",
        ]
        hints = _to_text_items(
            rationale_hints
            + material_hints
            + feedback_hints
            + list((DIMENSION_RAG_KEYWORDS.get(dim_id) or [])[:4]),
            max_items=10,
        )
        if len(hints) < 2:
            continue
        minimum_hint_hits = 2 if (sample_count >= 3 or effective_multiplier >= 1.12) else 1
        if feedback_positive_count >= 2 or avg_delta_100 >= 4.0:
            minimum_hint_hits = max(minimum_hint_hits, 3)
        req_index += 1
        reqs.append(
            {
                "id": f"runtime-feedback-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": (
                    f"进化反馈约束：{str((DIMENSIONS.get(dim_id) or {}).get('name') or dim_id)}"
                    "需体现近期真实评分偏好"
                ),
                "req_type": "semantic",
                "patterns": {
                    "hints": hints,
                    "minimum_hint_hits": minimum_hint_hits,
                    "source_mode": "feedback_evolution",
                    "multiplier": round(effective_multiplier, 4),
                    "sample_count": sample_count,
                    "material_coverage_score": round(coverage_score, 4),
                    "rationale": rationale_text,
                    "recent_feedback_count": feedback_sample_count,
                    "recent_feedback_positive_count": feedback_positive_count,
                    "recent_feedback_negative_count": feedback_negative_count,
                    "recent_feedback_avg_delta_100": round(avg_delta_100, 4),
                    "recent_feedback_avg_strength": round(avg_strength, 4),
                    "recent_feedback_decay_weight": round(
                        float(
                            _to_float_or_none(feedback_boost.get("avg_time_decay_weight")) or 0.0
                        ),
                        4,
                    ),
                    "recent_feedback_polarity": str(
                        feedback_boost.get("feedback_polarity") or "mixed"
                    ),
                },
                "mandatory": False,
                "weight": round(
                    min(
                        1.42,
                        0.8
                        + min(0.22, (effective_multiplier - 1.0) * 0.9)
                        + (0.06 if sample_count >= 3 else 0.0)
                        + (0.04 if coverage_score < 0.35 else 0.0)
                        + min(
                            0.12,
                            max(0.0, avg_strength) * 0.18 + feedback_positive_count * 0.02,
                        )
                        - min(
                            0.05,
                            max(0.0, -avg_strength) * 0.08 + feedback_negative_count * 0.01,
                        ),
                    ),
                    2,
                ),
                "source_anchor_id": None,
                "source_pack_id": "runtime_feedback_evolution",
                "source_pack_version": "v2-feedback-boost",
                "priority": 87.5,
                "override_key": f"runtime::feedback_evolution::{dim_id}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_material_consensus_requirements(
    project_id: str,
    material_knowledge_profile: Optional[Dict[str, object]],
    *,
    available_material_types: Optional[List[str]] = None,
) -> List[Dict[str, object]]:
    if not isinstance(material_knowledge_profile, dict):
        return []
    summary = (
        material_knowledge_profile.get("summary")
        if isinstance(material_knowledge_profile.get("summary"), dict)
        else {}
    )
    consensus_score = float(_to_float_or_none(summary.get("cross_type_consensus_score")) or 0.0)
    if consensus_score < 0.18:
        return []

    source_types = []
    for row in (
        material_knowledge_profile.get("by_type")
        if isinstance(material_knowledge_profile.get("by_type"), list)
        else []
    ):
        if not isinstance(row, dict):
            continue
        mat_type = _normalize_material_type(row.get("material_type"))
        if not mat_type:
            continue
        if float(_clip_score01(row.get("structured_quality_score")) or 0.0) < 0.25:
            continue
        source_types.append(mat_type)
    source_types = _limit_unique_texts(source_types, limit=6)
    allowed_types = {
        _normalize_material_type(item)
        for item in (available_material_types or [])
        if str(item or "").strip()
    }
    if allowed_types:
        source_types = [item for item in source_types if item in allowed_types]

    consensus_terms = _to_text_items(summary.get("cross_type_consensus_terms"), max_items=10)
    numeric_summary_items = (
        summary.get("cross_type_numeric_category_summary")
        if isinstance(summary.get("cross_type_numeric_category_summary"), list)
        else []
    )
    if not source_types or not numeric_summary_items:
        return []

    focus_dimensions = [
        str(item or "").zfill(2)
        for item in (summary.get("cross_type_focus_dimensions") or [])
        if str(item or "").strip().zfill(2) in DIMENSION_IDS
    ]

    now = _now_iso()
    reqs: List[Dict[str, object]] = []
    req_index = 0
    for item in numeric_summary_items[:4]:
        match = re.match(r"([^：:]+)[：:]\s*(.+)", str(item or "").strip())
        if not match:
            continue
        label = match.group(1).strip()
        category = next(
            (key for key, value in NUMERIC_ANCHOR_CATEGORY_LABELS.items() if str(value) == label),
            "",
        )
        if not category:
            continue
        dim_candidates = [
            dim
            for dim in (NUMERIC_ANCHOR_CATEGORY_DIMENSIONS.get(category) or ["01"])
            if dim in DIMENSION_IDS
        ] or ["01"]
        dim_candidates = [
            dim for dim in dim_candidates if not focus_dimensions or dim in focus_dimensions
        ] or dim_candidates
        dim_id = next((dim for dim in dim_candidates if dim in DIMENSION_IDS), "01")
        numeric_terms = [
            token
            for token in (
                _normalize_numeric_token(x.replace("等", ""))
                for x in re.split(r"[、,，\s]+", match.group(2))
            )
            if token
        ][:4]
        if not numeric_terms:
            continue
        hints = _to_text_items(
            consensus_terms[:4] + list((DIMENSION_RAG_KEYWORDS.get(dim_id) or [])[:4]),
            max_items=8,
        )
        req_index += 1
        reqs.append(
            {
                "id": f"runtime-consensus-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": f"跨资料共识约束：{label}",
                "req_type": "material_consistency",
                "patterns": {
                    "must_hit_terms": hints[:6],
                    "minimum_terms": 1 if hints else 0,
                    "must_hit_numbers": numeric_terms,
                    "minimum_numbers": 2 if len(numeric_terms) >= 3 else 1,
                    "material_type": "cross_material_consensus",
                    "source_types": source_types,
                    "consensus_score": round(consensus_score, 4),
                    "consensus_terms": consensus_terms[:6],
                    "numeric_category_label": label,
                    "within_dimension_scope": False,
                    "source_mode": "cross_material_consensus",
                },
                "mandatory": len(source_types) >= 2 and category in {"duration", "specification"},
                "weight": round(
                    min(
                        1.28,
                        0.92
                        + min(0.18, consensus_score * 0.28)
                        + min(0.08, len(source_types) * 0.03)
                        + min(0.08, len(numeric_terms) * 0.02),
                    ),
                    2,
                ),
                "material_type": "cross_material_consensus",
                "source_anchor_id": None,
                "source_pack_id": "runtime_material_consensus",
                "source_pack_version": "v1",
                "priority": 91.0,
                "override_key": f"runtime::material_consensus::{category}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_site_photo_visual_requirements(
    project_id: str,
    material_knowledge_profile: Optional[Dict[str, object]],
) -> List[Dict[str, object]]:
    if not isinstance(material_knowledge_profile, dict):
        return []
    photo_summary = (
        material_knowledge_profile.get("site_photo_evidence")
        if isinstance(material_knowledge_profile.get("site_photo_evidence"), dict)
        else {}
    )
    unique_count = int(_to_float_or_none(photo_summary.get("unique_evidence_count")) or 0)
    avg_conf = float(_to_float_or_none(photo_summary.get("avg_evidence_confidence")) or 0.0)
    if unique_count <= 0 or avg_conf < 0.18:
        return []
    scene_type_summary = (
        photo_summary.get("scene_type_summary")
        if isinstance(photo_summary.get("scene_type_summary"), list)
        else []
    )
    top_findings = _to_text_items(photo_summary.get("top_findings"), max_items=10)
    top_objects = _to_text_items(photo_summary.get("top_visible_objects"), max_items=10)
    numeric_markers = _merge_numeric_values(photo_summary.get("numeric_markers"), limit=8)
    reqs: List[Dict[str, object]] = []
    now = _now_iso()
    scene_to_dims = {
        "安全": ["02", "07"],
        "文明": ["03"],
        "质量": ["08", "16"],
        "进度": ["09", "15"],
    }
    req_index = 0
    for scene_row in scene_type_summary[:4]:
        if not isinstance(scene_row, dict):
            continue
        scene_type = str(scene_row.get("scene_type") or "").strip()
        if not scene_type:
            continue
        dim_ids = next(
            (dims for token, dims in scene_to_dims.items() if token in scene_type),
            ["03", "08"],
        )
        hints = _to_text_items([scene_type] + top_findings[:4] + top_objects[:3], max_items=8)
        if len(hints) < 2:
            continue
        req_index += 1
        reqs.append(
            {
                "id": f"runtime-photo-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_ids[0],
                "req_label": f"现场照片视觉证据：{scene_type}",
                "req_type": "visual_evidence",
                "patterns": {
                    "hints": hints,
                    "minimum_hint_hits": 2 if unique_count >= 3 else 1,
                    "must_hit_numbers": numeric_markers[:3],
                    "source_mode": "site_photo_visual",
                    "scene_type": scene_type,
                    "avg_evidence_confidence": round(avg_conf, 4),
                    "unique_evidence_count": unique_count,
                },
                "mandatory": False,
                "weight": round(
                    min(
                        1.26,
                        0.82 + min(0.16, avg_conf * 0.22) + min(0.12, unique_count * 0.03),
                    ),
                    2,
                ),
                "source_anchor_id": None,
                "source_pack_id": "runtime_site_photo_visual",
                "source_pack_version": "v1",
                "priority": 88.0,
                "override_key": f"runtime::site_photo_visual::{scene_type}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_material_score_shaping(
    report: Dict[str, object],
    *,
    runtime_req_meta: Optional[Dict[str, object]],
    material_knowledge_snapshot: Optional[Dict[str, object]],
) -> Dict[str, object]:
    meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
    evidence_trace = (
        meta.get("evidence_trace") if isinstance(meta.get("evidence_trace"), dict) else {}
    )
    summary = (
        material_knowledge_snapshot.get("summary")
        if isinstance(material_knowledge_snapshot, dict)
        and isinstance(material_knowledge_snapshot.get("summary"), dict)
        else {}
    )
    runtime_meta = runtime_req_meta if isinstance(runtime_req_meta, dict) else {}
    mandatory_hit_rate = float(
        _to_float_or_none(
            evidence_trace.get("mandatory_hit_rate")
            if evidence_trace
            else report.get("mandatory_req_hit_rate")
        )
        or 0.0
    )
    cross_score = float(_to_float_or_none(summary.get("cross_type_consensus_score")) or 0.0)
    cross_types = int(_to_float_or_none(summary.get("cross_type_consensus_type_count")) or 0)
    structured_quality_avg = float(_to_float_or_none(summary.get("structured_quality_avg")) or 0.0)
    structured_quality_type_rate = float(
        _to_float_or_none(summary.get("structured_quality_type_rate")) or 0.0
    )
    strong_types = int(_to_float_or_none(summary.get("strong_structured_types")) or 0)
    parsed_ok_files = int(_to_float_or_none(summary.get("parsed_ok_files")) or 0)
    total_files = int(_to_float_or_none(summary.get("total_files")) or 0)
    structured_signal_total = int(_to_float_or_none(summary.get("structured_signal_total")) or 0)
    dimension_coverage_rate = float(
        _to_float_or_none(summary.get("dimension_coverage_rate")) or 0.0
    )
    mandatory_clause_signal_count = 0
    for row in (
        material_knowledge_snapshot.get("by_type")
        if isinstance(material_knowledge_snapshot, dict)
        and isinstance(material_knowledge_snapshot.get("by_type"), list)
        else []
    ):
        if not isinstance(row, dict):
            continue
        mandatory_clause_signal_count += len(row.get("mandatory_clause_terms_preview") or [])
    visual_req_count = int(
        _to_float_or_none(runtime_meta.get("site_photo_visual_requirements")) or 0
    )
    feedback_req_count = int(
        _to_float_or_none(runtime_meta.get("feedback_evolution_requirements")) or 0
    )
    feature_req_count = int(
        _to_float_or_none(runtime_meta.get("feature_confidence_requirements")) or 0
    )
    consensus_req_count = int(
        _to_float_or_none(runtime_meta.get("material_consensus_requirements")) or 0
    )
    dimension_req_count = int(
        _to_float_or_none(runtime_meta.get("material_dimension_requirements")) or 0
    )
    retrieval_req_count = int(
        _to_float_or_none(runtime_meta.get("material_retrieval_requirements")) or 0
    )
    shaping_req_count = int(
        _to_float_or_none(
            ((runtime_meta.get("material_constraint_pack") or {}).get("score_shaping"))
            if isinstance(runtime_meta.get("material_constraint_pack"), dict)
            else None
        )
        or 0
    )
    has_real_material_evidence = any(
        (
            parsed_ok_files > 0,
            structured_signal_total > 0,
            mandatory_clause_signal_count > 0,
            cross_types > 0,
            dimension_coverage_rate > 0.0,
        )
    )
    has_runtime_shaping_signals = any(
        (
            visual_req_count > 0,
            feedback_req_count > 0,
            feature_req_count > 0,
            consensus_req_count > 0,
            dimension_req_count > 0,
            retrieval_req_count > 0,
            shaping_req_count > 0,
        )
    )
    if not has_real_material_evidence and not has_runtime_shaping_signals:
        return {
            "enabled": False,
            "positive_delta": 0.0,
            "negative_delta": 0.0,
            "net_delta": 0.0,
            "reasons": ["insufficient_material_evidence_context"],
            "signals": {
                "mandatory_hit_rate": round(mandatory_hit_rate, 4),
                "mandatory_clause_signal_count": mandatory_clause_signal_count,
                "cross_type_consensus_score": round(cross_score, 4),
                "cross_type_consensus_type_count": cross_types,
                "structured_quality_avg": round(structured_quality_avg, 4),
                "structured_quality_type_rate": round(structured_quality_type_rate, 4),
                "strong_structured_types": strong_types,
                "parsed_ok_files": parsed_ok_files,
                "total_files": total_files,
                "structured_signal_total": structured_signal_total,
                "dimension_coverage_rate": round(dimension_coverage_rate, 4),
                "site_photo_visual_requirements": visual_req_count,
                "feedback_requirements": feedback_req_count,
                "feature_requirements": feature_req_count,
                "material_consensus_requirements": consensus_req_count,
                "material_dimension_requirements": dimension_req_count,
                "material_retrieval_requirements": retrieval_req_count,
                "score_shaping_requirements": shaping_req_count,
            },
        }
    positive = 0.0
    negative = 0.0
    reasons: List[str] = []
    if mandatory_clause_signal_count >= 3 and mandatory_hit_rate < 0.5:
        delta = min(3.8, (0.5 - mandatory_hit_rate) * 7.2 + mandatory_clause_signal_count * 0.08)
        negative += delta
        reasons.append("mandatory_clause_underhit")
    if parsed_ok_files > 0 and structured_quality_avg < 0.28:
        delta = min(2.4, (0.28 - structured_quality_avg) * 5.5 + 0.4)
        negative += delta
        reasons.append("structured_quality_weak")
    if parsed_ok_files > 0 and structured_quality_type_rate < 0.34:
        negative += min(1.4, (0.34 - structured_quality_type_rate) * 3.0 + 0.2)
        reasons.append("structured_type_coverage_weak")
    if cross_score >= 0.3 and cross_types >= 2:
        positive += min(2.2, cross_score * 3.2 + max(0, cross_types - 1) * 0.18)
        reasons.append("cross_material_consensus")
    if cross_score >= 0.42 and cross_types >= 3:
        positive += 0.65
        reasons.append("core_material_alignment")
    if visual_req_count > 0:
        positive += min(0.9, visual_req_count * 0.16)
        reasons.append("visual_evidence_support")
    if feedback_req_count > 0 or feature_req_count > 0:
        positive += min(0.8, feedback_req_count * 0.06 + feature_req_count * 0.04)
        reasons.append("feedback_evolution_context")
    if parsed_ok_files > 0 and strong_types <= 1 and mandatory_clause_signal_count <= 1:
        negative += 0.55
        reasons.append("weak_core_material_support")
    net_delta = round(max(-5.0, min(3.5, positive - negative)), 2)
    return {
        "enabled": True,
        "positive_delta": round(positive, 2),
        "negative_delta": round(negative, 2),
        "net_delta": net_delta,
        "reasons": _limit_unique_texts(reasons, limit=8),
        "signals": {
            "mandatory_hit_rate": round(mandatory_hit_rate, 4),
            "mandatory_clause_signal_count": mandatory_clause_signal_count,
            "cross_type_consensus_score": round(cross_score, 4),
            "cross_type_consensus_type_count": cross_types,
            "structured_quality_avg": round(structured_quality_avg, 4),
            "structured_quality_type_rate": round(structured_quality_type_rate, 4),
            "strong_structured_types": strong_types,
            "parsed_ok_files": parsed_ok_files,
            "total_files": total_files,
            "structured_signal_total": structured_signal_total,
            "dimension_coverage_rate": round(dimension_coverage_rate, 4),
            "site_photo_visual_requirements": visual_req_count,
            "feedback_requirements": feedback_req_count,
            "feature_requirements": feature_req_count,
            "material_consensus_requirements": consensus_req_count,
            "material_dimension_requirements": dimension_req_count,
            "material_retrieval_requirements": retrieval_req_count,
            "score_shaping_requirements": shaping_req_count,
        },
    }


def _apply_material_constraint_score_shaping(
    report: Dict[str, object],
    *,
    runtime_req_meta: Optional[Dict[str, object]],
    material_knowledge_snapshot: Optional[Dict[str, object]],
) -> Dict[str, object]:
    shaping = _build_material_score_shaping(
        report,
        runtime_req_meta=runtime_req_meta,
        material_knowledge_snapshot=material_knowledge_snapshot,
    )
    raw_rule_total = float(_to_float_or_none(report.get("rule_total_score")) or 0.0)
    shaped_rule_total = _clip_score(raw_rule_total + float(shaping.get("net_delta") or 0.0))
    report["raw_rule_total_score_100"] = raw_rule_total
    report["rule_total_score"] = round(shaped_rule_total, 2)
    report["total_score"] = round(shaped_rule_total, 2)
    report.setdefault("meta", {})
    report["meta"]["material_constraint_shaping"] = shaping
    return shaping


def _build_runtime_custom_requirements(
    project_id: str,
    *,
    project: Dict[str, object],
    submission_text: str = "",
    weights_norm: Optional[Dict[str, float]] = None,
) -> tuple[List[Dict[str, object]], Dict[str, object]]:
    evo = load_evolution_reports().get(project_id) or {}
    compilation = (
        evo.get("compilation_instructions")
        if isinstance(evo.get("compilation_instructions"), dict)
        else {}
    )
    required_sections = _to_text_items(compilation.get("required_sections"), max_items=20)
    required_charts = _to_text_items(compilation.get("required_charts_images"), max_items=20)
    mandatory_elements = _to_text_items(compilation.get("mandatory_elements"), max_items=24)

    custom_text_items: List[str] = []
    meta_obj = project.get("meta") if isinstance(project.get("meta"), dict) else {}
    custom_text_items.extend(
        _to_text_items((meta_obj or {}).get("custom_scoring_instructions"), max_items=20)
    )
    # 允许在项目上下文里用“指令:”行注入运行时评分提示，避免另开配置入口。
    context_text = _load_project_context_text(project_id)
    for line in context_text.splitlines():
        s = line.strip()
        if not s or len(s) > 120:
            continue
        if any(mark in s for mark in ("指令", "要求", "必须", "禁止", "关注")):
            custom_text_items.append(s)
    custom_text_items = _to_text_items(custom_text_items, max_items=20)

    runtime_requirements: List[Dict[str, object]] = []
    created_at = _now_iso()
    req_index = 0

    def _append_req(
        *,
        dim_id: str,
        label: str,
        hints: List[str],
        mandatory: bool,
        weight: float,
        kind: str,
    ) -> None:
        nonlocal req_index
        if not hints:
            return
        req_index += 1
        runtime_requirements.append(
            {
                "id": f"runtime-{project_id[:8]}-{kind}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": label,
                "req_type": "semantic",
                "patterns": {"hints": hints},
                "mandatory": mandatory,
                "weight": float(weight),
                "source_anchor_id": None,
                "source_pack_id": "runtime_custom",
                "source_pack_version": "v2-runtime",
                "priority": 90.0,
                "override_key": f"runtime::{kind}::{req_index}",
                "lint": {},
                "created_at": created_at,
            }
        )

    for item in required_sections:
        _append_req(
            dim_id="01",
            label=f"编制系统指令-必备章节：{item}",
            hints=[item],
            mandatory=True,
            weight=1.1,
            kind="section",
        )
    for item in required_charts:
        _append_req(
            dim_id="12",
            label=f"编制系统指令-图表要求：{item}",
            hints=[item],
            mandatory=False,
            weight=0.8,
            kind="chart",
        )
    for item in mandatory_elements:
        _append_req(
            dim_id="09",
            label=f"编制系统指令-必备要素：{item}",
            hints=[item],
            mandatory=True,
            weight=1.0,
            kind="element",
        )
    for item in custom_text_items:
        _append_req(
            dim_id="01",
            label=f"自定义评分指令：{item}",
            hints=[item],
            mandatory=False,
            weight=0.6,
            kind="custom",
        )

    material_index = _build_project_material_index(project_id)
    material_knowledge_profile = _build_material_knowledge_profile(project_id)
    retrieval_cfg = _resolve_material_retrieval_config(project)
    query_features = _build_material_query_features(
        project_id=project_id,
        submission_text=submission_text,
        required_sections=required_sections,
        required_charts=required_charts,
        mandatory_elements=mandatory_elements,
        custom_text_items=custom_text_items,
        context_text=context_text,
        material_knowledge_profile=material_knowledge_profile,
    )
    constraint_pack = _build_material_constraint_pack(
        project_id=project_id,
        project=project,
        submission_text=submission_text,
        material_index=material_index,
        material_knowledge_profile=material_knowledge_profile,
        weights_norm=weights_norm,
        query_features=query_features,
        retrieval_cfg=retrieval_cfg,
    )
    retrieval_budget = (
        constraint_pack.get("retrieval_budget")
        if isinstance(constraint_pack.get("retrieval_budget"), dict)
        else {}
    )
    retrieval_top_k = int(
        constraint_pack.get("retrieval_top_k")
        or retrieval_cfg.get("top_k")
        or DEFAULT_MATERIAL_RETRIEVAL_TOP_K
    )
    retrieval_per_type_quota = int(
        constraint_pack.get("retrieval_per_type_quota")
        or retrieval_cfg.get("per_type_quota")
        or DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA
    )
    retrieval_per_file_quota = int(
        constraint_pack.get("retrieval_per_file_quota")
        or retrieval_cfg.get("per_file_quota")
        or DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA
    )
    retrieval_chunks = (
        list(constraint_pack.get("retrieval_chunks") or [])
        if isinstance(constraint_pack.get("retrieval_chunks"), list)
        else []
    )
    retrieval_requirements = (
        list(constraint_pack.get("retrieval_requirements") or [])
        if isinstance(constraint_pack.get("retrieval_requirements"), list)
        else []
    )
    consistency_requirements = (
        list(constraint_pack.get("consistency_requirements") or [])
        if isinstance(constraint_pack.get("consistency_requirements"), list)
        else []
    )
    material_dimension_requirements = (
        list(constraint_pack.get("material_dimension_requirements") or [])
        if isinstance(constraint_pack.get("material_dimension_requirements"), list)
        else []
    )
    material_consensus_requirements = (
        list(constraint_pack.get("material_consensus_requirements") or [])
        if isinstance(constraint_pack.get("material_consensus_requirements"), list)
        else []
    )
    site_photo_visual_requirements = (
        list(constraint_pack.get("site_photo_visual_requirements") or [])
        if isinstance(constraint_pack.get("site_photo_visual_requirements"), list)
        else []
    )
    feedback_requirements = (
        list(constraint_pack.get("feedback_requirements") or [])
        if isinstance(constraint_pack.get("feedback_requirements"), list)
        else []
    )
    feature_requirements = (
        list(constraint_pack.get("feature_requirements") or [])
        if isinstance(constraint_pack.get("feature_requirements"), list)
        else []
    )
    available_material_types = (
        list(constraint_pack.get("available_material_types") or [])
        if isinstance(constraint_pack.get("available_material_types"), list)
        else []
    )
    available_material_filenames = (
        list(constraint_pack.get("available_material_filenames") or [])
        if isinstance(constraint_pack.get("available_material_filenames"), list)
        else []
    )
    retrieval_selected_filenames = (
        list(constraint_pack.get("retrieval_selected_filenames") or [])
        if isinstance(constraint_pack.get("retrieval_selected_filenames"), list)
        else []
    )
    retrieval_selected_via_counts = (
        dict(constraint_pack.get("retrieval_selected_via_counts") or {})
        if isinstance(constraint_pack.get("retrieval_selected_via_counts"), dict)
        else {}
    )
    retrieval_types = (
        list(constraint_pack.get("retrieval_types") or [])
        if isinstance(constraint_pack.get("retrieval_types"), list)
        else []
    )
    runtime_requirements.extend(list(constraint_pack.get("requirements") or []))

    meta = {
        "required_sections": len(required_sections),
        "required_charts_images": len(required_charts),
        "mandatory_elements": len(mandatory_elements),
        "custom_instruction_lines": len(custom_text_items),
        "runtime_custom_requirements": len(runtime_requirements),
        "project_context_chars": len(context_text),
        "material_retrieval_chunks": len(retrieval_chunks),
        "material_retrieval_requirements": len(retrieval_requirements),
        "material_consistency_requirements": len(consistency_requirements),
        "material_dimension_requirements": len(material_dimension_requirements),
        "material_consensus_requirements": len(material_consensus_requirements),
        "site_photo_visual_requirements": len(site_photo_visual_requirements),
        "feedback_evolution_requirements": len(feedback_requirements),
        "feature_confidence_requirements": len(feature_requirements),
        "material_retrieval_top_k": retrieval_top_k,
        "material_retrieval_per_type_quota": retrieval_per_type_quota,
        "material_retrieval_per_file_quota": retrieval_per_file_quota,
        "material_retrieval_base_top_k": int(
            retrieval_budget.get("base_top_k")
            or retrieval_cfg.get("top_k")
            or DEFAULT_MATERIAL_RETRIEVAL_TOP_K
        ),
        "material_retrieval_base_per_type_quota": int(
            retrieval_budget.get("base_per_type_quota")
            or retrieval_cfg.get("per_type_quota")
            or DEFAULT_MATERIAL_RETRIEVAL_PER_TYPE_QUOTA
        ),
        "material_retrieval_base_per_file_quota": int(
            retrieval_budget.get("base_per_file_quota")
            or retrieval_cfg.get("per_file_quota")
            or DEFAULT_MATERIAL_RETRIEVAL_PER_FILE_QUOTA
        ),
        "material_retrieval_budget_reasons": list(retrieval_budget.get("budget_reasons") or []),
        "material_query_seed_lines": int(query_features.get("seed_lines_count") or 0),
        "material_query_terms_count": len(query_features.get("query_terms") or []),
        "material_query_numeric_terms_count": len(query_features.get("query_numeric_terms") or []),
        "material_query_terms_preview": list((query_features.get("query_terms") or [])[:12]),
        "material_query_numeric_terms_preview": list(
            (query_features.get("query_numeric_terms") or [])[:12]
        ),
        "material_profile_query_terms_count": int(
            query_features.get("material_profile_query_terms_count") or 0
        ),
        "material_profile_query_numeric_terms_count": int(
            query_features.get("material_profile_query_numeric_terms_count") or 0
        ),
        "material_profile_focus_dimensions": list(
            (query_features.get("material_profile_focus_dimensions") or [])[:8]
        ),
        "material_profile_query_terms_preview": list(
            (query_features.get("material_profile_query_terms_preview") or [])[:12]
        ),
        "material_profile_query_numeric_terms_preview": list(
            (query_features.get("material_profile_query_numeric_terms_preview") or [])[:12]
        ),
        "material_query_anchor_count": int(query_features.get("project_anchor_count") or 0),
        "material_query_requirement_count": int(
            query_features.get("project_requirement_count") or 0
        ),
        "material_profile_dimension_coverage_rate": float(
            _to_float_or_none(
                ((material_knowledge_profile.get("summary") or {}).get("dimension_coverage_rate"))
                if isinstance(material_knowledge_profile, dict)
                else None
            )
            or 0.0
        ),
        "material_available_files": len(
            (material_index.get("files") or []) if isinstance(material_index, dict) else []
        ),
        "material_available_filenames": available_material_filenames[:120],
        "material_available_types": available_material_types,
        "material_total_size_mb": float(retrieval_budget.get("material_total_size_mb") or 0.0),
        "material_type_count": int(retrieval_budget.get("material_type_count") or 0),
        "material_retrieval_types": retrieval_types,
        "material_retrieval_selected_via_counts": retrieval_selected_via_counts,
        "material_retrieval_selected_filenames": retrieval_selected_filenames[:120],
        "material_retrieval_missing_types": [
            t for t in available_material_types if t not in retrieval_types
        ],
        "material_constraint_pack": {
            "requirement_total": len(list(constraint_pack.get("requirements") or [])),
            "retrieval_gating": len(retrieval_requirements),
            "dimension_gating": len(
                material_dimension_requirements
                + material_consensus_requirements
                + site_photo_visual_requirements
                + feedback_requirements
                + feature_requirements
            ),
            "score_shaping": len(
                material_consensus_requirements
                + site_photo_visual_requirements
                + feedback_requirements
                + feature_requirements
            ),
            "available_types": available_material_types[:8],
            "selected_filenames": retrieval_selected_filenames[:12],
            "pack_version": "v4-unified-material-pack",
        },
        "material_retrieval_preview": [
            {
                "material_type": c.get("material_type"),
                "filename": c.get("filename"),
                "chunk_id": c.get("chunk_id"),
                "dimension_id": c.get("dimension_id"),
                "score": c.get("score"),
                "file_structured_quality": c.get("file_structured_quality"),
                "matched_terms": c.get("matched_terms"),
                "matched_numeric_terms": c.get("matched_numeric_terms"),
                "matched_file_anchor_terms": c.get("matched_file_anchor_terms"),
                "matched_file_numeric_terms": c.get("matched_file_numeric_terms"),
                "selected_via": c.get("selected_via"),
            }
            for c in retrieval_chunks[:8]
        ],
        "material_consistency_preview": [
            {
                "material_type": req.get("material_type"),
                "dimension_id": req.get("dimension_id"),
                "mandatory": req.get("mandatory"),
                "terms": ((req.get("patterns") or {}).get("must_hit_terms") or [])[:6],
                "numbers": ((req.get("patterns") or {}).get("must_hit_numbers") or [])[:4],
            }
            for req in consistency_requirements[:6]
        ],
        "material_dimension_preview": [
            {
                "dimension_id": req.get("dimension_id"),
                "label": req.get("req_label"),
                "hints": (((req.get("patterns") or {}).get("hints")) or [])[:6],
                "source_types": (((req.get("patterns") or {}).get("source_types")) or [])[:4],
                "coverage_score": (req.get("patterns") or {}).get("source_coverage_score"),
                "source_file_count": (req.get("patterns") or {}).get("source_file_count"),
            }
            for req in material_dimension_requirements[:8]
        ],
        "material_consensus_preview": [
            {
                "dimension_id": req.get("dimension_id"),
                "label": req.get("req_label"),
                "terms": (((req.get("patterns") or {}).get("must_hit_terms")) or [])[:6],
                "numbers": (((req.get("patterns") or {}).get("must_hit_numbers")) or [])[:4],
                "source_types": (((req.get("patterns") or {}).get("source_types")) or [])[:4],
                "consensus_score": (req.get("patterns") or {}).get("consensus_score"),
            }
            for req in material_consensus_requirements[:6]
        ],
        "site_photo_visual_preview": [
            {
                "dimension_id": req.get("dimension_id"),
                "label": req.get("req_label"),
                "hints": (((req.get("patterns") or {}).get("hints")) or [])[:6],
                "scene_type": (req.get("patterns") or {}).get("scene_type"),
                "avg_evidence_confidence": (req.get("patterns") or {}).get(
                    "avg_evidence_confidence"
                ),
            }
            for req in site_photo_visual_requirements[:6]
        ],
        "feature_confidence_preview": [
            {
                "dimension_id": req.get("dimension_id"),
                "label": req.get("req_label"),
                "hints": (((req.get("patterns") or {}).get("hints")) or [])[:6],
                "feature_ids": (((req.get("patterns") or {}).get("feature_ids")) or [])[:4],
                "feature_confidence_scores": (
                    ((req.get("patterns") or {}).get("feature_confidence_scores")) or []
                )[:4],
            }
            for req in feature_requirements[:8]
        ],
        "feedback_evolution_preview": [
            {
                "dimension_id": req.get("dimension_id"),
                "label": req.get("req_label"),
                "hints": (((req.get("patterns") or {}).get("hints")) or [])[:6],
                "multiplier": (req.get("patterns") or {}).get("multiplier"),
                "sample_count": (req.get("patterns") or {}).get("sample_count"),
            }
            for req in feedback_requirements[:8]
        ],
    }
    return runtime_requirements, meta


def _build_current_runtime_constraint_snapshot(
    project_id: str,
    *,
    submission_text: str = "",
) -> Dict[str, object]:
    snapshot: Dict[str, object] = {
        "generated_at": _now_iso(),
        "weights_source": "unknown",
        "effective_multipliers_preview": [],
        "material_dimension_requirements": 0,
        "site_photo_visual_requirements": 0,
        "feedback_evolution_requirements": 0,
        "feature_confidence_requirements": 0,
        "material_dimension_preview": [],
        "site_photo_visual_preview": [],
        "feedback_evolution_preview": [],
        "feature_confidence_preview": [],
    }
    try:
        multipliers, profile_snapshot, project = _resolve_project_scoring_context(project_id)
    except HTTPException:
        return snapshot
    weights_norm = (
        dict(profile_snapshot.get("weights_norm") or {})
        if isinstance(profile_snapshot, dict)
        else _weights_from_multipliers(multipliers)
    )
    _, runtime_meta = _build_runtime_custom_requirements(
        project_id,
        project=project,
        submission_text=submission_text,
        weights_norm=weights_norm,
    )
    multiplier_rows = sorted(
        [
            {
                "dimension_id": dim_id,
                "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
                "multiplier": round(float(multipliers.get(dim_id, 1.0)), 4),
            }
            for dim_id in DIMENSION_IDS
        ],
        key=lambda item: (
            -float(item.get("multiplier") or 1.0),
            str(item.get("dimension_id") or ""),
        ),
    )
    snapshot.update(
        {
            "weights_source": _infer_weights_source(project_id, profile_snapshot, project=project),
            "effective_multipliers_preview": multiplier_rows[:8],
            "expert_profile_id": (
                str(profile_snapshot.get("id") or "") if isinstance(profile_snapshot, dict) else ""
            ),
            "material_dimension_requirements": int(
                _to_float_or_none(runtime_meta.get("material_dimension_requirements")) or 0
            ),
            "site_photo_visual_requirements": int(
                _to_float_or_none(runtime_meta.get("site_photo_visual_requirements")) or 0
            ),
            "feedback_evolution_requirements": int(
                _to_float_or_none(runtime_meta.get("feedback_evolution_requirements")) or 0
            ),
            "feature_confidence_requirements": int(
                _to_float_or_none(runtime_meta.get("feature_confidence_requirements")) or 0
            ),
            "material_dimension_preview": list(
                runtime_meta.get("material_dimension_preview") or []
            ),
            "site_photo_visual_preview": list(runtime_meta.get("site_photo_visual_preview") or []),
            "feedback_evolution_preview": list(
                runtime_meta.get("feedback_evolution_preview") or []
            ),
            "feature_confidence_preview": list(
                runtime_meta.get("feature_confidence_preview") or []
            ),
        }
    )
    return snapshot


def _infer_weights_source(
    project_id: str,
    profile_snapshot: Optional[Dict[str, object]],
    project: Optional[Dict[str, object]] = None,
) -> str:
    status: Dict[str, object] = {"usable": False, "stored": False}
    try:
        current_project = project
        if not isinstance(current_project, dict):
            current_project = next(
                (p for p in load_projects() if str(p.get("id") or "") == project_id),
                None,
            )
        if isinstance(current_project, dict):
            status = _evaluate_evolution_weight_status(project_id, project=current_project)
    except Exception:
        status = {"usable": False, "stored": False}
    if bool(status.get("usable")):
        return "evolution"
    if profile_snapshot:
        return "expert_profile"
    if bool(status.get("stored")):
        return "evolution_stored_inactive"
    if any(str(p.get("project_id")) == project_id for p in load_learning_profiles()):
        return "learning_profile"
    return "default_uniform"


def _build_scoring_input_injection_meta(
    *,
    project_id: str,
    text: str,
    anchors_count: int,
    base_requirements_count: int,
    runtime_custom_requirements_count: int,
    weights_norm: Dict[str, float],
    profile_snapshot: Optional[Dict[str, object]],
    constraints_rebuilt: bool,
    runtime_req_meta: Dict[str, object],
    material_quality_snapshot: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    material_rows = [m for m in load_materials() if str(m.get("project_id")) == project_id]
    material_type_counts: Dict[str, int] = {}
    for row in material_rows:
        key = _normalize_material_type(row.get("material_type"), filename=row.get("filename"))
        material_type_counts[key] = material_type_counts.get(key, 0) + 1
    snapshot = material_quality_snapshot if isinstance(material_quality_snapshot, dict) else None
    if snapshot:
        snapshot_type_counts = snapshot.get("counts_by_type")
        if isinstance(snapshot_type_counts, dict) and snapshot_type_counts:
            material_type_counts = {
                str(k): int(_to_float_or_none(v) or 0) for k, v in snapshot_type_counts.items()
            }
        materials_count = int(_to_float_or_none(snapshot.get("total_files")) or len(material_rows))
        total_parsed_chars = int(_to_float_or_none(snapshot.get("total_parsed_chars")) or 0)
        parse_fail_ratio = float(_to_float_or_none(snapshot.get("parse_fail_ratio")) or 0.0)
    else:
        materials_count = len(material_rows)
        total_parsed_chars = 0
        parse_fail_ratio = 0.0
    context_text = _load_project_context_text(project_id)
    gate = snapshot.get("gate") if isinstance(snapshot, dict) else {}
    gate_passed = bool((gate or {}).get("passed", True))
    return {
        "mece_inputs": {
            "project_materials_extracted": materials_count > 0,
            "shigong_parsed": bool(str(text or "").strip()),
            "bid_requirements_loaded": base_requirements_count > 0,
            "attention_16d_weights_injected": bool(weights_norm),
            "custom_instructions_injected": runtime_custom_requirements_count > 0
            or bool(context_text.strip()),
            "materials_quality_gate_passed": gate_passed,
        },
        "materials_count": materials_count,
        "material_type_counts": material_type_counts,
        "materials_total_parsed_chars": total_parsed_chars,
        "materials_parse_fail_ratio": round(parse_fail_ratio, 4),
        "project_context_chars": len(context_text),
        "anchors_count": int(anchors_count),
        "requirements_count": int(base_requirements_count),
        "runtime_custom_requirements_count": int(runtime_custom_requirements_count),
        "weights_source": _infer_weights_source(project_id, profile_snapshot),
        "weights_sum": round(sum(float(weights_norm.get(d, 0.0)) for d in DIMENSION_IDS), 6),
        "constraints_rebuilt": bool(constraints_rebuilt),
        "runtime_instruction_breakdown": runtime_req_meta,
        "material_gate": gate if isinstance(gate, dict) else {},
    }


def _build_material_utilization_summary(
    report: Dict[str, object],
    runtime_req_meta: Dict[str, object],
) -> Dict[str, object]:
    req_hits = (
        report.get("requirement_hits") if isinstance(report.get("requirement_hits"), list) else []
    )
    req_hits = req_hits if isinstance(req_hits, list) else []
    by_type: Dict[str, Dict[str, object]] = {}
    retrieval_total = 0
    retrieval_hit = 0
    consistency_total = 0
    consistency_hit = 0
    fallback_total = 0
    fallback_hit = 0
    dimension_total = 0
    dimension_hit = 0
    retrieval_file_total_set: set[str] = set()
    retrieval_file_hit_set: set[str] = set()
    retrieval_total_via_counts: Dict[str, int] = {}
    retrieval_hit_via_counts: Dict[str, int] = {}
    dimension_by_dim: Dict[str, Dict[str, object]] = {}

    def _bucket(material_type: str) -> Dict[str, object]:
        if material_type not in by_type:
            by_type[material_type] = {
                "retrieval_total": 0,
                "retrieval_hit": 0,
                "consistency_total": 0,
                "consistency_hit": 0,
                "fallback_total": 0,
                "fallback_hit": 0,
                "sample_labels": [],
            }
        return by_type[material_type]

    def _dimension_bucket(dim_id: str) -> Dict[str, object]:
        if dim_id not in dimension_by_dim:
            dimension_by_dim[dim_id] = {
                "dimension_id": dim_id,
                "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
                "total": 0,
                "hit": 0,
                "source_types": [],
                "sample_labels": [],
            }
        return dimension_by_dim[dim_id]

    retrieval_files_raw = runtime_req_meta.get("material_retrieval_selected_filenames")
    if isinstance(retrieval_files_raw, list):
        for item in retrieval_files_raw:
            filename_text = str(item or "").strip()
            if filename_text:
                retrieval_file_total_set.add(filename_text)
    selected_via_raw = runtime_req_meta.get("material_retrieval_selected_via_counts")
    retrieval_selected_via_counts: Dict[str, int] = {}
    if isinstance(selected_via_raw, dict):
        for key, value in selected_via_raw.items():
            mode = str(key or "").strip() or "unknown"
            count = int(_to_float_or_none(value) or 0)
            if count > 0:
                retrieval_selected_via_counts[mode] = (
                    int(retrieval_selected_via_counts.get(mode, 0)) + count
                )

    for row in req_hits:
        if not isinstance(row, dict):
            continue
        source_pack_id = str(row.get("source_pack_id") or "")
        if source_pack_id not in {
            "runtime_material_rag",
            "runtime_material_consistency",
            "runtime_material_dimension",
        }:
            continue
        hit = bool(row.get("hit"))
        source_mode = str(row.get("source_mode") or "").strip()
        source_filename = str(row.get("source_filename") or "").strip()
        if not source_filename:
            chunk_id = str(row.get("chunk_id") or "").strip()
            if "#c" in chunk_id:
                source_filename = chunk_id.split("#c", 1)[0].strip()

        if source_pack_id == "runtime_material_rag":
            material_type = _normalize_material_type(row.get("material_type"))
            bucket = _bucket(material_type)
            retrieval_total += 1
            bucket["retrieval_total"] = int(bucket.get("retrieval_total", 0)) + 1
            via_key = source_mode or "unknown"
            retrieval_total_via_counts[via_key] = (
                int(retrieval_total_via_counts.get(via_key, 0)) + 1
            )
            if source_filename:
                retrieval_file_total_set.add(source_filename)
            if hit:
                retrieval_hit += 1
                bucket["retrieval_hit"] = int(bucket.get("retrieval_hit", 0)) + 1
                retrieval_hit_via_counts[via_key] = (
                    int(retrieval_hit_via_counts.get(via_key, 0)) + 1
                )
                if source_filename:
                    retrieval_file_hit_set.add(source_filename)
        elif source_pack_id == "runtime_material_consistency":
            material_type = _normalize_material_type(row.get("material_type"))
            bucket = _bucket(material_type)
            consistency_total += 1
            bucket["consistency_total"] = int(bucket.get("consistency_total", 0)) + 1
            if hit:
                consistency_hit += 1
                bucket["consistency_hit"] = int(bucket.get("consistency_hit", 0)) + 1
        else:
            dim_id = str(row.get("dimension_id") or "").strip() or "01"
            dim_bucket = _dimension_bucket(dim_id)
            dim_bucket["total"] = int(dim_bucket.get("total", 0)) + 1
            dimension_total += 1
            for item in row.get("source_types") or []:
                type_key = _normalize_material_type(item)
                if type_key and type_key not in dim_bucket["source_types"]:
                    dim_bucket["source_types"].append(type_key)
            if hit:
                dim_bucket["hit"] = int(dim_bucket.get("hit", 0)) + 1
                dimension_hit += 1

        if source_mode == "fallback_keywords":
            material_type = _normalize_material_type(row.get("material_type"))
            bucket = _bucket(material_type)
            bucket["fallback_total"] = int(bucket.get("fallback_total", 0)) + 1
            fallback_total += 1
            if hit:
                bucket["fallback_hit"] = int(bucket.get("fallback_hit", 0)) + 1
                fallback_hit += 1

        label = str(row.get("label") or "").strip()
        if label:
            if source_pack_id == "runtime_material_dimension":
                dim_id = str(row.get("dimension_id") or "").strip() or "01"
                sample_labels = _dimension_bucket(dim_id).get("sample_labels")
                if (
                    isinstance(sample_labels, list)
                    and label not in sample_labels
                    and len(sample_labels) < 3
                ):
                    sample_labels.append(label)
            else:
                material_type = _normalize_material_type(row.get("material_type"))
                sample_labels = _bucket(material_type).get("sample_labels")
                if (
                    isinstance(sample_labels, list)
                    and label not in sample_labels
                    and len(sample_labels) < 3
                ):
                    sample_labels.append(label)

    available_types_raw = runtime_req_meta.get("material_available_types")
    available_types = (
        [_normalize_material_type(x) for x in available_types_raw]
        if isinstance(available_types_raw, list)
        else []
    )
    uncovered_types = []
    for material_type in available_types:
        bucket = by_type.get(material_type) or {}
        any_hit = int(bucket.get("retrieval_hit", 0)) + int(bucket.get("consistency_hit", 0))
        if any_hit <= 0:
            uncovered_types.append(material_type)

    def _rate(hit_cnt: int, total_cnt: int) -> Optional[float]:
        if total_cnt <= 0:
            return None
        return round(float(hit_cnt) / float(total_cnt), 4)

    unhit_files = sorted(retrieval_file_total_set - retrieval_file_hit_set)

    return {
        "retrieval_total": retrieval_total,
        "retrieval_hit": retrieval_hit,
        "retrieval_hit_rate": _rate(retrieval_hit, retrieval_total),
        "retrieval_file_total": len(retrieval_file_total_set),
        "retrieval_file_hit": len(retrieval_file_hit_set),
        "retrieval_file_coverage_rate": _rate(
            len(retrieval_file_hit_set),
            len(retrieval_file_total_set),
        ),
        "retrieval_selected_filenames": sorted(retrieval_file_total_set)[:120],
        "retrieval_hit_filenames": sorted(retrieval_file_hit_set)[:120],
        "retrieval_unhit_filenames": unhit_files[:120],
        "retrieval_unhit_file_count": len(unhit_files),
        "retrieval_top_k": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_top_k")) or 0
        ),
        "retrieval_per_type_quota": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_per_type_quota")) or 0
        ),
        "retrieval_per_file_quota": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_per_file_quota")) or 0
        ),
        "retrieval_base_top_k": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_base_top_k")) or 0
        ),
        "retrieval_base_per_type_quota": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_base_per_type_quota")) or 0
        ),
        "retrieval_base_per_file_quota": int(
            _to_float_or_none(runtime_req_meta.get("material_retrieval_base_per_file_quota")) or 0
        ),
        "retrieval_budget_reasons": list(
            runtime_req_meta.get("material_retrieval_budget_reasons")
            if isinstance(runtime_req_meta.get("material_retrieval_budget_reasons"), list)
            else []
        ),
        "material_total_size_mb": float(
            _to_float_or_none(runtime_req_meta.get("material_total_size_mb")) or 0.0
        ),
        "material_type_count": int(
            _to_float_or_none(runtime_req_meta.get("material_type_count")) or 0
        ),
        "material_file_count": int(
            _to_float_or_none(runtime_req_meta.get("material_available_files")) or 0
        ),
        "retrieval_selected_via_counts": retrieval_selected_via_counts,
        "retrieval_total_via_counts": retrieval_total_via_counts,
        "retrieval_hit_via_counts": retrieval_hit_via_counts,
        "consistency_total": consistency_total,
        "consistency_hit": consistency_hit,
        "consistency_hit_rate": _rate(consistency_hit, consistency_total),
        "fallback_total": fallback_total,
        "fallback_hit": fallback_hit,
        "fallback_hit_rate": _rate(fallback_hit, fallback_total),
        "material_dimension_total": dimension_total,
        "material_dimension_hit": dimension_hit,
        "material_dimension_hit_rate": _rate(dimension_hit, dimension_total),
        "material_dimension_by_dimension": sorted(
            [
                {
                    **row,
                    "hit_rate": _rate(int(row.get("hit", 0)), int(row.get("total", 0))),
                }
                for row in dimension_by_dim.values()
            ],
            key=lambda x: (
                -float(_to_float_or_none(x.get("hit_rate")) or 0.0),
                -int(_to_float_or_none(x.get("hit")) or 0),
                str(x.get("dimension_id") or ""),
            ),
        ),
        "query_terms_count": int(
            _to_float_or_none(runtime_req_meta.get("material_query_terms_count")) or 0
        ),
        "query_numeric_terms_count": int(
            _to_float_or_none(runtime_req_meta.get("material_query_numeric_terms_count")) or 0
        ),
        "material_profile_query_terms_count": int(
            _to_float_or_none(runtime_req_meta.get("material_profile_query_terms_count")) or 0
        ),
        "material_profile_query_numeric_terms_count": int(
            _to_float_or_none(runtime_req_meta.get("material_profile_query_numeric_terms_count"))
            or 0
        ),
        "material_profile_focus_dimensions": list(
            runtime_req_meta.get("material_profile_focus_dimensions")
            if isinstance(runtime_req_meta.get("material_profile_focus_dimensions"), list)
            else []
        ),
        "by_type": by_type,
        "available_types": available_types,
        "uncovered_types": uncovered_types,
    }


def _normalize_material_retrieval_meta(raw: object) -> Dict[str, object]:
    meta = copy.deepcopy(raw) if isinstance(raw, dict) else {}
    if not isinstance(meta.get("material_retrieval_preview"), list):
        meta["material_retrieval_preview"] = []
    if not isinstance(meta.get("material_consistency_preview"), list):
        meta["material_consistency_preview"] = []
    if not isinstance(meta.get("material_dimension_preview"), list):
        meta["material_dimension_preview"] = []
    if not isinstance(meta.get("feature_confidence_preview"), list):
        meta["feature_confidence_preview"] = []
    if not isinstance(meta.get("feedback_evolution_preview"), list):
        meta["feedback_evolution_preview"] = []
    if not isinstance(meta.get("material_profile_focus_dimensions"), list):
        meta["material_profile_focus_dimensions"] = []
    for key in (
        "material_dimension_requirements",
        "feature_confidence_requirements",
        "feedback_evolution_requirements",
        "material_profile_query_terms_count",
        "material_profile_query_numeric_terms_count",
    ):
        numeric = _to_float_or_none(meta.get(key))
        meta[key] = int(numeric or 0)
    return meta


def _ensure_report_material_usage_metadata(
    report: Optional[Dict[str, object]],
) -> tuple[Dict[str, object], Dict[str, object]]:
    if not isinstance(report, dict):
        return {}, {}
    meta = report.get("meta")
    if not isinstance(meta, dict):
        meta = {}
        report["meta"] = meta
    retrieval_meta = _normalize_material_retrieval_meta(meta.get("material_retrieval"))
    meta["material_retrieval"] = retrieval_meta
    computed_utilization = _build_material_utilization_summary(report, retrieval_meta)
    existing_utilization = (
        copy.deepcopy(meta.get("material_utilization"))
        if isinstance(meta.get("material_utilization"), dict)
        else {}
    )
    merged_utilization = existing_utilization if isinstance(existing_utilization, dict) else {}
    computed_only_prefixes = ("material_dimension_", "material_profile_")
    for key, value in computed_utilization.items():
        if key not in merged_utilization:
            merged_utilization[key] = value
            continue
        if any(str(key).startswith(prefix) for prefix in computed_only_prefixes):
            merged_utilization[key] = value
    meta["material_utilization"] = merged_utilization
    return retrieval_meta, merged_utilization


def _build_evidence_trace_summary(report: Dict[str, object]) -> Dict[str, object]:
    req_hits_raw = report.get("requirement_hits")
    req_hits = req_hits_raw if isinstance(req_hits_raw, list) else []
    total_requirements = 0
    total_hits = 0
    mandatory_total = 0
    mandatory_hit = 0
    runtime_hits = 0
    source_pack_counter: Counter[str] = Counter()
    source_file_hits: List[str] = []
    preview_rows: List[Dict[str, object]] = []

    for item in req_hits:
        if not isinstance(item, dict):
            continue
        total_requirements += 1
        mandatory = bool(item.get("mandatory"))
        if mandatory:
            mandatory_total += 1
        if not bool(item.get("hit")):
            continue
        total_hits += 1
        if mandatory:
            mandatory_hit += 1

        source_pack = str(item.get("source_pack_id") or "").strip() or "unknown"
        source_pack_counter[source_pack] += 1
        if source_pack in {
            "runtime_material_rag",
            "runtime_material_consistency",
            "runtime_material_dimension",
        }:
            runtime_hits += 1

        source_filename = str(item.get("source_filename") or "").strip()
        if not source_filename:
            chunk_id = str(item.get("chunk_id") or "").strip()
            if "#c" in chunk_id:
                source_filename = chunk_id.split("#c", 1)[0].strip()
        if source_filename and source_filename not in source_file_hits:
            source_file_hits.append(source_filename)

        if len(preview_rows) < 16:
            preview_rows.append(
                {
                    "dimension_id": str(item.get("dimension_id") or ""),
                    "label": str(item.get("label") or ""),
                    "reason": str(item.get("reason") or ""),
                    "mandatory": mandatory,
                    "source_pack_id": source_pack,
                    "material_type": str(item.get("material_type") or ""),
                    "source_filename": source_filename,
                    "chunk_id": str(item.get("chunk_id") or ""),
                }
            )

    mandatory_hit_rate = (
        round(float(mandatory_hit) / float(mandatory_total), 4) if mandatory_total > 0 else None
    )
    overall_hit_rate = (
        round(float(total_hits) / float(total_requirements), 4) if total_requirements > 0 else None
    )
    return {
        "total_requirements": total_requirements,
        "total_hits": total_hits,
        "overall_hit_rate": overall_hit_rate,
        "mandatory_total": mandatory_total,
        "mandatory_hit": mandatory_hit,
        "mandatory_hit_rate": mandatory_hit_rate,
        "runtime_material_hits": runtime_hits,
        "source_files_hit": source_file_hits[:120],
        "source_files_hit_count": len(source_file_hits),
        "source_pack_hit_counts": dict(source_pack_counter),
        "preview": preview_rows,
    }


def _parse_reason_ratio(reason: str, marker: str) -> tuple[int, int]:
    text = str(reason or "")
    m = re.search(rf"{re.escape(marker)}(\d+)/(\d+)", text)
    if not m:
        return 0, 0
    try:
        left = int(m.group(1))
        right = int(m.group(2))
        return max(0, left), max(0, right)
    except Exception:
        return 0, 0


def _build_material_conflict_summary_from_report(report: Dict[str, object]) -> Dict[str, object]:
    req_hits = (
        report.get("requirement_hits") if isinstance(report.get("requirement_hits"), list) else []
    )
    consistency = (
        report.get("material_consistency")
        if isinstance(report.get("material_consistency"), dict)
        else {}
    )
    by_type_raw = (
        consistency.get("by_material_type")
        if isinstance(consistency.get("by_material_type"), dict)
        else {}
    )

    by_type: Dict[str, Dict[str, object]] = {}
    for key, row in by_type_raw.items():
        mat_type = _normalize_material_type(key)
        row_dict = row if isinstance(row, dict) else {}
        by_type[mat_type] = {
            "material_type": mat_type,
            "material_type_label": _material_type_label(mat_type),
            "total": int(_to_float_or_none(row_dict.get("total")) or 0),
            "hit": int(_to_float_or_none(row_dict.get("hit")) or 0),
            "mandatory_total": int(_to_float_or_none(row_dict.get("mandatory_total")) or 0),
            "mandatory_hit": int(_to_float_or_none(row_dict.get("mandatory_hit")) or 0),
            "hit_rate": _to_float_or_none(row_dict.get("hit_rate")),
        }

    conflicts: List[Dict[str, object]] = []
    for item in req_hits:
        if not isinstance(item, dict):
            continue
        if bool(item.get("hit")):
            continue
        source_pack = str(item.get("source_pack_id") or "")
        if source_pack != "runtime_material_consistency":
            continue
        mat_type = _normalize_material_type(item.get("material_type"))
        bucket = by_type.setdefault(
            mat_type,
            {
                "material_type": mat_type,
                "material_type_label": _material_type_label(mat_type),
                "total": 0,
                "hit": 0,
                "mandatory_total": 0,
                "mandatory_hit": 0,
                "hit_rate": None,
            },
        )
        bucket["total"] = int(bucket.get("total", 0)) + 1
        mandatory = bool(item.get("mandatory"))
        if mandatory:
            bucket["mandatory_total"] = int(bucket.get("mandatory_total", 0)) + 1

        reason = str(item.get("reason") or "")
        term_hit, term_need = _parse_reason_ratio(reason, "t")
        num_hit, num_need = _parse_reason_ratio(reason, "n")
        numeric_conflict = num_need > 0 and num_hit < num_need
        term_conflict = term_need > 0 and term_hit < term_need
        severity = "high" if (mandatory or numeric_conflict) else "medium"
        conflict_kind = (
            "numeric_mismatch"
            if numeric_conflict
            else ("term_coverage_missing" if term_conflict else "material_consistency_missing")
        )
        conflicts.append(
            {
                "severity": severity,
                "conflict_kind": conflict_kind,
                "dimension_id": str(item.get("dimension_id") or ""),
                "material_type": mat_type,
                "material_type_label": _material_type_label(mat_type),
                "label": str(item.get("label") or ""),
                "reason": reason,
                "mandatory": mandatory,
                "source_filename": str(item.get("source_filename") or ""),
                "chunk_id": str(item.get("chunk_id") or ""),
                "source_mode": str(item.get("source_mode") or ""),
                "term_hit": term_hit,
                "term_need": term_need,
                "num_hit": num_hit,
                "num_need": num_need,
            }
        )

    for row in by_type.values():
        total = int(row.get("total", 0))
        hit = int(row.get("hit", 0))
        if total > 0 and row.get("hit_rate") is None:
            row["hit_rate"] = round(float(hit) / float(total), 4)

    high_cnt = sum(1 for x in conflicts if str(x.get("severity")) == "high")
    medium_cnt = sum(1 for x in conflicts if str(x.get("severity")) == "medium")
    recommendations: List[str] = []
    if conflicts:
        recommendations.append("施组与上传资料存在一致性缺口，建议按冲突项逐条补齐。")
    for row in sorted(
        by_type.values(),
        key=lambda x: float(_to_float_or_none(x.get("hit_rate")) or 0.0),
    ):
        hit_rate = _to_float_or_none(row.get("hit_rate"))
        total = int(row.get("total", 0))
        if hit_rate is None or total <= 0:
            continue
        if hit_rate < 0.35:
            recommendations.append(
                f"{row.get('material_type_label')}一致性命中率偏低（{hit_rate * 100:.1f}%），建议补充明确的量化约束与章节引用。"
            )

    return {
        "has_conflicts": bool(conflicts),
        "conflict_count": len(conflicts),
        "high_severity_count": high_cnt,
        "medium_severity_count": medium_cnt,
        "by_material_type": sorted(
            list(by_type.values()),
            key=lambda x: str(x.get("material_type") or ""),
        ),
        "conflicts": conflicts[:60],
        "recommendations": recommendations[:10],
    }


def _build_submission_material_conflicts(
    *,
    project_id: str,
    submission: Dict[str, object],
) -> Dict[str, object]:
    report = submission.get("report") if isinstance(submission.get("report"), dict) else {}
    base = _build_material_conflict_summary_from_report(report)
    submission_text = str(submission.get("text") or "")
    submission_numbers = {
        token
        for token in (
            _normalize_numeric_token(item)
            for item in _extract_numeric_terms(submission_text, max_terms=320)
        )
        if token
    }

    material_retrieval = (
        (report.get("meta") or {}).get("material_retrieval")
        if isinstance((report.get("meta") or {}), dict)
        else {}
    )
    consistency_preview = (
        material_retrieval.get("consistency_preview")
        if isinstance(material_retrieval, dict)
        and isinstance(material_retrieval.get("consistency_preview"), list)
        else []
    )
    key_material_numbers: List[str] = []
    for row in consistency_preview:
        if not isinstance(row, dict):
            continue
        for raw in row.get("numbers") or []:
            token = _normalize_numeric_token(raw)
            if token and token not in key_material_numbers:
                key_material_numbers.append(token)

    merged_material_text = _merge_materials_text(project_id)
    material_numbers = {
        token
        for token in (
            _normalize_numeric_token(item)
            for item in _extract_numeric_terms(merged_material_text, max_terms=420)
        )
        if token
    }
    if not key_material_numbers:
        key_material_numbers = sorted(list(material_numbers))[:40]
    missing_key_numbers = [n for n in key_material_numbers if n not in submission_numbers][:30]

    numeric_base = len(key_material_numbers)
    numeric_hit = len([n for n in key_material_numbers if n in submission_numbers])
    numeric_coverage_rate = (
        round(float(numeric_hit) / float(numeric_base), 4) if numeric_base > 0 else None
    )
    numeric_conflict = numeric_base > 0 and numeric_hit < max(1, int(numeric_base * 0.25))
    if numeric_conflict:
        conflicts = base.get("conflicts") if isinstance(base.get("conflicts"), list) else []
        conflicts.append(
            {
                "severity": "high",
                "conflict_kind": "key_numeric_constraint_missing",
                "dimension_id": "",
                "material_type": "cross_material",
                "material_type_label": "跨资料",
                "label": "关键数字约束未在施组中体现",
                "reason": f"关键数字命中 {numeric_hit}/{numeric_base}",
                "mandatory": True,
                "source_filename": "",
                "chunk_id": "",
                "source_mode": "numeric_cross_check",
                "term_hit": 0,
                "term_need": 0,
                "num_hit": numeric_hit,
                "num_need": numeric_base,
                "missing_numbers": missing_key_numbers[:12],
            }
        )
        base["conflicts"] = conflicts[:60]
        base["conflict_count"] = len(base["conflicts"])
        base["high_severity_count"] = int(base.get("high_severity_count", 0)) + 1

    recommendations = (
        base.get("recommendations") if isinstance(base.get("recommendations"), list) else []
    )
    if numeric_coverage_rate is not None and numeric_coverage_rate < 0.35:
        recommendations.append(
            f"关键数字约束覆盖率偏低（{numeric_coverage_rate * 100:.1f}%），建议在施组中补充工期/工程量/阈值等量化指标。"
        )
    base["recommendations"] = recommendations[:12]
    base["numeric_cross_check"] = {
        "key_numbers_total": numeric_base,
        "key_numbers_hit": numeric_hit,
        "key_numbers_coverage_rate": numeric_coverage_rate,
        "missing_key_numbers": missing_key_numbers,
        "submission_number_count": len(submission_numbers),
        "material_number_count": len(material_numbers),
    }
    return base


