def _is_five_scale_global_prior_model(model: Dict[str, object]) -> bool:
    return str(model.get("synthetic_prior_kind") or "").strip() == "five_scale_global_prior"


def _is_hundred_scale_global_prior_model(model: Dict[str, object]) -> bool:
    return str(model.get("synthetic_prior_kind") or "").strip() == "hundred_scale_global_prior"


def _should_apply_five_scale_global_prior(
    submission: Dict[str, object],
    *,
    project: Dict[str, object],
) -> bool:
    if _resolve_project_score_scale_max(project) != 5:
        return False
    report = submission.get("report") if isinstance(submission.get("report"), dict) else {}
    if _to_float_or_none(report.get("pred_total_score")) is not None:
        return False
    rule_total_100 = _extract_submission_rule_total_100(submission)
    if rule_total_100 is None:
        return False
    display_rule = _convert_score_from_100(rule_total_100, 5)
    return display_rule is not None and float(display_rule) < float(
        DEFAULT_FIVE_SCALE_PRIOR_TRIGGER_DISPLAY_MAX
    )


def _should_apply_hundred_scale_global_prior(
    submission: Dict[str, object],
    *,
    project: Dict[str, object],
) -> bool:
    if _resolve_project_score_scale_max(project) != 100:
        return False
    report = submission.get("report") if isinstance(submission.get("report"), dict) else {}
    if _to_float_or_none(report.get("pred_total_score")) is not None:
        return False
    rule_total_100 = _extract_submission_rule_total_100(submission)
    return rule_total_100 is not None and float(rule_total_100) < float(
        DEFAULT_HUNDRED_SCALE_PRIOR_TRIGGER_TOTAL_MAX
    )


def _preview_submission_with_live_prediction(
    submission: Dict[str, object],
    *,
    project: Dict[str, object],
    model_override: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    preview = dict(submission)
    report_obj = preview.get("report")
    if not isinstance(report_obj, dict) or not _submission_has_generated_score(preview):
        return preview
    model = (
        model_override if isinstance(model_override, dict) else _select_calibrator_model(project)
    )
    if not model:
        return preview
    artifact = model.get("model_artifact") or model.get("artifact") or {}
    is_five_scale_prior = _is_five_scale_global_prior_model(model)
    is_hundred_scale_prior = _is_hundred_scale_global_prior_model(model)
    is_synthetic_prior = is_five_scale_prior or is_hundred_scale_prior
    if _to_float_or_none(report_obj.get("pred_total_score")) is not None and not is_synthetic_prior:
        return preview
    if not is_synthetic_prior and not isinstance(artifact, dict):
        return preview
    if is_five_scale_prior and not _should_apply_five_scale_global_prior(preview, project=project):
        return preview
    if is_hundred_scale_prior and not _should_apply_hundred_scale_global_prior(
        preview,
        project=project,
    ):
        return preview
    preview_report = dict(report_obj)
    preview["report"] = preview_report
    submission_like = dict(preview)
    _apply_prediction_to_report_with_model(
        preview_report,
        submission_like=submission_like,
        project=project,
        model_override=model,
    )
    preview["total_score"] = float(
        submission_like.get(
            "total_score",
            preview_report.get("total_score", preview.get("total_score", 0.0)),
        )
        or 0.0
    )
    return preview


def _select_deployed_patch(project_id: str) -> Optional[Dict[str, object]]:
    packages = [
        p
        for p in load_patch_packages()
        if str(p.get("project_id")) == project_id and str(p.get("status")) == "deployed"
    ]
    if not packages:
        return None
    packages.sort(key=lambda x: str(x.get("updated_at", "")), reverse=True)
    return packages[0]


def _auto_govern_deployed_patch(
    *,
    project_id: str,
    delta_cases: List[Dict[str, object]],
) -> Dict[str, object]:
    """
    对当前已部署补丁做自动治理：
    - shadow 评估通过：保留部署
    - shadow 评估失败且样本充分：自动回滚，并尝试回退到 rollback_pointer
    """
    result: Dict[str, object] = {
        "checked": False,
        "project_id": project_id,
        "patch_id": None,
        "gate_passed": None,
        "sample_count": 0,
        "action": "skip",
        "reason": "no_deployed_patch",
        "rolled_back": False,
        "rollback_to_patch_id": None,
        "metrics_before_after": {},
        "deployment_record_ids": [],
    }
    if not delta_cases:
        result["reason"] = "no_delta_cases"
        return result

    packages = load_patch_packages()
    deployed = [
        p
        for p in packages
        if str(p.get("project_id")) == project_id and str(p.get("status")) == "deployed"
    ]
    if not deployed:
        return result

    deployed = sorted(deployed, key=lambda x: str(x.get("updated_at", "")), reverse=True)
    patch = deployed[0]
    patch_id = str(patch.get("id") or "")
    result["checked"] = True
    result["patch_id"] = patch_id

    shadow = evaluate_patch_shadow(patch=patch, delta_cases=delta_cases)
    metrics = shadow.get("metrics_before_after") or {}
    sample_count = int(_to_float_or_none(metrics.get("sample_count")) or len(delta_cases) or 0)
    gate_passed = bool(shadow.get("gate_passed"))
    result["sample_count"] = sample_count
    result["gate_passed"] = gate_passed
    result["metrics_before_after"] = metrics

    # 样本不足时不做自动回滚，避免少量噪声导致频繁抖动。
    min_rollback_samples = 3
    if gate_passed:
        result["action"] = "keep"
        result["reason"] = "shadow_passed"
        return result
    if sample_count < min_rollback_samples:
        result["action"] = "skip"
        result["reason"] = "insufficient_samples_for_rollback"
        return result

    now_iso = _now_iso()
    rollback_pointer = str(patch.get("rollback_pointer") or "").strip()
    rollback_target = None
    if rollback_pointer:
        rollback_target = next(
            (
                p
                for p in packages
                if str(p.get("id") or "") == rollback_pointer
                and str(p.get("project_id") or "") == project_id
            ),
            None,
        )

    for row in packages:
        if str(row.get("project_id") or "") != project_id:
            continue
        if str(row.get("status") or "") == "deployed":
            row["status"] = "shadow_pass"
            row["updated_at"] = now_iso

    patch["status"] = "rolled_back"
    patch["updated_at"] = now_iso

    rollback_to_patch_id: Optional[str] = None
    if rollback_target is not None:
        rollback_target["status"] = "deployed"
        rollback_target["updated_at"] = now_iso
        rollback_to_patch_id = str(rollback_target.get("id") or "")

    save_patch_packages(packages)

    deployment_record_ids: List[str] = []
    deploys = load_patch_deployments()
    rollback_record = {
        "id": str(uuid4()),
        "patch_id": patch_id,
        "project_id": project_id,
        "action": "auto_rollback",
        "deployed": False,
        "metrics_before_after": metrics,
        "rollback_to_version": rollback_to_patch_id or rollback_pointer or None,
        "created_at": now_iso,
    }
    deploys.append(rollback_record)
    deployment_record_ids.append(str(rollback_record["id"]))
    if rollback_to_patch_id:
        promote_record = {
            "id": str(uuid4()),
            "patch_id": rollback_to_patch_id,
            "project_id": project_id,
            "action": "auto_promote_rollback_pointer",
            "deployed": True,
            "metrics_before_after": metrics,
            "rollback_to_version": None,
            "created_at": now_iso,
        }
        deploys.append(promote_record)
        deployment_record_ids.append(str(promote_record["id"]))
    save_patch_deployments(deploys)

    result["action"] = "rollback"
    result["reason"] = "shadow_failed"
    result["rolled_back"] = True
    result["rollback_to_patch_id"] = rollback_to_patch_id
    result["deployment_record_ids"] = deployment_record_ids
    return result


def _apply_deployed_patch_to_report(project_id: str, report: Dict[str, object]) -> None:
    patch = _select_deployed_patch(project_id)
    if not patch:
        return
    payload = patch.get("patch_payload") or {}
    penalties = report.get("penalties")
    if not isinstance(penalties, list) or not penalties:
        report.setdefault("meta", {})
        report["meta"]["patch_id"] = patch.get("id")
        return

    multipliers = payload.get("penalty_multiplier") or {}
    old_penalty_total = sum(
        float(p.get("points", p.get("deduct", 0.0))) for p in penalties if isinstance(p, dict)
    )
    new_penalty_total = 0.0
    for penalty in penalties:
        if not isinstance(penalty, dict):
            continue
        code = str(penalty.get("code") or "")
        mul = float(multipliers.get(code, 1.0)) if code else 1.0
        if "points" in penalty and penalty.get("points") is not None:
            penalty["points"] = round(float(penalty.get("points", 0.0)) * mul, 2)
            new_penalty_total += float(penalty["points"])
        elif "deduct" in penalty and penalty.get("deduct") is not None:
            penalty["deduct"] = round(float(penalty.get("deduct", 0.0)) * mul, 2)
            new_penalty_total += float(penalty["deduct"])
        else:
            new_penalty_total += 0.0

    has_dim_components = ("dim_total_90" in report) or ("dim_total_80" in report)
    if has_dim_components:
        dim_total_80 = float(report.get("dim_total_80", 0.0))
        dim_total_90 = report.get("dim_total_90")
        if dim_total_90 is not None:
            # 统一回推为 dim_total_80 再走同一聚合公式，避免历史/新字段混用时口径漂移
            dim_total_80 = max(0.0, min(80.0, float(dim_total_90) * (80.0 / 90.0)))
        consistency_bonus = float(report.get("consistency_bonus", 0.0))
        new_rule_total, normalized_dim_total_90 = compute_v2_rule_total(
            dim_total_80=dim_total_80,
            consistency_bonus=consistency_bonus,
            penalty_points=new_penalty_total,
        )
        report["rule_total_score"] = new_rule_total
        report["total_score"] = new_rule_total
        report["dim_total_80"] = round(dim_total_80, 2)
        report["dim_total_90"] = normalized_dim_total_90
    else:
        old_total = float(report.get("rule_total_score", report.get("total_score", 0.0)))
        delta = new_penalty_total - old_penalty_total
        new_total = max(0.0, min(100.0, round(old_total - delta, 2)))
        report["rule_total_score"] = new_total
        report["total_score"] = new_total

    report.setdefault("meta", {})
    report["meta"]["patch_id"] = patch.get("id")
    report["meta"]["patch_status"] = patch.get("status")


def _clip_score(value: float, low: float = 0.0, high: float = 100.0) -> float:
    return max(low, min(high, float(value)))


def _normalize_score_scale_max(value: object, default: int = DEFAULT_SCORE_SCALE_MAX) -> int:
    try:
        numeric = int(float(value))
    except (TypeError, ValueError):
        numeric = int(default)
    return 5 if numeric == 5 else 100


def _resolve_project_score_scale_max(project: Dict[str, object]) -> int:
    meta = project.get("meta") if isinstance(project.get("meta"), dict) else {}
    return _normalize_score_scale_max(
        (meta or {}).get("score_scale_max"),
        default=DEFAULT_SCORE_SCALE_MAX,
    )


def _score_scale_label(score_scale_max: int) -> str:
    return "5分制" if int(score_scale_max) == 5 else "100分制"


def _score_scale_decimal_places(score_scale_max: int) -> int:
    return 4 if int(_normalize_score_scale_max(score_scale_max)) == 5 else 2


def _quantize_decimal_score(value: Decimal, *, score_scale_max: int) -> float:
    places = _score_scale_decimal_places(score_scale_max)
    quantizer = Decimal("1").scaleb(-places)
    return float(value.quantize(quantizer, rounding=ROUND_HALF_UP))


def _convert_score_from_100(score: object, score_scale_max: int) -> Optional[float]:
    value = _to_float_or_none(score)
    if value is None:
        return None
    clipped = Decimal(str(_clip_score(value, 0.0, 100.0)))
    scale = Decimal(str(_normalize_score_scale_max(score_scale_max)))
    converted = clipped * (scale / Decimal("100"))
    return _quantize_decimal_score(converted, score_scale_max=score_scale_max)


def _convert_score_to_100(score: object, score_scale_max: int) -> Optional[float]:
    value = _to_float_or_none(score)
    if value is None:
        return None
    scale = Decimal(str(_normalize_score_scale_max(score_scale_max)))
    if scale <= 0:
        return None
    clipped = Decimal(str(_clip_score(value, 0.0, float(scale))))
    normalized = clipped * (Decimal("100") / scale)
    clipped_normalized = Decimal(str(_clip_score(float(normalized), 0.0, 100.0)))
    return _quantize_decimal_score(clipped_normalized, score_scale_max=100)


def _quantize_ground_truth_final_score(value: object, *, digits: int = 2) -> Optional[float]:
    numeric = _to_float_or_none(value)
    if numeric is None:
        return None
    decimal_value = Decimal(str(numeric))
    quantizer = Decimal("1").scaleb(-max(0, int(digits)))
    return float(decimal_value.quantize(quantizer, rounding=ROUND_HALF_UP))


def _extract_ground_truth_rule_page_hint(text: str, start: int, end: int) -> Optional[str]:
    window = str(text or "")[max(0, int(start) - 200) : max(int(end), int(start)) + 260]
    page_match = re.search(r"\[PAGE:(\d+)\]", window)
    if not page_match:
        page_match = re.search(r"\[PAGE_SECTION_HINTS:(\d+)\]", window)
    if not page_match:
        return None
    return f"第{page_match.group(1)}页"


def _extract_ground_truth_score_rule_from_text(
    text: str,
    *,
    filename: str,
) -> Optional[Dict[str, object]]:
    cleaned_text = str(text or "")
    if not cleaned_text.strip():
        return None
    patterns = [
        (
            "simple_mean",
            re.compile(
                r"(?:技术文件|商务文件).{0,120}?评标委员会各成员.{0,40}?打\s*分平均值确定",
                re.IGNORECASE | re.DOTALL,
            ),
            "按招标文件：评标委员会各成员打分平均值",
            100,
        ),
        (
            "trim_one_each_mean",
            re.compile(
                r"(?:技术文件|商务文件|综合评审).{0,120}?"
                r"(?:去掉|去除).{0,30}?(?:最高|较高).{0,30}?"
                r"(?:最低|较低).{0,80}?(?:平均|算术平均)",
                re.IGNORECASE | re.DOTALL,
            ),
            "按招标文件：去最高分、最低分后取平均",
            95,
        ),
        (
            "simple_mean",
            re.compile(
                r"评标委员会各成员.{0,40}?打\s*分平均值确定",
                re.IGNORECASE | re.DOTALL,
            ),
            "按招标文件：评标委员会各成员打分平均值",
            80,
        ),
        (
            "trim_one_each_mean",
            re.compile(
                r"(?:评标委员会|评委|专家).{0,80}?"
                r"(?:去掉|去除).{0,20}?(?:最高|较高).{0,20}?"
                r"(?:最低|较低).{0,60}?(?:平均|算术平均)",
                re.IGNORECASE | re.DOTALL,
            ),
            "按招标文件：去最高分、最低分后取平均",
            75,
        ),
    ]
    matched_rule: Optional[Dict[str, object]] = None
    for formula, pattern, label, confidence in patterns:
        match = pattern.search(cleaned_text)
        if not match:
            continue
        start, end = match.span()
        excerpt = re.sub(r"\s+", " ", cleaned_text[max(0, start - 60) : end + 100]).strip()
        page_hint = _extract_ground_truth_rule_page_hint(cleaned_text, start, end)
        matched_rule = {
            "formula": formula,
            "label": label,
            "rounding_digits": 2,
            "drop_highest_count": 1 if formula == "trim_one_each_mean" else 0,
            "drop_lowest_count": 1 if formula == "trim_one_each_mean" else 0,
            "detected": True,
            "confidence": confidence,
            "source_filename": str(filename or "").strip() or None,
            "source_page_hint": page_hint,
            "source_excerpt": excerpt or None,
        }
        break
    return matched_rule


def _default_ground_truth_score_rule(
    *,
    project_id: str,
    project: Dict[str, object],
) -> Dict[str, object]:
    return {
        "project_id": project_id,
        "score_scale_max": _resolve_project_score_scale_max(project),
        "formula": "manual",
        "label": "未识别招标文件取分规则，请人工录入最终得分",
        "rounding_digits": 2,
        "drop_highest_count": 0,
        "drop_lowest_count": 0,
        "auto_compute": False,
        "detected": False,
        "source_filename": None,
        "source_page_hint": None,
        "source_excerpt": None,
    }


def _resolve_project_ground_truth_score_rule(
    project_id: str,
    *,
    project: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    project_row = project
    if project_row is None:
        project_row = next(
            (item for item in load_projects() if str(item.get("id") or "") == str(project_id)),
            None,
        )
    if not isinstance(project_row, dict):
        raise HTTPException(status_code=404, detail="项目不存在")
    default_rule = _default_ground_truth_score_rule(project_id=project_id, project=project_row)
    meta = project_row.get("meta") if isinstance(project_row.get("meta"), dict) else {}
    override_formula = str((meta or {}).get("ground_truth_final_score_formula") or "").strip()
    if override_formula in {"simple_mean", "trim_one_each_mean"}:
        override_rule = dict(default_rule)
        override_rule.update(
            {
                "formula": override_formula,
                "label": (
                    "按项目配置：评标委员会各成员打分平均值"
                    if override_formula == "simple_mean"
                    else "按项目配置：去最高分、最低分后取平均"
                ),
                "drop_highest_count": 1 if override_formula == "trim_one_each_mean" else 0,
                "drop_lowest_count": 1 if override_formula == "trim_one_each_mean" else 0,
                "auto_compute": True,
                "detected": True,
                "source_filename": "project.meta.ground_truth_final_score_formula",
            }
        )
        return override_rule
    candidates: List[Dict[str, object]] = []
    for material in load_materials():
        if str(material.get("project_id") or "") != str(project_id):
            continue
        if str(material.get("material_type") or "") != "tender_qa":
            continue
        parsed_text = str(material.get("parsed_text") or "").strip()
        if not parsed_text:
            continue
        candidate = _extract_ground_truth_score_rule_from_text(
            parsed_text,
            filename=str(material.get("filename") or ""),
        )
        if candidate:
            candidates.append(candidate)
    if not candidates:
        return default_rule
    candidates.sort(
        key=lambda item: (
            -int(_to_float_or_none(item.get("confidence")) or 0),
            str(item.get("source_filename") or ""),
        )
    )
    resolved_rule = dict(default_rule)
    resolved_rule.update(candidates[0])
    resolved_rule["auto_compute"] = resolved_rule.get("formula") in {
        "simple_mean",
        "trim_one_each_mean",
    }
    return resolved_rule


def _calculate_ground_truth_final_score(
    judge_scores: object,
    *,
    scoring_rule: Dict[str, object],
) -> float:
    normalized_scores = _normalize_judge_scores_or_422(judge_scores)
    score_values = [Decimal(str(score)) for score in normalized_scores]
    formula = str(scoring_rule.get("formula") or "").strip()
    if formula == "trim_one_each_mean" and len(score_values) > 2:
        score_values = sorted(score_values)[1:-1]
    average = sum(score_values, Decimal("0")) / Decimal(str(len(score_values)))
    digits = int(_to_float_or_none(scoring_rule.get("rounding_digits")) or 2)
    quantized = _quantize_ground_truth_final_score(average, digits=digits)
    return float(quantized if quantized is not None else 0.0)


def _resolve_score_blend_weights(project: Dict[str, object]) -> tuple[float, float, float]:
    meta = project.get("meta") if isinstance(project.get("meta"), dict) else {}
    blend_raw = meta.get("score_blend") if isinstance(meta, dict) else {}
    blend_cfg = blend_raw if isinstance(blend_raw, dict) else {}

    def _f(v: object, default: float) -> float:
        try:
            return float(v)
        except Exception:
            return default

    rule_w = _f(
        blend_cfg.get("rule_weight", blend_cfg.get("rule", DEFAULT_RULE_SCORE_WEIGHT)),
        DEFAULT_RULE_SCORE_WEIGHT,
    )
    llm_w = _f(
        blend_cfg.get("llm_weight", blend_cfg.get("llm", DEFAULT_LLM_SCORE_WEIGHT)),
        DEFAULT_LLM_SCORE_WEIGHT,
    )
    delta_cap = _f(blend_cfg.get("llm_delta_cap", DEFAULT_LLM_DELTA_CAP), DEFAULT_LLM_DELTA_CAP)

    rule_w = max(0.0, rule_w)
    llm_w = max(0.0, llm_w)
    total = rule_w + llm_w
    if total <= 1e-9:
        rule_w, llm_w = DEFAULT_RULE_SCORE_WEIGHT, DEFAULT_LLM_SCORE_WEIGHT
        total = rule_w + llm_w
    rule_w /= total
    llm_w /= total
    delta_cap = max(0.0, delta_cap)
    return rule_w, llm_w, delta_cap


def _resolve_dynamic_blend_adjustment(
    report: Dict[str, object],
) -> tuple[float, float, Dict[str, object]]:
    """
    根据证据覆盖质量动态调整融合权重：
    - 资料利用门禁 blocked/warn 时，显著降低 LLM 权重
    - 资料文件覆盖率/强制项命中率低时，进一步降权
    """
    meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
    util = (
        meta.get("material_utilization")
        if isinstance(meta.get("material_utilization"), dict)
        else {}
    )
    gate = (
        meta.get("material_utilization_gate")
        if isinstance(meta.get("material_utilization_gate"), dict)
        else {}
    )
    trace = meta.get("evidence_trace") if isinstance(meta.get("evidence_trace"), dict) else {}
    has_material_signal = bool(util) or bool(gate) or bool(trace)
    if not has_material_signal:
        return (
            1.0,
            1.0,
            {
                "coverage_scale": 1.0,
                "delta_cap_scale": 1.0,
                "reasons": [],
                "retrieval_file_coverage_rate": None,
                "retrieval_hit_rate": None,
                "mandatory_hit_rate": None,
                "source_files_hit_count": None,
                "signal_state": "no_material_signal",
            },
        )

    scale = 1.0
    reasons: List[str] = []

    if bool(gate.get("blocked")):
        scale *= 0.1
        reasons.append("material_gate_blocked")
    elif bool(gate.get("warned")):
        scale *= 0.45
        reasons.append("material_gate_warned")

    retrieval_file_cov = _to_float_or_none(util.get("retrieval_file_coverage_rate"))
    if retrieval_file_cov is not None and retrieval_file_cov < 0.7:
        ratio = max(0.2, float(retrieval_file_cov) / 0.7)
        scale *= ratio
        reasons.append(f"low_retrieval_file_coverage:{retrieval_file_cov:.3f}")

    retrieval_hit_rate = _to_float_or_none(util.get("retrieval_hit_rate"))
    if retrieval_hit_rate is not None and retrieval_hit_rate < 0.35:
        ratio = max(0.3, float(retrieval_hit_rate) / 0.35)
        scale *= ratio
        reasons.append(f"low_retrieval_hit_rate:{retrieval_hit_rate:.3f}")

    mandatory_hit_rate = _to_float_or_none(trace.get("mandatory_hit_rate"))
    if mandatory_hit_rate is not None and mandatory_hit_rate < 0.45:
        ratio = max(0.35, float(mandatory_hit_rate) / 0.45)
        scale *= ratio
        reasons.append(f"low_mandatory_hit_rate:{mandatory_hit_rate:.3f}")

    source_files_hit_count_raw = (
        _to_float_or_none(trace.get("source_files_hit_count"))
        if isinstance(trace, dict) and "source_files_hit_count" in trace
        else None
    )
    source_files_hit_count = (
        int(source_files_hit_count_raw) if source_files_hit_count_raw is not None else None
    )
    if source_files_hit_count is not None and source_files_hit_count <= 0:
        scale *= 0.25
        reasons.append("no_material_source_files_hit")

    scale = max(0.02, min(1.0, float(scale)))
    delta_cap_scale = max(0.2, min(1.0, 0.2 + scale))
    return (
        scale,
        delta_cap_scale,
        {
            "coverage_scale": round(scale, 4),
            "delta_cap_scale": round(delta_cap_scale, 4),
            "reasons": reasons,
            "retrieval_file_coverage_rate": retrieval_file_cov,
            "retrieval_hit_rate": retrieval_hit_rate,
            "mandatory_hit_rate": mandatory_hit_rate,
            "source_files_hit_count": source_files_hit_count,
            "signal_state": "material_signal_detected",
        },
    )


def _build_score_self_awareness(
    report: Dict[str, object],
    *,
    material_knowledge_snapshot: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    """
    为评分结果生成统一的“自我意识/置信度”指标。

    目标不是表达统计学严格置信区间，而是让系统显式回答：
    - 当前分数是否建立在足够的资料证据之上；
    - 当前分数是否覆盖到足够多的评分维度；
    - 若启用了预测校准器，其波动范围是否可接受。
    """

    _retrieval_meta, util = _ensure_report_material_usage_metadata(report)
    meta = report.get("meta") if isinstance(report.get("meta"), dict) else {}
    gate = (
        meta.get("material_utilization_gate")
        if isinstance(meta.get("material_utilization_gate"), dict)
        else {}
    )
    trace = meta.get("evidence_trace") if isinstance(meta.get("evidence_trace"), dict) else {}
    knowledge_summary = (
        material_knowledge_snapshot.get("summary")
        if isinstance(material_knowledge_snapshot, dict)
        and isinstance(material_knowledge_snapshot.get("summary"), dict)
        else {}
    )
    knowledge_by_type = (
        material_knowledge_snapshot.get("by_type")
        if isinstance(material_knowledge_snapshot, dict)
        and isinstance(material_knowledge_snapshot.get("by_type"), list)
        else []
    )
    pred_confidence = (
        report.get("pred_confidence") if isinstance(report.get("pred_confidence"), dict) else {}
    )

    def _clip01(value: object) -> Optional[float]:
        numeric = _to_float_or_none(value)
        if numeric is None:
            return None
        return max(0.0, min(1.0, float(numeric)))

    retrieval_file_coverage_rate = _clip01(util.get("retrieval_file_coverage_rate"))
    retrieval_hit_rate = _clip01(util.get("retrieval_hit_rate"))
    material_dimension_hit_rate = _clip01(util.get("material_dimension_hit_rate"))
    mandatory_hit_rate = _clip01(trace.get("mandatory_hit_rate"))
    dimension_coverage_rate = _clip01(knowledge_summary.get("dimension_coverage_rate"))
    source_files_hit_count = int(_to_float_or_none(trace.get("source_files_hit_count")) or 0)
    numeric_category_count = len(
        [
            item
            for item in (knowledge_summary.get("numeric_category_summary") or [])
            if str(item or "").strip()
        ]
    )
    structured_signal_total = int(
        _to_float_or_none(knowledge_summary.get("structured_signal_total")) or 0
    )
    structured_quality_avg = _clip01(knowledge_summary.get("structured_quality_avg"))
    structured_quality_type_rate = _clip01(knowledge_summary.get("structured_quality_type_rate"))
    structured_type_rows = [row for row in knowledge_by_type if isinstance(row, dict)]
    available_structured_types = [
        row for row in structured_type_rows if int(_to_float_or_none(row.get("files")) or 0) > 0
    ]
    strong_structured_types = [
        row
        for row in available_structured_types
        if int(_to_float_or_none(row.get("structured_signal_count")) or 0) > 0
    ]
    structured_type_coverage_rate = (
        max(
            0.0,
            min(
                1.0,
                float(len(strong_structured_types)) / float(len(available_structured_types)),
            ),
        )
        if available_structured_types
        else None
    )
    structured_signal_score = (
        max(0.0, min(1.0, float(structured_signal_total) / 24.0))
        if structured_signal_total > 0 or available_structured_types
        else None
    )
    if structured_quality_avg is None and available_structured_types:
        structured_quality_avg = max(
            0.0,
            min(
                1.0,
                sum(
                    float(_to_float_or_none(row.get("structured_quality_score")) or 0.0)
                    for row in available_structured_types
                )
                / float(len(available_structured_types)),
            ),
        )
    strong_quality_structured_types = [
        row
        for row in available_structured_types
        if float(_to_float_or_none(row.get("structured_quality_score")) or 0.0) >= 0.45
    ]
    if structured_quality_type_rate is None and available_structured_types:
        structured_quality_type_rate = max(
            0.0,
            min(
                1.0,
                float(len(strong_quality_structured_types))
                / float(len(available_structured_types)),
            ),
        )

    source_file_signal = min(1.0, float(source_files_hit_count) / 3.0)
    numeric_cluster_signal = min(1.0, float(numeric_category_count) / 4.0)

    weighted_metrics: List[tuple[float, Optional[float], str]] = [
        (0.22, retrieval_file_coverage_rate, "资料文件覆盖率"),
        (0.16, retrieval_hit_rate, "资料检索命中率"),
        (0.12, material_dimension_hit_rate, "资料维度约束命中率"),
        (0.20, mandatory_hit_rate, "强制项命中率"),
        (0.20, dimension_coverage_rate, "维度覆盖率"),
        (0.06, structured_signal_score, "结构化资料信号"),
        (0.04, structured_type_coverage_rate, "结构化资料类型覆盖"),
        (0.06, structured_quality_avg, "结构化资料质量"),
        (0.04, structured_quality_type_rate, "高质量结构化资料覆盖"),
        (0.04, source_file_signal, "命中文件广度"),
        (0.04, numeric_cluster_signal, "数值约束簇"),
    ]
    available_weight = sum(weight for weight, value, _ in weighted_metrics if value is not None)
    if available_weight > 1e-9:
        data_score = (
            sum(weight * float(value or 0.0) for weight, value, _ in weighted_metrics)
            / available_weight
        )
    else:
        data_score = 0.25

    sigma = _to_float_or_none(pred_confidence.get("fused_sigma"))
    if sigma is None:
        sigma = _to_float_or_none(pred_confidence.get("sigma"))
    ci_lower = _to_float_or_none(pred_confidence.get("fused_ci95_lower"))
    ci_upper = _to_float_or_none(pred_confidence.get("fused_ci95_upper"))
    ci_width = None
    if ci_lower is not None and ci_upper is not None:
        ci_width = max(0.0, float(ci_upper) - float(ci_lower))

    model_signals: List[float] = []
    if sigma is not None:
        model_signals.append(max(0.0, min(1.0, 1.0 - float(sigma) / 12.0)))
    if ci_width is not None:
        model_signals.append(max(0.0, min(1.0, 1.0 - float(ci_width) / 30.0)))
    model_score = (
        round(sum(model_signals) / float(len(model_signals)), 4) if model_signals else None
    )

    overall_score = data_score if model_score is None else (data_score * 0.82 + model_score * 0.18)
    reasons: List[str] = []

    if bool(gate.get("blocked")):
        overall_score = min(overall_score, 0.18)
        reasons.append("资料利用门禁阻断")
    elif bool(gate.get("warned")):
        overall_score *= 0.78
        reasons.append("资料利用门禁预警")

    if retrieval_file_coverage_rate is not None and retrieval_file_coverage_rate < 0.35:
        reasons.append(f"资料文件覆盖率偏低（{retrieval_file_coverage_rate * 100:.1f}%）")
    if retrieval_hit_rate is not None and retrieval_hit_rate < 0.25:
        reasons.append(f"资料检索命中率偏低（{retrieval_hit_rate * 100:.1f}%）")
    if material_dimension_hit_rate is not None and material_dimension_hit_rate < 0.35:
        reasons.append(f"资料维度约束命中率偏低（{material_dimension_hit_rate * 100:.1f}%）")
    if mandatory_hit_rate is not None and mandatory_hit_rate < 0.45:
        reasons.append(f"强制项命中率偏低（{mandatory_hit_rate * 100:.1f}%）")
    if dimension_coverage_rate is not None and dimension_coverage_rate < 0.45:
        reasons.append(f"资料支撑维度覆盖率偏低（{dimension_coverage_rate * 100:.1f}%）")
    if structured_signal_score is not None and structured_signal_score < 0.35:
        reasons.append(f"结构化资料信号偏弱（{structured_signal_total}）")
    if structured_type_coverage_rate is not None and structured_type_coverage_rate < 0.5:
        reasons.append(
            "具备结构化证据的资料类型不足"
            f"（{len(strong_structured_types)}/{len(available_structured_types)}）"
        )
    if structured_quality_avg is not None and structured_quality_avg < 0.42:
        reasons.append(f"结构化资料质量偏弱（{structured_quality_avg * 100:.1f}%）")
    if structured_quality_type_rate is not None and structured_quality_type_rate < 0.34:
        reasons.append(
            "高质量结构化资料类型不足"
            f"（{len(strong_quality_structured_types)}/{len(available_structured_types)}）"
        )
    if source_files_hit_count <= 0:
        reasons.append("尚未形成有效命中文件")
    if numeric_category_count <= 0:
        reasons.append("资料中的数值约束簇不足")
    if sigma is not None and sigma > 6:
        reasons.append(f"预测波动偏大（sigma={sigma:.2f}）")
    if ci_width is not None and ci_width > 18:
        reasons.append(f"预测区间过宽（95%区间宽度={ci_width:.2f}）")

    overall_score = max(0.0, min(1.0, float(overall_score)))
    if overall_score >= 0.72:
        level = "high"
    elif overall_score >= 0.45:
        level = "medium"
    else:
        level = "low"
    if not reasons and level == "high":
        reasons.append("资料证据、维度覆盖与模型波动均处于可接受范围")

    return {
        "level": level,
        "score_0_1": round(overall_score, 4),
        "score_0_100": round(overall_score * 100.0, 1),
        "data_score_0_1": round(float(data_score), 4),
        "model_score_0_1": round(float(model_score), 4) if model_score is not None else None,
        "retrieval_file_coverage_rate": retrieval_file_coverage_rate,
        "retrieval_hit_rate": retrieval_hit_rate,
        "material_dimension_hit_rate": material_dimension_hit_rate,
        "mandatory_hit_rate": mandatory_hit_rate,
        "dimension_coverage_rate": dimension_coverage_rate,
        "structured_signal_total": structured_signal_total,
        "structured_signal_score": (
            round(float(structured_signal_score), 4)
            if structured_signal_score is not None
            else None
        ),
        "structured_quality_avg": (
            round(float(structured_quality_avg), 4) if structured_quality_avg is not None else None
        ),
        "structured_quality_type_rate": (
            round(float(structured_quality_type_rate), 4)
            if structured_quality_type_rate is not None
            else None
        ),
        "structured_type_coverage_rate": (
            round(float(structured_type_coverage_rate), 4)
            if structured_type_coverage_rate is not None
            else None
        ),
        "source_files_hit_count": source_files_hit_count,
        "numeric_category_count": numeric_category_count,
        "calibrator_sigma": round(float(sigma), 4) if sigma is not None else None,
        "confidence_interval_width": round(float(ci_width), 4) if ci_width is not None else None,
        "state": (
            "blocked"
            if bool(gate.get("blocked"))
            else ("warned" if bool(gate.get("warned")) else "normal")
        ),
        "reasons": reasons[:8],
    }


def _ensure_report_score_self_awareness(
    report: Optional[Dict[str, object]],
    *,
    project_id: Optional[str] = None,
    material_knowledge_snapshot: Optional[Dict[str, object]] = None,
) -> Dict[str, object]:
    if not isinstance(report, dict):
        return {}
    meta = report.get("meta")
    if not isinstance(meta, dict):
        meta = {}
        report["meta"] = meta
    _ensure_report_material_usage_metadata(report)
    gate = _normalize_material_utilization_gate_state(
        (
            meta.get("material_utilization_gate")
            if isinstance(meta.get("material_utilization_gate"), dict)
            else {}
        )
    )
    if gate:
        meta["material_utilization_gate"] = gate
    awareness = meta.get("score_self_awareness")
    expected_gate_state = (
        "blocked"
        if bool(gate.get("blocked"))
        else ("warned" if bool(gate.get("warned")) else "normal")
    )
    if isinstance(awareness, dict) and awareness:
        existing_state = str(awareness.get("state") or "").strip().lower()
        stale_gate_state = existing_state not in {"", expected_gate_state}
        stale_block_reason = expected_gate_state != "blocked" and any(
            "资料利用门禁阻断" in str(item or "") for item in (awareness.get("reasons") or [])
        )
        if not stale_gate_state and not stale_block_reason:
            if not meta.get("score_confidence_level"):
                meta["score_confidence_level"] = str(awareness.get("level") or "low")
            return awareness
    knowledge_snapshot = material_knowledge_snapshot
    if knowledge_snapshot is None and project_id:
        try:
            knowledge_snapshot = _build_material_knowledge_profile(project_id)
        except Exception:
            knowledge_snapshot = None
    awareness = _build_score_self_awareness(
        report,
        material_knowledge_snapshot=knowledge_snapshot,
    )
    meta["score_self_awareness"] = awareness
    meta["score_confidence_level"] = str(
        awareness.get("level") or meta.get("score_confidence_level") or "low"
    )
    return awareness


def _fuse_rule_and_llm_scores(
    *,
    rule_total: float,
    llm_total_raw: float,
    project: Dict[str, object],
    report: Optional[Dict[str, object]] = None,
) -> tuple[float, float, Dict[str, object]]:
    rule = _clip_score(rule_total)
    llm_raw = _clip_score(llm_total_raw)
    rule_w, llm_w, delta_cap = _resolve_score_blend_weights(project)
    coverage_meta: Dict[str, object] = {}
    if isinstance(report, dict):
        coverage_scale, delta_cap_scale, coverage_meta = _resolve_dynamic_blend_adjustment(report)
        llm_w *= coverage_scale
        total = rule_w + llm_w
        if total > 1e-9:
            rule_w /= total
            llm_w /= total
        else:
            rule_w, llm_w = 1.0, 0.0
        delta_cap *= delta_cap_scale
    llm_bounded = _clip_score(max(rule - delta_cap, min(rule + delta_cap, llm_raw)))
    fused = _clip_score(rule * rule_w + llm_bounded * llm_w)
    blend_info = {
        "rule_weight": round(rule_w, 4),
        "llm_weight": round(llm_w, 4),
        "llm_delta_cap": round(delta_cap, 2),
        "dynamic_coverage": coverage_meta,
    }
    return round(fused, 2), round(llm_bounded, 2), blend_info


def _apply_prediction_to_report_with_model(
    report: Dict[str, object],
    *,
    submission_like: Dict[str, object],
    project: Dict[str, object],
    model_override: Optional[Dict[str, object]] = None,
) -> Optional[str]:
    model = (
        model_override if isinstance(model_override, dict) else _select_calibrator_model(project)
    )
    if not model:
        report["pred_total_score"] = None
        report["llm_total_score"] = None
        report["pred_confidence"] = None
        report["pred_dim_scores"] = None
        report["score_blend"] = None
        # `total_score` is the primary score used by UI/sorting.
        report["total_score"] = float(
            report.get("rule_total_score", report.get("total_score", 0.0))
        )
        submission_like["total_score"] = float(report.get("total_score", 0.0))
        return None
    artifact = model.get("model_artifact") or model.get("artifact") or {}
    if not isinstance(artifact, dict):
        report["pred_total_score"] = None
        report["llm_total_score"] = None
        report["pred_confidence"] = None
        report["pred_dim_scores"] = None
        report["score_blend"] = None
        report["total_score"] = float(
            report.get("rule_total_score", report.get("total_score", 0.0))
        )
        submission_like["total_score"] = float(report.get("total_score", 0.0))
        return None
    row = build_feature_row(report, submission=submission_like)
    try:
        pred, conf = predict_with_model(artifact, row.get("x_features") or {})
    except Exception as e:
        # 预测模型不应影响主流程可用性；失败时保留 rule 分并显式记录错误。
        report["pred_total_score"] = None
        report["llm_total_score"] = None
        report["pred_confidence"] = None
        report["pred_dim_scores"] = None
        report["score_blend"] = None
        report["total_score"] = float(
            report.get("rule_total_score", report.get("total_score", 0.0))
        )
        submission_like["total_score"] = float(report.get("total_score", 0.0))
        report.setdefault("meta", {})
        report["meta"]["calibrator_version"] = model.get("calibrator_version")
        report["meta"]["calibrator_error"] = f"{type(e).__name__}: {e}"
        return str(model.get("calibrator_version") or "")

    rule_total = float(report.get("rule_total_score", report.get("total_score", 0.0)))
    is_five_scale_prior = _is_five_scale_global_prior_model(model)
    is_hundred_scale_prior = _is_hundred_scale_global_prior_model(model)
    if is_five_scale_prior and not _should_apply_five_scale_global_prior(
        submission_like,
        project=project,
    ):
        report["pred_total_score"] = None
        report["llm_total_score"] = None
        report["pred_confidence"] = None
        report["pred_dim_scores"] = None
        report["score_blend"] = None
        report["total_score"] = float(rule_total)
        submission_like["total_score"] = float(rule_total)
        return str(model.get("calibrator_version") or "")
    if is_hundred_scale_prior and not _should_apply_hundred_scale_global_prior(
        submission_like,
        project=project,
    ):
        report["pred_total_score"] = None
        report["llm_total_score"] = None
        report["pred_confidence"] = None
        report["pred_dim_scores"] = None
        report["score_blend"] = None
        report["total_score"] = float(rule_total)
        submission_like["total_score"] = float(rule_total)
        return str(model.get("calibrator_version") or "")
    if is_five_scale_prior or is_hundred_scale_prior:
        fused_total = _clip_score(float(pred))
        llm_total = None
        prior_kind = (
            "five_scale_global_prior" if is_five_scale_prior else "hundred_scale_global_prior"
        )
        blend_info = {
            "mode": "synthetic_prior",
            "prior_kind": prior_kind,
            "bias": round(float((artifact or {}).get("bias", 0.0)), 4),
            "sample_count": int(
                _to_float_or_none(((artifact or {}).get("metrics") or {}).get("sample_count")) or 0
            ),
        }
    else:
        fused_total, llm_total, blend_info = _fuse_rule_and_llm_scores(
            rule_total=rule_total,
            llm_total_raw=float(pred),
            project=project,
            report=report,
        )
    sigma = float(_to_float_or_none(conf.get("sigma")) or 0.0)
    ci95_delta = 1.96 * sigma if sigma > 0 else 0.0
    ci95_lower = _clip_score(fused_total - ci95_delta)
    ci95_upper = _clip_score(fused_total + ci95_delta)
    report["pred_total_score"] = fused_total
    report["llm_total_score"] = llm_total
    report["pred_confidence"] = {
        **conf,
        "raw_llm_score": float(pred),
        "bounded_llm_score": llm_total,
        "fused_ci95_lower": round(ci95_lower, 2),
        "fused_ci95_upper": round(ci95_upper, 2),
        "fused_sigma": round(sigma, 2),
    }
    report["score_blend"] = blend_info
    report["pred_dim_scores"] = None
    report["total_score"] = float(fused_total)
    submission_like["total_score"] = float(fused_total)
    report.setdefault("meta", {})
    report["meta"]["calibrator_version"] = model.get("calibrator_version")
    return str(model.get("calibrator_version") or "")


def _apply_prediction_to_report(
    report: Dict[str, object],
    *,
    submission_like: Dict[str, object],
    project: Dict[str, object],
) -> Optional[str]:
    return _apply_prediction_to_report_with_model(
        report,
        submission_like=submission_like,
        project=project,
    )


def _to_float_or_none(value: Any) -> Optional[float]:
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _load_evidence_units_safe() -> List[Dict[str, object]]:
    try:
        rows = load_evidence_units()
    except StorageDataError as exc:
        logger.warning(
            "evidence_units_storage_fallback path=%s code=%s detail=%s",
            exc.path,
            exc.code,
            exc.detail,
        )
        return []
    return [row for row in rows if isinstance(row, dict)]


def _load_calibration_models_safe() -> List[Dict[str, object]]:
    try:
        rows = load_calibration_models()
    except StorageDataError as exc:
        logger.warning(
            "calibration_models_storage_fallback path=%s code=%s detail=%s",
            exc.path,
            exc.code,
            exc.detail,
        )
        return []
    return [row for row in rows if isinstance(row, dict)]


def _resolve_submission_score_fields(
    submission: Dict[str, object],
    *,
    allow_pred_score: bool = True,
    score_scale_max: int = DEFAULT_SCORE_SCALE_MAX,
) -> Dict[str, object]:
    report = submission.get("report")
    pred_total = None
    rule_total = None
    if isinstance(report, dict):
        pred_total = _to_float_or_none(report.get("pred_total_score"))
        if not allow_pred_score:
            pred_total = None
        rule_total = _to_float_or_none(report.get("rule_total_score"))
        if rule_total is None:
            rule_total = _to_float_or_none(report.get("total_score"))
    fallback_total = _to_float_or_none(submission.get("total_score"))
    if rule_total is None:
        rule_total = fallback_total
    primary_total = pred_total if pred_total is not None else rule_total
    if primary_total is None:
        primary_total = fallback_total if fallback_total is not None else 0.0
    total_display = _convert_score_from_100(primary_total, score_scale_max)
    pred_display = _convert_score_from_100(pred_total, score_scale_max)
    rule_display = _convert_score_from_100(rule_total, score_scale_max)
    if total_display is None:
        total_display = 0.0
    return {
        "total_score": float(total_display),
        "pred_total_score": float(pred_display) if pred_display is not None else None,
        "rule_total_score": float(rule_display) if rule_display is not None else None,
        "score_source": "pred" if pred_total is not None else "rule",
    }


