    markdown = _render_project_analysis_bundle_markdown(
        project=project,
        factors_payload=factors_payload,
        evaluation_payload=eval_payload,
    )
    return AnalysisBundleResponse(
        project_id=project_id,
        markdown=markdown,
        generated_at=_now_iso(),
    )


