@router.post(
    "/score",
    response_model=ScoreReport,
    tags=["评分"],
    responses={**RESPONSES_401, **RESPONSES_422},
)
def score_endpoint(
    payload: ScoreRequest,
    api_key: Optional[str] = Depends(verify_api_key),
) -> ScoreReport:
    """
    对施组文本进行评分。

    接收施工组织设计文本内容，返回完整的评分报告，包括：
    - 总分及各维度得分
    - 命中的关键词证据
    - 扣分项及原因
    - 改进建议

    支持评分结果缓存，相同文本重复评分时直接返回缓存结果。

    **需要 API Key 认证**
    """
    config = load_config()

    # 尝试从缓存获取结果
    cached_result = get_cached_score(payload.text)
    if cached_result is not None:
        # 记录评分指标（命中缓存）
        record_score(cached_result.get("total_score", 0.0))
        return ScoreReport(**cached_result)

    # 缓存未命中，执行评分
    result = score_text(payload.text, config.rubric, config.lexicon)
    result_dict = result.model_dump()

    # 缓存评分结果
    cache_score_result(payload.text, result_dict)

    # 记录评分指标
    record_score(result.total_score)
    return result


@router.post(
    "/projects",
    response_model=ProjectRecord,
    tags=["项目管理"],
    responses={**RESPONSES_401, **RESPONSES_422},
)
def create_project(
    payload: ProjectCreate,
    api_key: Optional[str] = Depends(verify_api_key),
) -> ProjectRecord:
    """
    创建新项目。

    项目是施组评分的容器，可以包含多个施组文档和材料文件。
    创建项目后，可以上传材料和施组进行评分。

    **需要 API Key 认证**
    """
    ensure_data_dirs()
    projects = load_projects()
    changed = False
    for p in projects:
        if isinstance(p, dict):
            changed = _ensure_project_v2_fields(p) or changed
    if changed:
        save_projects(projects)
    clean_name = _normalize_project_name_key(payload.name)
    if not clean_name:
        raise HTTPException(status_code=422, detail="项目名称不能为空")
    if _find_project_by_name(projects, clean_name) is not None:
        raise HTTPException(status_code=422, detail="项目名称已存在，请更换名称")
    record = _build_project_record(clean_name, payload.meta or {})
    projects.append(record)
    save_projects(projects)
    return ProjectRecord(**record)


