def _structured_signal_material_keywords(material_type: str) -> set[str]:
    mat_type = _normalize_material_type(material_type)
    keywords: set[str] = set()
    for mapping in _STRUCTURED_SIGNAL_HINT_MAPS.get(mat_type, []):
        for label, hints in mapping.items():
            label_text = str(label or "").strip().lower()
            if label_text:
                keywords.add(label_text)
            for hint in hints:
                hint_text = str(hint or "").strip().lower()
                if hint_text:
                    keywords.add(hint_text)
    return keywords


def _structured_signal_quality_score(term: object, *, material_type: str = "") -> float:
    text_value = str(term or "").strip()
    if not text_value:
        return -1.0
    key = text_value.lower()
    if key in STRUCTURED_SIGNAL_STOP_WORDS or key in STRUCTURED_SIGNAL_GENERIC_TERMS:
        return -1.0
    if len(key) <= 1:
        return -1.0
    if re.fullmatch(r"[-_./\\]+", key):
        return -1.0
    if re.fullmatch(r"(?:\d+|\d+\.\d+)", key):
        return -1.0
    if re.fullmatch(r"[a-z]{1,2}\d*", key) and key not in {"bim", "iot", "ocr", "cad"}:
        return -0.6
    if re.fullmatch(r"(?:sheet|page|layer|block)\d*", key):
        return -0.8

    score = 0.0
    if re.search(r"[\u4e00-\u9fff]", text_value):
        score += 0.95
    if re.search(r"[A-Za-z]", text_value):
        score += 0.2
    if re.search(r"\d", text_value):
        score += 0.18
    if any(char in text_value for char in "/、-（）()"):
        score += 0.12
    if 2 <= len(text_value) <= 18:
        score += 0.28
    elif len(text_value) <= 30:
        score += 0.12
    else:
        score -= 0.08
    if any(unit in key for unit in ["mm", "cm", "dn", "kw", "kva", "m³", "㎡", "c30", "c35"]):
        score += 0.2
    if any(noise in key for noise in ("文件", "资料", "文本", "内容", "说明")):
        score -= 0.28

    material_keywords = _structured_signal_material_keywords(material_type)
    if material_keywords and any(hint in key or key in hint for hint in material_keywords):
        score += 0.72
    return round(score, 4)


def _filter_structured_signal_terms(
    raw_items: List[object],
    *,
    limit: int = 16,
    material_type: str = "",
) -> List[str]:
    out: List[str] = []
    kept_scores: List[float] = []
    seen: set[str] = set()
    for item in raw_items:
        text_value = str(item or "").strip()
        if not text_value:
            continue
        key = text_value.lower()
        score = _structured_signal_quality_score(text_value, material_type=material_type)
        if score < 0.72:
            continue
        if key in seen:
            continue
        replaced = False
        for idx, kept in enumerate(list(out)):
            kept_key = kept.lower()
            kept_score = kept_scores[idx]
            if key in kept_key and len(kept_key) - len(key) >= 2 and kept_score >= score:
                replaced = True
                break
            if kept_key in key and len(key) - len(kept_key) >= 2 and score >= kept_score:
                seen.discard(kept_key)
                out[idx] = text_value
                kept_scores[idx] = score
                seen.add(key)
                replaced = True
                break
        if replaced:
            if len(out) >= max(1, int(limit)):
                return out[: max(1, int(limit))]
            continue
        seen.add(key)
        out.append(text_value)
        kept_scores.append(score)
        if len(out) >= max(1, int(limit)):
            break
    return out


STRUCTURED_PAGE_TYPE_LABELS = {
    "cover": "封面",
    "toc": "目录",
    "chapter": "章节",
    "scoring_rules": "评分规则",
    "table": "约束表格",
    "attachment": "附件",
    "drawing_like": "图纸页",
    "narrative": "正文",
}


def _collect_structured_outline_terms(
    structured_summary: object,
    *,
    material_type: str = "",
    limit: int = 12,
) -> List[str]:
    summary = structured_summary if isinstance(structured_summary, dict) else {}
    raw_terms: List[object] = []
    raw_terms.extend(_to_text_items(summary.get("section_title_paths"), max_items=12))
    for row in summary.get("document_outline") or []:
        if not isinstance(row, dict):
            continue
        raw_terms.append(row.get("section_title"))
        raw_terms.extend(_to_text_items(row.get("section_path"), max_items=4))
        page_type = str(row.get("page_type") or "").strip().lower()
        if page_type in {"scoring_rules", "table", "drawing_like"}:
            raw_terms.append(STRUCTURED_PAGE_TYPE_LABELS.get(page_type, page_type))
    for row in summary.get("page_type_summary") or []:
        if not isinstance(row, dict):
            continue
        page_type = str(row.get("page_type") or "").strip().lower()
        if page_type in {"scoring_rules", "table", "drawing_like"}:
            raw_terms.append(STRUCTURED_PAGE_TYPE_LABELS.get(page_type, page_type))
    return _filter_structured_signal_terms(
        raw_terms,
        limit=limit,
        material_type=material_type,
    )


def _collect_structured_table_terms(
    structured_summary: object,
    *,
    material_type: str = "",
    limit: int = 12,
) -> List[str]:
    summary = structured_summary if isinstance(structured_summary, dict) else {}
    raw_terms: List[object] = []
    for row in summary.get("table_constraint_rows") or []:
        if not isinstance(row, dict):
            continue
        raw_terms.append(row.get("label"))
        value_text = str(row.get("value") or "").strip()
        if value_text:
            raw_terms.extend(_extract_terms(value_text, max_terms=6))
    if summary.get("scoring_rule_pages"):
        raw_terms.append("评分规则")
    return _filter_structured_signal_terms(
        raw_terms,
        limit=limit,
        material_type=material_type,
    )


def _collect_structured_anchor_numeric_terms(
    structured_summary: object,
    *,
    limit: int = 10,
) -> List[str]:
    summary = structured_summary if isinstance(structured_summary, dict) else {}
    numeric_terms: List[str] = []
    numeric_terms.extend(
        _merge_numeric_values(
            summary.get("top_numeric_terms"),
            summary.get("table_numeric_constraints"),
            limit=limit * 2,
        )
    )
    for row in summary.get("table_constraint_rows") or []:
        if not isinstance(row, dict):
            continue
        numeric_terms.extend(
            _merge_numeric_values(
                row.get("numbers"),
                row.get("value"),
                limit=6,
            )
        )
    return _limit_unique_numeric_tokens(numeric_terms, limit=limit)


def _collect_keyword_labels(
    text: str,
    mapping: Dict[str, List[str]],
    *,
    limit: int = 8,
) -> List[str]:
    corpus = str(text or "").lower()
    scored: List[tuple[str, int]] = []
    for label, hints in mapping.items():
        score = sum(
            corpus.count(str(hint or "").lower()) for hint in hints if str(hint or "").strip()
        )
        if score > 0:
            scored.append((label, score))
    scored.sort(key=lambda item: (-item[1], item[0]))
    return [label for label, _ in scored[: max(1, int(limit))]]


def _parse_summary_list_line(text: str, prefix: str, *, limit: int = 12) -> List[str]:
    match = re.search(rf"{re.escape(prefix)}:\s*(.+)", str(text or ""))
    if not match:
        return []
    items = [item.strip() for item in re.split(r"[、,，]", match.group(1)) if item.strip()]
    return _limit_unique_texts(items, limit=limit)


def _parse_summary_count_line(text: str, prefix: str, *, limit: int = 12) -> Dict[str, int]:
    match = re.search(rf"{re.escape(prefix)}:\s*(.+)", str(text or ""))
    if not match:
        return {}
    out: Dict[str, int] = {}
    for chunk in re.split(r"[、,，]", match.group(1)):
        if ":" not in chunk:
            continue
        key, value = chunk.split(":", 1)
        label = key.strip()
        numeric = _to_float_or_none(value.strip())
        if not label or numeric is None:
            continue
        out[label] = int(round(float(numeric)))
        if len(out) >= max(1, int(limit)):
            break
    return out


def _classify_numeric_anchor_category(
    *,
    terms: Optional[List[object]] = None,
    material_type: object = "",
    dimension_id: object = "",
    label: object = "",
) -> str:
    corpus_parts: List[str] = []
    for item in terms or []:
        text = str(item or "").strip().lower()
        if text:
            corpus_parts.append(text)
    label_text = str(label or "").strip().lower()
    if label_text:
        corpus_parts.append(label_text)
    material_key = _normalize_material_type(material_type)
    dim_key = str(dimension_id or "").strip()
    corpus = " ".join(corpus_parts)
    scores: Dict[str, int] = {key: 0 for key in NUMERIC_ANCHOR_CATEGORY_HINTS}
    for category, hints in NUMERIC_ANCHOR_CATEGORY_HINTS.items():
        for hint in hints:
            if hint and hint.lower() in corpus:
                scores[category] += 1

    if dim_key == "09":
        scores["duration"] += 2
    if dim_key in {"06", "13", "14"}:
        scores["specification"] += 1
    if material_key == "boq":
        scores["quantity"] += 2
    elif material_key == "drawing":
        scores["specification"] += 2
    elif material_key == "site_photo":
        scores["threshold"] += 1

    top_category, top_score = sorted(scores.items(), key=lambda item: (-item[1], item[0]))[0]
    if top_score > 0:
        return top_category
    if dim_key == "09":
        return "duration"
    if material_key == "boq":
        return "quantity"
    if material_key == "drawing":
        return "specification"
    return "threshold"


def _append_numeric_anchor_bucket(
    buckets: Dict[str, List[str]],
    category: str,
    token: object,
) -> None:
    clean_category = str(category or "").strip()
    clean_token = _normalize_numeric_token(token)
    if not clean_category or not clean_token:
        return
    bucket = buckets.setdefault(clean_category, [])
    if clean_token not in bucket:
        bucket.append(clean_token)


def _build_numeric_anchor_category_summary(
    buckets: Dict[str, List[str]],
) -> List[str]:
    summary: List[str] = []
    for category in ("duration", "quantity", "specification", "threshold"):
        tokens = [str(x) for x in (buckets.get(category) or []) if str(x).strip()]
        if not tokens:
            continue
        label = NUMERIC_ANCHOR_CATEGORY_LABELS.get(category, category)
        preview = "、".join(tokens[:4])
        if len(tokens) > 4:
            preview += " 等"
        summary.append(f"{label}：{preview}")
    return summary[:8]


def _build_cross_type_material_consensus(
    by_type_rows: List[Dict[str, object]],
) -> Dict[str, object]:
    if not isinstance(by_type_rows, list):
        return {}
    term_type_sets: Dict[str, set[str]] = {}
    numeric_type_sets: Dict[str, set[str]] = {}
    numeric_buckets: Dict[str, List[str]] = {key: [] for key in NUMERIC_ANCHOR_CATEGORY_LABELS}
    focused_dimensions: List[str] = []
    source_types: List[str] = []

    for row in by_type_rows:
        if not isinstance(row, dict):
            continue
        mat_type = _normalize_material_type(row.get("material_type"))
        if not mat_type:
            continue
        if int(_to_float_or_none(row.get("parsed_ok_files")) or 0) <= 0:
            continue
        if mat_type not in source_types:
            source_types.append(mat_type)
        row_quality = float(_clip_score01(row.get("structured_quality_score")) or 0.0)
        if row_quality < 0.25:
            continue
        term_candidates = (
            _to_text_items(row.get("structured_terms_preview"), max_items=8)
            + _to_text_items(row.get("section_titles_preview"), max_items=4)
            + _to_text_items(row.get("outline_terms_preview"), max_items=4)
            + _to_text_items(row.get("table_constraint_terms_preview"), max_items=4)
            + _to_text_items(row.get("scoring_point_terms_preview"), max_items=4)
            + _to_text_items(row.get("mandatory_clause_terms_preview"), max_items=3)
        )
        filtered_terms = _filter_structured_signal_terms(
            term_candidates,
            limit=10,
            material_type=mat_type,
        )
        for term in filtered_terms:
            term_type_sets.setdefault(str(term), set()).add(mat_type)

        raw_numeric_summary = row.get("numeric_category_summary")
        numeric_summary_items = raw_numeric_summary if isinstance(raw_numeric_summary, list) else []
        for item in numeric_summary_items:
            match = re.match(r"([^：:]+)[：:]\s*(.+)", str(item or "").strip())
            if not match:
                continue
            label = match.group(1).strip()
            category = next(
                (
                    key
                    for key, value in NUMERIC_ANCHOR_CATEGORY_LABELS.items()
                    if str(value) == label
                ),
                "",
            )
            if not category:
                continue
            for token in re.split(r"[、,，\s]+", match.group(2)):
                normalized = _normalize_numeric_token(token.replace("等", ""))
                if not normalized:
                    continue
                if normalized not in numeric_buckets[category]:
                    numeric_buckets[category].append(normalized)
                numeric_type_sets.setdefault(normalized, set()).add(mat_type)

        for dim_id in [
            str(item or "").zfill(2)
            for item in (row.get("focused_dimensions") or [])
            if str(item or "").strip().zfill(2) in DIMENSION_IDS
        ]:
            if dim_id not in focused_dimensions:
                focused_dimensions.append(dim_id)

    consensus_terms = [
        term
        for term, types in sorted(
            term_type_sets.items(),
            key=lambda item: (-len(item[1]), -len(item[0]), item[0]),
        )
        if len(types) >= 2
    ][:10]
    consensus_numeric_buckets: Dict[str, List[str]] = {}
    for category, tokens in numeric_buckets.items():
        kept = [token for token in tokens if len(numeric_type_sets.get(token) or set()) >= 2][:6]
        if kept:
            consensus_numeric_buckets[category] = kept
    consensus_numeric_category_summary = _build_numeric_anchor_category_summary(
        consensus_numeric_buckets
    )
    strong_type_count = len(
        [
            row
            for row in by_type_rows
            if isinstance(row, dict)
            and float(_clip_score01(row.get("structured_quality_score")) or 0.0) >= 0.45
        ]
    )
    consensus_score = round(
        min(
            1.0,
            min(0.36, len(source_types) * 0.12)
            + min(0.24, len(consensus_terms) * 0.04)
            + min(
                0.28,
                sum(len(tokens) for tokens in consensus_numeric_buckets.values()) * 0.05,
            )
            + min(0.12, strong_type_count * 0.03),
        ),
        4,
    )
    return {
        "source_types": source_types[:6],
        "source_type_count": len(source_types),
        "focused_dimensions": focused_dimensions[:8],
        "consensus_terms": consensus_terms,
        "consensus_numeric_buckets": consensus_numeric_buckets,
        "consensus_numeric_category_summary": consensus_numeric_category_summary,
        "consensus_score": consensus_score,
    }


def _clip_score01(value: object) -> float:
    numeric = _to_float_or_none(value)
    if numeric is None:
        return 0.0
    return max(0.0, min(1.0, float(numeric)))


def _normalize_ocr_text_block(text: object) -> str:
    raw = unicodedata.normalize("NFKC", str(text or "")).replace("\x0c", " ")
    normalized_lines: List[str] = []
    seen: set[str] = set()
    for raw_line in raw.splitlines():
        line = str(raw_line or "").strip()
        if not line:
            continue
        line = re.sub(r"(?<=[\u4e00-\u9fff])\s+(?=[\u4e00-\u9fff])", "", line)
        line = re.sub(r"(?<=第)\s+(?=[一二三四五六七八九十百零两0-9])", "", line)
        line = re.sub(r"(?<=[一二三四五六七八九十百零两0-9])\s+(?=章)", "", line)
        line = re.sub(r"(?<=\d)\s*[.．]\s*(?=\d)", ".", line)
        line = re.sub(r"\s+", " ", line)
        key = line.lower()
        if len(line) < 2 or key in seen:
            continue
        seen.add(key)
        normalized_lines.append(line)
    return "\n".join(normalized_lines).strip()


def _score_ocr_text_candidate(
    text: object,
    *,
    context_tokens: Optional[List[str]] = None,
) -> float:
    normalized = _normalize_ocr_text_block(text)
    if not normalized:
        return 0.0
    cjk_count = len(re.findall(r"[\u4e00-\u9fff]", normalized))
    digit_count = len(re.findall(r"\d", normalized))
    alpha_count = len(re.findall(r"[A-Za-z]", normalized))
    lines = [line for line in normalized.splitlines() if line.strip()]
    line_count = len(lines)
    text_len = len(normalized)
    keyword_hits = 0
    for token in context_tokens or []:
        key = str(token or "").strip().lower()
        if key and key in normalized.lower():
            keyword_hits += 1
    score = 0.0
    score += min(3.2, cjk_count / 45.0)
    score += min(1.3, digit_count / 16.0)
    score += min(0.8, alpha_count / 40.0)
    score += min(1.6, line_count * 0.18)
    score += min(1.2, text_len / 420.0)
    score += min(1.8, keyword_hits * 0.32)
    if re.search(r"(?:第[一二三四五六七八九十百零两0-9]+章|[0-9]+\.[0-9]+)", normalized):
        score += 0.45
    if re.search(r"[^\u4e00-\u9fffA-Za-z0-9\s:：、,，.。/()（）-]", normalized):
        score -= 0.2
    return round(max(0.0, score), 4)


def _extract_best_ocr_text_from_image(
    img: object,
    *,
    context_tokens: Optional[List[str]] = None,
) -> Dict[str, object]:
    if Image is None or pytesseract is None or img is None:
        return {"text": "", "mode": "", "score": 0.0, "attempts": 0}

    base = img.convert("RGB") if hasattr(img, "convert") else img
    gray = ImageOps.grayscale(base) if ImageOps is not None else base.convert("L")
    variants: List[tuple[str, object]] = [("raw_rgb", base), ("gray", gray)]
    width = max(1, int(getattr(gray, "width", 1)))
    height = max(1, int(getattr(gray, "height", 1)))
    if width < 2600 and height < 2600:
        variants.append(("gray_2x", gray.resize((width * 2, height * 2))))
    if ImageOps is not None:
        variants.append(("autocontrast", ImageOps.autocontrast(gray)))
    variants.append(("binary_180", gray.point(lambda p: 255 if int(p) > 180 else 0).convert("L")))

    candidates: List[Dict[str, object]] = []
    attempts = 0
    for variant_name, variant_img in variants:
        for psm in ("6", "11"):
            attempts += 1
            try:
                raw_text = str(
                    pytesseract.image_to_string(
                        variant_img,
                        lang="chi_sim+eng",
                        config=f"--psm {psm}",
                    )
                    or ""
                )
            except Exception:
                raw_text = ""
            normalized = _normalize_ocr_text_block(raw_text)
            if not normalized:
                continue
            candidates.append(
                {
                    "text": normalized,
                    "mode": f"{variant_name}:psm{psm}",
                    "score": _score_ocr_text_candidate(
                        normalized,
                        context_tokens=context_tokens,
                    ),
                }
            )

    if not candidates:
        return {"text": "", "mode": "", "score": 0.0, "attempts": attempts}

    candidates.sort(
        key=lambda item: (
            -float(_to_float_or_none(item.get("score")) or 0.0),
            -len(str(item.get("text") or "")),
        )
    )
    best = candidates[0]
    merged_lines: List[str] = []
    seen_lines: set[str] = set()
    for candidate in candidates[:2]:
        for raw_line in str(candidate.get("text") or "").splitlines():
            line = str(raw_line or "").strip()
            if not line:
                continue
            key = line.lower()
            if key in seen_lines:
                continue
            seen_lines.add(key)
            merged_lines.append(line)
    best["text"] = "\n".join(merged_lines).strip() or str(best.get("text") or "")
    best["attempts"] = attempts
    return best


def _extract_tender_qa_section_titles(text: str, *, limit: int = 10) -> List[str]:
    titles: List[str] = []
    seen: set[str] = set()
    patterns = (
        r"^(?:第\s*[一二三四五六七八九十百零两0-9]+\s*章)\s*[:：、.)）.-]?\s*([^\n]{2,40})$",
        r"^(?:[0-9]{1,2}(?:\s*[.．]\s*[0-9]{1,2}){0,2})\s*[、.)）-]?\s*([^\n]{2,40})$",
        r"^(?:[一二三四五六七八九十百零两]+\s*[、.)）-])\s*([^\n]{2,40})$",
    )
    for raw_line in str(text or "").splitlines():
        line = _normalize_ocr_text_block(str(raw_line or "").strip(" \t-—_:：.。"))
        if not line or len(line) > 42:
            continue
        if "[page" in line.lower():
            continue
        candidate = ""
        for pattern in patterns:
            match = re.match(pattern, line)
            if match:
                candidate = str(match.group(1) or "").strip()
                break
        if not candidate:
            lower = line.lower()
            if any(
                token in lower
                for token in (
                    "方案",
                    "措施",
                    "管理",
                    "计划",
                    "要求",
                    "标准",
                    "施工",
                    "部署",
                    "组织",
                )
            ):
                candidate = line
        candidate = re.sub(r"\s+", " ", candidate).strip()
        if not candidate or len(candidate) < 2:
            continue
        key = candidate.lower()
        if key in seen:
            continue
        seen.add(key)
        titles.append(candidate[:36])
        if len(titles) >= max(1, int(limit)):
            break
    return titles


def _extract_tender_qa_scoring_point_terms(text: str, *, limit: int = 12) -> List[str]:
    out: List[str] = []
    seen: set[str] = set()
    score_lines: List[str] = []
    for raw_line in str(text or "").splitlines():
        line = re.sub(r"\s+", " ", str(raw_line or "").strip())
        if not line:
            continue
        lower = line.lower()
        if any(
            token in lower for token in ("评分", "评审", "打分", "得分", "评标", "加分", "扣分")
        ):
            score_lines.append(line[:80])
    source_terms = _extract_terms("\n".join(score_lines), max_terms=36)
    for item in source_terms:
        token = str(item or "").strip()
        if not token:
            continue
        key = token.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(token)
        if len(out) >= max(1, int(limit)):
            break
    return out


def _extract_tender_qa_mandatory_clauses(text: str, *, limit: int = 8) -> List[str]:
    clauses: List[str] = []
    seen: set[str] = set()
    for raw_line in str(text or "").splitlines():
        line = re.sub(r"\s+", " ", str(raw_line or "").strip())
        if not line:
            continue
        lower = line.lower()
        if not any(token in lower for token in ("必须", "不得", "严禁", "应", "需", "须", "否决")):
            continue
        compact = line[:48]
        key = compact.lower()
        if key in seen:
            continue
        seen.add(key)
        clauses.append(compact)
        if len(clauses) >= max(1, int(limit)):
            break
    return clauses


def _infer_focus_dimensions_from_tender_terms(
    raw_items: List[object], *, limit: int = 6
) -> List[str]:
    corpus = " ".join(str(item or "") for item in raw_items if str(item or "").strip()).lower()
    scored: List[tuple[str, int]] = []
    for dim_id in DIMENSION_IDS:
        score = 0
        for kw in DIMENSION_RAG_KEYWORDS.get(dim_id, [])[:8]:
            token = str(kw or "").strip().lower()
            if token and token in corpus:
                score += 1
        if score > 0:
            scored.append((dim_id, score))
    scored.sort(key=lambda item: (-item[1], item[0]))
    return [dim_id for dim_id, _ in scored[: max(1, int(limit))]]


def _build_tender_qa_structured_summary(
    content: bytes,
    filename: str,
    *,
    parsed_text: str = "",
) -> Dict[str, object]:
    text = str(parsed_text or "")
    corpus = f"{filename}\n{text}"
    constraint_tags = _collect_keyword_labels(corpus, TENDER_QA_CONSTRAINT_HINTS, limit=8)
    section_titles = _extract_tender_qa_section_titles(text, limit=10)
    scoring_point_terms = _extract_tender_qa_scoring_point_terms(text, limit=12)
    mandatory_clause_terms = _extract_tender_qa_mandatory_clauses(text, limit=8)
    text_terms = _filter_structured_signal_terms(
        _extract_terms(corpus, max_terms=24),
        limit=18,
        material_type="tender_qa",
    )
    top_numeric_terms = _limit_unique_numeric_tokens(
        _extract_numeric_terms(text, max_terms=16),
        limit=10,
    )
    focused_dimensions = ["01", "08", "09"]
    if "招标范围/界面" in constraint_tags:
        focused_dimensions.extend(["01", "12"])
    if "答疑/补遗/澄清" in constraint_tags:
        focused_dimensions.extend(["01", "14"])
    if "工期/里程碑" in constraint_tags:
        focused_dimensions.append("09")
    if "质量目标/验收标准" in constraint_tags:
        focused_dimensions.extend(["08", "16"])
    if "安全文明/绿色" in constraint_tags:
        focused_dimensions.extend(["02", "03"])
    if "信息化/BIM" in constraint_tags:
        focused_dimensions.extend(["05", "14"])
    if "危大工程/专项方案" in constraint_tags:
        focused_dimensions.extend(["07", "10"])
    if "评审办法/评分点" in constraint_tags:
        focused_dimensions.extend(["01", "16"])
    if "材料设备/甲供界面" in constraint_tags:
        focused_dimensions.extend(["04", "13", "15"])
    focused_dimensions.extend(
        _infer_focus_dimensions_from_tender_terms(
            section_titles + scoring_point_terms + mandatory_clause_terms,
            limit=6,
        )
    )
    structured_terms = _filter_structured_signal_terms(
        constraint_tags
        + section_titles
        + scoring_point_terms
        + mandatory_clause_terms
        + text_terms,
        limit=24,
        material_type="tender_qa",
    )
    constraint_density = round(
        (
            float(len(structured_terms) + len(top_numeric_terms))
            / max(1.0, float(max(1, len(text.strip())) / 180.0))
        ),
        4,
    )
    structured_quality_score = round(
        min(
            1.0,
            _clip_score01(constraint_density / 10.0) * 0.35
            + min(0.25, len(constraint_tags) * 0.03)
            + min(0.12, len(section_titles) * 0.02)
            + min(0.14, len(scoring_point_terms) * 0.025)
            + min(0.14, len(mandatory_clause_terms) * 0.035),
        ),
        4,
    )
    return {
        "filename": filename,
        "detected_format": Path(filename).suffix.lower().lstrip("."),
        "bytes": len(content or b""),
        "constraint_tags": constraint_tags,
        "section_titles": section_titles,
        "scoring_point_terms": scoring_point_terms,
        "mandatory_clause_terms": mandatory_clause_terms,
        "structured_terms": structured_terms,
        "top_numeric_terms": top_numeric_terms,
        "focused_dimensions": _limit_unique_texts(focused_dimensions, limit=10),
        "constraint_density": constraint_density,
        "structured_quality_score": structured_quality_score,
    }


def _finalize_boq_structured_summary(
    summary: Dict[str, object],
    *,
    parsed_text: str,
) -> Dict[str, object]:
    structured_terms: List[object] = []
    numeric_terms: List[object] = []
    column_labels = {
        "code": "项目编码",
        "name": "项目名称",
        "unit": "单位",
        "quantity": "工程量",
        "unit_price": "综合单价",
        "amount": "合价",
    }
    for sheet in summary.get("sheets") if isinstance(summary.get("sheets"), list) else []:
        if not isinstance(sheet, dict):
            continue
        detected_columns = (
            sheet.get("detected_columns") if isinstance(sheet.get("detected_columns"), dict) else {}
        )
        structured_terms.extend(
            column_labels.get(str(key), str(key)) for key in detected_columns.keys()
        )
        structured_terms.extend(_to_text_items(sheet.get("units"), max_items=6))
        for item in (sheet.get("top_items_by_amount") or [])[:6]:
            if not isinstance(item, dict):
                continue
            structured_terms.extend(_extract_terms(str(item.get("name") or ""), max_terms=3))
            numeric_terms.extend([item.get("quantity"), item.get("amount")])
    for label, count in (
        summary.get("keyword_hits") if isinstance(summary.get("keyword_hits"), dict) else {}
    ).items():
        if int(_to_float_or_none(count) or 0) > 0:
            structured_terms.append(label)
    boq_corpus_parts: List[str] = [str(parsed_text or ""), str(summary.get("filename") or "")]
    for sheet in summary.get("sheets") if isinstance(summary.get("sheets"), list) else []:
        if not isinstance(sheet, dict):
            continue
        boq_corpus_parts.append(str(sheet.get("sheet") or ""))
        for item in (sheet.get("top_items_by_amount") or [])[:8]:
            if not isinstance(item, dict):
                continue
            boq_corpus_parts.append(str(item.get("name") or ""))
            boq_corpus_parts.append(str(item.get("code") or ""))
    boq_corpus = "\n".join(part for part in boq_corpus_parts if part)
    cost_structure_tags = _collect_keyword_labels(boq_corpus, BOQ_STRUCTURE_HINTS, limit=6)
    structured_terms.extend(_extract_terms(parsed_text, max_terms=14))
    structured_terms.extend(cost_structure_tags)
    numeric_terms.extend(_extract_numeric_terms(parsed_text, max_terms=12))
    summary["structured_terms"] = _filter_structured_signal_terms(
        structured_terms,
        limit=18,
        material_type="boq",
    )
    summary["top_numeric_terms"] = _limit_unique_numeric_tokens(numeric_terms, limit=10)
    focused_dimensions = ["04", "13", "15"]
    if "安全文明/绿色措施" in cost_structure_tags:
        focused_dimensions.extend(["02", "03"])
    if "人工与班组投入" in cost_structure_tags:
        focused_dimensions.append("11")
    if "措施项目/抢工" in cost_structure_tags:
        focused_dimensions.extend(["09", "15"])
    summary["cost_structure_tags"] = cost_structure_tags
    summary["focused_dimensions"] = _limit_unique_texts(focused_dimensions, limit=6)
    parsed_items = int(_to_float_or_none(summary.get("total_parsed_items")) or 0)
    summary["structured_quality_score"] = round(
        min(
            1.0,
            min(0.34, parsed_items / 20.0)
            + min(0.24, len(cost_structure_tags) * 0.04)
            + min(0.16, len(summary.get("top_numeric_terms") or []) * 0.02)
            + min(0.16, len(summary.get("structured_terms") or []) * 0.015),
        ),
        4,
    )
    return summary


def _build_drawing_structured_summary(
    content: bytes,
    filename: str,
    *,
    parsed_text: str = "",
) -> Dict[str, object]:
    ext = Path(filename).suffix.lower()
    text = str(parsed_text or "")
    lower = text.lower()
    detected_format = ext.lstrip(".")
    if "[dxf解析摘要]" in lower or "检测到ascii dxf内容" in lower:
        detected_format = "dxf"
    elif "[dwg图纸]" in lower or "[dwg预处理]" in lower or ext == ".dwg":
        detected_format = "dwg"
    elif "[pdf_backend:" in lower or ext == ".pdf":
        detected_format = "pdf"
    elif ext in {".png", ".jpg", ".jpeg", ".webp", ".bmp", ".tif", ".tiff"}:
        detected_format = "image"

    top_layers = _parse_summary_list_line(text, "图层", limit=12)
    top_blocks = _parse_summary_list_line(text, "块参照", limit=10)
    layout_tags = _parse_summary_list_line(text, "布局/空间", limit=10)
    dimension_markers = _parse_summary_list_line(text, "标注值", limit=10)
    binary_marker_terms = _parse_summary_list_line(text, "二进制标识提取", limit=12)
    if detected_format == "dwg":
        binary_marker_terms = _merge_unique_text_values(
            binary_marker_terms,
            _extract_dwg_binary_marker_terms(content, limit=14),
            limit=14,
        )
    entity_counts = _parse_summary_count_line(text, "实体统计", limit=12)
    discipline_keywords = _collect_keyword_labels(
        f"{filename}\n{text}",
        DRAWING_DISCIPLINE_HINTS,
        limit=8,
    )
    sheet_type_tags = _collect_keyword_labels(
        f"{filename}\n{text}",
        DRAWING_SHEET_TYPE_HINTS,
        limit=6,
    )
    risk_keywords = _collect_keyword_labels(
        f"{filename}\n{text}",
        DRAWING_RISK_HINTS,
        limit=8,
    )
    file_stem_terms = _filter_structured_signal_terms(
        _extract_terms(Path(filename).stem, max_terms=8),
        limit=6,
        material_type="drawing",
    )
    top_markers = _filter_structured_signal_terms(
        top_layers
        + top_blocks
        + layout_tags
        + binary_marker_terms
        + _extract_terms(text, max_terms=18),
        limit=14,
        material_type="drawing",
    )
    top_numeric_terms = _limit_unique_numeric_tokens(
        _extract_numeric_terms(
            text + "\n" + "\n".join(str(item or "") for item in dimension_markers),
            max_terms=20,
        ),
        limit=12,
    )

    focused_dimensions = ["14", "16"]
    if discipline_keywords:
        focused_dimensions.append("12")
    if sheet_type_tags:
        focused_dimensions.append("01")
    if layout_tags:
        focused_dimensions.extend(["01", "12"])
    if risk_keywords:
        focused_dimensions.extend(["06", "07"])
    if dimension_markers:
        focused_dimensions.extend(["06", "16"])
    if any(tag in {"节点详图/大样", "剖面/立面"} for tag in sheet_type_tags):
        focused_dimensions.extend(["06", "16"])
    if any(tag in {"系统图/原理图", "综合排布/净高复核"} for tag in sheet_type_tags):
        focused_dimensions.extend(["12", "14"])

    structured_terms = _filter_structured_signal_terms(
        discipline_keywords
        + sheet_type_tags
        + risk_keywords
        + file_stem_terms
        + top_layers
        + top_blocks
        + layout_tags
        + binary_marker_terms
        + dimension_markers
        + top_markers,
        limit=20,
        material_type="drawing",
    )
    signal_density = round(
        (
            float(len(structured_terms) + len(top_numeric_terms) + len(entity_counts))
            / max(1.0, float(max(1, len(text.strip())) / 180.0))
        ),
        4,
    )
    structured_quality_score = round(
        min(
            1.0,
            _clip_score01(signal_density / 4.0) * 0.34
            + min(0.2, len(discipline_keywords) * 0.03)
            + min(0.14, len(sheet_type_tags) * 0.03)
            + min(0.16, len(risk_keywords) * 0.03)
            + min(0.08, len(layout_tags) * 0.02)
            + min(0.1, len(top_numeric_terms) * 0.02),
        ),
        4,
    )
    return {
        "filename": filename,
        "detected_format": detected_format,
        "bytes": len(content or b""),
        "entity_counts": entity_counts,
        "top_layers": top_layers,
        "top_blocks": top_blocks,
        "layout_tags": layout_tags,
        "dimension_markers": dimension_markers[:10],
        "binary_marker_terms": binary_marker_terms[:10],
        "discipline_keywords": discipline_keywords,
        "sheet_type_tags": sheet_type_tags,
        "risk_keywords": risk_keywords,
        "top_markers": top_markers[:12],
        "top_numeric_terms": top_numeric_terms,
        "structured_terms": structured_terms,
        "focused_dimensions": _limit_unique_texts(focused_dimensions, limit=6),
        "signal_density": signal_density,
        "structured_quality_score": structured_quality_score,
    }


def _build_site_photo_structured_summary(
    content: bytes,
    filename: str,
    *,
    parsed_text: str = "",
) -> Dict[str, object]:
    ext = Path(filename).suffix.lower().lstrip(".")
    text = str(parsed_text or "")
    corpus = f"{filename}\n{text}"
    safety_scene_tags = _collect_keyword_labels(corpus, SITE_PHOTO_SAFETY_HINTS, limit=8)
    civilization_scene_tags = _collect_keyword_labels(
        corpus, SITE_PHOTO_CIVILIZATION_HINTS, limit=8
    )
    quality_scene_tags = _collect_keyword_labels(corpus, SITE_PHOTO_QUALITY_HINTS, limit=8)
    progress_scene_tags = _collect_keyword_labels(corpus, SITE_PHOTO_PROGRESS_HINTS, limit=6)
    top_numeric_terms = _limit_unique_numeric_tokens(
        _extract_numeric_terms(text, max_terms=12), limit=8
    )
    text_markers = _filter_structured_signal_terms(
        _extract_terms(corpus, max_terms=18),
        limit=12,
        material_type="site_photo",
    )
    focused_dimensions: List[str] = []
    if safety_scene_tags:
        focused_dimensions.extend(["02", "07"])
    if civilization_scene_tags:
        focused_dimensions.append("03")
    if quality_scene_tags:
        focused_dimensions.extend(["08", "16"])
    if progress_scene_tags:
        focused_dimensions.extend(["09", "15"])
    structured_terms = _filter_structured_signal_terms(
        safety_scene_tags
        + civilization_scene_tags
        + quality_scene_tags
        + progress_scene_tags
        + text_markers,
        limit=18,
        material_type="site_photo",
    )
    visual_capability = "metadata_only"
    ocr_mode = ""
    ocr_quality_score = 0.0
    if "[ocr文本提取]" in text.lower():
        visual_capability = "ocr_text"
    match_mode = re.search(r"OCR模式:\s*([^\n]+)", text)
    if match_mode:
        ocr_mode = str(match_mode.group(1) or "").strip()
        visual_capability = "ocr_multistage"
    match_quality = re.search(r"OCR质量分:\s*([0-9]+(?:\.[0-9]+)?)", text)
    if match_quality:
        ocr_quality_score = _clip_score01(
            float(_to_float_or_none(match_quality.group(1)) or 0.0) / 6.0
        )
    if "未安装 pytesseract" in text.lower():
        visual_capability = "ocr_unavailable"
    evidence_density = round(
        (
            float(len(structured_terms) + len(top_numeric_terms))
            / max(1.0, float(max(1, len(text.strip())) / 160.0))
        ),
        4,
    )
    structured_quality_score = round(
        min(
            1.0,
            _clip_score01(evidence_density / 4.0) * 0.32
            + min(0.18, len(safety_scene_tags) * 0.025)
            + min(0.14, len(civilization_scene_tags) * 0.025)
            + min(0.14, len(quality_scene_tags) * 0.025)
            + min(0.12, len(progress_scene_tags) * 0.025)
            + (0.08 if visual_capability in {"ocr_text", "ocr_multistage"} else 0.0)
            + min(0.12, ocr_quality_score * 0.12),
        ),
        4,
    )
    return {
        "filename": filename,
        "detected_format": ext or "image",
        "bytes": len(content or b""),
        "visual_capability": visual_capability,
        "ocr_mode": ocr_mode,
        "ocr_quality_score": round(ocr_quality_score, 4),
        "safety_scene_tags": safety_scene_tags,
        "civilization_scene_tags": civilization_scene_tags,
        "quality_scene_tags": quality_scene_tags,
        "progress_scene_tags": progress_scene_tags,
        "top_numeric_terms": top_numeric_terms,
        "structured_terms": structured_terms,
        "focused_dimensions": _limit_unique_texts(focused_dimensions, limit=6),
        "evidence_density": evidence_density,
        "structured_quality_score": structured_quality_score,
    }


def _build_boq_structured_summary(
    content: bytes,
    filename: str,
    *,
    parsed_text: str = "",
) -> Dict[str, object]:
    summary: Dict[str, object] = {
        "filename": filename,
        "detected_format": Path(filename).suffix.lower().lstrip("."),
    }
    ext = Path(filename).suffix.lower()
    header_alias = {
        "code": ["项目编码", "清单编码", "编码", "子目号"],
        "name": ["项目名称", "项目特征", "工程内容", "名称", "描述"],
        "unit": ["单位"],
        "quantity": ["工程量", "数量"],
        "unit_price": ["综合单价", "单价"],
        "amount": ["合价", "金额", "总价", "小计"],
    }

    def _find_col_map(header_row: List[str]) -> Dict[str, int]:
        out: Dict[str, int] = {}
        for idx, cell in enumerate(header_row):
            s = str(cell or "").strip()
            if not s:
                continue
            for field, aliases in header_alias.items():
                if field in out:
                    continue
                if any(a in s for a in aliases):
                    out[field] = idx
        return out

    def _sheet_struct_from_rows(rows: List[List[object]], sheet_name: str) -> Dict[str, object]:
        header_idx = -1
        col_map: Dict[str, int] = {}
        for i, row in enumerate(rows[:40]):
            str_row = [str(x or "").strip() for x in row]
            maybe = _find_col_map(str_row)
            if len(maybe) >= 2:
                header_idx = i
                col_map = maybe
                break
        if header_idx < 0:
            return {
                "sheet": sheet_name,
                "parsed_items": 0,
                "detected_columns": {},
                "quantity_sum": 0.0,
                "amount_sum": 0.0,
                "top_items_by_amount": [],
            }

        parsed_items = 0
        quantity_sum = 0.0
        amount_sum = 0.0
        unit_set: set[str] = set()
        top_items: List[Dict[str, object]] = []
        for row in rows[header_idx + 1 :]:
            if not row:
                continue

            def _cell(name: str) -> object:
                idx = col_map.get(name)
                if idx is None or idx >= len(row):
                    return ""
                return row[idx]

            code = str(_cell("code") or "").strip()
            name = str(_cell("name") or "").strip()
            if not code and not name:
                continue
            parsed_items += 1
            unit = str(_cell("unit") or "").strip()
            if unit:
                unit_set.add(unit)
            qty = _safe_float_from_cell(_cell("quantity"))
            amt = _safe_float_from_cell(_cell("amount"))
            if qty is not None:
                quantity_sum += qty
            if amt is not None:
                amount_sum += amt
            if name or code:
                top_items.append(
                    {
                        "code": code,
                        "name": name,
                        "unit": unit,
                        "quantity": round(float(qty), 4) if qty is not None else None,
                        "amount": round(float(amt), 2) if amt is not None else None,
                    }
                )
        top_items.sort(key=lambda x: float(x.get("amount") or 0.0), reverse=True)
        return {
            "sheet": sheet_name,
            "parsed_items": parsed_items,
            "detected_columns": col_map,
            "quantity_sum": round(quantity_sum, 4),
            "amount_sum": round(amount_sum, 2),
            "units": sorted(unit_set)[:20],
            "top_items_by_amount": top_items[:10],
        }

    if ext in {".xlsx", ".xls", ".xlsm"}:
        try:
            import openpyxl

            wb = openpyxl.load_workbook(io.BytesIO(content), read_only=True, data_only=True)
            sheet_summaries: List[Dict[str, object]] = []
            total_items = 0
            total_qty = 0.0
            total_amt = 0.0
            for sheet in wb.worksheets:
                rows: List[List[object]] = []
                for idx, row in enumerate(sheet.iter_rows(values_only=True), start=1):
                    rows.append(list(row))
                    if idx >= 3000:
                        break
                sheet_summary = _sheet_struct_from_rows(rows, sheet.title)
                sheet_summaries.append(sheet_summary)
                total_items += int(sheet_summary.get("parsed_items", 0))
                total_qty += float(sheet_summary.get("quantity_sum", 0.0))
                total_amt += float(sheet_summary.get("amount_sum", 0.0))
            wb.close()
            summary["sheets"] = sheet_summaries
            summary["total_parsed_items"] = total_items
            summary["total_quantity"] = round(total_qty, 4)
            summary["total_amount"] = round(total_amt, 2)
            return _finalize_boq_structured_summary(summary, parsed_text=parsed_text)
        except Exception as exc:
            summary["parse_error"] = f"excel_parse_failed: {type(exc).__name__}: {exc}"

    if ext == ".csv":
        try:
            decoded = content.decode("utf-8", errors="ignore")
            reader = csv.reader(io.StringIO(decoded))
            rows = [list(r) for _, r in zip(range(3000), reader)]
            csv_summary = _sheet_struct_from_rows(rows, "csv")
            summary["sheets"] = [csv_summary]
            summary["total_parsed_items"] = int(csv_summary.get("parsed_items", 0))
            summary["total_quantity"] = float(csv_summary.get("quantity_sum", 0.0))
            summary["total_amount"] = float(csv_summary.get("amount_sum", 0.0))
            return _finalize_boq_structured_summary(summary, parsed_text=parsed_text)
        except Exception as exc:
            summary["parse_error"] = f"csv_parse_failed: {type(exc).__name__}: {exc}"

    # 兜底：从已解析文本里识别关键信号，至少提供结构化可见性。
    text = str(parsed_text or "")
    summary["keyword_hits"] = {
        "工程量": len(re.findall(r"工程量|数量", text)),
        "综合单价": len(re.findall(r"综合单价|单价", text)),
        "合价金额": len(re.findall(r"合价|金额|总价|小计", text)),
    }
    summary["text_chars"] = len(text)
    summary["signal_density"] = round(
        (float(sum(summary["keyword_hits"].values())) / max(1.0, float(len(text) / 100.0))),
        4,
    )
    return _finalize_boq_structured_summary(summary, parsed_text=parsed_text)


def _extract_binary_text_snippet(content: bytes, *, max_chars: int = 4000) -> str:
    decoded = content.decode("utf-8", errors="ignore")
    cleaned = "".join(ch if ch.isprintable() else " " for ch in decoded)
    compact = " ".join(cleaned.split())
    if not compact:
        return ""
    return compact[: max(256, int(max_chars))]


def _extract_image_content(content: bytes, filename: str) -> str:
    lines = [f"[图像资料] 文件: {filename}", f"字节数: {len(content)}"]
    if Image is None:
        lines.append("图像解析: 当前环境未安装 Pillow，已纳入文件元信息。")
        return "\n".join(lines)
    try:
        with Image.open(io.BytesIO(content)) as img:
            lines.append(f"格式: {img.format or '未知'}")
            lines.append(f"尺寸: {img.width}x{img.height}")
            lines.append(f"模式: {img.mode}")
            if pytesseract is not None:
                ocr_result = _extract_best_ocr_text_from_image(
                    img,
                    context_tokens=_extract_terms(filename, max_terms=8),
                )
                ocr_text = str(ocr_result.get("text") or "").strip()
                if ocr_text:
                    lines.append(f"OCR模式: {ocr_result.get('mode') or 'single_pass'}")
                    lines.append(
                        f"OCR质量分: {round(float(_to_float_or_none(ocr_result.get('score')) or 0.0), 4)}"
                    )
                    lines.append("[OCR文本提取]")
                    lines.append(ocr_text[:4000])
                else:
                    lines.append("OCR文本提取: 未识别到有效文本。")
            else:
                lines.append("OCR文本提取: 当前环境未安装 pytesseract，已纳入图像元信息。")
    except Exception as exc:
        lines.append(f"图像解析失败: {exc}")
    return "\n".join(lines)


def _pdf_backend_name() -> str:
    if pymupdf is not None:
        return "pymupdf"
    if PdfReader is not None:
        return "pypdf"
    return "none"


def _extract_pdf_text_with_pypdf(content: bytes) -> str:
    if PdfReader is None:
        return ""
    if not bytes(content or b"").lstrip().startswith(b"%PDF"):
        return ""
    try:
        reader = PdfReader(io.BytesIO(content))
    except Exception:
        return ""
    parts: List[str] = []
    for idx, page in enumerate(getattr(reader, "pages", []) or [], start=1):
        try:
            page_text = str(page.extract_text() or "")
        except Exception:
            page_text = ""
        page_text = page_text.strip()
        if page_text:
            parts.append(f"[PAGE:{idx}]\n{page_text}")
    return "\n\n".join(parts).strip()


def _extract_pdf_text(content: bytes, filename: str) -> str:
    if pymupdf is not None:
        doc = pymupdf.open(stream=content, filetype="pdf")
        try:
            parts: List[str] = []
            filename_terms = _extract_terms(filename, max_terms=10)
            for idx, page in enumerate(doc, start=1):
                # Embed stable page markers so downstream diagnostics can map evidence to pages.
                page_text = _normalize_ocr_text_block(page.get_text() or "")
                page_lines: List[str] = [f"[PAGE:{idx}]"]
                ocr_result: Dict[str, object] = {"text": "", "mode": "", "score": 0.0}
                need_page_ocr = (
                    len(page_text.replace("\n", "").strip()) < DEFAULT_PDF_TEXT_MIN_CHARS_FOR_OCR
                    or _score_ocr_text_candidate(
                        page_text,
                        context_tokens=filename_terms,
                    )
                    < 2.2
                )
                if (
                    need_page_ocr
                    and idx <= DEFAULT_PDF_OCR_MAX_PAGES
                    and pytesseract is not None
                    and Image is not None
                ):
                    try:
                        pix = page.get_pixmap(matrix=pymupdf.Matrix(2.0, 2.0), alpha=False)
                        with Image.open(io.BytesIO(pix.tobytes("png"))) as img:
                            ocr_result = _extract_best_ocr_text_from_image(
                                img,
                                context_tokens=filename_terms
                                + _extract_terms(page_text, max_terms=8),
                            )
                    except Exception:
                        ocr_result = {"text": "", "mode": "", "score": 0.0}
                page_ocr_text = str(ocr_result.get("text") or "").strip()
                combined_text = page_text
                if page_ocr_text:
                    combined_text = (
                        combined_text + ("\n" if combined_text else "") + page_ocr_text
                    ).strip()
                    page_lines.append(
                        f"[PAGE_OCR_MODE:{idx}] {ocr_result.get('mode') or 'single_pass'} score={round(float(_to_float_or_none(ocr_result.get('score')) or 0.0), 4)}"
                    )
                    page_lines.append(f"[PAGE_OCR:{idx}]")
                    page_lines.append(page_ocr_text[:5000])
                if combined_text:
                    section_hints = _extract_tender_qa_section_titles(combined_text, limit=4)
                    if section_hints:
                        page_lines.append(
                            f"[PAGE_SECTION_HINTS:{idx}] " + "、".join(section_hints[:4])
                        )
                if page_text:
                    page_lines.append(page_text)
                elif page_ocr_text:
                    page_lines.append(page_ocr_text[:5000])
                parts.append("\n".join(page_lines).strip())
            merged_pdf_text = "\n\n".join(part for part in parts if part.strip()).strip()
            if merged_pdf_text:
                return f"[PDF_BACKEND:pymupdf]\n{merged_pdf_text}"
        finally:
            doc.close()

    pypdf_text = _extract_pdf_text_with_pypdf(content)
    if pypdf_text:
        return f"[PDF_BACKEND:pypdf]\n{pypdf_text}"

    if _pdf_backend_name() == "none":
        raise ValueError(
            "PDF 解析不可用：请安装与当前系统架构兼容的 PyMuPDF，或安装 pypdf 作为兼容解析后端。"
        )
    return f"[PDF资料] 文件: {filename}（未提取到有效文本）"


def _extract_pdf_text_preview(
    content: bytes,
    filename: str,
    *,
    max_pages: int = 4,
    max_chars: int = 16000,
    ocr_pages: int = 2,
    stop_when_project_name_found: bool = False,
) -> str:
    if pymupdf is not None:
        doc = pymupdf.open(stream=content, filetype="pdf")
        try:
            parts: List[str] = []
            filename_terms = _extract_terms(filename, max_terms=10)
            for idx, page in enumerate(doc, start=1):
                if idx > max(1, int(max_pages)):
                    break
                page_text = _normalize_ocr_text_block(page.get_text() or "")
                page_lines: List[str] = [f"[PAGE:{idx}]"]
                ocr_result: Dict[str, object] = {"text": "", "mode": "", "score": 0.0}
                need_page_ocr = (
                    len(page_text.replace("\n", "").strip()) < DEFAULT_PDF_TEXT_MIN_CHARS_FOR_OCR
                    or _score_ocr_text_candidate(
                        page_text,
                        context_tokens=filename_terms,
                    )
                    < 2.2
                )
                if (
                    need_page_ocr
                    and idx <= max(1, int(ocr_pages))
                    and pytesseract is not None
                    and Image is not None
                ):
                    try:
                        pix = page.get_pixmap(matrix=pymupdf.Matrix(2.0, 2.0), alpha=False)
                        with Image.open(io.BytesIO(pix.tobytes("png"))) as img:
                            ocr_result = _extract_best_ocr_text_from_image(
                                img,
                                context_tokens=filename_terms
                                + _extract_terms(page_text, max_terms=8),
                            )
                    except Exception:
                        ocr_result = {"text": "", "mode": "", "score": 0.0}
                page_ocr_text = str(ocr_result.get("text") or "").strip()
                combined_text = page_text
                if page_ocr_text:
                    combined_text = (
                        combined_text + ("\n" if combined_text else "") + page_ocr_text
                    ).strip()
                    page_lines.append(
                        f"[PAGE_OCR_MODE:{idx}] {ocr_result.get('mode') or 'single_pass'} score={round(float(_to_float_or_none(ocr_result.get('score')) or 0.0), 4)}"
                    )
                    page_lines.append(f"[PAGE_OCR:{idx}]")
                    page_lines.append(page_ocr_text[:3000])
                if combined_text:
                    section_hints = _extract_tender_qa_section_titles(combined_text, limit=2)
                    if section_hints:
                        page_lines.append(
                            f"[PAGE_SECTION_HINTS:{idx}] " + "、".join(section_hints[:2])
                        )
                if page_text:
                    page_lines.append(page_text)
                elif page_ocr_text:
                    page_lines.append(page_ocr_text[:3000])
                chunk = "\n".join(page_lines).strip()
                if chunk:
                    parts.append(chunk)
                if stop_when_project_name_found:
                    current_preview = "\n\n".join(part for part in parts if part.strip()).strip()
                    if any(
                        marker in current_preview for marker in ("项目名称", "工程名称", "标段名称")
                    ):
                        try:
                            current_project_name = _infer_project_name_from_tender_text(
                                current_preview, ""
                            )
                        except HTTPException:
                            current_project_name = ""
                        if current_project_name:
                            break
                if sum(len(part) for part in parts) >= max(4000, int(max_chars)):
                    break
            merged_pdf_text = "\n\n".join(part for part in parts if part.strip()).strip()
            if merged_pdf_text:
                return f"[PDF_BACKEND:pymupdf]\n{merged_pdf_text[: max(4000, int(max_chars))]}"
        finally:
            doc.close()

    pypdf_text = _extract_pdf_text_with_pypdf(content)
    if pypdf_text:
        limited_parts: List[str] = []
        for idx, chunk in enumerate(re.split(r"\n\s*\n", pypdf_text), start=1):
            if idx > max(1, int(max_pages)):
                break
            if not chunk.strip():
                continue
            limited_parts.append(chunk.strip())
            if sum(len(part) for part in limited_parts) >= max(4000, int(max_chars)):
                break
        preview = "\n\n".join(limited_parts).strip()
        if preview:
            return f"[PDF_BACKEND:pypdf]\n{preview[: max(4000, int(max_chars))]}"

    snippet = _extract_binary_text_snippet(content, max_chars=max_chars)
    if snippet:
        return snippet
    return f"[PDF资料] 文件: {filename}（预览未提取到有效文本）"


def _read_uploaded_file_content(content: bytes, filename: str) -> str:
    """根据文件名解析上传文件为文本，覆盖招标/清单/图纸/现场照片常见格式。"""
    name = filename.lower()
    if name.endswith(".txt") or name.endswith(".md") or name.endswith(".csv"):
        return content.decode("utf-8", errors="ignore")
    if name.endswith(".docx"):
        if Document is None:
            raise ValueError("DOCX 解析不可用：请安装与当前系统架构兼容的 python-docx/lxml。")
        doc = Document(io.BytesIO(content))
        return "\n".join(p.text for p in doc.paragraphs)
    if name.endswith(".doc") or name.endswith(".docm"):
        snippet = _extract_binary_text_snippet(content)
        if snippet:
            return snippet
        return f"[DOC资料] 文件: {filename}（当前环境未启用结构化解析，已纳入文件元信息）"
    if name.endswith(".pdf"):
        return _extract_pdf_text(content, filename)
    if name.endswith(".json"):
        return content.decode("utf-8", errors="ignore")
    if name.endswith(".xlsx") or name.endswith(".xls") or name.endswith(".xlsm"):
        try:
            import openpyxl

            wb = openpyxl.load_workbook(io.BytesIO(content), read_only=True, data_only=True)
            parts = []
            for sheet in wb.worksheets:
                for row in sheet.iter_rows(values_only=True):
                    parts.append("\t".join(str(c) if c is not None else "" for c in row))
            wb.close()
            return "\n".join(parts)
        except Exception as e:
            raise ValueError(f"Excel 解析失败: {e}") from e
    if name.endswith(".dxf"):
        try:
            return _extract_dxf_text(content)
        except ValueError:
            raise
        except Exception as e:
            raise ValueError(f"DXF 解析失败: {e}") from e
    if name.endswith(".dwg"):
        return _extract_dwg_text(content, filename)
    if name.endswith((".png", ".jpg", ".jpeg", ".webp", ".bmp", ".tif", ".tiff")):
        return _extract_image_content(content, filename)
    snippet = _extract_binary_text_snippet(content, max_chars=2000)
    if snippet:
        return snippet
    raise ValueError(
        "仅支持 .txt、.md、.csv、.doc/.docx/.docm、.pdf、.json、.xlsx/.xls/.xlsm、.dxf/.dwg、图片格式"
    )


def _read_uploaded_file_preview_for_project_name(content: bytes, filename: str) -> str:
    """为项目名识别提取轻量预览文本，避免自动创建时深解析整份大文件。"""
    name = filename.lower()
    if (
        name.endswith(".txt")
        or name.endswith(".md")
        or name.endswith(".csv")
        or name.endswith(".json")
    ):
        return content.decode("utf-8", errors="ignore")[:12000]
    if name.endswith(".docx"):
        if Document is None:
            raise ValueError("DOCX 解析不可用：请安装与当前系统架构兼容的 python-docx/lxml。")
        doc = Document(io.BytesIO(content))
        parts: List[str] = []
        total_chars = 0
        for paragraph in doc.paragraphs:
            text = str(paragraph.text or "").strip()
            if not text:
                continue
            parts.append(text)
            total_chars += len(text)
            if total_chars >= 12000 or len(parts) >= 80:
                break
        return "\n".join(parts)
    if name.endswith(".doc") or name.endswith(".docm"):
        snippet = _extract_binary_text_snippet(content, max_chars=12000)
        if snippet:
            return snippet
        return f"[DOC资料] 文件: {filename}（当前环境未启用结构化解析，已纳入文件元信息）"
    if name.endswith(".pdf"):
        return _extract_pdf_text_preview(
            content,
            filename,
            max_pages=10,
            max_chars=32000,
            ocr_pages=3,
            stop_when_project_name_found=True,
        )
    if name.endswith(".xlsx") or name.endswith(".xls") or name.endswith(".xlsm"):
        return _read_uploaded_file_content(content, filename)[:12000]
    if name.endswith(".dxf") or name.endswith(".dwg"):
        return _read_uploaded_file_content(content, filename)[:12000]
    if name.endswith((".png", ".jpg", ".jpeg", ".webp", ".bmp", ".tif", ".tiff")):
        return _read_uploaded_file_content(content, filename)[:12000]
    snippet = _extract_binary_text_snippet(content, max_chars=12000)
    if snippet:
        return snippet
    raise ValueError(
        "仅支持 .txt、.md、.csv、.doc/.docx/.docm、.pdf、.json、.xlsx/.xls/.xlsm、.dxf/.dwg、图片格式"
    )


def _merge_materials_text(project_id: str) -> str:
    """将本项目已上传资料按分类合并为文本，作为评分与学习进化的依据。"""
    material_index = _build_project_material_index(project_id)
    files = material_index.get("files") if isinstance(material_index.get("files"), list) else []
    if not files:
        return ""
    groups: Dict[str, List[Dict[str, object]]] = {}
    for file_entry in files:
        if not isinstance(file_entry, dict):
            continue
        mat_type = _normalize_material_type(
            file_entry.get("material_type"), filename=file_entry.get("filename")
        )
        groups.setdefault(mat_type, []).append(file_entry)
    merge_order = ["tender_qa", "boq", "drawing", "site_photo"]
    for key in sorted(groups.keys()):
        if key not in merge_order:
            merge_order.append(key)

    sections: List[str] = []
    for mat_type in merge_order:
        rows = groups.get(mat_type) or []
        if not rows:
            continue
        rows.sort(key=lambda x: str(x.get("created_at") or ""))
        section_lines: List[str] = [f"=== {_material_type_label(mat_type)} ==="]
        for row in rows:
            filename = str(row.get("filename") or "")
            created_at = str(row.get("created_at") or "")[:19]
            if not bool(row.get("parsed_ok")):
                reason = str(row.get("parse_error") or "解析失败")
                if reason == "missing_path":
                    section_lines.append(f"--- {filename} ---\n[资料缺失] 未记录路径。")
                elif reason == "path_not_exists":
                    section_lines.append(f"--- {filename} ---\n[资料缺失] 文件已不存在。")
                else:
                    section_lines.append(
                        f"--- {filename} ({created_at}) ---\n[资料解析失败] {reason}"
                    )
                continue
            text = str(row.get("text") or "").strip()
            if not text:
                section_lines.append(
                    f"--- {filename} ({created_at}) ---\n[资料为空] 文件解析后为空内容。"
                )
                continue
            section_block = f"--- {filename} ({created_at}) ---\n{text}"
            if mat_type == "tender_qa":
                tender_struct = (
                    row.get("tender_qa_structured_summary")
                    if isinstance(row.get("tender_qa_structured_summary"), dict)
                    else {}
                )
                if tender_struct:
                    section_block = (
                        section_block
                        + "\n\n[招标答疑结构化摘要]\n"
                        + json.dumps(tender_struct, ensure_ascii=False)
                    )
            elif mat_type == "boq":
                boq_struct = (
                    row.get("boq_structured_summary")
                    if isinstance(row.get("boq_structured_summary"), dict)
                    else {}
                )
                if boq_struct:
                    section_block = (
                        section_block
                        + "\n\n[BOQ结构化摘要]\n"
                        + json.dumps(boq_struct, ensure_ascii=False)
                    )
            elif mat_type == "drawing":
                drawing_struct = (
                    row.get("drawing_structured_summary")
                    if isinstance(row.get("drawing_structured_summary"), dict)
                    else {}
                )
                if drawing_struct:
                    section_block = (
                        section_block
                        + "\n\n[图纸结构化摘要]\n"
                        + json.dumps(drawing_struct, ensure_ascii=False)
                    )
            elif mat_type == "site_photo":
                photo_struct = (
                    row.get("site_photo_structured_summary")
                    if isinstance(row.get("site_photo_structured_summary"), dict)
                    else {}
                )
                if photo_struct:
                    section_block = (
                        section_block
                        + "\n\n[现场照片结构化摘要]\n"
                        + json.dumps(photo_struct, ensure_ascii=False)
                    )
            section_lines.append(section_block)
        sections.append("\n\n".join(section_lines))
    return "\n\n".join(sections).strip()


def _split_material_text_chunks(text: str, *, max_chars: int = 900) -> List[str]:
    raw_parts = re.split(r"\n{2,}|[。！？]\s*", str(text or ""))
    chunks: List[str] = []
    buf: List[str] = []
    size = 0
    for part in raw_parts:
        s = str(part or "").strip()
        if not s:
            continue
        if len(s) > max_chars:
            s = s[:max_chars]
        if size + len(s) > max_chars and buf:
            chunks.append("；".join(buf))
            buf = [s]
            size = len(s)
            continue
        buf.append(s)
        size += len(s)
    if buf:
        chunks.append("；".join(buf))
    return chunks[:80]


def _infer_chunk_dimension_id(material_type: str, chunk_text: str) -> str:
    candidates = MATERIAL_TYPE_DIMENSION_PRIORITY.get(material_type) or ["01"]
    lower = str(chunk_text or "").lower()
    best_dim = candidates[0]
    best_score = -1
    for dim_id in candidates:
        score = 0
        for kw in DIMENSION_RAG_KEYWORDS.get(dim_id, []):
            if kw.lower() in lower:
                score += 1
        if score > best_score:
            best_score = score
            best_dim = dim_id
    return best_dim


def _get_material_file_structured_summary(file_entry: Dict[str, object]) -> Dict[str, object]:
    if isinstance(file_entry.get("structured_summary"), dict):
        return file_entry.get("structured_summary")  # type: ignore[return-value]
    mat_type = _normalize_material_type(file_entry.get("material_type"))
    if mat_type == "tender_qa":
        return (
            file_entry.get("tender_qa_structured_summary")
            if isinstance(file_entry.get("tender_qa_structured_summary"), dict)
            else {}
        )
    if mat_type == "boq":
        return (
            file_entry.get("boq_structured_summary")
            if isinstance(file_entry.get("boq_structured_summary"), dict)
            else {}
        )
    if mat_type == "drawing":
        return (
            file_entry.get("drawing_structured_summary")
            if isinstance(file_entry.get("drawing_structured_summary"), dict)
            else {}
        )
    if mat_type == "site_photo":
        return (
            file_entry.get("site_photo_structured_summary")
            if isinstance(file_entry.get("site_photo_structured_summary"), dict)
            else {}
        )
    return {}


def _get_material_file_structured_quality(file_entry: Dict[str, object]) -> float:
    summary = _get_material_file_structured_summary(file_entry)
    return float(_clip_score01(summary.get("structured_quality_score")) or 0.0)


def _select_material_retrieval_chunks(
    project_id: str,
    submission_text: str,
    *,
    top_k: int = 12,
    per_type_quota: int = 1,
    per_file_quota: int = 3,
    query_terms_extra: Optional[List[str]] = None,
    query_numeric_terms: Optional[List[str]] = None,
    material_index: Optional[Dict[str, object]] = None,
) -> List[Dict[str, object]]:
    query_terms = set(_extract_terms(submission_text, max_terms=60))
    if isinstance(query_terms_extra, list):
        query_terms.update(str(x).strip().lower() for x in query_terms_extra if str(x).strip())
    # 确保不同资料类型关键词也参与检索，避免“只用施组词命中”。
    for kws in MATERIAL_TYPE_KEYWORDS.values():
        query_terms.update(k.lower() for k in kws)
    numeric_terms = set(_extract_numeric_terms(submission_text, max_terms=24))
    if isinstance(query_numeric_terms, list):
        numeric_terms.update(
            _normalize_numeric_token(x) for x in query_numeric_terms if _normalize_numeric_token(x)
        )
    ordered_query_terms = sorted(
        [str(token) for token in query_terms if str(token).strip()],
        key=lambda token: (-len(token), token),
    )
    ordered_numeric_terms = sorted(
        [str(token) for token in numeric_terms if str(token).strip()],
        key=lambda token: (-len(token), token),
    )

    index = (
        material_index
        if isinstance(material_index, dict)
        else _build_project_material_index(project_id)
    )
    available_types = [str(x) for x in (index.get("available_types") or []) if str(x).strip()]
    file_entries = index.get("files") if isinstance(index.get("files"), list) else []
    candidates: List[Dict[str, object]] = []
    backfill_candidates: List[Dict[str, object]] = []
    for file_entry in file_entries:
        if not isinstance(file_entry, dict):
            continue
        if not bool(file_entry.get("parsed_ok")):
            continue
        filename = str(file_entry.get("filename") or "").strip()
        mat_type = str(file_entry.get("material_type") or "").strip()
        structured_summary = _get_material_file_structured_summary(file_entry)
        file_structured_quality = _get_material_file_structured_quality(file_entry)
        file_outline_terms = _collect_structured_outline_terms(
            structured_summary,
            material_type=mat_type,
            limit=8,
        )
        file_table_terms = _collect_structured_table_terms(
            structured_summary,
            material_type=mat_type,
            limit=8,
        )
        file_structured_terms = _filter_structured_signal_terms(
            _to_text_items(structured_summary.get("structured_terms"), max_items=12)
            + _to_text_items(structured_summary.get("section_titles"), max_items=6)
            + file_outline_terms
            + _to_text_items(structured_summary.get("scoring_point_terms"), max_items=6)
            + file_table_terms
            + _to_text_items(structured_summary.get("mandatory_clause_terms"), max_items=4),
            limit=16,
            material_type=mat_type,
        )
        file_anchor_terms = _limit_unique_texts(file_outline_terms + file_table_terms, limit=10)
        file_anchor_numeric_terms = _collect_structured_anchor_numeric_terms(
            structured_summary,
            limit=10,
        )
        chunks = file_entry.get("chunks") if isinstance(file_entry.get("chunks"), list) else []
        if not chunks:
            text_raw = str(file_entry.get("text") or "")
            if text_raw:
                chunks = _split_material_text_chunks(text_raw, max_chars=900)
        for idx, chunk in enumerate(chunks, start=1):
            chunk_text = str(chunk or "")
            lower = chunk_text.lower()
            matched_terms = [t for t in ordered_query_terms if t and t in lower][:8]
            structured_term_hits = [
                term.lower()
                for term in file_structured_terms
                if str(term or "").strip() and str(term).lower() in lower
            ][:4]
            matched_file_anchor_terms = [
                str(term).lower()
                for term in file_anchor_terms
                if str(term).strip()
                and any(
                    query_term in str(term).lower() or str(term).lower() in query_term
                    for query_term in ordered_query_terms
                )
            ][:4]
            chunk_numeric_terms = _extract_numeric_terms(chunk_text, max_terms=30)
            chunk_numeric_set = {str(x) for x in chunk_numeric_terms}
            matched_numeric_terms = [
                token for token in ordered_numeric_terms if token and token in chunk_numeric_set
            ][:8]
            matched_file_numeric_terms = [
                token
                for token in ordered_numeric_terms
                if token and token in file_anchor_numeric_terms
            ][:4]
            type_keyword_hits = [
                kw.lower() for kw in MATERIAL_TYPE_KEYWORDS.get(mat_type, []) if kw.lower() in lower
            ][:6]
            if structured_term_hits:
                for term in structured_term_hits:
                    if term not in matched_terms:
                        matched_terms.append(term)
                    if len(matched_terms) >= 8:
                        break
            if matched_file_anchor_terms:
                for term in matched_file_anchor_terms:
                    if term not in matched_terms:
                        matched_terms.append(term)
                    if len(matched_terms) >= 8:
                        break
            if matched_file_numeric_terms:
                for token in matched_file_numeric_terms:
                    if token not in matched_numeric_terms:
                        matched_numeric_terms.append(token)
                    if len(matched_numeric_terms) >= 8:
                        break
            if not matched_terms:
                # 兜底：若命中该类型关键词也纳入候选
                matched_terms = list(type_keyword_hits)
            if not matched_terms and not matched_numeric_terms:
                # 二级兜底：即使没有直接命中查询词，也为每种资料类型保留“高信息密度”候选，
                # 后续用于类型补全，避免某类资料长期无法进入评分证据链。
                lexical_terms = _extract_terms(chunk_text, max_terms=20)
                chunk_numeric_norm = [
                    token
                    for token in (
                        _normalize_numeric_token(item)
                        for item in _extract_numeric_terms(chunk_text, max_terms=18)
                    )
                    if token
                ]
                fallback_score = 0
                fallback_score += min(4, len(lexical_terms))
                fallback_score += min(4, len(chunk_numeric_norm))
                fallback_score += min(3, len(type_keyword_hits))
                fallback_score += min(3, len(structured_term_hits))
                fallback_score += min(4, int(round(file_structured_quality * 4)))
                if mat_type in {"boq", "drawing"}:
                    fallback_score += 1
                if fallback_score <= 0 or len(chunk_text.strip()) < 24:
                    continue
                backfill_candidates.append(
                    {
                        "material_type": mat_type,
                        "filename": filename,
                        "chunk_id": f"{filename}#c{idx:03d}",
                        "dimension_id": _infer_chunk_dimension_id(mat_type, chunk),
                        "score": fallback_score,
                        "matched_terms": structured_term_hits
                        or matched_file_anchor_terms
                        or type_keyword_hits
                        or lexical_terms[:6],
                        "matched_numeric_terms": chunk_numeric_norm[:6],
                        "matched_file_anchor_terms": matched_file_anchor_terms,
                        "matched_file_numeric_terms": matched_file_numeric_terms,
                        "chunk_preview": chunk_text[:220],
                        "is_backfill": True,
                        "file_structured_quality": round(file_structured_quality, 4),
                    }
                )
                continue
            dimension_id = _infer_chunk_dimension_id(mat_type, chunk)
            score = len(matched_terms) + (2 if mat_type in {"boq", "drawing"} else 1)
            score += min(3, len(structured_term_hits))
            score += min(3, len(matched_file_anchor_terms))
            if matched_numeric_terms:
                score += min(4, len(matched_numeric_terms))
                if mat_type in {"tender_qa", "boq", "drawing"}:
                    score += 1
            if matched_file_numeric_terms and not chunk_numeric_terms:
                score += min(2, len(matched_file_numeric_terms))
            score += min(4, file_structured_quality * 4.0)
            candidates.append(
                {
                    "material_type": mat_type,
                    "filename": filename,
                    "chunk_id": f"{filename}#c{idx:03d}",
                    "dimension_id": dimension_id,
                    "score": score,
                    "matched_terms": matched_terms,
                    "matched_numeric_terms": matched_numeric_terms,
                    "matched_file_anchor_terms": matched_file_anchor_terms,
                    "matched_file_numeric_terms": matched_file_numeric_terms,
                    "chunk_preview": chunk_text[:220],
                    "file_structured_quality": round(file_structured_quality, 4),
                }
            )

    if not candidates and not backfill_candidates:
        return []
    candidates.sort(
        key=lambda x: (
            -float(x.get("score", 0)),
            -float(x.get("file_structured_quality", 0.0)),
            str(x.get("material_type")),
            str(x.get("filename")),
            str(x.get("chunk_id")),
        )
    )
    backfill_candidates.sort(
        key=lambda x: (
            -float(x.get("score", 0)),
            -float(x.get("file_structured_quality", 0.0)),
            str(x.get("material_type")),
            str(x.get("filename")),
            str(x.get("chunk_id")),
        )
    )
    target_k = max(1, int(top_k))
    selected: List[Dict[str, object]] = []
    seen_chunk_ids: set[str] = set()
    selected_per_file: Dict[str, int] = {}

    type_quota = max(1, int(per_type_quota))
    file_quota = max(1, int(per_file_quota))

    def _try_pick(candidate: Dict[str, object], *, selected_via: str) -> bool:
        chunk_id = str(candidate.get("chunk_id") or "")
        if not chunk_id or chunk_id in seen_chunk_ids:
            return False
        filename_text = str(candidate.get("filename") or "").strip()
        candidate_file_quota = file_quota + (
            1
            if float(_to_float_or_none(candidate.get("file_structured_quality")) or 0.0) >= 0.72
            else 0
        )
        if filename_text and int(selected_per_file.get(filename_text, 0)) >= candidate_file_quota:
            return False
        row = dict(candidate)
        row["selected_via"] = selected_via
        selected.append(row)
        seen_chunk_ids.add(chunk_id)
        if filename_text:
            selected_per_file[filename_text] = int(selected_per_file.get(filename_text, 0)) + 1
        return True

    # 先保证“每个已上传资料类型至少取 N 个块”，避免单一资料类型垄断检索。
    for mat_type in available_types:
        type_selected = 0
        for candidate in candidates:
            if str(candidate.get("material_type") or "") != mat_type:
                continue
            if not _try_pick(candidate, selected_via="type_quota"):
                continue
            type_selected += 1
            if len(selected) >= target_k:
                return selected
            if type_selected >= type_quota:
                break

    selected_types = {
        str(item.get("material_type") or "").strip()
        for item in selected
        if str(item.get("material_type") or "").strip()
    }
    for mat_type in available_types:
        if mat_type in selected_types:
            continue
        for candidate in backfill_candidates:
            if str(candidate.get("material_type") or "") != mat_type:
                continue
            if not _try_pick(candidate, selected_via="type_backfill"):
                continue
            selected_types.add(mat_type)
            if len(selected) >= target_k:
                return selected
            break

    # 再按全局相关性补齐 top_k。
    for candidate in candidates:
        if not _try_pick(candidate, selected_via="global_rank"):
            continue
        if len(selected) >= target_k:
            break
    if len(selected) < target_k:
        for candidate in backfill_candidates:
            if not _try_pick(candidate, selected_via="global_backfill"):
                continue
            if len(selected) >= target_k:
                break
    return selected


def _build_material_retrieval_requirements(
    project_id: str,
    retrieval_chunks: List[Dict[str, object]],
) -> List[Dict[str, object]]:
    now = _now_iso()
    reqs: List[Dict[str, object]] = []
    for idx, chunk in enumerate(retrieval_chunks, start=1):
        dim_id = str(chunk.get("dimension_id") or "01")
        chunk_id = str(chunk.get("chunk_id") or f"chunk-{idx}")
        mat_type = str(chunk.get("material_type") or MATERIAL_TYPE_DEFAULT)
        filename = str(chunk.get("filename") or "")
        hints = [str(x) for x in (chunk.get("matched_terms") or []) if str(x).strip()]
        hints.extend(
            str(x) for x in (chunk.get("matched_file_anchor_terms") or []) if str(x).strip()
        )
        preview = str(chunk.get("chunk_preview") or "").strip()
        if preview:
            hints.append(preview[:120])
        hints = _to_text_items(hints, max_items=8)
        if not hints:
            continue
        minimum_hint_hits = 2 if mat_type in {"tender_qa", "boq"} else 1
        reqs.append(
            {
                "id": f"runtime-rag-{project_id[:8]}-{idx}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": f"资料检索证据：{_material_type_label(mat_type)} / {filename} / {chunk_id}",
                "req_type": "semantic",
                "patterns": {
                    "hints": hints,
                    "minimum_hint_hits": minimum_hint_hits,
                    "material_type": mat_type,
                    "source_filename": filename,
                    "chunk_id": chunk_id,
                    "source_mode": str(chunk.get("selected_via") or "retrieval_chunks"),
                },
                "mandatory": False,
                "weight": 0.7,
                "material_type": mat_type,
                "source_anchor_id": None,
                "source_pack_id": "runtime_material_rag",
                "source_pack_version": "v2-rag-1",
                "priority": 88.0,
                "override_key": f"runtime::material_rag::{chunk_id}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_material_consistency_requirements(
    project_id: str,
    retrieval_chunks: List[Dict[str, object]],
    *,
    available_material_types: Optional[List[str]] = None,
) -> List[Dict[str, object]]:
    now = _now_iso()
    grouped: Dict[str, List[Dict[str, object]]] = {}
    for chunk in retrieval_chunks:
        mat_type = str(chunk.get("material_type") or MATERIAL_TYPE_DEFAULT)
        grouped.setdefault(mat_type, []).append(chunk)

    normalized_available_types: List[str] = []
    for item in available_material_types or []:
        key = _normalize_material_type(item)
        if key and key not in normalized_available_types:
            normalized_available_types.append(key)
    for mat_type in normalized_available_types:
        grouped.setdefault(mat_type, [])

    reqs: List[Dict[str, object]] = []
    req_index = 0
    ordered_types = normalized_available_types + [
        mat_type for mat_type in grouped.keys() if mat_type not in normalized_available_types
    ]
    for mat_type in ordered_types:
        chunks = grouped.get(mat_type) or []
        keyword_counter: Counter[str] = Counter()
        numeric_counter: Counter[str] = Counter()
        preview_terms: List[str] = []
        filenames: List[str] = []
        for chunk in chunks[:12]:
            filename = str(chunk.get("filename") or "")
            if filename:
                filenames.append(filename)
            for term in chunk.get("matched_terms") or []:
                token = str(term or "").strip()
                if token:
                    keyword_counter[token] += 1
            for term in chunk.get("matched_file_anchor_terms") or []:
                token = str(term or "").strip()
                if token:
                    keyword_counter[token] += 2
            for token in chunk.get("matched_numeric_terms") or []:
                numeric = _normalize_numeric_token(token)
                if numeric:
                    numeric_counter[numeric] += 1
            preview_terms.extend(
                _extract_terms(str(chunk.get("chunk_preview") or ""), max_terms=10)
            )
            for token in _extract_numeric_terms(str(chunk.get("chunk_preview") or ""), max_terms=8):
                numeric = _normalize_numeric_token(token)
                if numeric:
                    numeric_counter[numeric] += 1
        must_terms = [item for item, _ in keyword_counter.most_common(8)]
        if len(must_terms) < 4:
            must_terms.extend([item for item in preview_terms if item not in must_terms])
        if len(must_terms) < 3:
            must_terms.extend(
                [
                    item
                    for item in MATERIAL_TYPE_KEYWORDS.get(mat_type, [])
                    if item not in must_terms
                ]
            )
        must_terms = _to_text_items(must_terms, max_items=8)
        must_numbers = [item for item, _ in numeric_counter.most_common(4)]
        if not must_terms and not must_numbers:
            continue

        req_index += 1
        minimum_terms = (
            2 if (must_terms and mat_type in {"tender_qa", "boq"}) else (1 if must_terms else 0)
        )
        minimum_numbers = 1 if (must_numbers and mat_type in {"tender_qa", "boq"}) else 0
        known_required_types = {"tender_qa", "boq", "drawing", "site_photo"}
        mandatory = mat_type in known_required_types and (
            (not normalized_available_types) or (mat_type in normalized_available_types)
        )
        source_mode = "retrieval_chunks" if chunks else "fallback_keywords"
        dim_id = (MATERIAL_TYPE_DIMENSION_PRIORITY.get(mat_type) or ["01"])[0]
        reqs.append(
            {
                "id": f"runtime-consistency-{project_id[:8]}-{req_index}",
                "project_id": project_id,
                "dimension_id": dim_id,
                "req_label": f"跨资料一致性：施组需体现{_material_type_label(mat_type)}关键约束",
                "req_type": "material_consistency",
                "patterns": {
                    "must_hit_terms": must_terms,
                    "minimum_terms": minimum_terms,
                    "must_hit_numbers": must_numbers,
                    "minimum_numbers": minimum_numbers,
                    "material_type": mat_type,
                    "sample_filenames": _to_text_items(filenames, max_items=3),
                    "within_dimension_scope": False,
                    "source_mode": source_mode,
                },
                "mandatory": mandatory,
                "weight": 1.1
                if (mandatory and mat_type in {"tender_qa", "boq", "drawing"})
                else 0.9,
                "material_type": mat_type,
                "source_anchor_id": None,
                "source_pack_id": "runtime_material_consistency",
                "source_pack_version": "v2-consistency-1",
                "priority": 92.0,
                "override_key": f"runtime::material_consistency::{mat_type}",
                "lint": {},
                "created_at": now,
            }
        )
    return reqs


def _build_material_quality_snapshot(project_id: str) -> Dict[str, object]:
    index = _build_project_material_index(project_id)
    snapshot = (
        index.get("quality_snapshot") if isinstance(index.get("quality_snapshot"), dict) else {}
    )
    return copy.deepcopy(snapshot)


def _compute_adaptive_numeric_term_gate(
    project_id: str,
    cfg: Dict[str, object],
    snapshot: Dict[str, object],
) -> tuple[Dict[str, int], Dict[str, Dict[str, object]], Dict[str, object]]:
    base_numeric_map = dict(cfg.get("min_numeric_terms_by_type") or {})
    effective_numeric_map: Dict[str, int] = {
        _normalize_material_type(key): max(0, int(_to_float_or_none(value) or 0))
        for key, value in base_numeric_map.items()
        if _normalize_material_type(key)
    }
    adjustments: Dict[str, Dict[str, object]] = {}
    required_types = [
        _normalize_material_type(x)
        for x in (cfg.get("required_types") or [])
        if _normalize_material_type(x)
    ]
    if not required_types:
        return effective_numeric_map, adjustments, {"applied": False, "summary": []}

    min_chars_by_type = dict(cfg.get("min_chars_by_type") or {})
    min_chunks_by_type = dict(cfg.get("min_chunks_by_type") or {})
    chars_by_type = (
        snapshot.get("chars_by_type") if isinstance(snapshot.get("chars_by_type"), dict) else {}
    )
    chunks_by_type = (
        snapshot.get("chunks_by_type") if isinstance(snapshot.get("chunks_by_type"), dict) else {}
    )
    numeric_terms_by_type = (
        snapshot.get("numeric_terms_by_type")
        if isinstance(snapshot.get("numeric_terms_by_type"), dict)
        else {}
    )
    counts_by_type = (
        snapshot.get("counts_by_type") if isinstance(snapshot.get("counts_by_type"), dict) else {}
    )

    knowledge = _build_material_knowledge_profile(project_id)
    summary = knowledge.get("summary") if isinstance(knowledge.get("summary"), dict) else {}
    by_type = knowledge.get("by_type") if isinstance(knowledge.get("by_type"), list) else []
    by_type_map: Dict[str, Dict[str, object]] = {}
    for row in by_type:
        if not isinstance(row, dict):
            continue
        mat_type = _normalize_material_type(row.get("material_type"))
        if mat_type:
            by_type_map[mat_type] = row

    consensus_score = float(_to_float_or_none(summary.get("cross_type_consensus_score")) or 0.0)
    consensus_type_count = int(
        _to_float_or_none(summary.get("cross_type_consensus_type_count")) or 0
    )
    structured_quality_avg = float(_clip_score01(summary.get("structured_quality_avg")) or 0.0)
    structured_quality_type_rate = float(
        _clip_score01(summary.get("structured_quality_type_rate")) or 0.0
    )
    adaptive_summary: List[str] = []

    for mat_type in required_types:
        base_min = max(0, int(_to_float_or_none(base_numeric_map.get(mat_type)) or 0))
        if base_min <= 0:
            continue
        if int(_to_float_or_none(counts_by_type.get(mat_type)) or 0) <= 0:
            continue
        parsed_numeric_terms = int(_to_float_or_none(numeric_terms_by_type.get(mat_type)) or 0)
        if parsed_numeric_terms >= base_min:
            continue

        row = by_type_map.get(mat_type) or {}
        parsed_chars = int(_to_float_or_none(chars_by_type.get(mat_type)) or 0)
        parsed_chunks = int(_to_float_or_none(chunks_by_type.get(mat_type)) or 0)
        min_chars = max(0, int(_to_float_or_none(min_chars_by_type.get(mat_type)) or 0))
        min_chunks = max(0, int(_to_float_or_none(min_chunks_by_type.get(mat_type)) or 0))
        row_quality = float(_clip_score01(row.get("structured_quality_score")) or 0.0)
        row_quality_max = float(_clip_score01(row.get("structured_quality_max")) or 0.0)
        row_signal_count = int(_to_float_or_none(row.get("structured_signal_count")) or 0)
        focused_dimension_count = len(
            [
                dim_id
                for dim_id in (row.get("focused_dimensions") or [])
                if str(dim_id or "").strip().zfill(2) in DIMENSION_IDS
            ]
        )

        relaxation = 0.0
        reasons: List[str] = []
        if min_chars > 0 and parsed_chars >= max(int(math.ceil(min_chars * 1.8)), min_chars + 1200):
            relaxation += 0.10
            reasons.append("parsed_chars_surplus")
        if min_chunks > 0 and parsed_chunks >= max(
            min_chunks + 2, int(math.ceil(min_chunks * 1.8))
        ):
            relaxation += 0.08
            reasons.append("parsed_chunks_surplus")
        if row_quality >= 0.35:
            relaxation += 0.08
            reasons.append("structured_quality_ok")
        if row_quality_max >= 0.45:
            relaxation += 0.04
            reasons.append("structured_quality_peak")
        if row_signal_count >= 6:
            relaxation += 0.04
            reasons.append("structured_signals_dense")
        if focused_dimension_count >= 3:
            relaxation += 0.03
            reasons.append("focused_dimensions_sufficient")
        if consensus_score >= 0.2 and consensus_type_count >= 2:
            relaxation += 0.07
            reasons.append("cross_material_consensus")
        if structured_quality_avg >= 0.38:
            relaxation += 0.04
            reasons.append("project_structured_quality_ok")
        if structured_quality_type_rate >= 0.34:
            relaxation += 0.04
            reasons.append("strong_structured_types_available")

        relaxation = min(0.30, relaxation)
        relaxed_min = max(1, int(math.ceil(base_min * (1.0 - relaxation))))
        maximum_shortage = max(1, int(math.ceil(base_min * 0.30)))
        shortage = base_min - parsed_numeric_terms

        if (
            relaxed_min < base_min
            and parsed_numeric_terms >= relaxed_min
            and shortage <= maximum_shortage
        ):
            effective_numeric_map[mat_type] = relaxed_min
            adjustment = {
                "material_type": mat_type,
                "material_type_label": _material_type_label(mat_type),
                "base_min_numeric_terms": base_min,
                "effective_min_numeric_terms": relaxed_min,
                "parsed_numeric_terms": parsed_numeric_terms,
                "relaxation_ratio": round(relaxation, 4),
                "reasons": reasons,
                "consensus_score": round(consensus_score, 4),
                "consensus_type_count": consensus_type_count,
                "structured_quality_score": round(row_quality, 4),
                "structured_quality_max": round(row_quality_max, 4),
                "structured_signal_count": row_signal_count,
                "focused_dimension_count": focused_dimension_count,
            }
            adjustments[mat_type] = adjustment
            adaptive_summary.append(
                f"{_material_type_label(mat_type)}数字约束门槛自适应调整：{base_min}→{relaxed_min}"
            )

    return (
        effective_numeric_map,
        adjustments,
        {
            "applied": bool(adjustments),
            "summary": adaptive_summary[:8],
            "cross_type_consensus_score": round(consensus_score, 4),
            "cross_type_consensus_type_count": consensus_type_count,
            "structured_quality_avg": round(structured_quality_avg, 4),
            "structured_quality_type_rate": round(structured_quality_type_rate, 4),
        },
    )


def _resolve_material_gate_config(project: Dict[str, object]) -> Dict[str, object]:
    meta = project.get("meta") if isinstance(project.get("meta"), dict) else {}
    enforce = bool(meta.get("enforce_material_gate", DEFAULT_ENFORCE_MATERIAL_GATE))
    enforce_depth_gate = bool(
        meta.get("enforce_material_depth_gate", DEFAULT_ENFORCE_MATERIAL_DEPTH_GATE)
    )
    required_raw = meta.get("required_material_types", DEFAULT_REQUIRED_MATERIAL_TYPES)
    required_types: List[str] = []
    if isinstance(required_raw, list):
        for item in required_raw:
            key = _normalize_material_type(item)
            if key not in required_types:
                required_types.append(key)
    if not required_types:
        required_types = list(DEFAULT_REQUIRED_MATERIAL_TYPES)

    min_chars_map = dict(DEFAULT_MIN_PARSED_CHARS_BY_TYPE)
    raw_map = meta.get("min_parsed_chars_by_type")
    if isinstance(raw_map, dict):
        for k, v in raw_map.items():
            key = _normalize_material_type(k)
            numeric = _to_float_or_none(v)
            if numeric is None:
                continue
            min_chars_map[key] = max(0, int(round(numeric)))

    min_chunks_map = dict(DEFAULT_MIN_PARSED_CHUNKS_BY_TYPE)
    raw_chunks_map = meta.get("min_parsed_chunks_by_type")
    if isinstance(raw_chunks_map, dict):
        for k, v in raw_chunks_map.items():
            key = _normalize_material_type(k)
            numeric = _to_float_or_none(v)
            if numeric is None:
                continue
            min_chunks_map[key] = max(0, int(round(numeric)))

    min_numeric_terms_map = dict(DEFAULT_MIN_NUMERIC_TERMS_BY_TYPE)
    raw_numeric_map = meta.get("min_numeric_terms_by_type")
    if isinstance(raw_numeric_map, dict):
        for k, v in raw_numeric_map.items():
            key = _normalize_material_type(k)
            numeric = _to_float_or_none(v)
            if numeric is None:
                continue
            min_numeric_terms_map[key] = max(0, int(round(numeric)))

    total_chunks_raw = _to_float_or_none(meta.get("min_total_parsed_chunks"))
    min_total_chunks = (
        max(0, int(round(total_chunks_raw)))
        if total_chunks_raw is not None
        else int(DEFAULT_MIN_TOTAL_PARSED_CHUNKS)
    )

    total_chars = _to_float_or_none(meta.get("min_total_parsed_chars"))
    min_total_chars = (
        max(0, int(round(total_chars)))
        if total_chars is not None
        else int(DEFAULT_MIN_TOTAL_PARSED_CHARS)
    )
    fail_ratio_raw = _to_float_or_none(meta.get("max_material_parse_fail_ratio"))
    max_fail_ratio = (
        min(1.0, max(0.0, float(fail_ratio_raw)))
        if fail_ratio_raw is not None
        else float(DEFAULT_MAX_MATERIAL_PARSE_FAIL_RATIO)
    )
    block_on_parse_failure = bool(
        meta.get(
            "block_on_any_material_parse_failure",
            DEFAULT_BLOCK_ON_ANY_MATERIAL_PARSE_FAILURE,
        )
    )
    return {
        "enforce": enforce,
        "enforce_depth_gate": enforce_depth_gate,
        "required_types": required_types,
        "min_chars_by_type": min_chars_map,
        "min_chunks_by_type": min_chunks_map,
        "min_numeric_terms_by_type": min_numeric_terms_map,
        "min_total_chunks": min_total_chunks,
        "min_total_chars": min_total_chars,
        "max_fail_ratio": max_fail_ratio,
        "block_on_any_parse_failure": block_on_parse_failure,
    }


def _validate_material_gate_for_scoring(
    project_id: str,
    project: Dict[str, object],
    *,
    raise_on_fail: bool = True,
) -> tuple[Dict[str, object], List[str]]:
    snapshot = _build_material_quality_snapshot(project_id)
    cfg = _resolve_material_gate_config(project)
    (
        effective_numeric_terms_map,
        adaptive_numeric_adjustments,
        adaptive_numeric_meta,
    ) = _compute_adaptive_numeric_term_gate(project_id, cfg, snapshot)
    counts_by_type = snapshot.get("counts_by_type") if isinstance(snapshot, dict) else {}
    chars_by_type = snapshot.get("chars_by_type") if isinstance(snapshot, dict) else {}
    chunks_by_type = snapshot.get("chunks_by_type") if isinstance(snapshot, dict) else {}
    numeric_terms_by_type = (
        snapshot.get("numeric_terms_by_type") if isinstance(snapshot, dict) else {}
    )
    parse_status_by_type = (
        snapshot.get("parse_status_by_type")
        if isinstance(snapshot.get("parse_status_by_type"), dict)
        else {}
    )
    counts_by_type = counts_by_type if isinstance(counts_by_type, dict) else {}
    chars_by_type = chars_by_type if isinstance(chars_by_type, dict) else {}
    chunks_by_type = chunks_by_type if isinstance(chunks_by_type, dict) else {}
    numeric_terms_by_type = numeric_terms_by_type if isinstance(numeric_terms_by_type, dict) else {}
    parse_status_by_type = parse_status_by_type if isinstance(parse_status_by_type, dict) else {}
    issues: List[str] = []
    depth_issues: List[str] = []
    required_types = cfg.get("required_types") if isinstance(cfg, dict) else []
    required_types = required_types if isinstance(required_types, list) else []
    missing_required_types: List[str] = []
    for tpe in required_types:
        label = _material_type_label(tpe)
        count = int(counts_by_type.get(tpe, 0))
        if count <= 0:
            if tpe not in missing_required_types:
                missing_required_types.append(str(tpe))
            issues.append(f"缺少必需资料类型：{label}")
            continue
        status_counts = (
            parse_status_by_type.get(tpe) if isinstance(parse_status_by_type.get(tpe), dict) else {}
        )
        queued_count = int(_to_float_or_none(status_counts.get("queued")) or 0)
        processing_count = int(_to_float_or_none(status_counts.get("processing")) or 0)
        parsed_count = int(_to_float_or_none(status_counts.get("parsed")) or 0)
        failed_count = int(_to_float_or_none(status_counts.get("failed")) or 0)
        if parsed_count <= 0:
            if processing_count > 0:
                issues.append(f"{label}正在深读解析中：{processing_count} 份，请稍后再评分。")
            elif queued_count > 0:
                issues.append(f"{label}已上传但尚未开始深读：{queued_count} 份，请等待解析完成。")
            elif failed_count > 0:
                issues.append(f"{label}解析失败：{failed_count} 份，请重试或更换文件后再评分。")
            else:
                issues.append(f"{label}尚未完成解析，暂不可评分。")
            continue
        min_chars = int((cfg.get("min_chars_by_type") or {}).get(tpe, 0))
        parsed_chars = int(chars_by_type.get(tpe, 0))
        if parsed_chars < min_chars:
            issues.append(f"{label}解析文本不足：{parsed_chars} 字（要求至少 {min_chars} 字）")
        min_chunks = int((cfg.get("min_chunks_by_type") or {}).get(tpe, 0))
        parsed_chunks = int(chunks_by_type.get(tpe, 0))
        if parsed_chunks < min_chunks:
            depth_issues.append(
                f"{label}解析分块不足：{parsed_chunks} 段（建议至少 {min_chunks} 段）"
            )
        min_numeric_terms = int((effective_numeric_terms_map or {}).get(tpe, 0))
        base_min_numeric_terms = int((cfg.get("min_numeric_terms_by_type") or {}).get(tpe, 0))
        parsed_numeric_terms = int(numeric_terms_by_type.get(tpe, 0))
        if min_numeric_terms > 0 and parsed_numeric_terms < min_numeric_terms:
            base_suffix = (
                f"（基础阈值 {base_min_numeric_terms} 项）"
                if base_min_numeric_terms > min_numeric_terms
                else ""
            )
            depth_issues.append(
                f"{label}数字约束提取不足：{parsed_numeric_terms} 项（建议至少 {min_numeric_terms} 项）{base_suffix}"
            )

    total_parsed_chars = int(snapshot.get("total_parsed_chars", 0))
    min_total_chars = int(cfg.get("min_total_chars", DEFAULT_MIN_TOTAL_PARSED_CHARS))
    if total_parsed_chars < min_total_chars:
        issues.append(
            f"项目资料总解析文本不足：{total_parsed_chars} 字（要求至少 {min_total_chars} 字）"
        )
    total_parsed_chunks = int(snapshot.get("total_parsed_chunks", 0))
    min_total_chunks = int(cfg.get("min_total_chunks", DEFAULT_MIN_TOTAL_PARSED_CHUNKS))
    if total_parsed_chunks < min_total_chunks:
        depth_issues.append(
            f"项目资料总解析分块不足：{total_parsed_chunks} 段（建议至少 {min_total_chunks} 段）"
        )

    parse_fail_ratio = _to_float_or_none(snapshot.get("parse_fail_ratio")) or 0.0
    parsed_failed_files = int(_to_float_or_none(snapshot.get("parsed_failed_files")) or 0)
    max_fail_ratio = float(cfg.get("max_fail_ratio", DEFAULT_MAX_MATERIAL_PARSE_FAIL_RATIO))
    block_on_parse_failure = bool(
        cfg.get(
            "block_on_any_parse_failure",
            DEFAULT_BLOCK_ON_ANY_MATERIAL_PARSE_FAILURE,
        )
    )
    if block_on_parse_failure and parsed_failed_files > 0:
        parsed_fail_details = (
            snapshot.get("parsed_fail_details")
            if isinstance(snapshot.get("parsed_fail_details"), list)
            else []
        )
        preview = "；".join(
            str(item.get("filename") or "")
            for item in parsed_fail_details[:3]
            if isinstance(item, dict) and str(item.get("filename") or "").strip()
        )
        detail_suffix = f"（示例：{preview}）" if preview else ""
        issues.append(f"存在 {parsed_failed_files} 份资料解析失败，硬闸门已阻断评分{detail_suffix}")
    if parse_fail_ratio > max_fail_ratio:
        issues.append(f"资料解析失败比例过高：{parse_fail_ratio:.1%}（阈值 {max_fail_ratio:.1%}）")

    snapshot["gate"] = {
        "enforce": bool(cfg.get("enforce", False)),
        "required_types": required_types,
        "missing_required_types": missing_required_types,
        "min_chars_by_type": cfg.get("min_chars_by_type", {}),
        "min_total_chars": min_total_chars,
        "max_fail_ratio": max_fail_ratio,
        "block_on_any_parse_failure": block_on_parse_failure,
        "issues": issues,
        "passed": len(issues) == 0,
        "parse_status_by_type": parse_status_by_type,
    }
    enforce_depth_gate = bool(cfg.get("enforce_depth_gate", DEFAULT_ENFORCE_MATERIAL_DEPTH_GATE))
    snapshot["depth_gate"] = {
        "enforce": enforce_depth_gate,
        "required_types": required_types,
        "min_chunks_by_type": cfg.get("min_chunks_by_type", {}),
        "min_numeric_terms_by_type": cfg.get("min_numeric_terms_by_type", {}),
        "effective_min_numeric_terms_by_type": effective_numeric_terms_map,
        "adaptive_numeric_adjustments": adaptive_numeric_adjustments,
        "adaptive_numeric_meta": adaptive_numeric_meta,
        "min_total_chunks": min_total_chunks,
        "issues": depth_issues,
        "passed": len(depth_issues) == 0,
    }

    blocking_reasons: List[str] = []
    if bool(cfg.get("enforce", False)):
        blocking_reasons.extend(issues)
    if enforce_depth_gate:
        blocking_reasons.extend(depth_issues)

    if raise_on_fail and blocking_reasons:
        detail = "；".join(blocking_reasons)
        raise HTTPException(status_code=422, detail=f"资料门禁未通过：{detail}")
    return snapshot, issues


def _build_scoring_readiness(project_id: str, project: Dict[str, object]) -> Dict[str, object]:
    snapshot, issues = _validate_material_gate_for_scoring(
        project_id,
        project,
        raise_on_fail=False,
    )
    gate = snapshot.get("gate") if isinstance(snapshot.get("gate"), dict) else {}
    depth_gate = snapshot.get("depth_gate") if isinstance(snapshot.get("depth_gate"), dict) else {}
    depth_enforced = bool(depth_gate.get("enforce", False))
    depth_passed = bool(depth_gate.get("passed", True))
    gate_passed = bool(gate.get("passed", True)) and (depth_passed if depth_enforced else True)

    submissions = [s for s in load_submissions() if str(s.get("project_id")) == project_id]
    submission_count = len(submissions)
    non_empty_submission_count = sum(1 for s in submissions if str(s.get("text") or "").strip())
    scored_submission_count = sum(1 for s in submissions if _submission_is_scored(s))

    warnings: List[str] = []
    if non_empty_submission_count <= 0:
        warnings.append("尚未上传施组文件，上传后才能执行评分。")
    elif scored_submission_count <= 0:
        warnings.append("当前施组尚未完成评分，可点击“评分施组”触发。")

    parsed_failed_files = int(_to_float_or_none(snapshot.get("parsed_failed_files")) or 0)
    queued_files = int(_to_float_or_none(snapshot.get("queued_files")) or 0)
    processing_files = int(_to_float_or_none(snapshot.get("processing_files")) or 0)
    if parsed_failed_files > 0:
        warnings.append(f"存在 {parsed_failed_files} 份资料解析失败，建议修复后再评分。")
    if queued_files > 0 or processing_files > 0:
        warnings.append(
            f"仍有 {queued_files} 份资料排队、{processing_files} 份资料解析中，待深读完成后评分更稳定。"
        )
    depth_issues = depth_gate.get("issues") if isinstance(depth_gate.get("issues"), list) else []
    depth_issue_texts = [str(x).strip() for x in depth_issues if str(x).strip()]
    if depth_issue_texts:
        if depth_enforced:
            warnings.append("资料深读门禁已开启，需补齐深读质量后才能评分。")
        else:
            warnings.append("资料深读预警：建议补充关键约束资料，提高评分稳定性。")

    ready = gate_passed and non_empty_submission_count > 0
    issue_texts = [str(x).strip() for x in issues if str(x).strip()]
    if depth_enforced and depth_issue_texts:
        issue_texts.extend([f"资料深读门禁：{text}" for text in depth_issue_texts if text])

    return {
        "project_id": project_id,
        "ready": ready,
        "score_button_enabled": ready,
        "gate_passed": gate_passed,
        "issues": issue_texts,
        "warnings": warnings[:8],
        "material_quality": snapshot,
        "material_gate": gate,
        "material_depth_gate": depth_gate,
        "submissions": {
            "total": submission_count,
            "non_empty": non_empty_submission_count,
            "scored": scored_submission_count,
        },
        "retrieval_policy": _resolve_material_utilization_policy(project),
        "generated_at": _now_iso(),
    }


def _build_project_mece_audit(project_id: str, project: Dict[str, object]) -> Dict[str, object]:
    """
    项目级 MECE 审计（Mutually Exclusive, Collectively Exhaustive）。

    目标：对“资料输入 -> 评分输出 -> 进化闭环 -> 运行稳定性”给出可执行诊断，
    用于自动化验收与持续回归。
    """
    readiness = _build_scoring_readiness(project_id, project)
    depth = _build_material_depth_report(project_id, project)
    evo_health = _build_evolution_health_report(project_id, project)
    self_check = _run_system_self_check(project_id)

    submissions_all = [s for s in load_submissions() if str(s.get("project_id")) == project_id]
    scored_submissions = [s for s in submissions_all if _submission_is_scored(s)]
    scored_totals: List[float] = []
    for row in scored_submissions:
        score_fields = _resolve_submission_score_fields(
            row,
            allow_pred_score=True,
            score_scale_max=100,
        )
        scored_totals.append(float(_to_float_or_none(score_fields.get("total_score")) or 0.0))
    scored_totals = [max(0.0, min(100.0, x)) for x in scored_totals]
    if scored_totals:
        mean_score = sum(scored_totals) / len(scored_totals)
        variance = sum((x - mean_score) ** 2 for x in scored_totals) / len(scored_totals)
        std_score = variance**0.5
    else:
        std_score = 0.0
        mean_score = 0.0

    latest_scored: Optional[Dict[str, object]] = None
    if scored_submissions:
        latest_scored = max(
            scored_submissions,
            key=lambda x: str(x.get("updated_at") or x.get("created_at") or ""),
        )
    scoring_basis_ok = False
    evidence_trace_ok = False
    if isinstance(latest_scored, dict):
        try:
            basis_payload = _build_submission_scoring_basis_report(
                project_id=project_id,
                submission=latest_scored,
            )
            mece_inputs = (
                basis_payload.get("mece_inputs")
                if isinstance(basis_payload.get("mece_inputs"), dict)
                else {}
            )
            required_keys = (
                "project_materials_extracted",
                "shigong_parsed",
                "bid_requirements_loaded",
                "attention_16d_weights_injected",
                "custom_instructions_injected",
            )
            scoring_basis_ok = all(bool(mece_inputs.get(k)) for k in required_keys)
            evidence_trace = (
                basis_payload.get("evidence_trace")
                if isinstance(basis_payload.get("evidence_trace"), dict)
                else {}
            )
            total_req = int(_to_float_or_none(evidence_trace.get("total_requirements")) or 0)
            hit_req = int(_to_float_or_none(evidence_trace.get("total_hits")) or 0)
            evidence_trace_ok = total_req > 0 and hit_req > 0
        except Exception:
            scoring_basis_ok = False
            evidence_trace_ok = False

    dim_rows: List[Dict[str, object]] = []

    def _append_dim(
        *,
        key: str,
        title: str,
        checks: Dict[str, object],
        pass_condition: bool,
        warnings: Optional[List[str]] = None,
        fail_reasons: Optional[List[str]] = None,
    ) -> None:
        warn_rows = [str(x).strip() for x in (warnings or []) if str(x).strip()]
        fail_rows = [str(x).strip() for x in (fail_reasons or []) if str(x).strip()]
        status = "pass" if pass_condition else ("warn" if warn_rows else "fail")
        if fail_rows:
            status = "fail"
        dim_rows.append(
            {
                "key": key,
                "title": title,
                "status": status,
                "checks": checks,
                "warnings": warn_rows,
                "issues": fail_rows,
            }
        )

    _append_dim(
        key="input_chain",
        title="输入链路完整性",
        checks={
            "gate_passed": bool(readiness.get("gate_passed")),
            "ready": bool(readiness.get("ready")),
            "material_files": int(
                _to_float_or_none(((depth.get("quality_summary") or {}).get("total_files"))) or 0
            ),
            "materials_total_parsed_chars": int(
                _to_float_or_none(
                    ((readiness.get("material_quality") or {}).get("total_parsed_chars"))
                )
                or 0
            ),
            "required_types": list(
                ((readiness.get("material_gate") or {}).get("required_types")) or []
            ),
        },
        pass_condition=bool(readiness.get("gate_passed")) and bool(readiness.get("ready")),
        warnings=[str(x) for x in (readiness.get("warnings") or [])],
        fail_reasons=[str(x) for x in (readiness.get("issues") or [])],
    )

    score_variance_warn = []
    if len(scored_totals) >= 3 and std_score < 1.0:
        score_variance_warn.append(
            f"已评分样本 {len(scored_totals)} 份，但总分标准差仅 {std_score:.2f}，建议检查区分度。"
        )
    _append_dim(
        key="scoring_validity",
        title="评分有效性与可解释性",
        checks={
            "scored_submissions": len(scored_submissions),
            "mean_total_score": round(mean_score, 2),
            "std_total_score": round(std_score, 4),
            "scoring_basis_ok": bool(scoring_basis_ok),
            "evidence_trace_ok": bool(evidence_trace_ok),
        },
        pass_condition=len(scored_submissions) > 0 and scoring_basis_ok and evidence_trace_ok,
        warnings=score_variance_warn,
        fail_reasons=[],
    )

    gt_summary = evo_health.get("summary") if isinstance(evo_health.get("summary"), dict) else {}
    gt_count = int(_to_float_or_none(gt_summary.get("ground_truth_count")) or 0)
    matched_pred_count = int(_to_float_or_none(gt_summary.get("matched_prediction_count")) or 0)
    has_evolved_multipliers = bool(gt_summary.get("has_evolved_multipliers"))
    stored_evolved_multipliers = bool(gt_summary.get("stored_evolved_multipliers"))
    evo_fail_reasons: List[str] = []
    evo_warnings: List[str] = []
    min_learning_samples = _resolve_project_learning_min_samples(project)
    if gt_count <= 0:
        evo_fail_reasons.append("未录入真实评标，进化闭环未激活。")
    elif gt_count < min_learning_samples:
        evo_warnings.append(
            f"真实评标样本仅 {gt_count} 条，建议至少 {min_learning_samples} 条以上。"
        )
    if gt_count > 0 and matched_pred_count <= 0:
        evo_fail_reasons.append("真实评标与系统预测未形成有效匹配，闭环训练不可用。")
    if gt_count >= min_learning_samples and not has_evolved_multipliers:
        evo_warnings.append("已具备样本但尚未产出进化权重，建议执行“学习进化”。")
    if stored_evolved_multipliers and not has_evolved_multipliers:
        evo_warnings.append("系统内已有进化权重，但当前未达到生效条件，评分仍未使用该权重。")
    _append_dim(
        key="self_evolution_loop",
        title="自我进化闭环",
        checks={
            "ground_truth_count": gt_count,
            "matched_prediction_count": matched_pred_count,
            "has_evolved_multipliers": has_evolved_multipliers,
            "stored_evolved_multipliers": stored_evolved_multipliers,
            "weights_source": str(gt_summary.get("current_weights_source") or "-"),
            "drift_level": str((evo_health.get("drift") or {}).get("level") or "unknown"),
        },
        pass_condition=gt_count >= 1 and matched_pred_count >= 1,
        warnings=evo_warnings,
        fail_reasons=evo_fail_reasons,
    )

    self_check_items = self_check.get("items") if isinstance(self_check.get("items"), list) else []
    failed_rows = [x for x in self_check_items if not bool(x.get("ok"))]
    failed_items = [str(x.get("name") or "") for x in failed_rows]
    blocking_runtime_failures = [
        f"{str(x.get('name') or '')}: {str(x.get('detail') or '').strip() or 'failed'}"
        for x in failed_rows
        if str(x.get("name") or "") in SYSTEM_SELF_CHECK_REQUIRED_ITEM_NAMES
    ]
    optional_runtime_warnings = [
        f"{str(x.get('name') or '')}: {str(x.get('detail') or '').strip() or 'failed'}"
        for x in failed_rows
        if str(x.get("name") or "") not in SYSTEM_SELF_CHECK_REQUIRED_ITEM_NAMES
    ]
    _append_dim(
        key="runtime_stability",
        title="运行稳定性",
        checks={
            "self_check_ok": bool(self_check.get("ok")),
            "failed_items": failed_items,
            "service_health": bool(
                next(
                    (bool(i.get("ok")) for i in self_check_items if str(i.get("name")) == "health"),
                    False,
                )
            ),
        },
        pass_condition=bool(self_check.get("ok")) and not optional_runtime_warnings,
        warnings=optional_runtime_warnings,
        fail_reasons=blocking_runtime_failures,
    )

    pass_count = sum(1 for row in dim_rows if row.get("status") == "pass")
    warn_count = sum(1 for row in dim_rows if row.get("status") == "warn")
    fail_count = sum(1 for row in dim_rows if row.get("status") == "fail")
    total_dims = max(1, len(dim_rows))
    pass_rate = round(pass_count / total_dims, 4)
    health_score = round((pass_count + 0.5 * warn_count) / total_dims * 100, 2)
    level = "good"
    if fail_count > 0:
        level = "critical" if fail_count >= 2 else "watch"
    elif warn_count > 0:
        level = "watch"

    recommendations: List[str] = []
    for row in dim_rows:
        for text in (row.get("issues") or []) + (row.get("warnings") or []):
            s = str(text).strip()
            if s and s not in recommendations:
                recommendations.append(s)

    return {
        "project_id": project_id,
        "generated_at": _now_iso(),
        "overall": {
            "health_score": health_score,
            "level": level,
            "pass_rate": pass_rate,
            "pass_count": pass_count,
            "warn_count": warn_count,
            "fail_count": fail_count,
            "total_dimensions": total_dims,
        },
        "dimensions": dim_rows,
        "summary": {
            "submission_total": len(submissions_all),
            "submission_scored": len(scored_submissions),
            "score_mean_100": round(mean_score, 2),
            "score_std_100": round(std_score, 4),
            "ground_truth_count": gt_count,
            "matched_prediction_count": matched_pred_count,
            "self_check_ok": bool(self_check.get("ok")),
        },
        "recommendations": recommendations[:20],
    }


def _build_material_depth_report(project_id: str, project: Dict[str, object]) -> Dict[str, object]:
    readiness = _build_scoring_readiness(project_id, project)
    quality = (
        readiness.get("material_quality")
        if isinstance(readiness.get("material_quality"), dict)
        else {}
    )
    gate = (
        readiness.get("material_gate") if isinstance(readiness.get("material_gate"), dict) else {}
    )
    depth_gate = (
        readiness.get("material_depth_gate")
        if isinstance(readiness.get("material_depth_gate"), dict)
        else {}
    )
    counts_by_type = (
        quality.get("counts_by_type") if isinstance(quality.get("counts_by_type"), dict) else {}
    )
    chars_by_type = (
        quality.get("chars_by_type") if isinstance(quality.get("chars_by_type"), dict) else {}
    )
    chunks_by_type = (
        quality.get("chunks_by_type") if isinstance(quality.get("chunks_by_type"), dict) else {}
    )
    numeric_terms_by_type = (
        quality.get("numeric_terms_by_type")
        if isinstance(quality.get("numeric_terms_by_type"), dict)
        else {}
    )
    parsed_ok_by_type = (
        quality.get("parsed_ok_by_type")
        if isinstance(quality.get("parsed_ok_by_type"), dict)
        else {}
    )
    parsed_fail_by_type = (
        quality.get("parsed_fail_by_type")
        if isinstance(quality.get("parsed_fail_by_type"), dict)
        else {}
    )
    required_types = (
        gate.get("required_types") if isinstance(gate.get("required_types"), list) else []
    )
    all_types: List[str] = []
    for src in (required_types, list(counts_by_type.keys())):
        for item in src:
            key = _normalize_material_type(item)
            if key and key not in all_types:
                all_types.append(key)

    per_type_rows: List[Dict[str, object]] = []
    min_chars_by_type = (
        gate.get("min_chars_by_type") if isinstance(gate.get("min_chars_by_type"), dict) else {}
    )
    min_chunks_by_type = (
        depth_gate.get("min_chunks_by_type")
        if isinstance(depth_gate.get("min_chunks_by_type"), dict)
        else {}
    )
    min_numeric_terms_by_type = (
        depth_gate.get("min_numeric_terms_by_type")
        if isinstance(depth_gate.get("min_numeric_terms_by_type"), dict)
        else {}
    )
    for mat_type in all_types:
        files = int(_to_float_or_none(counts_by_type.get(mat_type)) or 0)
        chars = int(_to_float_or_none(chars_by_type.get(mat_type)) or 0)
        chunks = int(_to_float_or_none(chunks_by_type.get(mat_type)) or 0)
        numeric_terms = int(_to_float_or_none(numeric_terms_by_type.get(mat_type)) or 0)
        parsed_ok = int(_to_float_or_none(parsed_ok_by_type.get(mat_type)) or 0)
        parsed_fail = int(_to_float_or_none(parsed_fail_by_type.get(mat_type)) or 0)
        min_chars = int(_to_float_or_none(min_chars_by_type.get(mat_type)) or 0)
        min_chunks = int(_to_float_or_none(min_chunks_by_type.get(mat_type)) or 0)
        min_numeric_terms = int(_to_float_or_none(min_numeric_terms_by_type.get(mat_type)) or 0)
        per_type_rows.append(
            {
                "material_type": mat_type,
                "material_type_label": _material_type_label(mat_type),
                "files": files,
                "parsed_ok_files": parsed_ok,
                "parsed_failed_files": parsed_fail,
                "parsed_chars": chars,
                "parsed_chunks": chunks,
                "numeric_terms": numeric_terms,
                "targets": {
                    "min_chars": min_chars,
                    "min_chunks": min_chunks,
                    "min_numeric_terms": min_numeric_terms,
                },
                "meets_chars": chars >= min_chars,
                "meets_chunks": chunks >= min_chunks,
                "meets_numeric_terms": numeric_terms >= min_numeric_terms,
            }
        )

    recommendations: List[str] = []
    for issue in readiness.get("issues") or []:
        text = str(issue).strip()
        if text and text not in recommendations:
            recommendations.append(text)
    for warning in readiness.get("warnings") or []:
        text = str(warning).strip()
        if text and text not in recommendations:
            recommendations.append(text)
    for detail in (quality.get("parsed_fail_details") or [])[:8]:
        if not isinstance(detail, dict):
            continue
        fn = str(detail.get("filename") or "").strip()
        rs = str(detail.get("reason") or "").strip()
        tip = f"解析失败文件：{fn or '未命名文件'}（{rs or '未知原因'}），建议重新上传可解析版本。"
        if tip not in recommendations:
            recommendations.append(tip)

    material_rows = [m for m in load_materials() if str(m.get("project_id")) == project_id]
    dwg_files = 0
    site_photo_files = 0
    pdf_files = 0
    for row in material_rows:
        filename = str(row.get("filename") or "").strip()
        ext = Path(filename).suffix.lower()
        material_type = _normalize_material_type(row.get("material_type"), filename=filename)
        if ext == ".dwg" or (material_type == "drawing" and ext == ".dwg"):
            dwg_files += 1
        if ext == ".pdf":
            pdf_files += 1
        if material_type == "site_photo" and ext in {
            ".png",
            ".jpg",
            ".jpeg",
            ".webp",
            ".bmp",
            ".tif",
            ".tiff",
        }:
            site_photo_files += 1
    ocr_available = bool(pytesseract is not None and Image is not None)
    dwg_converter_bins = _resolve_dwg_converter_binaries()
    dwg_converter_available = bool(dwg_converter_bins)
    pdf_backend = _pdf_backend_name()
    pdf_parser_available = pdf_backend != "none"
    capabilities = {
        "pdf_parser_available": pdf_parser_available,
        "pdf_backend": pdf_backend,
        "pdf_file_count": pdf_files,
        "ocr_available": ocr_available,
        "dwg_converter_available": dwg_converter_available,
        "dwg_converter_bins": [Path(p).name for p in dwg_converter_bins][:8],
        "dwg_file_count": dwg_files,
        "site_photo_file_count": site_photo_files,
    }
    if site_photo_files > 0 and not ocr_available:
        tip = "已上传现场照片，但当前环境未启用 OCR（pytesseract/PIL），建议安装后重评分以提升图片信息利用率。"
        if tip not in recommendations:
            recommendations.append(tip)
    if dwg_files > 0 and not dwg_converter_available:
        tip = "已上传 DWG 图纸，但未检测到 DWG 转换器（如 dwg2dxf/ODAFileConverter），建议安装后重评分以提升图纸解析深度。"
        if tip not in recommendations:
            recommendations.append(tip)
    if pdf_files > 0 and not pdf_parser_available:
        tip = "已上传 PDF 资料，但当前环境未启用 PDF 解析后端（PyMuPDF/pypdf），建议安装后重评分。"
        if tip not in recommendations:
            recommendations.append(tip)

    quality_summary = {
        "total_files": int(_to_float_or_none(quality.get("total_files")) or 0),
        "parsed_ok_files": int(_to_float_or_none(quality.get("parsed_ok_files")) or 0),
        "parsed_failed_files": int(_to_float_or_none(quality.get("parsed_failed_files")) or 0),
        "total_parsed_chars": int(_to_float_or_none(quality.get("total_parsed_chars")) or 0),
        "total_parsed_chunks": int(_to_float_or_none(quality.get("total_parsed_chunks")) or 0),
        "total_numeric_terms": int(_to_float_or_none(quality.get("total_numeric_terms")) or 0),
        "parse_fail_ratio": float(_to_float_or_none(quality.get("parse_fail_ratio")) or 0.0),
    }

    return {
        "project_id": project_id,
        "generated_at": _now_iso(),
        "ready_to_score": bool(readiness.get("ready")),
        "capabilities": capabilities,
        "gate": gate,
        "depth_gate": depth_gate,
        "quality_summary": quality_summary,
        "by_type": per_type_rows,
        "recommendations": recommendations[:20],
    }


def _render_material_depth_report_markdown(payload: Dict[str, object]) -> str:
    by_type = payload.get("by_type") if isinstance(payload.get("by_type"), list) else []
    quality_summary = (
        payload.get("quality_summary") if isinstance(payload.get("quality_summary"), dict) else {}
    )
    capabilities = (
        payload.get("capabilities") if isinstance(payload.get("capabilities"), dict) else {}
    )
    gate = payload.get("gate") if isinstance(payload.get("gate"), dict) else {}
    depth_gate = payload.get("depth_gate") if isinstance(payload.get("depth_gate"), dict) else {}
    recommendations = (
        payload.get("recommendations") if isinstance(payload.get("recommendations"), list) else []
    )
    lines = [
        "# 项目资料深读体检报告",
        "",
        f"- 项目ID：`{payload.get('project_id') or '-'}`",
        f"- 生成时间：`{payload.get('generated_at') or '-'}`",
        f"- 评分就绪：`{bool(payload.get('ready_to_score'))}`",
        "",
        "## 总览",
        "",
        f"- 资料总数：`{quality_summary.get('total_files', 0)}`",
        f"- 解析成功：`{quality_summary.get('parsed_ok_files', 0)}`",
        f"- 解析失败：`{quality_summary.get('parsed_failed_files', 0)}`",
        f"- 解析字数：`{quality_summary.get('total_parsed_chars', 0)}`",
        f"- 解析分块：`{quality_summary.get('total_parsed_chunks', 0)}`",
        f"- 数字约束项：`{quality_summary.get('total_numeric_terms', 0)}`",
        f"- 失败率：`{quality_summary.get('parse_fail_ratio', 0.0):.2%}`",
        "",
        "## 解析能力",
        "",
        f"- PDF 解析可用：`{bool(capabilities.get('pdf_parser_available'))}`（后端：`{capabilities.get('pdf_backend', '-')}`，PDF 文件数：`{capabilities.get('pdf_file_count', 0)}`）",
        f"- OCR 可用：`{bool(capabilities.get('ocr_available'))}`（现场照片文件数：`{capabilities.get('site_photo_file_count', 0)}`）",
        f"- DWG 转换器可用：`{bool(capabilities.get('dwg_converter_available'))}`（DWG 文件数：`{capabilities.get('dwg_file_count', 0)}`）",
        f"- 已检测转换器：`{', '.join(str(x) for x in (capabilities.get('dwg_converter_bins') or [])) or '-'}`",
        "",
        "## 门禁状态",
        "",
        f"- 基础资料门禁：`{bool(gate.get('passed', True))}`（enforce={bool(gate.get('enforce', False))}）",
        f"- 深读门禁：`{bool(depth_gate.get('passed', True))}`（enforce={bool(depth_gate.get('enforce', False))}）",
        "",
        "## 分类型体检",
        "",
        "| 资料类型 | 文件数 | 成功/失败 | 解析字数 | 分块数 | 数字约束项 | 目标(字数/分块/数字) |",
        "|---|---:|---:|---:|---:|---:|---|",
    ]
    for row in by_type:
        if not isinstance(row, dict):
            continue
        targets = row.get("targets") if isinstance(row.get("targets"), dict) else {}
        lines.append(
            f"| {row.get('material_type_label', row.get('material_type', '-'))} "
            f"| {row.get('files', 0)} "
            f"| {row.get('parsed_ok_files', 0)}/{row.get('parsed_failed_files', 0)} "
            f"| {row.get('parsed_chars', 0)} "
            f"| {row.get('parsed_chunks', 0)} "
            f"| {row.get('numeric_terms', 0)} "
            f"| {targets.get('min_chars', 0)}/{targets.get('min_chunks', 0)}/{targets.get('min_numeric_terms', 0)} |"
        )
    lines.extend(["", "## 建议动作", ""])
    if recommendations:
        for item in recommendations:
            text = str(item or "").strip()
            if text:
                lines.append(f"- {text}")
    else:
        lines.append("- 当前资料深读质量满足要求，无需额外整改。")
    return "\n".join(lines).strip()


def _build_material_knowledge_profile(project_id: str) -> Dict[str, object]:
    """
    构建项目资料知识画像：
    - 按资料类型聚合：提取词项、数字约束、覆盖维度
    - 按16维聚合：评估每个维度在资料中的证据覆盖强度
    """
    material_index = _build_project_material_index(project_id)
    rows = material_index.get("files") if isinstance(material_index.get("files"), list) else []
    rows = sorted(
        [r for r in rows if isinstance(r, dict)],
        key=lambda x: str(x.get("created_at") or ""),
    )

    by_type_term_counter: Dict[str, Counter[str]] = {}
    by_type_numeric_counter: Dict[str, Counter[str]] = {}
    by_type_dim_counter: Dict[str, Counter[str]] = {}
    by_type_structured_term_counter: Dict[str, Counter[str]] = {}
    by_type_structured_dim_counter: Dict[str, Counter[str]] = {}
    by_type_section_title_counter: Dict[str, Counter[str]] = {}
    by_type_outline_term_counter: Dict[str, Counter[str]] = {}
    by_type_table_term_counter: Dict[str, Counter[str]] = {}
    by_type_scoring_point_counter: Dict[str, Counter[str]] = {}
    by_type_mandatory_clause_counter: Dict[str, Counter[str]] = {}
    by_type_numeric_categories: Dict[str, Dict[str, List[str]]] = {}
    by_type_structured_signal_count: Dict[str, int] = {}
    by_type_structured_quality_sum: Dict[str, float] = {}
    by_type_structured_quality_max: Dict[str, float] = {}
    by_type_structured_quality_files: Dict[str, int] = {}
    by_type_file_count: Dict[str, int] = {}
    by_type_ok_files: Dict[str, int] = {}
    by_type_chars: Dict[str, int] = {}
    by_type_chunks: Dict[str, int] = {}
    total_numeric_categories: Dict[str, List[str]] = {}
    site_photo_summaries: List[Dict[str, object]] = []

    by_dim_stats: Dict[str, Dict[str, object]] = {
        dim_id: {
            "keyword_hits": 0,
            "numeric_signal_hits": 0,
            "structured_signal_hits": 0,
            "source_types": set(),
            "source_files": set(),
        }
        for dim_id in DIMENSION_IDS
    }

    parsed_ok_files = 0
    parsed_failed_files = 0
    total_chars = 0
    total_chunks = 0
    total_numeric_terms = 0
    parse_fail_details: List[Dict[str, str]] = []

    for row in rows:
        filename = str(row.get("filename") or "").strip()
        mat_type = _normalize_material_type(row.get("material_type"), filename=filename)
        by_type_file_count[mat_type] = int(by_type_file_count.get(mat_type, 0)) + 1
        by_type_term_counter.setdefault(mat_type, Counter())
        by_type_numeric_counter.setdefault(mat_type, Counter())
        by_type_dim_counter.setdefault(mat_type, Counter())
        by_type_structured_term_counter.setdefault(mat_type, Counter())
        by_type_structured_dim_counter.setdefault(mat_type, Counter())
        by_type_section_title_counter.setdefault(mat_type, Counter())
        by_type_outline_term_counter.setdefault(mat_type, Counter())
        by_type_table_term_counter.setdefault(mat_type, Counter())
        by_type_scoring_point_counter.setdefault(mat_type, Counter())
        by_type_mandatory_clause_counter.setdefault(mat_type, Counter())
        by_type_numeric_categories.setdefault(mat_type, {})
        by_type_structured_signal_count.setdefault(mat_type, 0)
        by_type_structured_quality_sum.setdefault(mat_type, 0.0)
        by_type_structured_quality_max.setdefault(mat_type, 0.0)
        by_type_structured_quality_files.setdefault(mat_type, 0)
        by_type_ok_files.setdefault(mat_type, 0)
        by_type_chars.setdefault(mat_type, 0)
        by_type_chunks.setdefault(mat_type, 0)

        if not bool(row.get("parsed_ok")):
            parsed_failed_files += 1
            parse_fail_details.append(
                {
                    "filename": filename,
                    "material_type": mat_type,
                    "reason": str(row.get("parse_error") or "parse_failed"),
                }
            )
            continue
        text = str(row.get("text") or "").strip()
        if not text:
            parsed_failed_files += 1
            parse_fail_details.append(
                {"filename": filename, "material_type": mat_type, "reason": "empty_text"}
            )
            continue

        parsed_ok_files += 1
        by_type_ok_files[mat_type] = int(by_type_ok_files.get(mat_type, 0)) + 1

        chars = len(text)
        chunks = len(row.get("chunks") if isinstance(row.get("chunks"), list) else [])
        if chunks <= 0:
            chunks = len(_split_material_text_chunks(text, max_chars=900))
        total_chars += chars
        total_chunks += chunks
        by_type_chars[mat_type] = int(by_type_chars.get(mat_type, 0)) + chars
        by_type_chunks[mat_type] = int(by_type_chunks.get(mat_type, 0)) + chunks

        lexical_terms = (
            row.get("lexical_terms")
            if isinstance(row.get("lexical_terms"), list)
            else _extract_terms(text, max_terms=220)
        )
        by_type_term_counter[mat_type].update(lexical_terms)

        structured_summary: Dict[str, object] = {}
        if mat_type == "tender_qa":
            structured_summary = (
                row.get("tender_qa_structured_summary")
                if isinstance(row.get("tender_qa_structured_summary"), dict)
                else {}
            )
        elif mat_type == "boq":
            structured_summary = (
                row.get("boq_structured_summary")
                if isinstance(row.get("boq_structured_summary"), dict)
                else {}
            )
        elif mat_type == "drawing":
            structured_summary = (
                row.get("drawing_structured_summary")
                if isinstance(row.get("drawing_structured_summary"), dict)
                else {}
            )
        elif mat_type == "site_photo":
            structured_summary = (
                row.get("site_photo_structured_summary")
                if isinstance(row.get("site_photo_structured_summary"), dict)
                else {}
            )
            if structured_summary:
                site_photo_summaries.append(dict(structured_summary))
        structured_quality_score = _clip_score01(structured_summary.get("structured_quality_score"))
        if structured_quality_score is not None:
            by_type_structured_quality_sum[mat_type] = float(
                by_type_structured_quality_sum.get(mat_type, 0.0)
            ) + float(structured_quality_score)
            by_type_structured_quality_max[mat_type] = max(
                float(by_type_structured_quality_max.get(mat_type, 0.0)),
                float(structured_quality_score),
            )
            by_type_structured_quality_files[mat_type] = (
                int(by_type_structured_quality_files.get(mat_type, 0)) + 1
            )

        structured_terms = _to_text_items(structured_summary.get("structured_terms"), max_items=24)
        if structured_terms:
            by_type_term_counter[mat_type].update(structured_terms)
            by_type_structured_term_counter[mat_type].update(structured_terms)
        section_titles = _to_text_items(structured_summary.get("section_titles"), max_items=12)
        if section_titles:
            by_type_term_counter[mat_type].update(section_titles)
            by_type_section_title_counter[mat_type].update(section_titles)
        outline_terms = _collect_structured_outline_terms(
            structured_summary,
            material_type=mat_type,
            limit=12,
        )
        if outline_terms:
            by_type_term_counter[mat_type].update(outline_terms)
            by_type_outline_term_counter[mat_type].update(outline_terms)
        scoring_point_terms = _to_text_items(
            structured_summary.get("scoring_point_terms"),
            max_items=12,
        )
        if scoring_point_terms:
            by_type_term_counter[mat_type].update(scoring_point_terms)
            by_type_scoring_point_counter[mat_type].update(scoring_point_terms)
        table_constraint_terms = _collect_structured_table_terms(
            structured_summary,
            material_type=mat_type,
            limit=12,
        )
        if table_constraint_terms:
            by_type_term_counter[mat_type].update(table_constraint_terms)
            by_type_table_term_counter[mat_type].update(table_constraint_terms)
        mandatory_clause_terms = _to_text_items(
            structured_summary.get("mandatory_clause_terms"),
            max_items=10,
        )
        if mandatory_clause_terms:
            by_type_term_counter[mat_type].update(mandatory_clause_terms)
            by_type_mandatory_clause_counter[mat_type].update(mandatory_clause_terms)

        numeric_terms = (
            row.get("numeric_terms_norm") if isinstance(row.get("numeric_terms_norm"), list) else []
        )
        if not numeric_terms:
            numeric_terms = [
                token
                for token in (
                    _normalize_numeric_token(item)
                    for item in _extract_numeric_terms(text, max_terms=260)
                )
                if token
            ]
        structured_numeric_terms = _collect_structured_anchor_numeric_terms(
            structured_summary,
            limit=10,
        )
        combined_numeric_terms = _limit_unique_numeric_tokens(
            numeric_terms + structured_numeric_terms,
            limit=48,
        )
        total_numeric_terms += len(set(combined_numeric_terms))
        by_type_numeric_counter[mat_type].update(combined_numeric_terms)

        structured_dims = [
            str(item or "").zfill(2)
            for item in (structured_summary.get("focused_dimensions") or [])
            if str(item or "").strip().zfill(2) in DIMENSION_IDS
        ]
        file_name = filename
        structured_signal_strength = max(
            0,
            len(structured_terms)
            + len(structured_numeric_terms)
            + len(structured_dims)
            + min(3, len(section_titles))
            + min(3, len(outline_terms))
            + min(3, len(table_constraint_terms))
            + min(3, len(scoring_point_terms))
            + min(2, len(mandatory_clause_terms)),
        )
        by_type_structured_signal_count[mat_type] = (
            int(by_type_structured_signal_count.get(mat_type, 0)) + structured_signal_strength
        )
        if structured_dims:
            structured_dim_boost = max(1, min(4, (structured_signal_strength + 2) // 3))
            for dim_id in structured_dims:
                by_dim_stats[dim_id]["structured_signal_hits"] = (
                    int(by_dim_stats[dim_id].get("structured_signal_hits", 0))
                    + structured_dim_boost
                )
                (by_dim_stats[dim_id].get("source_types") or set()).add(mat_type)
                (by_dim_stats[dim_id].get("source_files") or set()).add(file_name)
                by_type_dim_counter[mat_type][dim_id] += structured_dim_boost
                by_type_structured_dim_counter[mat_type][dim_id] += structured_dim_boost

        lower = text.lower()
        file_numeric_strength = min(8, len(set(combined_numeric_terms)))
        for dim_id in DIMENSION_IDS:
            hit_count = 0
            for kw in DIMENSION_RAG_KEYWORDS.get(dim_id, [])[:10]:
                token = str(kw or "").strip().lower()
                if token:
                    hit_count += lower.count(token)
            if hit_count <= 0:
                continue
            dim_row = by_dim_stats[dim_id]
            dim_row["keyword_hits"] = int(dim_row.get("keyword_hits", 0)) + int(hit_count)
            dim_row["numeric_signal_hits"] = int(dim_row.get("numeric_signal_hits", 0)) + int(
                file_numeric_strength
            )
            (dim_row.get("source_types") or set()).add(mat_type)
            (dim_row.get("source_files") or set()).add(file_name)
            by_type_dim_counter[mat_type][dim_id] += int(hit_count)

        dominant_dim = by_type_dim_counter[mat_type].most_common(1)
        dominant_dim_id = str(dominant_dim[0][0]) if dominant_dim else ""
        numeric_category = _classify_numeric_anchor_category(
            terms=(lexical_terms + structured_terms)[:18],
            material_type=mat_type,
            dimension_id=dominant_dim_id,
            label=filename,
        )
        for token in sorted(set(combined_numeric_terms)):
            _append_numeric_anchor_bucket(
                by_type_numeric_categories[mat_type], numeric_category, token
            )
            _append_numeric_anchor_bucket(total_numeric_categories, numeric_category, token)

    dwg_files = 0
    site_photo_files = 0
    pdf_files = 0
    for row in rows:
        filename = str(row.get("filename") or "").strip()
        ext = Path(filename).suffix.lower()
        mat_type = _normalize_material_type(row.get("material_type"), filename=filename)
        if ext == ".dwg" or (mat_type == "drawing" and ext == ".dwg"):
            dwg_files += 1
        if ext == ".pdf":
            pdf_files += 1
        if mat_type == "site_photo" and ext in {
            ".png",
            ".jpg",
            ".jpeg",
            ".webp",
            ".bmp",
            ".tif",
            ".tiff",
        }:
            site_photo_files += 1

    pdf_backend = _pdf_backend_name()
    capabilities = {
        "pdf_parser_available": pdf_backend != "none",
        "pdf_backend": pdf_backend,
        "pdf_file_count": pdf_files,
        "ocr_available": bool(pytesseract is not None and Image is not None),
        "dwg_converter_available": bool(_resolve_dwg_converter_binaries()),
        "dwg_file_count": dwg_files,
        "site_photo_file_count": site_photo_files,
    }

    all_types: List[str] = []
    for mat_type in ["tender_qa", "boq", "drawing", "site_photo"]:
        if int(by_type_file_count.get(mat_type, 0)) > 0:
            all_types.append(mat_type)
    for mat_type in sorted(by_type_file_count.keys()):
        if mat_type not in all_types:
            all_types.append(mat_type)

    by_type_structured_summary_preview: Dict[str, Dict[str, object]] = {}
    for mat_type in all_types:
        source_summaries: List[Dict[str, object]] = []
        for row in rows:
            if (
                _normalize_material_type(row.get("material_type"), filename=row.get("filename"))
                != mat_type
            ):
                continue
            candidate: Dict[str, object] = {}
            if mat_type == "tender_qa":
                candidate = (
                    row.get("tender_qa_structured_summary")
                    if isinstance(row.get("tender_qa_structured_summary"), dict)
                    else {}
                )
            elif mat_type == "drawing":
                candidate = (
                    row.get("drawing_structured_summary")
                    if isinstance(row.get("drawing_structured_summary"), dict)
                    else {}
                )
            elif mat_type == "site_photo":
                candidate = (
                    row.get("site_photo_structured_summary")
                    if isinstance(row.get("site_photo_structured_summary"), dict)
                    else {}
                )
            elif mat_type == "boq":
                candidate = (
                    row.get("boq_structured_summary")
                    if isinstance(row.get("boq_structured_summary"), dict)
                    else {}
                )
            if candidate:
                source_summaries.append(candidate)
        page_type_counter: Counter[str] = Counter()
        document_outline_preview: List[Dict[str, object]] = []
        table_constraint_rows_preview: List[Dict[str, object]] = []
        for summary_row in source_summaries:
            for item in summary_row.get("page_type_summary") or []:
                if isinstance(item, dict):
                    page_type_counter[str(item.get("page_type") or "")] += int(
                        _to_float_or_none(item.get("count")) or 0
                    )
            for item in summary_row.get("document_outline") or []:
                if isinstance(item, dict) and item not in document_outline_preview:
                    document_outline_preview.append(item)
            for item in summary_row.get("table_constraint_rows") or []:
                if isinstance(item, dict) and item not in table_constraint_rows_preview:
                    table_constraint_rows_preview.append(item)
        by_type_structured_summary_preview[mat_type] = {
            "page_type_summary": [
                {"page_type": key, "count": int(value)}
                for key, value in page_type_counter.most_common(6)
            ],
            "document_outline_preview": document_outline_preview[:8],
            "table_constraint_rows_preview": table_constraint_rows_preview[:6],
        }

    by_type_rows: List[Dict[str, object]] = []
    for mat_type in all_types:
        dim_hits = by_type_dim_counter.get(mat_type, Counter())
        structured_preview = by_type_structured_summary_preview.get(mat_type) or {}
        parsed_ok_count = int(by_type_ok_files.get(mat_type, 0))
        quality_files = int(by_type_structured_quality_files.get(mat_type, 0))
        quality_avg = (
            float(by_type_structured_quality_sum.get(mat_type, 0.0)) / float(parsed_ok_count)
            if parsed_ok_count > 0
            else 0.0
        )
        quality_signal_coverage = (
            float(quality_files) / float(parsed_ok_count) if parsed_ok_count > 0 else 0.0
        )
        top_dims = [
            {
                "dimension_id": dim_id,
                "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
                "keyword_hits": int(score),
            }
            for dim_id, score in dim_hits.most_common(4)
        ]
        by_type_rows.append(
            {
                "material_type": mat_type,
                "material_type_label": _material_type_label(mat_type),
                "files": int(by_type_file_count.get(mat_type, 0)),
                "parsed_ok_files": int(by_type_ok_files.get(mat_type, 0)),
                "parsed_chars": int(by_type_chars.get(mat_type, 0)),
                "parsed_chunks": int(by_type_chunks.get(mat_type, 0)),
                "unique_terms": int(len(by_type_term_counter.get(mat_type, Counter()))),
                "numeric_terms": int(
                    sum(by_type_numeric_counter.get(mat_type, Counter()).values())
                ),
                "top_terms": [
                    term
                    for term, _ in by_type_term_counter.get(mat_type, Counter()).most_common(10)
                ],
                "structured_terms_preview": [
                    term
                    for term, _ in by_type_structured_term_counter.get(
                        mat_type, Counter()
                    ).most_common(10)
                ],
                "section_titles_preview": [
                    term
                    for term, _ in by_type_section_title_counter.get(
                        mat_type, Counter()
                    ).most_common(8)
                ],
                "outline_terms_preview": [
                    term
                    for term, _ in by_type_outline_term_counter.get(
                        mat_type, Counter()
                    ).most_common(8)
                ],
                "table_constraint_terms_preview": [
                    term
                    for term, _ in by_type_table_term_counter.get(mat_type, Counter()).most_common(
                        8
                    )
                ],
                "scoring_point_terms_preview": [
                    term
                    for term, _ in by_type_scoring_point_counter.get(
                        mat_type, Counter()
                    ).most_common(8)
                ],
                "mandatory_clause_terms_preview": [
                    term
                    for term, _ in by_type_mandatory_clause_counter.get(
                        mat_type, Counter()
                    ).most_common(6)
                ],
                "page_type_summary": list(structured_preview.get("page_type_summary") or [])[:8],
                "document_outline_preview": list(
                    structured_preview.get("document_outline_preview") or []
                )[:8],
                "table_constraint_rows_preview": list(
                    structured_preview.get("table_constraint_rows_preview") or []
                )[:6],
                "structured_signal_count": int(by_type_structured_signal_count.get(mat_type, 0)),
                "structured_quality_score": round(float(quality_avg), 4),
                "structured_quality_max": round(
                    float(by_type_structured_quality_max.get(mat_type, 0.0)),
                    4,
                ),
                "structured_quality_signal_coverage": round(float(quality_signal_coverage), 4),
                "top_numeric_terms": [
                    term
                    for term, _ in by_type_numeric_counter.get(mat_type, Counter()).most_common(8)
                ],
                "numeric_category_summary": _build_numeric_anchor_category_summary(
                    by_type_numeric_categories.get(mat_type) or {}
                ),
                "focused_dimensions": [
                    dim_id
                    for dim_id, _ in by_type_structured_dim_counter.get(
                        mat_type, Counter()
                    ).most_common(4)
                ],
                "top_dimensions": top_dims,
            }
        )

    quality_rows = [
        row for row in by_type_rows if int(_to_float_or_none(row.get("parsed_ok_files")) or 0) > 0
    ]
    structured_quality_avg = (
        round(
            sum(
                float(_to_float_or_none(row.get("structured_quality_score")) or 0.0)
                for row in quality_rows
            )
            / float(len(quality_rows)),
            4,
        )
        if quality_rows
        else 0.0
    )
    structured_quality_max = (
        round(
            max(
                float(_to_float_or_none(row.get("structured_quality_max")) or 0.0)
                for row in quality_rows
            ),
            4,
        )
        if quality_rows
        else 0.0
    )
    strong_structured_types = [
        row
        for row in quality_rows
        if float(_to_float_or_none(row.get("structured_quality_score")) or 0.0) >= 0.45
    ]
    structured_quality_type_rate = (
        round(float(len(strong_structured_types)) / float(len(quality_rows)), 4)
        if quality_rows
        else 0.0
    )
    cross_type_consensus = _build_cross_type_material_consensus(by_type_rows)
    site_photo_evidence_summary = _build_site_photo_evidence_summary(site_photo_summaries)

    by_dimension_rows: List[Dict[str, object]] = []
    low_dims: List[Dict[str, object]] = []
    for dim_id in DIMENSION_IDS:
        row = by_dim_stats.get(dim_id) or {}
        keyword_hits = int(row.get("keyword_hits", 0))
        numeric_signal_hits = int(row.get("numeric_signal_hits", 0))
        structured_signal_hits = int(row.get("structured_signal_hits", 0))
        source_types = sorted(str(x) for x in (row.get("source_types") or set()) if str(x))
        source_files = sorted(str(x) for x in (row.get("source_files") or set()) if str(x))
        # 覆盖评分：关键词命中 + 跨类型覆盖共同决定（0..1）。
        coverage_score = min(
            1.0,
            (keyword_hits / 8.0)
            + (len(source_types) * 0.16)
            + min(0.24, structured_signal_hits * 0.05),
        )
        if numeric_signal_hits > 0:
            coverage_score = min(1.0, coverage_score + 0.06)
        coverage_level = (
            "high" if coverage_score >= 0.75 else ("medium" if coverage_score >= 0.35 else "low")
        )
        dim_row = {
            "dimension_id": dim_id,
            "dimension_name": str((DIMENSIONS.get(dim_id) or {}).get("name") or dim_id),
            "keyword_hits": keyword_hits,
            "numeric_signal_hits": numeric_signal_hits,
            "structured_signal_hits": structured_signal_hits,
            "source_types": source_types,
            "source_file_count": len(source_files),
            "source_files_preview": source_files[:6],
            "coverage_score": round(float(coverage_score), 4),
            "coverage_level": coverage_level,
            "suggested_keywords": list((DIMENSION_RAG_KEYWORDS.get(dim_id) or [])[:4]),
        }
        by_dimension_rows.append(dim_row)
        if coverage_level == "low":
            low_dims.append(dim_row)

    covered_dimensions = sum(1 for item in by_dimension_rows if item.get("coverage_level") != "low")
    coverage_rate = (
        round(float(covered_dimensions) / float(len(DIMENSION_IDS)), 4) if DIMENSION_IDS else 0.0
    )

    recommendations: List[str] = []
    if not rows:
        recommendations.append("尚未上传任何项目资料，请先上传招答/清单/图纸/现场照片后再评分。")
    if parsed_failed_files > 0:
        recommendations.append(
            f"存在 {parsed_failed_files} 份资料未解析成功，建议优先修复（见失败详情）。"
        )
    if capabilities["site_photo_file_count"] > 0 and not capabilities["ocr_available"]:
        recommendations.append("已上传现场照片但 OCR 不可用，建议安装 OCR 组件后重评分。")
    if site_photo_evidence_summary:
        if (
            int(_to_float_or_none(site_photo_evidence_summary.get("duplicate_evidence_count")) or 0)
            > 0
        ):
            recommendations.append(
                "现场照片存在重复证据，系统已自动去重；建议补充不同区域/工序/时段的现场照片。"
            )
        if (
            float(
                _to_float_or_none(site_photo_evidence_summary.get("avg_evidence_confidence")) or 0.0
            )
            < 0.32
        ):
            recommendations.append(
                "现场照片视觉证据置信度偏弱，建议补充更清晰、带标识和工序特征的现场照片。"
            )
    if capabilities["dwg_file_count"] > 0 and not capabilities["dwg_converter_available"]:
        recommendations.append("已上传 DWG 图纸但转换器不可用，建议安装 DWG 转换器后重评分。")
    if capabilities["pdf_file_count"] > 0 and not capabilities["pdf_parser_available"]:
        recommendations.append(
            "已上传 PDF 资料但 PDF 解析后端不可用，建议安装 PyMuPDF 或 pypdf 后重评分。"
        )
    if quality_rows and structured_quality_avg < 0.35:
        recommendations.append(
            "资料已解析，但整体结构化质量偏弱，建议补充章节标题、评分点、强制条款和硬参数。"
        )
    if quality_rows and structured_quality_type_rate < 0.34:
        recommendations.append(
            "高质量结构化资料类型不足，建议优先增强招答、清单、图纸三类核心资料。"
        )
    if float(_to_float_or_none(cross_type_consensus.get("consensus_score")) or 0.0) < 0.2:
        recommendations.append(
            "跨资料共识锚点偏弱，建议让招答、清单、图纸在工期/规格/阈值类关键参数上形成一致表述。"
        )
    for dim_row in low_dims[:6]:
        dim_name = str(dim_row.get("dimension_name") or dim_row.get("dimension_id") or "")
        kw = "、".join(str(x) for x in (dim_row.get("suggested_keywords") or [])[:3])
        if kw:
            recommendations.append(f"维度[{dim_name}]证据薄弱，建议在资料/施组中补充：{kw}。")
        else:
            recommendations.append(
                f"维度[{dim_name}]证据薄弱，建议补充可量化的执行条款与验收口径。"
            )
    for item in parse_fail_details[:8]:
        fn = str(item.get("filename") or "").strip() or "未命名文件"
        rs = str(item.get("reason") or "").strip() or "未知原因"
        recommendations.append(f"解析失败：{fn}（{rs}）。")

    return {
        "project_id": project_id,
        "generated_at": _now_iso(),
        "capabilities": capabilities,
        "summary": {
            "total_files": len(rows),
            "parsed_ok_files": parsed_ok_files,
            "parsed_failed_files": parsed_failed_files,
            "total_parsed_chars": total_chars,
            "total_parsed_chunks": total_chunks,
            "total_numeric_terms": total_numeric_terms,
            "structured_signal_total": int(sum(by_type_structured_signal_count.values())),
            "structured_quality_avg": structured_quality_avg,
            "structured_quality_max": structured_quality_max,
            "strong_structured_types": len(strong_structured_types),
            "structured_quality_type_rate": structured_quality_type_rate,
            "numeric_category_summary": _build_numeric_anchor_category_summary(
                total_numeric_categories
            ),
            "cross_type_consensus_score": float(cross_type_consensus.get("consensus_score") or 0.0),
            "cross_type_consensus_type_count": int(
                _to_float_or_none(cross_type_consensus.get("source_type_count")) or 0
            ),
            "cross_type_focus_dimensions": list(
                cross_type_consensus.get("focused_dimensions") or []
            )[:8],
            "cross_type_consensus_terms": list(cross_type_consensus.get("consensus_terms") or [])[
                :10
            ],
            "cross_type_numeric_category_summary": list(
                cross_type_consensus.get("consensus_numeric_category_summary") or []
            )[:8],
            "covered_dimensions": covered_dimensions,
            "dimension_coverage_rate": coverage_rate,
            "low_coverage_dimensions": len(low_dims),
            "site_photo_unique_evidence_count": int(
                _to_float_or_none(site_photo_evidence_summary.get("unique_evidence_count")) or 0
            ),
            "site_photo_duplicate_evidence_count": int(
                _to_float_or_none(site_photo_evidence_summary.get("duplicate_evidence_count")) or 0
            ),
            "site_photo_avg_evidence_confidence": float(
                _to_float_or_none(site_photo_evidence_summary.get("avg_evidence_confidence")) or 0.0
            ),
        },
        "by_type": by_type_rows,
        "by_dimension": by_dimension_rows,
        "site_photo_evidence": site_photo_evidence_summary,
        "recommendations": recommendations[:24],
    }


def _render_material_knowledge_profile_markdown(payload: Dict[str, object]) -> str:
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    by_type = payload.get("by_type") if isinstance(payload.get("by_type"), list) else []
    by_dimension = (
        payload.get("by_dimension") if isinstance(payload.get("by_dimension"), list) else []
    )
    recommendations = (
        payload.get("recommendations") if isinstance(payload.get("recommendations"), list) else []
    )
    capabilities = (
        payload.get("capabilities") if isinstance(payload.get("capabilities"), dict) else {}
    )
    lines = [
        "# 项目资料知识画像报告",
        "",
        f"- 项目ID：`{payload.get('project_id') or '-'}`",
        f"- 生成时间：`{payload.get('generated_at') or '-'}`",
        "",
        "## 总览",
        "",
        f"- 资料总数：`{summary.get('total_files', 0)}`",
        f"- 解析成功/失败：`{summary.get('parsed_ok_files', 0)}/{summary.get('parsed_failed_files', 0)}`",
        f"- 解析字数：`{summary.get('total_parsed_chars', 0)}`",
        f"- 分块数：`{summary.get('total_parsed_chunks', 0)}`",
        f"- 数字约束项：`{summary.get('total_numeric_terms', 0)}`",
        f"- 结构化信号总量：`{summary.get('structured_signal_total', 0)}`",
        f"- 结构化平均质量：`{float(summary.get('structured_quality_avg', 0.0) or 0.0):.2%}`",
        f"- 高质量资料类型覆盖：`{float(summary.get('structured_quality_type_rate', 0.0) or 0.0):.2%}`",
        f"- 数值约束簇：`{'；'.join(str(x) for x in (summary.get('numeric_category_summary') or [])) or '-'}`",
        f"- 维度覆盖率：`{summary.get('dimension_coverage_rate', 0.0):.2%}`",
        "",
        "## 解析能力",
        "",
        f"- PDF 解析可用：`{bool(capabilities.get('pdf_parser_available'))}`（后端：`{capabilities.get('pdf_backend', '-')}`）",
        f"- OCR 可用：`{bool(capabilities.get('ocr_available'))}`",
        f"- DWG 转换器可用：`{bool(capabilities.get('dwg_converter_available'))}`",
        f"- PDF 文件数：`{capabilities.get('pdf_file_count', 0)}`",
        f"- 现场照片文件数：`{capabilities.get('site_photo_file_count', 0)}`",
        f"- DWG 文件数：`{capabilities.get('dwg_file_count', 0)}`",
        "",
        "## 按资料类型",
        "",
        "| 资料类型 | 文件数 | 解析字数 | 分块数 | 词项数 | 数字约束项 | 数值约束簇 |",
        "|---|---:|---:|---:|---:|---:|---|",
    ]
    for row in by_type:
        if not isinstance(row, dict):
            continue
        lines.append(
            f"| {row.get('material_type_label', row.get('material_type', '-'))} "
            f"| {row.get('files', 0)} "
            f"| {row.get('parsed_chars', 0)} "
            f"| {row.get('parsed_chunks', 0)} "
            f"| {row.get('unique_terms', 0)} "
            f"| {row.get('numeric_terms', 0)} |"
            f" {'；'.join(str(x) for x in (row.get('numeric_category_summary') or [])) or '-'} |"
        )

    lines.extend(
        [
            "",
            "## 按评分维度",
            "",
            "| 维度 | 关键词命中 | 来源类型数 | 覆盖评分 | 等级 |",
            "|---|---:|---:|---:|---|",
        ]
    )
    for row in by_dimension:
        if not isinstance(row, dict):
            continue
        lines.append(
            f"| {row.get('dimension_id', '-')} {row.get('dimension_name', '')} "
            f"| {row.get('keyword_hits', 0)} "
            f"| {len(row.get('source_types') or [])} "
            f"| {row.get('coverage_score', 0)} "
            f"| {row.get('coverage_level', '-')} |"
        )

    lines.extend(["", "## 建议动作", ""])
    if recommendations:
        for item in recommendations:
            text = str(item or "").strip()
            if text:
                lines.append(f"- {text}")
    else:
        lines.append("- 当前知识覆盖正常，无需额外动作。")
    return "\n".join(lines).strip()


def _compute_multipliers_hash(multipliers: dict) -> str:
    """计算 multipliers 的 hash，用于缓存 key"""
    import hashlib
    import json

    content = json.dumps(multipliers, sort_keys=True)
    return hashlib.sha256(content.encode("utf-8")).hexdigest()[:16]


def _get_effective_dimension_multipliers(project_id: str) -> Dict[str, float]:
    multipliers, _, _ = _resolve_project_scoring_context(project_id)
    return multipliers


def _get_evolution_total_score_scale(project_id: str) -> float | None:
    """进化报告中的总分缩放因子，用于使本系统总分贴近青天平均分。"""
    reports = load_evolution_reports()
    evo = reports.get(project_id) or {}
    se = evo.get("scoring_evolution") or {}
    scale = se.get("total_score_scale")
    if scale is not None and isinstance(scale, (int, float)):
        return float(scale)
    return None


def _apply_evolution_total_scale(project_id: str, report: Dict[str, object]) -> None:
    """若进化报告有 total_score_scale，对总分进行缩放（原地修改 report）。"""
    scale = _get_evolution_total_score_scale(project_id)
    if scale is None or abs(scale - 1.0) < 1e-6:
        return
    for key in ("total_score", "rule_total_score", "pred_total_score", "llm_total_score"):
        v = report.get(key)
        if v is not None:
            try:
                report[key] = round(min(100.0, max(0.0, float(v) * scale)), 2)
            except (TypeError, ValueError):
                pass
    # 若存在 pred_total_score，则保持 total_score 与展示/排序主分一致。
    pred_total = _to_float_or_none(report.get("pred_total_score"))
    rule_total = _to_float_or_none(report.get("rule_total_score"))
    if pred_total is not None:
        report["total_score"] = pred_total
    elif rule_total is not None:
        report["total_score"] = rule_total


@router.post(
    "/projects/{project_id}/shigong",
    response_model=SubmissionRecord,
    tags=["施组提交"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
def upload_shigong(
    project_id: str,
    file: UploadFile = File(...),
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> SubmissionRecord:
    """
    上传施工组织设计文档（仅上传，不自动评分）。

    上传 TXT / DOCX / PDF / JSON / XLSX / DXF 格式施组文档并保存解析文本。
    上传后提交会进入“待评分”状态，需手动调用“评分施组”才会产生分数。

    **需要 API Key 认证**

    支持 Accept-Language header 进行多语言响应。
    """
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    raw_filename = file.filename or ""
    normalized_filename = _normalize_uploaded_filename(raw_filename)
    if not normalized_filename:
        raise HTTPException(status_code=422, detail="施组文件名为空，请重试或重命名后上传。")
    content = file.file.read()
    try:
        text = _read_uploaded_file_content(content, normalized_filename)
    except ValueError as e:
        raise HTTPException(status_code=422, detail=str(e))
    submissions = load_submissions()
    now_utc = datetime.now(timezone.utc)
    duplicate = _find_recent_duplicate_submission(
        submissions,
        project_id=project_id,
        filename=normalized_filename,
        text=text,
        now_utc=now_utc,
    )
    if duplicate is not None:
        return SubmissionRecord(**duplicate)

    _, profile_snapshot, project = _resolve_project_scoring_context(project_id)
    scoring_engine_version = str(project.get("scoring_engine_version_locked") or "v1")
    submission_id = str(uuid4())

    report = _build_pending_submission_report(
        project=project,
        scoring_engine_version=scoring_engine_version,
    )
    if profile_snapshot:
        report_meta = report.get("meta")
        report_meta = report_meta if isinstance(report_meta, dict) else {}
        report_meta["expert_profile_snapshot"] = profile_snapshot
        report_meta["expert_profile_id"] = profile_snapshot.get("id")
        report["meta"] = report_meta

    record = {
        "id": submission_id,
        "project_id": project_id,
        "filename": normalized_filename,
        "total_score": 0.0,
        "report": report,
        "text": text,
        "created_at": now_utc.isoformat(),
        "updated_at": now_utc.isoformat(),
        "expert_profile_id_used": profile_snapshot.get("id") if profile_snapshot else None,
    }
    submissions.append(record)
    save_submissions(submissions)

    return SubmissionRecord(**record)


@router.post(
    "/projects/{project_id}/score",
    response_model=SubmissionRecord,
    tags=["施组提交"],
    responses={**RESPONSES_401, **RESPONSES_404, **RESPONSES_422},
)
def score_text_for_project(
    project_id: str,
    payload: ScoreRequest,
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> SubmissionRecord:
    """
    对文本内容进行项目级评分。

    与直接上传文件不同，此端点接收内联文本进行评分。
    适用于已解析的文本内容或 API 集成场景。
    支持评分结果缓存，相同文本和配置重复评分时直接返回缓存结果。

    **需要 API Key 认证**

    支持 Accept-Language header 进行多语言响应。
    """
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    config = load_config()
    multipliers, profile_snapshot, project = _resolve_project_scoring_context(project_id)
    submission_id = str(uuid4())
    scoring_engine_version = str(project.get("scoring_engine_version_locked") or "v1")
    engine_version = _determine_engine_version(project, scoring_engine_version)
    material_knowledge_snapshot = _build_material_knowledge_profile(project_id)

    if engine_version == "v1":
        config_hash = _compute_multipliers_hash(multipliers) if multipliers else None
        cached_result = get_cached_score(payload.text, config_hash)
        if cached_result is not None:
            report = dict(cached_result)
        else:
            raw_report, _ = _score_submission_for_project(
                submission_id=submission_id,
                text=payload.text,
                project_id=project_id,
                project=project,
                config=config,
                multipliers=multipliers,
                profile_snapshot=profile_snapshot,
                scoring_engine_version=scoring_engine_version,
                material_knowledge_snapshot=material_knowledge_snapshot,
            )
            # 缓存仅存“未缩放原始分”，避免后续读取时重复应用 total_score_scale。
            cache_score_result(payload.text, raw_report, config_hash)
            report = dict(raw_report)
        _apply_evolution_total_scale(project_id, report)
        evidence_units: List[Dict[str, object]] = []
    else:
        report, evidence_units = _score_submission_for_project(
            submission_id=submission_id,
            text=payload.text,
            project_id=project_id,
            project=project,
            config=config,
            multipliers=multipliers,
            profile_snapshot=profile_snapshot,
            scoring_engine_version=scoring_engine_version,
            material_knowledge_snapshot=material_knowledge_snapshot,
        )
        _apply_evolution_total_scale(project_id, report)

    record = {
        "id": submission_id,
        "project_id": project_id,
        "filename": "inline",
        "total_score": float(report.get("total_score", report.get("rule_total_score", 0.0))),
        "report": report,
        "text": payload.text,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "expert_profile_id_used": profile_snapshot.get("id") if profile_snapshot else None,
    }
    submissions = load_submissions()
    submissions.append(record)
    save_submissions(submissions)

    snapshots = load_score_reports()
    snapshots.append(
        _build_score_report_snapshot(
            submission_id=submission_id,
            project=project,
            report=report,
            profile_snapshot=profile_snapshot,
            scoring_engine_version=scoring_engine_version,
        )
    )
    save_score_reports(snapshots)
    if evidence_units:
        all_units = _load_evidence_units_safe()
        all_units = _replace_submission_evidence_units(
            all_units,
            submission_id=submission_id,
            new_units=evidence_units,
        )
        save_evidence_units(all_units)

    # 记录评分历史
    dimension_scores = {
        dim_id: dim.get("score", 0.0) for dim_id, dim in report.get("dimension_scores", {}).items()
    }
    penalty_count = len(report.get("penalties", []))
    record_history_score(
        project_id=project_id,
        submission_id=submission_id,
        filename="inline",
        total_score=float(report.get("total_score", report.get("rule_total_score", 0.0))),
        dimension_scores=dimension_scores,
        penalty_count=penalty_count,
    )

    return SubmissionRecord(**record)


@router.get(
    "/projects/{project_id}/submissions",
    response_model=list[SubmissionRecord] | ProjectPreScoreListResponse,
    tags=["施组提交"],
)
def list_submissions(
    project_id: str,
    with_: Optional[str] = Query(None, alias="with"),
):
    """
    获取项目的所有施组提交记录。

    返回指定项目下的所有历史评分记录，包括评分报告详情。
    """
    ensure_data_dirs()
    projects = load_projects()
    project = next((p for p in projects if str(p.get("id")) == project_id), {"id": project_id})
    submissions = [s for s in load_submissions() if s["project_id"] == project_id]
    bundle = submission_dual_track_views_module.build_project_submission_views(
        project_id,
        submissions,
        project=project,
    )
    submissions_view = bundle["submissions_view"]
    allow_pred_score = bool(bundle["allow_pred_score"])
    score_scale_max = int(bundle["score_scale_max"])
    if with_ != "latest_report":
        return [SubmissionRecord(**s) for s in submissions_view]

    return ProjectPreScoreListResponse(
        project_id=project_id,
        expert_profile_id=project.get("expert_profile_id"),
        submissions=submission_dual_track_views_module.build_project_pre_score_rows(
            project_id,
            submissions_view,
            allow_pred_score=allow_pred_score,
            score_scale_max=score_scale_max,
        ),
    )


def _delete_submission_record(project_id: str, submission_id: str, locale: str) -> None:
    ensure_data_dirs()
    projects = load_projects()
    if not any(p["id"] == project_id for p in projects):
        raise HTTPException(status_code=404, detail=t("api.project_not_found", locale=locale))
    submissions = load_submissions()
    found = next(
        (
            s
            for s in submissions
            if s.get("id") == submission_id and s.get("project_id") == project_id
        ),
        None,
    )
    if not found:
        raise HTTPException(status_code=404, detail="施组提交记录不存在")
    raw_path = str(found.get("path") or "").strip()
    if raw_path:
        p = Path(raw_path)
        if p.exists():
            p.unlink()
    submissions = [
        s
        for s in submissions
        if not (s.get("id") == submission_id and s.get("project_id") == project_id)
    ]
    save_submissions(submissions)
    snapshots = load_score_reports()
    snapshots = [
        r
        for r in snapshots
        if not (r.get("submission_id") == submission_id and r.get("project_id") == project_id)
    ]
    save_score_reports(snapshots)
    evidence_units = _load_evidence_units_safe()
    evidence_units = [u for u in evidence_units if str(u.get("submission_id")) != submission_id]
    save_evidence_units(evidence_units)
    qingtian_results = load_qingtian_results()
    qingtian_results = [q for q in qingtian_results if str(q.get("submission_id")) != submission_id]
    save_qingtian_results(qingtian_results)
    delta_cases = load_delta_cases()
    delta_cases = [d for d in delta_cases if str(d.get("submission_id")) != submission_id]
    save_delta_cases(delta_cases)
    calibration_samples = load_calibration_samples()
    calibration_samples = [
        s for s in calibration_samples if str(s.get("submission_id")) != submission_id
    ]
    save_calibration_samples(calibration_samples)
    # 删除属于显式反馈信号：自动刷新样本并触发校准/调权重闭环。
    _run_feedback_closed_loop_safe(project_id, locale=locale, trigger="delete_submission")


@router.delete(
    "/projects/{project_id}/submissions/{submission_id}",
    tags=["施组提交"],
    responses={**RESPONSES_401, **RESPONSES_404},
)
def delete_submission(
    project_id: str,
    submission_id: str,
    api_key: Optional[str] = Depends(verify_api_key),
    locale: str = Depends(get_locale),
) -> dict:
    """删除指定项目下的一条施组提交记录。"""
    _delete_submission_record(project_id=project_id, submission_id=submission_id, locale=locale)
    return {"ok": True, "id": submission_id}


